// Batched read clients come from the shared `createPublicClientForChain` (wallet.js, re-exported by
// component-base) — one cache for the whole app, keyed by chainId|customRpc so a custom RPC takes
// effect immediately (the old discover-local cache keyed by chainId only, ignoring RPC changes).
var clientFor = createPublicClientForChain;

// The V6 contracts are deployed (same CREATE2 addresses) on every chain below. Discover pivots between
// the two networks via the header dropdown; `DISCOVER_CHAINS` is the active set and is reassigned by
// setNetwork(). Every consumer reads it live, so reassigning + re-rendering is enough to switch.
var TESTNET_CHAINS = [
  { id: 11155111, name: 'Sepolia', short: 'Eth' },
  { id: 421614, name: 'Arbitrum Sepolia', short: 'Arb' },
  { id: 84532, name: 'Base Sepolia', short: 'Base' },
  { id: 11155420, name: 'OP Sepolia', short: 'OP' },
];
var MAINNET_CHAINS = [
  { id: 1, name: 'Ethereum', short: 'Eth' },
  { id: 42161, name: 'Arbitrum', short: 'Arb' },
  { id: 8453, name: 'Base', short: 'Base' },
  { id: 10, name: 'Optimism', short: 'OP' },
];
// A testnet slug (#sep:/#arbsep:/#basesep:/#opsep:) or mainnet slug (#eth:/#arb:/#base:/#op:) in the URL hash
// dictates the network — otherwise someone opening a shared TESTNET link with no `jb-network` in localStorage loads
// mainnet (the default) and the project + its owner Safe resolve on the WRONG network ("connect a signer" for an
// address that IS a signer on the testnet Safe). The saved preference is only the fallback. Self-contained (no
// CHAIN_SLUGS dependency) so it is safe to call at module load, before that map is assigned.
function networkModeFromHash() {
  try {
    var slug = (location.hash || '').replace(/^#/, '').split(/[:/]/)[0];
    if (/^(sep|arbsep|basesep|opsep)$/.test(slug)) return 'testnet';
    if (/^(eth|arb|base|op)$/.test(slug)) return 'mainnet';
    return null;
  } catch (_) { return null; }
}
function getNetworkMode() {
  var fromHash = networkModeFromHash();
  if (fromHash) return fromHash;
  // Default to mainnet (the real network — 7 canonical revnets live). Project metadata/feeds use the matching
  // Bendystraw host while transaction-critical state stays onchain. Testnets are available via the toggle.
  try { return localStorage.getItem('jb-network') === 'testnet' ? 'testnet' : 'mainnet'; } catch (_) { return 'mainnet'; }
}
var DISCOVER_NETWORK = getNetworkMode();
var DISCOVER_CHAINS = DISCOVER_NETWORK === 'mainnet' ? MAINNET_CHAINS : TESTNET_CHAINS;
// Reconcile the indexer host with the (hash-aware) network at module load — bendystraw-client seeds its host from
// localStorage only, so a fresh visitor on a #sep: link would otherwise get testnet chains but mainnet feeds.
setBendystrawNetwork(DISCOVER_NETWORK);
// Switch the active network: persist, swap the chain set + indexer host, drop caches + any open project
// route, and re-render the grid from scratch.
export function setDiscoverNetwork(mode) {
  mode = mode === 'mainnet' ? 'mainnet' : 'testnet';
  if (mode === DISCOVER_NETWORK) {
    setBendystrawNetwork(mode);
    return;
  }
  DISCOVER_NETWORK = mode;
  try { localStorage.setItem('jb-network', mode); } catch (_) {}
  DISCOVER_CHAINS = mode === 'mainnet' ? MAINNET_CHAINS : TESTNET_CHAINS;
  setBendystrawNetwork(mode);
  _groups = null; _cache = {}; _splitProjCache = {}; _bendystrawProjectRecordCache = {}; _preferredProjectMetadataCache = {};
  _tiersCache = {}; _tierMetadataCache = {}; _dataHookCache = {}; _instanceProvenanceCache = {}; _activeDetail = null;
  // Only discard a project route from the other network. Top-level routes such as #data must stay put.
  if (networkModeFromHash()) location.hash = '';
  if (_container) renderDiscoverTab();
}

