var LOAN_REV_FEE_PERCENT = 10; // 1% of the borrow, out of MAX_FEE (1000), to the $REV revnet
var _loanRevIdCache = {};
function loanRevIdOf(chainId) {
  if (_loanRevIdCache[chainId] !== undefined) return Promise.resolve(_loanRevIdCache[chainId]);
  var loans = getAddress('REVLoans', chainId);
  if (!loans) return Promise.resolve(null);
  return clientFor(chainId).readContract({ address: loans, abi: revLoanIdAbi, functionName: 'REV_ID', args: [] })
    .then(function (id) { _loanRevIdCache[chainId] = toBigInt(id); return _loanRevIdCache[chainId]; })
    .catch(function () { _loanRevIdCache[chainId] = null; return null; });
}

// Direct issuance estimate for paying `amount` of `token` into `projectId` — the beneficiary's minted
// token count. Used for fee-token previews (how many JB #1 / REV / source-project tokens a fee mints).
// Reads previewPayFor's beneficiaryTokenCount directly rather than going through computePayPreview, whose
// buyback-route branch returns the AMM minOut (often ~0 on illiquid testnet pools) when a revnet's data
// hook attaches a non-noop pay spec — which would otherwise hide the real issuance amount.
var feePreviewPayAbi = [{
  type: 'function', name: 'previewPayFor', stateMutability: 'view',
  inputs: [
    { name: 'projectId', type: 'uint256' }, { name: 'token', type: 'address' },
    { name: 'amount', type: 'uint256' }, { name: 'beneficiary', type: 'address' }, { name: 'metadata', type: 'bytes' },
  ],
  outputs: [
    { name: 'ruleset', type: 'tuple', components: [
      { name: 'cycleNumber', type: 'uint256' }, { name: 'id', type: 'uint256' }, { name: 'basedOnId', type: 'uint256' },
      { name: 'start', type: 'uint256' }, { name: 'duration', type: 'uint256' }, { name: 'weight', type: 'uint256' },
      { name: 'weightCutPercent', type: 'uint256' }, { name: 'approvalHook', type: 'address' }, { name: 'metadata', type: 'uint256' },
    ]},
    { name: 'beneficiaryTokenCount', type: 'uint256' },
    { name: 'reservedTokenCount', type: 'uint256' },
    { name: 'hookSpecifications', type: 'tuple[]', components: [
      { name: 'hook', type: 'address' }, { name: 'noop', type: 'bool' }, { name: 'amount', type: 'uint256' }, { name: 'metadata', type: 'bytes' },
    ]},
  ],
}];
function feeTokenEstimate(chainId, projectId, token, amount, beneficiary) {
  var terminal = getAddress('JBMultiTerminal', chainId);
  if (!terminal || !amount || amount === 0n) return Promise.resolve(null);
  return clientFor(chainId).readContract({
    address: terminal, abi: feePreviewPayAbi, functionName: 'previewPayFor',
    args: [BigInt(projectId), token, amount, beneficiary || '0x0000000000000000000000000000000000000001', '0x'],
  }).then(function (o) { return toBigInt(o[1]); }).catch(function () { return null; });
}

// Whether an address pays NO protocol fee for a project — feeless protocol-wide or per-project. Mirrors
// JBMultiTerminal._isFeeless → JBFeelessAddresses.isFeelessFor(addr, projectId, caller). For these
// self-beneficiary ops (cash out / use allowance / borrow) the caller IS the beneficiary, so we pass addr twice.
var isFeelessForAbi = [{ type: 'function', name: 'isFeelessFor', stateMutability: 'view', inputs: [{ name: 'addr', type: 'address' }, { name: 'projectId', type: 'uint256' }, { name: 'caller', type: 'address' }], outputs: [{ type: 'bool' }] }];
function isFeelessForCall(chainId, addr, projectId, caller) {
  var fa = getAddress('JBFeelessAddresses', chainId);
  if (!fa || !addr || addr === ZERO_ADDRESS || !caller || caller === ZERO_ADDRESS) return Promise.resolve(null);
  return clientFor(chainId).readContract({ address: fa, abi: isFeelessForAbi, functionName: 'isFeelessFor', args: [addr, BigInt(projectId), caller] })
    .then(function (b) { return !!b; }).catch(function () { return null; });
}
function isFeelessAddress(chainId, addr, projectId) {
  return isFeelessForCall(chainId, addr, projectId, addr);
}
// Whether the protocol fee can actually route for `token`: JB project #1 must have a primary terminal that can
// process a pay in it. When it can't (e.g. a project-specific accounting token with no swap route), JBMultiTerminal's
// _processFee forgives the fee and credits it straight back to the paying project — so don't warn about a fee.
// Probe: previewPayFor(#1, token) on primaryTerminalOf(#1, token). A viable route returns project #1's live
// ruleset; the router registry fail-softs to an all-zero ruleset when no route exists, and other terminals
// revert — both mean the fee pay would revert and be forgiven. NOTE an accountingContextForTokenOf read is NOT
// enough: the registry answers it for tokens it still can't route a pay for (verified against basesep #1/KMAC).
// Resolves true / false / null (unknown — RPC failure; keep the hedged fee note).
var primaryTerminalOfAbi = [{ type: 'function', name: 'primaryTerminalOf', stateMutability: 'view', inputs: [{ name: 'projectId', type: 'uint256' }, { name: 'token', type: 'address' }], outputs: [{ type: 'address' }] }];
var _feeRouteCache = {};
function feeWillRoute(chainId, token, decimals) {
  var key = Number(chainId) + ':' + String(token || '').toLowerCase();
  if (_feeRouteCache[key] === undefined) {
    _feeRouteCache[key] = read(chainId, 'JBDirectory', primaryTerminalOfAbi, 'primaryTerminalOf', [BigInt(FEE_BENEFICIARY_PROJECT_ID), token]).then(function (term) {
      if (!term || /^0x0+$/.test(term)) return false;
      var probeAmount = 10n ** BigInt(decimals == null ? 18 : decimals); // a nominal 1 token
      return clientFor(chainId).readContract({
        address: term, abi: feePreviewPayAbi, functionName: 'previewPayFor',
        args: [BigInt(FEE_BENEFICIARY_PROJECT_ID), token, probeAmount, '0x0000000000000000000000000000000000000001', '0x'],
      }).then(function (o) { return toBigInt(o[0] && o[0].id) !== 0n; })
        .catch(function () { return false; });
    }).catch(function () { return null; });
  }
  return _feeRouteCache[key];
}

// Whether the router registry can actually route a pay of `token` into `projectId` right now (direct forward,
// swap, or cash-out loop). Same fail-soft signal as feeWillRoute: a dead route previews an all-zero ruleset.
var _payRouteCache = {};
function routerPayRouteWorks(chainId, projectId, token, decimals) {
  var registry = routerTerminalFor(chainId);
  if (!registry) return Promise.resolve(false);
  var key = Number(chainId) + ':' + String(projectId) + ':' + String(token || '').toLowerCase();
  if (_payRouteCache[key] === undefined) {
    _payRouteCache[key] = clientFor(chainId).readContract({
      address: registry, abi: feePreviewPayAbi, functionName: 'previewPayFor',
      args: [BigInt(projectId), token, 10n ** BigInt(decimals == null ? 18 : decimals), '0x0000000000000000000000000000000000000001', '0x'],
    }).then(function (o) { return toBigInt(o[0] && o[0].id) !== 0n; })
      .catch(function () { return false; });
  }
  return _payRouteCache[key];
}

// `useAllowanceOf` waives its protocol fee when EITHER the project owner or the funds beneficiary is feeless,
// evaluated against the actual caller. The fee beneficiary does not participate in this decision.
async function isAllowanceFeeless(chainId, projectId, beneficiary, caller) {
  var owner = await read(chainId, 'JBProjects', ownerOfAbi, 'ownerOf', [BigInt(projectId)]).catch(function () { return null; });
  if (!owner) return null;
  var checks = await Promise.all([
    isFeelessForCall(chainId, owner, projectId, caller),
    isFeelessForCall(chainId, beneficiary, projectId, caller),
  ]);
  return checks[0] == null || checks[1] == null ? null : (checks[0] || checks[1]);
}

// A link to a project's page (the fee-beneficiary project), so the user can see where the fee goes.
function feeProjectLink(chainId, projectId, label) {
  var a = document.createElement('a'); a.className = 'fee-project-link';
  a.href = '#' + slugForChain(chainId) + ':' + String(projectId);
  a.textContent = label || ('JB #' + String(projectId));
  return a;
}
// Subtle fee receipt: "<label>: <feeAmount>" then "• get ~<X> <token> in <project link> for the fee" — shows where
// the protocol fee goes and the project token it mints back to the beneficiary. opts: { chainId, feeProjectId,
// feeTokenAddr, decimals, symbol, feeAmount (bigint), beneficiary, label, projectLabel }.
function renderFeeReceipt(container, opts) {
  if (!opts.feeAmount || opts.feeAmount <= 0n) return;
  var feeLine = el('div', 'ops-preview-line ops-preview-fee');
  feeLine.textContent = (opts.label || '2.5% protocol fee') + ': ' + formatBalance(opts.feeAmount, opts.decimals, opts.symbol);
  container.appendChild(feeLine);
  var feeTok = el('div', 'ops-preview-line ops-preview-feetok');
  function withLink(prefix, suffix) {
    while (feeTok.firstChild) feeTok.removeChild(feeTok.firstChild);
    feeTok.appendChild(document.createTextNode(prefix));
    feeTok.appendChild(feeProjectLink(opts.chainId, opts.feeProjectId, opts.projectLabel));
    if (suffix) feeTok.appendChild(document.createTextNode(suffix));
  }
  withLink('• paid into ', ', minting its token to you…');
  container.appendChild(feeTok);
  Promise.all([
    computePayPreview({ chainId: opts.chainId, projectId: Number(opts.feeProjectId), token: opts.feeTokenAddr || NATIVE_TOKEN, amount: opts.feeAmount, beneficiary: opts.beneficiary }),
    projectTokenSymbol(opts.chainId, opts.feeProjectId),
  ]).then(function (r) {
    var p = r[0], fsym = r[1] || 'tokens';
    if (p && !p.unavailable && p.received != null && p.received > 0n) {
      withLink('• get ~ ' + formatTokens(p.received) + ' ' + fsym + ' in ', ' for the fee');
      if (opts.onReceived) opts.onReceived(p.received, fsym);
    } else withLink('• fee funds ', null);
  }).catch(function () {});
}

