export function httpUrlOnly(url) { var u = (url || '').trim(); return /^https?:\/\//i.test(u) ? u : ''; }

// DOMParser is INERT — unlike `div.innerHTML = html`, the parsed document never loads <img src> (so an
// `<img onerror>` in untrusted onchain text can't fire) and never runs script. Use it everywhere we parse
// project-controlled HTML to extract text/structure.
function parseInertHtml(html) { return new DOMParser().parseFromString(String(html || ''), 'text/html').body; }

function stripHtml(html) {
  if (!html) return '';
  return (parseInertHtml(html).textContent || '').replace(/\s+/g, ' ').trim();
}

// Like stripHtml, but PRESERVES paragraph/line breaks. Rich-text descriptions are HTML
// (`<p>…</p><p><br></p><p>…</p>`); textContent concatenates block elements with no whitespace, so
// sentences run together ("loans.$CPN"). Convert <br> and block boundaries to newlines first, then
// extract text — never inject the raw HTML into the live DOM (untrusted onchain content).
function htmlToText(html) {
  if (!html) return '';
  var tmp = parseInertHtml(html);
  tmp.querySelectorAll('br').forEach(function (br) { br.replaceWith(document.createTextNode('\n')); });
  tmp.querySelectorAll('p, div, li, h1, h2, h3, h4, h5, h6, blockquote, tr').forEach(function (b) { b.appendChild(document.createTextNode('\n\n')); });
  return (tmp.textContent || '')
    .replace(/[ \t]+/g, ' ')      // collapse runs of spaces
    .replace(/ *\n */g, '\n')      // trim spaces around newlines
    .replace(/\n{3,}/g, '\n\n')    // cap consecutive blank lines
    .trim();
}

// Render rich-text metadata (HTML from the editor) into `container` as paragraphs AND lists — so
// `<ul>`/`<ol>` keep their bullets/numbers instead of flattening to plain lines. Untrusted onchain
// content: parse into a detached node and copy only text + list structure (never inject raw HTML).
function renderRichTextInto(container, html) {
  var tmp = parseInertHtml(html);
  var rendered = false;
  for (var i = 0; i < tmp.children.length; i++) {
    var b = tmp.children[i], tag = b.tagName;
    if (tag === 'UL' || tag === 'OL') {
      var list = el(tag === 'OL' ? 'ol' : 'ul', 'detail-about-list');
      var items = b.querySelectorAll('li');
      for (var j = 0; j < items.length; j++) { var li = el('li', 'detail-about-li'); li.textContent = htmlToText(items[j].innerHTML); list.appendChild(li); }
      if (items.length) { container.appendChild(list); rendered = true; }
    } else {
      var txt = htmlToText(b.innerHTML);
      if (txt) { var p = el('p', 'detail-about-para'); p.textContent = txt; container.appendChild(p); rendered = true; }
    }
  }
  // Fallback (no block children — plain text): split on blank lines.
  if (!rendered) {
    htmlToText(html).split(/\n{2,}/).forEach(function (para) {
      if (!para.trim()) return;
      var p = el('p', 'detail-about-para'); p.textContent = para.trim(); container.appendChild(p);
    });
  }
}

// addressNode wrapped in a link to the chain's block explorer (etherscan-style).
function addressLinkNode(address, chainId) {
  var node = addressNode(address);
  if (!address || address === ZERO_ADDRESS) return node;
  var chain = CHAINS[chainId];
  var base = chain && chain.blockExplorers && chain.blockExplorers.default && chain.blockExplorers.default.url;
  var inner = node;
  if (base) {
    var a = document.createElement('a');
    a.href = base.replace(/\/$/, '') + '/address/' + address;
    a.target = '_blank'; a.rel = 'noopener'; a.className = 'detail-address-link';
    a.appendChild(node);
    inner = a;
  }
  // Safe badge sits OUTSIDE the explorer link so its click opens the details modal, not the link.
  var wrap = el('span', 'address-with-safe');
  wrap.appendChild(inner);
  wrap.appendChild(safeBadge(address, chainId));
  return wrap;
}

function formatEth(wei) {
  if (wei === null || wei === undefined) return '—';
  return formatTokenCount(wei) + ' ETH';
}

function pricingSymbol(currency, decimals, chainId) {
  var c = Number(currency || 1);
  if (c === 1) return 'ETH';
  if (c === 2) return 'USD';
  var nativeCur = Number(BigInt(NATIVE_TOKEN) & 0xffffffffn);
  if (c === nativeCur) return 'ETH';
  var usdc = USDC_BY_CHAIN[chainId];
  if (usdc && c === Number(BigInt(usdc) & 0xffffffffn)) return 'USDC';
  var known = getChainTokens(chainId || 1).filter(function (t) { return Number(BigInt(t.address) & 0xffffffffn) === c; })[0];
  return known ? currencyLabel(known.symbol) : ('currency ' + c);
}
function pricingContextOf(shop, chainId) {
  var p = (shop && shop.pricing) || {};
  var dec = p.decimals == null ? 18 : Number(p.decimals);
  return { currency: Number(p.currency || 1), decimals: dec, symbol: p.symbol || pricingSymbol(p.currency || 1, dec, chainId) };
}
function formatShopPrice(shop, amount, chainId) {
  var p = pricingContextOf(shop, chainId);
  return formatBalance(amount, p.decimals, p.symbol);
}

// Format a raw token amount with its own decimals + symbol (e.g. USDC at 6 decimals, ETH at 18).
// Precision rules come from the shared formatAdaptive; '—' (null/non-finite) stays symbol-less.
function formatBalance(amount, decimals, symbol) {
  if (amount === null || amount === undefined) return '—';
  var s = formatRawAdaptive(amount, decimals == null ? 18 : decimals);
  return s === '—' ? s : s + (symbol ? ' ' + symbol : '');
}

function accountingContextMeta(chainId, ctx) {
  if (!ctx || !isAddr(ctx.token)) throw new Error('The accounting context returned an invalid token address.');
  var address = ctx.token;
  var decimals = Number(ctx.decimals);
  if (!Number.isInteger(decimals) || decimals < 0 || decimals > 36) throw new Error('The accounting context returned invalid token decimals.');
  var currency = ctx.currency != null ? BigInt(ctx.currency) : tokenCurrencyIdForAccounting(address);
  if (currency <= 0n || currency > 0xffffffffn) throw new Error('The accounting context returned an invalid currency.');
  if (address.toLowerCase() === NATIVE_TOKEN.toLowerCase()) {
    if (decimals !== 18) throw new Error('The native-token accounting context must use 18 decimals.');
    return { address: address, decimals: decimals, symbol: 'ETH', currency: currency };
  }
  var chainTokens = getChainTokens(chainId);
  var known = chainTokens.filter(function (candidate) { return candidate.address.toLowerCase() === address.toLowerCase(); })[0];
  var usdc = USDC_BY_CHAIN[chainId];
  var symbol = known ? tokenSymbolClean(known.symbol) : ((usdc && address.toLowerCase() === usdc.toLowerCase()) ? 'USDC' : truncAddr(address));
  return { address: address, decimals: decimals, symbol: symbol, name: known && known.name ? String(known.name) : '', currency: currency };
}

function cleanAccountingTokenText(value, maxLength) {
  var text = String(value || '').replace(/[\u0000-\u001f\u007f]/g, '').trim();
  if (!text) return '';
  return text.length > maxLength ? text.slice(0, maxLength - 1) + '…' : text;
}

// ERC-20 display priority: symbol → name → address. The address remains attached to every enriched context for
// calldata/audit use; this helper only chooses the human-facing label.
export function accountingTokenDisplayLabel(symbol, name, address) {
  return cleanAccountingTokenText(tokenSymbolClean(symbol), 24)
    || cleanAccountingTokenText(name, 40)
    || (isAddr(address) ? truncAddr(address) : 'Token');
}

var _accountingTokenMetadataCache = {};
function resolveAccountingContextMetadata(chainId, ctx) {
  var base = ctx && ctx.address ? ctx : accountingContextMeta(chainId, ctx);
  var address = base.address;
  var lc = address.toLowerCase();
  if (lc === NATIVE_TOKEN.toLowerCase()) return Promise.resolve(Object.assign({}, base, { symbol: 'ETH', name: 'Ether' }));
  var usdc = USDC_BY_CHAIN[chainId];
  if (usdc && lc === usdc.toLowerCase()) return Promise.resolve(Object.assign({}, base, { symbol: 'USDC', name: 'USD Coin' }));
  var key = Number(chainId) + ':' + lc;
  if (!_accountingTokenMetadataCache[key]) {
    var client = clientFor(chainId);
    _accountingTokenMetadataCache[key] = Promise.all([
      client.readContract({ address: address, abi: erc20SymbolAbi, functionName: 'symbol', args: [] }).catch(function () { return ''; }),
      client.readContract({ address: address, abi: erc20NameAbi, functionName: 'name', args: [] }).catch(function () { return ''; }),
    ]).then(function (values) {
      var symbol = cleanAccountingTokenText(tokenSymbolClean(values[0]), 24);
      var name = cleanAccountingTokenText(values[1], 80);
      return { symbol: accountingTokenDisplayLabel(symbol, name, address), name: name };
    }).catch(function () { return { symbol: truncAddr(address), name: '' }; });
  }
  return _accountingTokenMetadataCache[key].then(function (metadata) {
    return Object.assign({}, base, metadata);
  });
}

// Every token context the terminal accepts. Transaction forms that let the user choose a source must use
// this list; silently selecting ctxs[0] can quote and submit a different currency than the user intended.
function resolveAcctTokens(chainId, pid) {
  if (!getAddress('JBMultiTerminal', chainId)) return Promise.reject(new Error('No terminal on this chain.'));
  return read(chainId, 'JBMultiTerminal', TERMINAL_CONTEXTS_ABI, 'accountingContextsOf', [pid]).then(function (ctxs) {
    if (!ctxs || !ctxs.length) throw new Error('No accounting contexts are configured for this project.');
    return Promise.all(ctxs.map(function (ctx) { return resolveAccountingContextMetadata(chainId, ctx); }));
  });
}

// The project's primary accounting token (what its balance is denominated in).
function resolveAcctToken(chainId, pid) {
  return resolveAcctTokens(chainId, pid).then(function (contexts) {
    if (!contexts[0]) throw new Error('Could not resolve an accounting context.');
    return contexts[0];
  });
}

// Shorter display names than the manifest's (Arbitrum One → Arbitrum, OP Mainnet → Optimism).
var SHORT_CHAIN_NAME = { 10: 'Optimism', 42161: 'Arbitrum' };
function chainNameOf(cid) {
  return SHORT_CHAIN_NAME[Number(cid)] || (CHAINS[cid] && CHAINS[cid].name) || ('Chain ' + cid);
}

// The unit a project's issuance/weight is denominated in — its ruleset baseCurrency (USD or ETH), NOT
// its accounting token. "625 ART / USD" means 625 tokens per dollar paid.
function baseUnitLabel(project) {
  return currencyUnitLabel(project && project.metadata && project.metadata.baseCurrency, project);
}

// Symbol for any ruleset/pricing currency id: ETH, USD, the project's own accounting token (a custom
// accounting token's currency is uint32(uint160(token))), or the known-token fallback.
function currencyUnitLabel(currency, project) {
  var c = Number(currency || 1);
  if (c === 1) return 'ETH';
  if (c === 2) return 'USD';
  var acct = project && project.acctToken;
  if (acct && acct.currency != null && Number(acct.currency) === c) return acct.symbol || ('currency ' + c);
  return pricingSymbol(c, 18, project && project.chainId);
}

// USD value of a chosen amount of dollars (USDC is $1; ETH needs the live feed).
function formatUsd(n) {
  if (n === null || n === undefined || !isFinite(n)) return '—';
  if (n === 0) return '$0';
  if (n > 0 && n < 0.01) return '<$0.01';
  return '$' + n.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

// ETH/USD spot from the protocol's own Chainlink feed (cached per chain). currentUnitPrice(18) returns
// USD-per-ETH scaled to 18 decimals; null when the feed is absent/reverting (testnet gaps).
var ETH_USD_CACHE = {};
var ETH_USD_FEED_ABI = [{ type: 'function', name: 'currentUnitPrice', stateMutability: 'view', inputs: [{ type: 'uint256' }], outputs: [{ type: 'uint256' }] }];
function fetchEthUsd(chainId) {
  if (ETH_USD_CACHE[chainId] !== undefined) return Promise.resolve(ETH_USD_CACHE[chainId]);
  if (!getAddress('JBChainlinkV3PriceFeed__ETH_USD', chainId)) { ETH_USD_CACHE[chainId] = null; return Promise.resolve(null); }
  return read(chainId, 'JBChainlinkV3PriceFeed__ETH_USD', ETH_USD_FEED_ABI, 'currentUnitPrice', [18n])
    .then(function (p) { var v = Number(p) / 1e18; ETH_USD_CACHE[chainId] = (isFinite(v) && v > 0) ? v : null; return ETH_USD_CACHE[chainId]; })
    .catch(function () { ETH_USD_CACHE[chainId] = null; return null; });
}

// One chain's balances across EVERY accounting token the terminal accepts (a project can hold
// both ETH and USDC). Missing context data stays unavailable; it is never guessed as native ETH.
function readChainBalances(chainId, pid) {
  var term = getAddress('JBMultiTerminal', chainId);
  if (!term) return Promise.resolve({ chainId: chainId, tokens: [], verified: false });
  return clientFor(chainId).readContract({ address: term, abi: TERMINAL_CONTEXTS_ABI, functionName: 'accountingContextsOf', args: [pid] }).then(function (ctxs) {
    if (!ctxs || !ctxs.length) return { chainId: chainId, tokens: [], verified: true };
    return Promise.all(ctxs.map(function (ctx) {
      // Resolve the real ERC-20 symbol (cached) — acctTokenLabel alone shows a truncated ADDRESS for
      // custom accounting tokens, which leaks into the header balance and its per-chain popover.
      var metaP = Promise.resolve().then(function () { return resolveAccountingContextMetadata(chainId, ctx); }).catch(function () { return null; });
      var balP = read(chainId, 'JBTerminalStore', storeBalanceAbi, 'balanceOf', [term, pid, ctx.token]).catch(function () { return null; });
      return Promise.all([balP, metaP]).then(function (r) {
        return { token: ctx.token, balance: r[0], decimals: Number(ctx.decimals), symbol: (r[1] && r[1].symbol) || acctTokenLabel(ctx.token) };
      });
    })).then(function (toks) { return { chainId: chainId, tokens: toks, verified: true }; });
  }).catch(function () { return { chainId: chainId, tokens: [], verified: false }; });
}

export function accountingTokenUsdValue(balance, decimals, token, chainId, ethUsd) {
  if (balance == null) return null;
  var amount;
  try { amount = Number(formatAmount(BigInt(balance), decimals == null ? 18 : Number(decimals))); } catch (_) { return null; }
  if (!isFinite(amount)) return null;
  var address = String(token || '').toLowerCase();
  if (address === NATIVE_TOKEN.toLowerCase()) return ethUsd == null ? null : amount * ethUsd;
  var usdc = String(USDC_BY_CHAIN[chainId] || '').toLowerCase();
  if (usdc && address === usdc) return amount;
  return null; // A custom accounting token has no trustworthy USD price merely because it is an ERC-20.
}

function accountingTokenContextKey(token, chainId) {
  var address = String(token || '').toLowerCase();
  if (address === NATIVE_TOKEN.toLowerCase()) return 'native';
  var usdc = String(USDC_BY_CHAIN[chainId] || '').toLowerCase();
  if (usdc && address === usdc) return 'usdc';
  return address || 'unknown';
}

// Cross-chain balance breakdown across ALL accounting tokens + a USD total only when every non-zero token is
// actually priced. ETH converts through the protocol feed; canonical USDC is $1; custom tokens stay unpriced.
function fetchBalanceBreakdown(project) {
  if (project._balBreakdown) return Promise.resolve(project._balBreakdown);
  var chains = (project.chains && project.chains.length) ? project.chains : [{ id: project.chainId }];
  var pid = BigInt(project.id);
  return Promise.all(chains.map(function (c) { return readChainBalances(c.id, pid); })).then(function (results) {
    var hasContextFailure = results.some(function (result) { return !result.verified; });
    var isEthTok = function (t) { return (t.token || '').toLowerCase() === NATIVE_TOKEN.toLowerCase(); };
    var needEth = results.some(function (cr) { return cr.tokens.some(function (t) { return isEthTok(t) && t.balance != null && BigInt(t.balance) > 0n; }); });
    return (needEth ? fetchEthUsd(project.chainId) : Promise.resolve(1)).then(function (ethUsd) {
      var rows = [], total = 0, hasUnpricedBalance = false, hasUnreadable = hasContextFailure, contextKeys = {}, chainVerified = {};
      results.forEach(function (cr) {
        chainVerified[cr.chainId] = !!cr.verified;
        cr.tokens.forEach(function (t) {
          var dec = t.decimals == null ? 18 : t.decimals;
          var raw = t.balance != null ? BigInt(t.balance) : null;
          var hasBalance = raw != null && raw > 0n;
          var usd = accountingTokenUsdValue(raw, dec, t.token, cr.chainId, ethUsd);
          var contextKey = accountingTokenContextKey(t.token, cr.chainId) + '@' + dec;
          contextKeys[contextKey] = true;
          if (t.balance == null) hasUnreadable = true;
          if (hasBalance && usd == null) hasUnpricedBalance = true;
          if (usd != null) total += usd;
          rows.push({ chainId: cr.chainId, name: chainNameOf(cr.chainId), token: t.token, balance: t.balance, decimals: dec, symbol: t.symbol, usd: usd, contextKey: contextKey, hasBalance: hasBalance });
        });
      });
      rows.sort(function (a, b) { return (b.usd || 0) - (a.usd || 0); });
      var active = rows.filter(function (r) { return r.hasBalance; });
      var totalRows = active.length ? active : rows;
      var activeKeys = {}; totalRows.forEach(function (r) { activeKeys[r.contextKey] = true; });
      var singleTokenTotal = null;
      if (!hasUnreadable && Object.keys(activeKeys).length === 1 && totalRows.length) {
        singleTokenTotal = {
          amount: totalRows.reduce(function (sum, r) { return sum + BigInt(r.balance || 0); }, 0n),
          decimals: totalRows[0].decimals,
          symbol: totalRows[0].symbol,
        };
      }
      var bd = {
        rows: rows,
        totalUsd: total,
        priced: !hasContextFailure && !hasUnreadable && !hasUnpricedBalance && (!needEth || ethUsd != null),
        singleTokenTotal: singleTokenTotal,
        contextHomogeneous: !hasContextFailure && Object.keys(contextKeys).length <= 1,
        chainVerified: chainVerified,
      };
      // Cache only a complete read. A transient RPC failure must be retryable on the next render/open.
      if (!hasContextFailure && !hasUnreadable) project._balBreakdown = bd;
      return bd;
    });
  });
}

// A balance shown as a USD total with a hover popup breaking it down per chain. Renders a loading
// placeholder immediately, then fills async. `opts.suffix` appends e.g. ' balance' after the figure.
function mountUsdBalance(project, opts) {
  opts = opts || {};
  var wrap = el('span', 'usd-balance');
  var fig = el('strong', 'usd-balance-fig');
  fig.textContent = '…';
  wrap.appendChild(fig);
  if (opts.suffix) wrap.appendChild(document.createTextNode(opts.suffix));

  fetchBalanceBreakdown(project).then(function (bd) {
    fig.textContent = bd.priced ? formatUsd(bd.totalUsd)
      : (bd.singleTokenTotal ? formatBalance(bd.singleTokenTotal.amount, bd.singleTokenTotal.decimals, bd.singleTokenTotal.symbol) : '—');
    if (!bd.rows.length) return;

    var pop = el('div', 'usd-balance-pop');
    bd.rows.forEach(function (r) {
      var row = el('div', 'usd-balance-pop-row' + (r.hasBalance ? '' : ' usd-balance-pop-row--empty'));
      var name = el('span', 'usd-balance-pop-chain'); name.textContent = r.name;
      var val = el('span', 'usd-balance-pop-amt'); val.textContent = formatBalance(r.balance, r.decimals, r.symbol);
      row.appendChild(name); row.appendChild(val);
      pop.appendChild(row);
    });
    // When every chain holds the same token, total in that token (the breakdown is "actual tokens",
    // so a single-currency project reads cleaner as "3 USDC" than "$3.00"). Mixed tokens → USD.
    var totalText = bd.priced ? formatUsd(bd.totalUsd)
      : (bd.singleTokenTotal ? formatBalance(bd.singleTokenTotal.amount, bd.singleTokenTotal.decimals, bd.singleTokenTotal.symbol) : '—');
    var totalRow = el('div', 'usd-balance-pop-row usd-balance-pop-total');
    var tName = el('span', 'usd-balance-pop-chain'); tName.textContent = 'All chains';
    var tVal = el('span', 'usd-balance-pop-amt'); tVal.textContent = totalText;
    totalRow.appendChild(tName); totalRow.appendChild(tVal);
    pop.appendChild(totalRow);

    wrap.classList.add('usd-balance--has-pop');
    wrap.appendChild(pop);
  }).catch(function () {
    fig.textContent = '—';
  });

  return wrap;
}

function formatTokens(raw) {
  if (raw === null || raw === undefined) return '—';
  // Adaptive significant digits: big numbers drop decimals (and get thousands separators),
  // small numbers keep more — see formatTokenCount.
  return formatTokenCount(raw);
}

// The site's "|" stat separator.
function headSep() { var s = el('span', 'detail-head-sep'); s.textContent = '|'; return s; }

// Append indexed payments + (priced) volume to a header stat line. Bendystraw-derived, so it can trail
// the chain. "raised" is shown only when the USD volume is actually priced (>0) — otherwise it reads as a
// confusing "$0 raised" even though the live balance is non-zero. "contributors" is omitted here (it's the
// Owners/Token-holders count, shown on the card + Owners tab; it double-counts confusingly in the header).
function appendIndexedStats(statLine, stats) {
  if (!stats) return;
  statLine.appendChild(headSep());
  var pStrong = el('strong'); pStrong.textContent = String(stats.paymentsCount);
  statLine.appendChild(pStrong);
  statLine.appendChild(document.createTextNode(stats.paymentsCount === 1 ? ' payment' : ' payments'));
}

function formatCompactTokenAmount(raw) {
  if (raw === null || raw === undefined) return '—';
  var n = Number(formatAmount(raw, 18));
  if (!isFinite(n)) return formatTokens(raw);
  if (n === 0) return '0';
  if (n >= 1000000000) return (n / 1000000000).toFixed(n >= 10000000000 ? 0 : 1).replace(/\.0$/, '') + 'b';
  if (n >= 1000000) return (n / 1000000).toFixed(n >= 10000000 ? 0 : 1).replace(/\.0$/, '') + 'm';
  if (n >= 1000) return (n / 1000).toFixed(n >= 10000 ? 0 : 1).replace(/\.0$/, '') + 'k';
  return formatTokenCount(raw);
}

function formatOwnerPortion(balance, total) {
  // A percentage without a complete cross-chain supply denominator is worse than no percentage. RPC failures
  // therefore render as unknown instead of silently treating the indexed balances (or one chain) as 100%.
  if (total == null || balance == null) return '—';
  var b = toBigInt(balance), t = toBigInt(total);
  if (t <= 0n) return b <= 0n ? '0%' : '—';
  if (b <= 0n) return '0%';
  var pct = Number(b * 100000000n / t) / 1000000;
  if (pct >= 10) return pct.toFixed(2).replace(/0+$/, '').replace(/\.$/, '') + '%';
  if (pct >= 1) return pct.toFixed(3).replace(/0+$/, '').replace(/\.$/, '') + '%';
  if (pct >= 0.01) return pct.toFixed(4).replace(/0+$/, '').replace(/\.$/, '') + '%';
  return '<0.01%';
}

// reservedPercent / cashOutTaxRate are out of 10_000 (= 100%).
function percentFromRuleset(value) {
  if (value === null || value === undefined) return '—';
  return (Number(value) / 100).toFixed(Number(value) % 100 === 0 ? 0 : 2) + '%';
}
// The split-limit (as % of issuance) that an edit-splits group's percentages must sum to: the reserved
// group is capped at the ruleset's reserved rate (reservedPercent is out of 10000 → /100 = % of issuance);
// every other group (e.g. payouts) uses the full 100%.
function splitLimitPctFor(project, groupId) {
  if (groupId === RESERVED_TOKEN_SPLIT_GROUP && project.metadata && project.metadata.reservedPercent != null) {
    var rp = Number(project.metadata.reservedPercent);
    if (rp > 0) return rp / 100;
  }
  return 100;
}

function formatDuration(secs) {
  var s = Number(secs);
  if (s === 0) return 'No expiry';
  if (s >= 86400) return (s / 86400).toFixed(s % 86400 === 0 ? 0 : 1) + ' days';
  if (s >= 3600) return (s / 3600).toFixed(1) + ' hours';
  return s + ' seconds';
}

// -- ENS reverse resolution (mainnet only; primary names live on mainnet even for
// testnet projects). Cached per address; resolves "where possible", silent otherwise. --
var _ensCache = {};
var _ensResolved = {}; // lowercased addr -> resolved primary name (sync read; lets the table search match names)
function ensNameOf(address) {
  if (!address || address === ZERO_ADDRESS) return Promise.resolve(null);
  var key = address.toLowerCase();
  if (_ensCache[key]) return _ensCache[key];
  var p = (async function () {
    try {
      var n = await clientFor(1).getEnsName({ address: address });
      if (n) _ensResolved[key] = n;
      return n;
    } catch (e) {
      return null;
    }
  })();
  _ensCache[key] = p;
  return p;
}
// Sync read of an already-resolved ENS name (or null) — lets the account search substring-match names without awaiting.
export function ensNameCached(address) { return _ensResolved[(address || '').toLowerCase()] || null; }

// Forward ENS resolution (name → address), mainnet, cached. Returns null for non-names / no record.
var _ensAddrCache = {};
function ensAddressOf(name) {
  var key = (name || '').trim().toLowerCase();
  if (!key || key.indexOf('.') === -1) return Promise.resolve(null);
  if (_ensAddrCache[key]) return _ensAddrCache[key];
  var p = (async function () {
    try { return await clientFor(1).getEnsAddress({ name: key }); } catch (e) { return null; }
  })();
  _ensAddrCache[key] = p;
  return p;
}

var _operatorCache = {};
function addressOrNull(address) {
  if (!address || String(address).toLowerCase() === ZERO_ADDRESS.toLowerCase()) return null;
  return address;
}

async function bendystrawRevnetOperatorOf(projectId, chainId) {
  // The revnet operator = the permissionHolder flagged `isRevnetOperator`. Bendystraw's V6 reindex sets this
  // flag (the v6-isrevnet-revowner PR), so filter on it directly — no REVOwner-address lookup needed.
  //
  // Bendystraw can return MORE THAN ONE flagged row: when REVOwner.setOperatorOf reassigns the operator, the
  // indexer currently leaves `isRevnetOperator: true` on the prior operator (its `permissions` array is
  // emptied, but the flag is stale). Taking `items[0]` blindly surfaces whichever the indexer returns first —
  // for BAN (project 4 / Sepolia) that's the old Sphinx Safe with an empty permission set, not team.banny.eth.
  // Disambiguate using authoritative per-row data: the live operator is the flagged holder that still HOLDS
  // permissions. The prior operator's row carries `permissions: []`. Once the indexer clears the stale flag
  // this filter collapses to a single row and is a no-op.
  var data = await bendystrawQuery(BENDYSTRAW_PROJECT_OPERATOR_QUERY, {
    chainId: Number(chainId),
    projectId: Number(projectId),
    version: BENDYSTRAW_VERSION,
  });
  var rows = (data && data.permissionHolders && data.permissionHolders.items) || [];
  var live = rows.filter(function (r) { return r && r.permissions && r.permissions.length > 0; });
  var pick = (live.length ? live[0] : rows[0]) || null;
  return addressOrNull(pick && pick.operator);
}

async function revnetOperatorOf(projectId, chainId) {
  var key = chainId + ':' + projectId;
  if (_operatorCache[key]) return _operatorCache[key];
  // Bendystraw only — no deploy-script fallback. If the indexer fails or has nothing, return null
  // (the UI then hides the operator rather than showing fabricated data).
  _operatorCache[key] = bendystrawRevnetOperatorOf(projectId, chainId).catch(function () { return null; });
  return _operatorCache[key];
}

function projectAuthorityLabel(project) {
  return project && project.isRevnet ? 'Operator' : 'Owner';
}

function projectAuthorityAddress(project) {
  return project && project.isRevnet ? project.operator : project.owner;
}

function projectOwnerRecipientLabel(project) {
  return project && project.isRevnet ? 'REVOwner' : 'Project owner';
}

// Render the "Account" cell for a single JBSplit. Precedence matches the JBSplit struct's own routing:
//   projectId > 0          → reserved tokens are minted to that project
//   beneficiary != 0       → tokens go to that address
//   hook != 0              → tokens are forwarded to a split hook (e.g. JBP6FeeLPSplitHook for LP'ing)
//   otherwise              → the project owner / REVOwner
// The hook check MUST come before the owner fallback: a hook-routed split has beneficiary == 0 by design,
// so without this the row mislabels the LP split hook as the project owner. Returns a fresh node.
function splitAccountNode(sp, project, chainId, opts) {
  opts = opts || {};
  var node = el('span', 'splits-acct-inner');
  if (Number(sp.projectId) > 0) {
    node.classList.add('split-project-recipient');
    var pid = Number(sp.projectId);
    var link = document.createElement('a'); link.className = 'split-project-link';
    link.href = '#' + slugForChain(chainId) + ':' + pid + '/overview';
    link.textContent = 'Project #' + pid;
    node.appendChild(link);
    preferredSplitProjectInfo(pid, chainId).then(function (info) {
      if (info && info.name && link.isConnected) link.textContent = info.name + ' | #' + pid;
    }).catch(function () {});

    var route = el('span', 'split-project-route');
    if (opts.kind === 'payout') route.textContent = sp.preferAddToBalance ? 'Add to balance | no tokens minted' : 'Pay project';
    else route.textContent = 'reserved-token project recipient';
    node.appendChild(route);

    if (!sp.preferAddToBalance) {
      var beneficiary = el('span', 'split-project-beneficiary');
      if (sp.beneficiary && !isZeroishAddress(sp.beneficiary)) {
        beneficiary.appendChild(document.createTextNode(opts.kind === 'payout' ? 'destination tokens → ' : 'fallback tokens → '));
        beneficiary.appendChild(addressNode(sp.beneficiary, chainId));
      } else if (opts.kind === 'payout') {
        beneficiary.classList.add('warn');
        beneficiary.textContent = 'destination tokens → distribution caller';
        beneficiary.title = 'No beneficiary is set. The account which triggers payout distribution receives any tokens minted by the destination project.';
      } else {
        beneficiary.classList.add('warn');
        beneficiary.textContent = 'fallback tokens → distribution caller';
      }
      node.appendChild(beneficiary);
    }
    return node;
  }
  if (sp.beneficiary && sp.beneficiary !== ZERO_ADDRESS) { node.appendChild(addressNode(sp.beneficiary, chainId)); return node; }
  if (sp.hook && sp.hook !== ZERO_ADDRESS) {
    var label = el('span', 'split-hook-label'); label.textContent = 'Split hook'; label.title = 'Reserved tokens are forwarded to a split hook';
    node.appendChild(label);
    node.appendChild(document.createTextNode(' '));
    node.appendChild(addressNode(sp.hook, chainId));
    registeredInstanceProvenance(sp.hook, chainId).then(function (provenance) {
      if (!provenance || !provenance.known || !label.isConnected) return;
      label.textContent = provenance.family;
      label.title = 'Registered in JBAddressRegistry as deployed by ' + provenance.deployerName;
      label.classList.add('known');
    }).catch(function () {});
    return node;
  }
  node.textContent = projectOwnerRecipientLabel(project);
  return node;
}


function chainById(chainId) {
  var cid = Number(chainId);
  return CHAINS[cid] ? { id: cid, name: CHAINS[cid].name } : { id: cid, name: 'Chain ' + cid };
}

// A span that shows the truncated address immediately, then upgrades to the ENS name
// (keeping the address as a tooltip) if one resolves.
function addressNode(address, chainId) {
  var span = el('span', 'detail-address');
  if (!address || address === ZERO_ADDRESS) { span.textContent = '—'; return span; }
  var label = el('span', 'detail-address-label'); label.textContent = truncAddr(address); span.appendChild(label);
  // Custom tooltip (shows the full address) so it reveals INSTANTLY on hover — native `title` has a delay.
  var tip = el('span', 'addr-tip'); tip.textContent = address; span.appendChild(tip);
  ensNameOf(address).then(function (name) { if (name) { label.textContent = name; tip.textContent = address; } });
  // Click the truncated address (or ENS) to copy the full address. The native title carries the FULL address
  // too — the instant .addr-tip is clipped inside ellipsis cells (e.g. the owners table), so this guarantees the
  // address is visible on hover everywhere.
  label.style.cursor = 'pointer';
  label.title = address + ' | click to copy';
  label.addEventListener('click', function (e) {
    e.preventDefault(); e.stopPropagation();
    var prevTip = tip.textContent;
    copyText(address).then(function () { tip.textContent = 'Copied'; setTimeout(function () { tip.textContent = prevTip; }, 1200); }).catch(function () {});
  });
  if (chainId) span.appendChild(safeBadge(address, chainId));
  return span;
}

function copyText(text) {
  if (navigator.clipboard && navigator.clipboard.writeText) return navigator.clipboard.writeText(text);

  var textarea = document.createElement('textarea');
  textarea.value = text;
  textarea.setAttribute('readonly', '');
  textarea.style.position = 'fixed';
  textarea.style.left = '-9999px';
  document.body.appendChild(textarea);
  textarea.select();
  try {
    document.execCommand('copy');
    return Promise.resolve();
  } catch (e) {
    return Promise.reject(e);
  } finally {
    textarea.remove();
  }
}

function fullAddressNode(address, resolveEns, chainId) {
  var wrap = el('span', 'detail-address-copy');
  var value = el('span', 'detail-full-address');
  value.textContent = address || '—';
  wrap.appendChild(value);
  if (resolveEns && address && address !== ZERO_ADDRESS) {
    value.title = address;
    ensNameOf(address).then(function (n) { if (n) value.textContent = n; }).catch(function () {});
  }

  if (!address || address === ZERO_ADDRESS) return wrap;

  var btn = document.createElement('button');
  btn.type = 'button';
  btn.className = 'address-copy-btn';
  btn.title = 'Copy address';
  btn.setAttribute('aria-label', 'Copy address');
  btn.appendChild(el('span', 'copy-icon'));
  btn.addEventListener('click', function (e) {
    e.preventDefault();
    e.stopPropagation();
    copyText(address).then(function () {
      btn.classList.add('copied');
      btn.title = 'Copied';
      setTimeout(function () {
        btn.classList.remove('copied');
        btn.title = 'Copy address';
      }, 1200);
    }).catch(function () {});
  });
  wrap.appendChild(btn);
  if (chainId) wrap.appendChild(safeBadge(address, chainId));
  return wrap;
}

// ── Safe (Gnosis Safe) detection + details ───────────────────────────────────
var SAFE_ABI = [
  { type: 'function', name: 'getThreshold', stateMutability: 'view', inputs: [], outputs: [{ type: 'uint256' }] },
  { type: 'function', name: 'getOwners', stateMutability: 'view', inputs: [], outputs: [{ type: 'address[]' }] },
];
// Safe wallet-app chain prefixes (https://app.safe.global) for the "Open in Safe" link. Best-effort.
var SAFE_CHAIN_PREFIX = { 1: 'eth', 10: 'oeth', 8453: 'base', 42161: 'arb1', 11155111: 'sep' };
var SAFE_ICON_SVG = '<svg viewBox="0 0 661.62 661.47" xmlns="http://www.w3.org/2000/svg" aria-hidden="true"><path d="m531.98 330.7h-49.42c-14.76 0-26.72 11.96-26.72 26.72v71.73c0 14.76-11.96 26.72-26.72 26.72h-196.61c-14.76 0-26.72 11.96-26.72 26.72v49.42c0 14.76 11.96 26.72 26.72 26.72h207.99c14.76 0 26.55-11.96 26.55-26.72v-39.65c0-14.76 11.96-25.23 26.72-25.23h38.2c14.76 0 26.72-11.96 26.72-26.72v-83.3c0-14.76-11.96-26.41-26.72-26.41zm-326.2-98.18c0-14.76 11.96-26.72 26.72-26.72h196.49c14.76 0 26.72-11.96 26.72-26.72v-49.42c0-14.76-11.96-26.72-26.72-26.72h-207.88c-14.76 0-26.72 11.96-26.72 26.72v38.08c0 14.76-11.96 26.72-26.72 26.72h-38.03c-14.76 0-26.72 11.96-26.72 26.72v83.39c0 14.76 12.01 26.12 26.77 26.12h49.42c14.76 0 26.72-11.96 26.72-26.72l-.05-71.44zm101.77 46.23h47.47c15.47 0 28.02 12.56 28.02 28.02v47.47c0 15.47-12.56 28.02-28.02 28.02h-47.47c-15.47 0-28.02-12.56-28.02-28.02v-47.47c0-15.47 12.56-28.02 28.02-28.02z" fill="currentColor"></path></svg>';

var _safeCache = {};
// Return { owners, threshold } if `address` is a Safe on `chainId`, else null. Onchain (works any chain).
function fetchSafeInfo(address, chainId) {
  if (!address || address === ZERO_ADDRESS || !chainId) return Promise.resolve(null);
  var key = chainId + ':' + address.toLowerCase();
  if (_safeCache[key]) return _safeCache[key];
  var p = (async function () {
    try {
      var client = clientFor(chainId);
      var threshold = await client.readContract({ address: address, abi: SAFE_ABI, functionName: 'getThreshold', args: [] });
      var owners = await client.readContract({ address: address, abi: SAFE_ABI, functionName: 'getOwners', args: [] });
      if (owners && owners.length && BigInt(threshold) > 0n) return { owners: owners, threshold: Number(threshold) };
      return null;
    } catch (_) { return null; }
  })();
  _safeCache[key] = p;
  return p;
}
// A slot that fills with a small Safe icon (opening the details modal) once we confirm the address is a Safe.
function safeBadge(address, chainId) {
  var slot = el('span', 'safe-badge-slot');
  fetchSafeInfo(address, chainId).then(function (info) {
    if (!info || !slot.isConnected) return;
    var btn = el('button', 'safe-badge'); btn.type = 'button';
    btn.title = 'Safe | ' + info.threshold + ' of ' + info.owners.length + ' signers — view details';
    btn.innerHTML = SAFE_ICON_SVG;
    btn.addEventListener('click', function (e) { e.preventDefault(); e.stopPropagation(); openSafeModal(address, chainId, info); });
    slot.appendChild(btn);
  }).catch(function () {});
  return slot;
}
function openSafeModal(address, chainId, info) {
  var content = el('div', 'modal-body safe-modal');
  var policy = el('div', 'safe-policy');
  policy.innerHTML = 'Requires <strong>' + info.threshold + ' of ' + info.owners.length + '</strong> signatures';
  content.appendChild(policy);

  var addrRow = el('div', 'safe-addr'); addrRow.appendChild(fullAddressNode(address, true));
  // fullAddressNode swaps the text to the ENS name when it resolves — show the raw 0x address alongside it too.
  ensNameOf(address).then(function (n) {
    if (n && addrRow.isConnected) { var raw = el('span', 'safe-addr-raw'); raw.textContent = address; addrRow.appendChild(raw); }
  }).catch(function () {});
  content.appendChild(addrRow);

  var lbl = el('div', 'safe-signers-label'); lbl.textContent = 'Signers'; content.appendChild(lbl);
  var list = el('div', 'safe-signers');
  info.owners.forEach(function (o) { var row = el('div', 'safe-signer'); row.appendChild(addressNode(o, chainId)); list.appendChild(row); });
  content.appendChild(list);

  var prefix = SAFE_CHAIN_PREFIX[chainId];
  if (prefix) {
    var link = document.createElement('a'); link.className = 'safe-applink';
    link.href = 'https://app.safe.global/home?safe=' + prefix + ':' + address;
    link.target = '_blank'; link.rel = 'noopener'; link.textContent = 'Open in Safe ↗';
    content.appendChild(link);
  }
  openModal('Safe', content);
}

// -- Onchain fetch --

export async function fetchMetadata(uri) {
  if (!uri) return null;
  var cached = readMetadataCache(uri);
  if (cached !== undefined) return cached;
  var urls = ipfsGatewayUrls(uri);
  var stagger = ipfsPath(uri) ? METADATA_FETCH_STAGGER_MS : 0;
  var json = await fetchFirstJson(urls, METADATA_FETCH_TIMEOUT_MS, stagger);
  if (json) writeMetadataCache(uri, json);
  return json;
}

async function read(chainId, contractName, abi, functionName, args) {
  var address = getAddress(contractName, chainId);
  if (!address) throw new Error('No ' + contractName + ' on chain ' + chainId);
  return clientFor(chainId).readContract({ address: address, abi: abi, functionName: functionName, args: args });
}

async function controllerAddressFor(chainId, projectId) {
  var controller = await read(chainId, 'JBDirectory', controllerOfAbi, 'controllerOf', [BigInt(projectId)]);
  if (!controller || !isAddr(controller) || /^0x0+$/.test(controller)) throw new Error('This project has no verified controller on ' + chainNameOf(chainId) + '.');
  return controller;
}

async function controllerRead(chainId, projectId, abi, functionName, args) {
  var controller = await controllerAddressFor(chainId, projectId);
  return clientFor(chainId).readContract({ address: controller, abi: abi, functionName: functionName, args: args });
}

async function controllerMapFor(chains, projectId) {
  var entries = await Promise.all((chains || []).map(async function (chain) {
    return [chain.id, await controllerAddressFor(chain.id, projectId)];
  }));
  var map = {};
  entries.forEach(function (entry) { map[entry[0]] = entry[1]; });
  return map;
}

var _bendystrawProjectRecordCache = {};
var _preferredProjectMetadataCache = {};
var INDEXED_PROJECT_METADATA_FIELDS = [
  'name', 'description', 'projectTagline', 'logoUri', 'coverImageUri', 'infoUri', 'payDisclosure',
  'twitter', 'farcaster', 'discord', 'telegram', 'domain', 'tags', 'tokens',
];

function parsedJsonObject(value) {
  if (value && typeof value === 'object' && !Array.isArray(value)) return Object.assign({}, value);
  if (typeof value === 'string' && value.trim()) {
    try {
      var parsed = JSON.parse(value);
      if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) return parsed;
    } catch (_) {}
  }
  return null;
}

// Normalize Bendystraw's complete parsed metadata JSON, filling any absent searchable fields from the row.
// `hasEmbeddedMetadata` distinguishes the complete JSON from a row containing only denormalized columns.
export function projectMetadataFromBendystraw(row) {
  if (!row) return null;
  var embedded = parsedJsonObject(row.metadata);
  var hasEmbedded = !!(embedded && Object.keys(embedded).length);
  var meta = embedded ? Object.assign({}, embedded) : {};
  INDEXED_PROJECT_METADATA_FIELDS.forEach(function (field) {
    if (meta[field] == null && row[field] != null) meta[field] = row[field];
  });
  var hasValues = Object.keys(meta).some(function (key) { return meta[key] != null; });
  if (!hasValues && !row.metadataUri && !row.handle) return null;
  return {
    uri: row.metadataUri || '',
    metadata: meta,
    handle: row.handle || null,
    source: 'bendystraw',
    hasEmbeddedMetadata: hasEmbedded,
  };
}

function fetchBendystrawProjectRecord(id, chainId) {
  var key = DISCOVER_NETWORK + ':' + chainId + ':' + id;
  if (_bendystrawProjectRecordCache[key]) return _bendystrawProjectRecordCache[key];
  _bendystrawProjectRecordCache[key] = optionalWithin(
    bendystrawQuery(BENDYSTRAW_PROJECT_QUERY, {
      projectId: Number(id), chainId: Number(chainId), version: BENDYSTRAW_VERSION,
    }).then(function (data) { return data && data.project || null; }).catch(function () { return null; }),
    INDEXED_STATS_TIMEOUT_MS,
    null
  );
  return _bendystrawProjectRecordCache[key];
}

async function fetchOnchainProjectMetadata(id, chainId) {
  try {
    var uri = await controllerRead(chainId, BigInt(id), uriOfAbi, 'uriOf', [BigInt(id)]);
    if (!uri) return null;
    var meta = await fetchMetadata(uri);
    return meta ? { uri: uri, metadata: meta, handle: null, source: 'onchain', hasEmbeddedMetadata: true } : null;
  } catch (_) { return null; }
}

// Project display metadata is indexed-first. If Bendystraw has only a URI, fetch that URI directly; only when
// the indexed row/URI is absent or unusable do we ask the controller for its current URI.
function fetchPreferredProjectMetadata(id, chainId) {
  var key = DISCOVER_NETWORK + ':' + chainId + ':' + id;
  if (_preferredProjectMetadataCache[key]) return _preferredProjectMetadataCache[key];
  _preferredProjectMetadataCache[key] = (async function () {
    var row = await fetchBendystrawProjectRecord(id, chainId);
    var indexed = projectMetadataFromBendystraw(row);
    if (indexed && indexed.hasEmbeddedMetadata) return indexed;
    if (indexed && indexed.uri) {
      var fetched = await fetchMetadata(indexed.uri).catch(function () { return null; });
      if (fetched) {
        return Object.assign({}, indexed, {
          metadata: Object.assign({}, indexed.metadata || {}, fetched),
          hasEmbeddedMetadata: true,
        });
      }
    }
    var fallback = await fetchOnchainProjectMetadata(id, chainId);
    if (fallback && indexed) {
      // Bendystraw remains primary for every field it has; the controller URI fills only missing indexed fields.
      fallback.uri = indexed.uri || fallback.uri;
      fallback.metadata = Object.assign({}, fallback.metadata || {}, indexed.metadata || {});
      fallback.handle = indexed.handle || fallback.handle;
      fallback.source = 'bendystraw';
    }
    return fallback || indexed;
  })();
  return _preferredProjectMetadataCache[key];
}

export function applyProjectMetadata(project, record) {
  if (!project || !record || !record.metadata) return project;
  var meta = record.metadata;
  project.projectMetadata = meta;
  project.projectMetadataSource = record.source || null;
  project.metadataUri = record.uri || null;
  project.handle = record.handle || null;
  project.name = meta.name || null;
  project.description = htmlToText(meta.description);
  project.descriptionHtml = meta.description || null;
  project.tagline = stripHtml(meta.projectTagline || meta.tagline) || null;
  project.logoUri = meta.logoUri ? ipfsToHttp(meta.logoUri) : null;
  project.coverImageUri = meta.coverImageUri ? ipfsToHttp(meta.coverImageUri) : null;
  project.infoUri = meta.infoUri || meta.domain || null;
  project.twitter = meta.twitter || null;
  project.farcaster = meta.farcaster || null;
  project.discord = meta.discord || null;
  project.telegram = meta.telegram || null;
  project.whatsapp = meta.whatsapp || null;
  project.domain = meta.domain || null;
  project.payDisclosure = meta.payDisclosure || null;
  project.tags = Array.isArray(meta.tags) ? meta.tags : [];
  project.tokens = Array.isArray(meta.tokens) ? meta.tokens : [];
  project.metaSymbol = (meta.symbol || meta.ticker || '').toString().trim() || null;
  project.storeCategories = (meta.storeCategories && typeof meta.storeCategories === 'object') ? meta.storeCategories : {};
  return project;
}

// Fetch the full project record: Bendystraw-first display metadata/aggregates plus live contract state.
// Never throws — missing pieces come back null so a single failed read can't blank the whole card.
async function fetchProject(id, chainId) {
  var pid = BigInt(id);
  var project = {
    id: id,
    chainId: chainId,
    name: null,
    description: null,
    tagline: null,
    logoUri: null,
    coverImageUri: null,
    infoUri: null,
    tags: [],
    tokens: [],
    metadataUri: null,
    projectMetadata: null,
    projectMetadataSource: null,
    owner: null,
    operator: null,
    tokenAddress: null,
    tokenSymbol: null,
    metaSymbol: null, // offchain display symbol from projectUri (custom credits-only projects)
    tokenName: null,
    totalSupply: null,
    pendingReserved: null,
    balance: null,
    ruleset: null,
    metadata: null,
    reservedSplits: null,
    isRevnet: false,
    stages: null,
    loanBorrowed: null,
    loanCollateral: null,
    indexedStats: null,
  };

  var jobs = [];

  // Indexed volume / payments / contributors from Bendystraw (cross-chain aggregate when available).
  jobs.push(fetchProjectIndexedStats(id, chainId)
    .then(function (s) { if (s) project.indexedStats = s; }));

  jobs.push(fetchPreferredProjectMetadata(id, chainId)
    .then(function (record) { if (record) applyProjectMetadata(project, record); })
    .catch(function () {}));

  var revOwnerAddr = getAddress('REVOwner', chainId);
  jobs.push(read(chainId, 'JBProjects', ownerOfAbi, 'ownerOf', [pid])
    .then(function (o) {
      project.owner = o;
      // A revnet's project NFT is held by the REVOwner contract.
      if (o && revOwnerAddr && o.toLowerCase() === revOwnerAddr.toLowerCase()) project.isRevnet = true;
    }).catch(function () {}));

  // Stages = the project's queued rulesets (revnet stage timeline).
  jobs.push(readAllRulesets(chainId, pid)
    .then(function (rs) { project.stages = rs; }).catch(function () {}));

  // Loan exposure (RevLoans). Reverts for non-loan-source projects — caught.
  jobs.push(read(chainId, 'REVLoans', totalBorrowedAbi, 'totalBorrowedFrom', [pid, NATIVE_TOKEN])
    .then(function (v) { project.loanBorrowed = v; }).catch(function () {}));
  jobs.push(read(chainId, 'REVLoans', totalCollateralAbi, 'totalCollateralOf', [pid])
    .then(function (v) { project.loanCollateral = v; }).catch(function () {}));

  jobs.push(read(chainId, 'JBTokens', tokenOfAbi, 'tokenOf', [pid])
    .then(async function (tokenAddr) {
      if (!tokenAddr || tokenAddr === ZERO_ADDRESS) return;
      project.tokenAddress = tokenAddr;
      var c = clientFor(chainId);
      project.tokenSymbol = await c.readContract({
        address: tokenAddr, abi: erc20SymbolAbi, functionName: 'symbol', args: [],
      }).catch(function () { return null; });
      // The ERC-20 name is the authoritative onchain project name (set from the deploy config,
      // e.g. "Bananapus (Juicebox V6)") — fresher than the reused IPFS metadata JSON.
      project.tokenName = await c.readContract({
        address: tokenAddr, abi: erc20NameAbi, functionName: 'name', args: [],
      }).catch(function () { return null; });
    }).catch(function () {}));

  jobs.push(read(chainId, 'JBTokens', totalSupplyAbi, 'totalSupplyOf', [pid])
    .then(function (s) { project.totalSupply = s; }).catch(function () {}));

  jobs.push(controllerRead(chainId, pid, pendingReservedAbi, 'pendingReservedTokenBalanceOf', [pid])
    .then(function (s) { project.pendingReserved = s; }).catch(function () {}));

  var terminalAddr = getAddress('JBMultiTerminal', chainId);
  if (terminalAddr) {
    jobs.push(resolveAcctToken(chainId, pid).then(function (acct) {
      project.acctToken = acct;
      return read(chainId, 'JBTerminalStore', storeBalanceAbi, 'balanceOf', [terminalAddr, pid, acct.address])
        .then(function (s) { project.balance = s; }).catch(function () {});
    }).catch(function () {}));
  }

  jobs.push(controllerRead(chainId, pid, currentRulesetAbi, 'currentRulesetOf', [pid])
    .then(async function (result) {
      project.ruleset = result[0];
      project.metadata = result[1];
      // A project whose first ruleset hasn't started yet has no current ruleset (start 0). Fall back
      // to the upcoming/queued ruleset so the pay card's issuance and the start countdown are correct.
      if (!project.ruleset || Number(project.ruleset.start || 0) === 0) {
        try {
          var up = await controllerRead(chainId, pid, upcomingRulesetAbi, 'upcomingRulesetOf', [pid]);
          if (up && up[0] && Number(up[0].start || 0) > 0) { project.ruleset = up[0]; project.metadata = up[1]; }
        } catch (e) { /* keep current */ }
      }
      // Reserved-token splits are keyed by the ruleset id.
      try {
        var splits = await read(chainId, 'JBSplits', splitsOfAbi, 'splitsOf', [pid, BigInt(project.ruleset.id), RESERVED_TOKEN_SPLIT_GROUP]);
        project.reservedSplits = splits || [];
      } catch (e) { /* leave null */ }
    }).catch(function () {}));

  await Promise.all(jobs);

  if (project.isRevnet) {
    project.operator = await revnetOperatorOf(id, chainId);
  }

  // Symbol priority: deployed ERC-20 symbol (authoritative) → offchain projectUri symbol (credits-only
  // custom projects). Resolved here, after both the token-of read and the metadata fetch have settled.
  if (!project.tokenSymbol && project.metaSymbol) project.tokenSymbol = project.metaSymbol;
  // Project metadata owns the project name. The ERC-20 name, handle, symbol, and id are progressively weaker
  // fallbacks for projects whose indexed and onchain URI metadata are both absent.
  if (!project.name) project.name = project.handle || project.tokenName || project.tokenSymbol || ('Project #' + id);
  return project;
}

// -- State --
var _container = null;
var _gridWrapper = null;
var _cache = {}; // "<chainId>-<projectId>" -> projectData
var _groups = null; // cached buildGroups result
var _activeDetail = null; // { key, showTab, project, isMobile } for the currently open project detail
var _projectRefreshTimer = null;
var _projectRefreshSeq = 0;

function scheduleActiveProjectRefresh(project) {
  if (!_activeDetail || !_activeDetail.project || String(_activeDetail.project.id) !== String(project.id)) return;
  if (_projectRefreshTimer) clearTimeout(_projectRefreshTimer);
  var seq = ++_projectRefreshSeq;
  // Give load-balanced RPCs a short moment to converge after the confirmed receipt, then rebuild the active tab
  // from onchain state. The browser URL/tab stays put and no manual refresh is required.
  _projectRefreshTimer = setTimeout(function () {
    _projectRefreshTimer = null;
    var active = _activeDetail;
    if (!active || !active.project || String(active.project.id) !== String(project.id)) return;
    var tab = active.current, subtab = active.subtab;
    var chains = (active.project.chains || project.chains || []).slice();
    var urlChainId = active.project._urlChainId || project._urlChainId || project.chainId;
    Object.keys(_cache).forEach(function (key) { if (key.endsWith('-' + project.id)) delete _cache[key]; });
    _tiersCache = {}; _tierMetadataCache = {}; _dataHookCache = {}; _accountingTokenMetadataCache = {};
    fetchProject(project.id, urlChainId).then(function (fresh) {
      if (seq !== _projectRefreshSeq || !_activeDetail || String(_activeDetail.project.id) !== String(project.id)) return;
      fresh.chains = chains.length ? chains : [{ id: urlChainId, name: chainNameOf(urlChainId) }];
      fresh._urlChainId = urlChainId;
      _cache[urlChainId + '-' + project.id] = fresh;
      showProjectDetail(fresh, tab, true, subtab);
    }).catch(function () {});
  }, 700);
}

function notifyProjectUpdated(project) {
  document.dispatchEvent(new CustomEvent('jb:bridge-updated'));
  var detail = _container && _container.querySelector('.project-detail');
  if (detail && _activeDetail && String(_activeDetail.project.id) === String(project.id)) {
    detail.dispatchEvent(new CustomEvent('jb:project-updated'));
  }
}

export function invalidateDiscoverProjects() {
  _groups = null; _cache = {}; _splitProjCache = {}; _bendystrawProjectRecordCache = {};
  _preferredProjectMetadataCache = {}; _tiersCache = {}; _tierMetadataCache = {}; _dataHookCache = {}; _instanceProvenanceCache = {};
  _activeDetail = null;
  if (_container) renderDiscoverTab();
}

if (typeof document !== 'undefined') {
  document.addEventListener('jb:project-created', function (event) {
    var chainId = Number(event && event.detail && event.detail.chainId || 0);
    var mode = [11155111, 11155420, 84532, 421614].indexOf(chainId) !== -1 ? 'testnet'
      : ([1, 10, 8453, 42161].indexOf(chainId) !== -1 ? 'mainnet' : DISCOVER_NETWORK);
    if (mode !== DISCOVER_NETWORK) setDiscoverNetwork(mode);
    else invalidateDiscoverProjects();
  });
}

// Activity-card-vs-tab and the column stacking are decided at build time from the viewport width. If the
// window is resized ACROSS the 600px breakpoint while a detail is open, re-render it so Activity moves
// between the left column (wide) and the first subtab (narrow). Debounced; only fires on an actual cross.
if (typeof window !== 'undefined') {
  var _resizeT = null;
  window.addEventListener('resize', function () {
    if (!_activeDetail || !_activeDetail.project) return;
    if (_resizeT) clearTimeout(_resizeT);
    _resizeT = setTimeout(function () {
      if (!_activeDetail || !_activeDetail.project) return;
      var nowMobile = !!(window.matchMedia && window.matchMedia('(max-width: 600px)').matches);
      if (nowMobile === _activeDetail.isMobile) return; // breakpoint not crossed
      showProjectDetail(_activeDetail.project, _activeDetail.current, true, _activeDetail.subtab);
    }, 150);
  });
}

function ensureGroups() {
  if (_groups) return Promise.resolve(_groups);
  return buildGroups().then(function (g) { _groups = g; return g; });
}

export function renderDiscoverTab() {
  _container = document.getElementById('tab-discover');
  if (!_container) return;
  _container.innerHTML = '';
  renderGrid();
}

// Open whatever project route is in the hash (called on load and on back/forward). null → grid.
export function applyDiscoverRoute(route) {
  if (!route) {
    if (_activeDetail) showProjectGrid(true);
    return;
  }
  var m = /^([a-z0-9]+):(\d+)(?:\/([a-z0-9]+))?(?:\/([a-z0-9]+))?$/i.exec(route);
  if (!m) { showProjectGrid(true); return; }
  // Hide the grid immediately (before the async fetch) so it doesn't flash before the detail loads.
  if (_gridWrapper) _gridWrapper.style.display = 'none';
  var chainId = chainForSlug(m[1].toLowerCase());
  var id = Number(m[2]);
  var tab = m[3] ? m[3].toLowerCase() : null;
  var sub = m[4] ? m[4].toLowerCase() : null; // nested subtab (e.g. Tokens → Settlement)
  var key = m[1].toLowerCase() + ':' + id;

  // Same project already open → just switch the tab (no re-fetch / re-render).
  if (_activeDetail && _activeDetail.key === key) {
    if (tab) _activeDetail.showTab(tab);
    if (sub && _activeDetail.showSubTab) _activeDetail.showSubTab(sub);
    return;
  }

  // Show a ghost detail immediately so a direct route load isn't blank during the fetch.
  // showProjectDetail() later removes this `.project-detail` and swaps in the real page.
  if (_container) {
    var stale = _container.querySelector('.project-detail');
    if (stale) stale.remove();
    _container.appendChild(renderDetailSkeleton());
  }

  ensureGroups().then(function (groups) {
    var g = null;
    for (var i = 0; i < groups.length; i++) if (groups[i].id === id) { g = groups[i]; break; }
    if (!g) { showProjectGrid(true); return; }
    var urlChain = (chainId && g.chains.some(function (c) { return c.id === chainId; })) ? chainId : defaultChainId(g.chains);
    var fk = urlChain + '-' + id;
    var p = _cache[fk] ? Promise.resolve(_cache[fk]) : fetchProject(id, urlChain).then(function (d) { _cache[fk] = d; return d; });
    p.then(function (project) {
      project.chains = g.chains;
      project._urlChainId = urlChain;
      showProjectDetail(project, tab, true, sub);
    }).catch(function () { showProjectGrid(true); });
  });
}

function renderGrid() {
  _gridWrapper = el('div', 'discover-grid-wrapper');

  // Top row: subtle network text-toggle on the left; Create button top-right.
  var topRow = el('div', 'discover-top');
  // Network pivot: mainnet ⇄ testnet. Switches the queried chains + the indexer host.
  var netSel = el('select', 'discover-net-select');
  [['mainnet', 'Mainnets'], ['testnet', 'Testnets']].forEach(function (o) {
    var opt = document.createElement('option'); opt.value = o[0]; opt.textContent = o[1]; netSel.appendChild(opt);
  });
  netSel.value = getNetworkMode();
  netSel.title = 'Switch between mainnet and testnet deployments';
  netSel.addEventListener('change', function () { setDiscoverNetwork(netSel.value); });
  topRow.appendChild(netSel);
  setTimeout(function () { fitSelectWidth(netSel); }, 0);
  var rightCtrls = el('div', 'discover-top-ctrls');
  var createBtn = el('button', 'tab-create'); createBtn.textContent = 'New project';
  createBtn.title = 'Create — in tuning before launch';
  createBtn.addEventListener('click', function () { openCreateFlow(); });
  rightCtrls.appendChild(createBtn);
  topRow.appendChild(rightCtrls);
  _gridWrapper.appendChild(topRow);

  var grid = el('div', 'discover-grid');
  _gridWrapper.appendChild(grid);
  var gridFoot = discoverPromptFoot('Discover explorer (project grid)'); // [copy build prompt] — bottom-right (default)
  _gridWrapper.appendChild(gridFoot);
  _container.appendChild(_gridWrapper);

  var status = el('div', 'discover-card-desc');
  status.textContent = 'Discovering projects across chains…';
  grid.appendChild(status);

  ensureGroups().then(function (groups) {
    grid.innerHTML = '';
    if (!groups.length) { grid.textContent = 'No projects found.'; return; }
    groups.forEach(function (g) {
      var card = renderSkeletonCard(g.id);
      grid.appendChild(card);
      loadGroupCard(g, card, grid);
    });
  }).catch(function () {
    grid.innerHTML = '';
    var e = el('div', 'discover-card-desc');
    e.textContent = 'Could not read projects from chain.';
    grid.appendChild(e);
  });
}

function hasDirectoryController(chainId, id) {
  return read(chainId, 'JBDirectory', controllerOfAbi, 'controllerOf', [BigInt(id)])
    .then(function (controller) {
      return !!(controller && controller !== ZERO_ADDRESS);
    })
    .catch(function () { return false; });
}

// Enumerate projects across every chain and dedup omnichain copies. JBProjects.count is only the upper
// bound: a project NFT can exist on a chain before the project has any JBDirectory state there. Treat a
// chain as live for a project only once JBDirectory.controllerOf(projectId) is set.
function buildGroups() {
  return Promise.all(DISCOVER_CHAINS.map(function (c) {
    return read(c.id, 'JBProjects', countAbi, 'count', [])
      .then(function (n) { return { chain: c, count: Number(n) }; })
      .catch(function () { return { chain: c, count: 0 }; });
  })).then(async function (counts) {
    var max = 0;
    counts.forEach(function (x) { if (x.count > max) max = x.count; });
    var groups = await Promise.all(Array.from({ length: max }, async function (_, i) {
      var id = i + 1;
      var candidates = counts.filter(function (x) { return id <= x.count; });
      var live = await Promise.all(candidates.map(function (x) {
        return hasDirectoryController(x.chain.id, id).then(function (ok) {
          return ok ? x.chain : null;
        });
      }));
      var chains = live.filter(Boolean);
      return chains.length ? { id: id, chains: chains, primary: chains[0] } : null;
    }));
    groups = groups.filter(Boolean);
    return groups;
  });
}

function loadGroupCard(g, skeleton, grid) {
  var key = g.primary.id + '-' + g.id;
  var promise = _cache[key] ? Promise.resolve(_cache[key]) : fetchProject(g.id, g.primary.id).then(function (data) {
    _cache[key] = data;
    return data;
  });
  promise.then(function (project) {
    project.chains = g.chains;
    if (skeleton.parentNode !== grid) return;
    grid.replaceChild(renderProjectCard(project), skeleton);
  }).catch(function () {
    if (skeleton.parentNode === grid) {
      skeleton.classList.remove('discover-card--loading');
      skeleton.innerHTML = '';
      var err = el('div', 'discover-card-desc'); err.textContent = 'Could not load this project from chain.';
      skeleton.appendChild(err);
    }
  });
}

function renderSkeletonCard() {
  // Shimmer ghost in the same shape as a real card (logo + name, two meta lines, a description line).
  var card = el('div', 'discover-card discover-card--loading');
  var head = el('div', 'discover-card-header');
  head.appendChild(skel('28px', '28px'));
  head.appendChild(skel('46%', '15px'));
  card.appendChild(head);
  var m1 = skel('62%', '11px'); m1.style.marginTop = '12px'; card.appendChild(m1);
  var m2 = skel('40%', '11px'); m2.style.marginTop = '8px'; card.appendChild(m2);
  var d = skel('85%', '11px'); d.style.marginTop = '14px'; card.appendChild(d);
  return card;
}

function renderProjectCard(project) {
  var card = el('div', 'discover-card');
  card.dataset.metadataSource = project.projectMetadataSource || 'none';
  card.style.cursor = 'pointer';
  card.addEventListener('click', function () { showProjectDetail(project); });

  var cardLbl = function (text) { var s = el('span', 'discover-card-lbl'); s.textContent = text; return s; };

  // Line 1: logo + name + #id.
  var head = el('div', 'discover-card-header');
  head.appendChild(renderLogo(project, 'discover-card-logo'));
  var name = el('span', 'discover-card-name');
  name.textContent = project.name;
  head.appendChild(name);
  card.appendChild(head);

  // Line 2: Type | On (chain logos). Each label+value is a nowrap pair joined by a breakable space;
  // the "|" is drawn by CSS ::after inside the pair so it trails the previous line on a wrap.
  var meta1 = el('div', 'discover-card-meta');
  var flavorPair = el('span', 'discover-card-pair');
  flavorPair.appendChild(cardLbl('Flavor: '));
  var typeVal = el('span', 'discover-card-val'); typeVal.textContent = project.isRevnet ? 'REVNET' : 'CUSTOM';
  flavorPair.appendChild(typeVal);
  meta1.appendChild(flavorPair);
  if (project.chains && project.chains.length) {
    meta1.appendChild(document.createTextNode(' '));
    var onPair = el('span', 'discover-card-pair');
    onPair.appendChild(cardLbl('On: '));
    var cardLogos = el('span', 'discover-chain-logos');
    project.chains.forEach(function (c) { cardLogos.appendChild(projectChainLogo(project, c)); });
    onPair.appendChild(cardLogos);
    meta1.appendChild(onPair);
  }
  card.appendChild(meta1);

  // Line 3: owner/operator authority.
  var meta2 = el('div', 'discover-card-meta discover-card-on');
  meta2.appendChild(cardLbl(projectAuthorityLabel(project) + ': '));
  meta2.appendChild(addressNode(projectAuthorityAddress(project)));
  card.appendChild(meta2);

  var desc = el('div', 'discover-card-desc');
  desc.textContent = project.tagline || project.description || 'No description set onchain.';
  card.appendChild(desc);

  var stats = el('div', 'discover-card-stats');
  stats.appendChild(statItem('Balance', mountUsdBalance(project)));
  if (project.indexedStats) {
    stats.appendChild(statItem('Volume', formatUsd(usdFromScaled(project.indexedStats.volumeUsd))));
    stats.appendChild(statItem('Payments', String(project.indexedStats.paymentsCount)));
    // Token-holder count — revnets call them "Owners", custom projects "Token holders".
    // contributorsCount only counts addresses that paid; holders who received tokens via
    // auto-issuance / reserved mint (ART has one) are missed. Seed with it, then correct to
    // the real current-holder count (same aggregation the detail header uses).
    var ownersVal = el('span', ''); ownersVal.textContent = String(project.indexedStats.contributorsCount);
    stats.appendChild(statItem(project.isRevnet ? 'Owners' : 'Token holders', ownersVal));
    fetchOwnersCount(project).then(function (n) {
      if (n != null && ownersVal.isConnected) ownersVal.textContent = String(n);
    }).catch(function () {});
  }
  card.appendChild(stats);

  return card;
}

function renderLogo(project, className) {
  if (project.logoUri) {
    var img = document.createElement('img');
    img.className = className + ' discover-logo-img';
    img.alt = project.name;
    img.loading = 'lazy';
    setMediaSource(img, project.logoUri, function () {
      var fallback = renderLetterLogo(project, className);
      if (img.parentNode) img.parentNode.replaceChild(fallback, img);
    });
    return img;
  }
  return renderLetterLogo(project, className);
}

function renderLetterLogo(project, className) {
  var logo = el('div', className);
  logo.textContent = (project.name || '#').charAt(0).toUpperCase();
  logo.style.background = logoColor(project.id);
  return logo;
}

function statItem(label, value) {
  var item = el('div', 'discover-stat');
  var lbl = el('div', 'discover-stat-label');
  lbl.textContent = label;
  item.appendChild(lbl);
  var val = el('div', 'discover-stat-value');
  if (value && value.nodeType) val.appendChild(value); else val.textContent = value;
  item.appendChild(val);
  return item;
}

// -- Navigation --

// URL-safe slug for a detail tab name (e.g. "Rulesets & Funds" → "rulesetsfunds").
function tabSlug(name) { return String(name).toLowerCase().replace(/[^a-z0-9]+/g, ''); }

function projectHash(project, tabName, subTab) {
  var h = '#' + slugForChain(project._urlChainId) + ':' + project.id;
  if (tabName) { h += '/' + tabSlug(tabName); if (subTab) h += '/' + tabSlug(subTab); }
  return h;
}

function showProjectDetail(project, initialTab, fromRoute, initialSubTab) {
  if (project._urlChainId == null) {
    project._urlChainId = defaultChainId(project.chains || [{ id: project.chainId }]);
  }
  _gridWrapper.style.display = 'none';
  var existing = _container.querySelector('.project-detail');
  if (existing) existing.remove();
  _container.appendChild(renderProjectDetail(project, initialTab, initialSubTab));
  if (!fromRoute) routerSetHash(projectHash(project, _activeDetail && _activeDetail.current, _activeDetail && _activeDetail.subtab));
}

function showProjectGrid(fromRoute) {
  var detail = _container.querySelector('.project-detail');
  if (detail) detail.remove();
  _activeDetail = null;
  _gridWrapper.style.display = '';
  if (!fromRoute) routerSetHash('#discover');
}

// -- Detail Page --

function renderProjectDetail(project, initialTab, initialSubTab) {
  // `detail-spacious`: juicy-vision-style low-border layout — drop the boxed cards in favor of whitespace,
  // a single column divider, and thin section separators.
  var wrap = el('div', 'project-detail detail-spacious');
  wrap.dataset.metadataSource = project.projectMetadataSource || 'none';
  var nftCart = makeNftCart(); // shared between the Pay-card strip and the Shop tab

  var back = document.createElement('button');
  back.className = 'detail-back';
  back.textContent = '←';
  back.title = 'Back to projects';
  back.addEventListener('click', function () { showProjectGrid(false); });
  wrap.appendChild(back);

  var headerEl = renderDetailHeader(project);
  wrap.appendChild(headerEl);
  wrap.appendChild(renderProjectContractWarnings(project));

  // Auto-refresh balance/supply (+ owners via the rebuilt header) and the activity feed when a tx
  // confirms in this view — a bubbling 'jb:project-updated' event is dispatched by the
  // pay/cash out/distribute flows. `activityCardEl` is assigned just below, before any tx can fire.
  var activityCardEl = null;
  wrap.addEventListener('jb:project-updated', function () {
    var pid = BigInt(project.id);
    var terminal = getAddress('JBMultiTerminal', project.chainId);
    var acctAddr = (project.acctToken && project.acctToken.address) || NATIVE_TOKEN;
    Promise.all([
      terminal ? read(project.chainId, 'JBTerminalStore', storeBalanceAbi, 'balanceOf', [terminal, pid, acctAddr]).catch(function () { return null; }) : Promise.resolve(null),
      read(project.chainId, 'JBTokens', totalSupplyAbi, 'totalSupplyOf', [pid]).catch(function () { return null; }),
    ]).then(function (res) {
      if (res[0] != null) project.balance = res[0];
      if (res[1] != null) project.totalSupply = res[1];
      var fresh = renderDetailHeader(project);
      if (headerEl.parentNode) { headerEl.parentNode.replaceChild(fresh, headerEl); headerEl = fresh; }
    });
    if (activityCardEl && activityCardEl._refresh) activityCardEl._refresh();
    scheduleActiveProjectRefresh(project);
  });

  var columns = el('div', 'project-detail-columns');

  var leftCol = el('div', 'project-detail-left');
  leftCol.appendChild(renderPayRuleChangeNotice(project));
  leftCol.appendChild(renderPayCard(project, nftCart));
  // On phones, Activity becomes the first detail subtab (added below, and default) instead of a tall
  // always-on card wedged between Pay and the tabs; on wider screens it stays in the left column.
  var activityAsTab = !!(window.matchMedia && window.matchMedia('(max-width: 600px)').matches);
  // Activity panel height: at least as tall as the body (right column), and twice its own content when populated
  // — so the feed isn't clipped to a short body and stays a substantial panel.
  function sizeActivity() {
    if (activityAsTab || !activityCardEl || !activityCardEl.isConnected) return;
    var feed = activityCardEl.querySelector('.activity-feed');
    if (!feed) return;
    if (!feed.querySelector('.activity-row')) { feed.style.minHeight = ''; feed.style.maxHeight = ''; return; }
    // A tall panel: twice the default 390px feed, and at least most of the viewport (a proxy for the body
    // content height — measuring the body column directly feeds back through the equal-height column stretch).
    // Content shorter than this shows in full; longer histories scroll within the panel.
    var target = Math.max(2 * ACTIVITY_FEED_BASE_PX, Math.round(0.82 * (window.innerHeight || 900)));
    feed.style.minHeight = target + 'px';
    feed.style.maxHeight = target + 'px';
  }
  activityCardEl = renderActivityCard(project, { asTab: activityAsTab, onContent: function () { requestAnimationFrame(sizeActivity); } });
  if (!activityAsTab) leftCol.appendChild(activityCardEl);
  columns.appendChild(leftCol);
  window.addEventListener('resize', function () { requestAnimationFrame(sizeActivity); });

  var rightCol = el('div', 'project-detail-right');
  // Sections build lazily on first view so the cross-chain "Ops" fan-out only fires when opened.
  // The price chart (revnets' issuance-price ladder) lives at the top of the About tab.
  var builders = {
    Overview: function () {
      var wrap = el('div');
      if (project.isRevnet && project.stages && project.stages.length) wrap.appendChild(renderPriceChart(project, project.stages));
      wrap.appendChild(renderAboutSection(project));
      return wrap;
    },
    Owners: function () { return renderOwnersSection(project, { tabName: 'Owners', initialSubTab: initialSubTab }); },
    Ops: function () { return renderOpsSection(project); },
  };
  // The Safe/queue tab: signers approve + execute queued owner-only txs. Labeled "Operator" for revnets
  // (the controlling account is the operator) and "Owner" for custom projects. Shown only when that
  // account is actually a Safe (the tab button is hidden async otherwise).
  var ownerTabName = project.isRevnet ? 'Operator' : 'Owner';
  builders[ownerTabName] = function () { return renderBackOfficeSection(project); };
  var tabs;
  if (project.isRevnet) {
    // Revnets express rules through stages (Terms) and holders through Owners (splits + auto-issuance).
    builders.Terms = function () { return renderStagesSection(project); };
    // Revnets carry the wallet actions in the Owners → "You" card, so no separate Ops tab.
    // The Operator tab goes after Shop (added below).
    tabs = ['Overview', 'Terms', 'Owners'];
  } else {
    // Custom projects get the same subtabbed holders view as revnets, minus the revnet-only concepts
    // (Auto Issuance, Loans). The cross-chain composition that used to live in "Ops" now sits under
    // Settlement, so there's no separate Ops tab. Rulesets and Funds are their own tabs.
    builders.Rulesets = function () { return renderRulesetsFundsSection(project); };
    builders.Funds = function () { return renderFundsSection(project); };
    builders.Tokens = function () {
      return renderOwnersSection(project, {
        subtabs: ['Accounts', 'Market', 'Settlement', 'Reserved'],
        noLoans: true,
        tabName: 'Tokens',
        initialSubTab: initialSubTab,
      });
    };
    tabs = ['Overview', 'Rulesets', 'Funds', 'Tokens'];
  }
  // Shop tab: shown optimistically (assume the project can sell items) so a #shop route resolves and the
  // tab doesn't pop in late. Once the 721-hook read resolves it's either filled with real content or removed
  // (no hook yet — a custom project can add one via Rulesets → Queue → "Sell NFT items").
  var shopState = { shop: null, loaded: false };
  builders.Shop = function () {
    if (shopState.loaded && shopState.shop) return renderShopSection(project, shopState.shop, nftCart);
    var wrap = el('div', 'detail-section'); var card = el('div', 'detail-card shop-card');
    var t = el('div', 'detail-card-title'); t.textContent = 'Shop'; card.appendChild(t);
    var b = el('div', 'shop-body'); b.textContent = 'Loading…'; card.appendChild(b);
    wrap.appendChild(card); return wrap;
  };
  tabs.push('Shop');
  builders.Extras = function () { return renderExtrasSection(project); };
  tabs.push('Extras');
  tabs.push(ownerTabName); // Owner/Operator stays last, after Shop and Extras.
  // Phones: Activity is the first subtab and the default (the left-column card is omitted above).
  if (activityAsTab) { builders.Activity = function () { return activityCardEl; }; tabs.unshift('Activity'); }
  var tabRow = el('div', 'project-detail-tabs');
  var contentArea = el('div', 'project-detail-content');
  attachCardPromptLinks(wrap); // every card across the whole detail (tabs + activity + side cards) gets a link
  var built = {};
  // Resolve the initial tab (from a deep link) case-insensitively; fall back to the first tab.
  var startTab = tabs[0];
  if (initialTab) {
    for (var k = 0; k < tabs.length; k++) if (tabSlug(tabs[k]) === tabSlug(initialTab)) { startTab = tabs[k]; break; }
  }
  var detailKey = slugForChain(project._urlChainId) + ':' + project.id;
  function showTab(tabName) {
    // Accept slugified route names too (e.g. "rulesetsfunds").
    for (var t = 0; t < tabs.length; t++) if (tabSlug(tabs[t]) === tabSlug(tabName)) { tabName = tabs[t]; break; }
    if (!builders[tabName]) return;
    // Set `current` BEFORE building so a subtabbed section's show() (which fires during build) reads the
    // right top tab. Reset subtab state on every tab switch; the section re-registers it if it has subtabs.
    if (_activeDetail) { _activeDetail.current = tabName; _activeDetail.subtab = null; _activeDetail.showSubTab = null; }
    if (!built[tabName]) built[tabName] = builders[tabName]();
    contentArea.innerHTML = '';
    contentArea.appendChild(built[tabName]);
    var btns = tabRow.querySelectorAll('.detail-tab-btn');
    for (var b = 0; b < btns.length; b++) btns[b].classList.toggle('active', btns[b].textContent === tabName);
  }
  for (var i = 0; i < tabs.length; i++) {
    (function (tabName) {
      var btn = document.createElement('button');
      btn.className = 'detail-tab-btn';
      btn.textContent = tabName;
      btn.addEventListener('click', function () {
        showTab(tabName);
        // A subtabbed section sets _activeDetail.subtab during build; include it so refresh restores both.
        routerSetHash(projectHash(project, tabName, _activeDetail && _activeDetail.subtab));
      });
      tabRow.appendChild(btn);
    })(tabs[i]);
  }
  // Resolve the 721 hook: fill the optimistic Shop tab with real content, or remove it if the project
  // has no hook and can't get one (revnets always keep it — operators can add tiers even before any exist).
  fetchProjectTiers(project).then(function (shop) {
    if (!wrap.isConnected) return;
    // Show the Shop whenever a 721 hook is attached (fetchProjectTiers only returns non-null when STORE()
    // confirms a real 721 hook) — even with 0 tiers, so an operator can add items to an empty shop.
    var show = !!shop;
    if (show) {
      shopState.shop = shop; shopState.loaded = true;
      built.Shop = null; // drop the loading placeholder so the real section rebuilds
      if (_activeDetail && _activeDetail.current === 'Shop') showTab('Shop');
    } else {
      tabs = tabs.filter(function (t) { return t !== 'Shop'; });
      delete builders.Shop; delete built.Shop;
      var btns = tabRow.querySelectorAll('.detail-tab-btn');
      for (var b = 0; b < btns.length; b++) if (btns[b].textContent === 'Shop') { btns[b].remove(); break; }
      if (_activeDetail && _activeDetail.current === 'Shop') showTab(tabs[0]);
    }
  }).catch(function () {});

  // The Owner/Operator tab ALWAYS shows — it holds the owner/operator transactions, which an EOA controller can
  // execute directly via relayr (not just Safe signers). The Safe-only queue/sign views inside are hidden for
  // non-Safe controllers (see renderBackOfficeSection). This also keeps the tab reachable when the indexer is
  // down and the operator can't be resolved — the actions self-gate on connect.

  rightCol.appendChild(tabRow);
  _activeDetail = { key: detailKey, showTab: showTab, current: startTab, project: project, isMobile: activityAsTab };
  showTab(startTab);
  rightCol.appendChild(contentArea);
  columns.appendChild(rightCol);

  wrap.appendChild(columns);
  return wrap;
}

// Display label for a pay currency — drop the "(native)" suffix so ETH reads as just "ETH".
function currencyLabel(symbol) {
  return (symbol || '').replace(/\s*\(native\)\s*/i, '') || symbol || '';
}

// Size an inline (appearance:none) select to its CURRENTLY selected option's text, so the caret hugs
// the name regardless of which option is chosen (a native select otherwise sizes to its widest option).
// fontPx must match the select's CSS font-size (chain 11, currency 13). We measure with an explicit
// font rather than getComputedStyle so it's correct even before the element is attached to the DOM
// (computed style returns defaults for a detached node, which made the caret tight on first render).
function sizeSelectToText(sel, fontPx) {
  var opt = sel.options[sel.selectedIndex];
  if (!opt) return;
  if (!sizeSelectToText.ctx) sizeSelectToText.ctx = document.createElement('canvas').getContext('2d');
  sizeSelectToText.ctx.font = 'bold ' + (fontPx || 11) + 'px ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace';
  var w = sizeSelectToText.ctx.measureText(opt.textContent).width;
  sel.style.width = Math.ceil(w + 18) + 'px'; // text + caret gap (border-box: includes padding-right)
}

function renderPayRuleChangeNotice(project) {
  var link = el('a', 'paybox-rules-link');
  link.href = projectHash(project, project.isRevnet ? 'Terms' : 'Rulesets');
  link.title = 'View upcoming ruleset changes';
  link.style.display = 'none';
  var label = el('span', 'paybox-rules-label'); label.textContent = 'Rules change in'; link.appendChild(label);
  var time = el('span', 'paybox-rules-time'); link.appendChild(time);
  link.addEventListener('click', function (e) {
    e.preventDefault();
    var tab = project.isRevnet ? 'Terms' : 'Rulesets';
    if (_activeDetail && _activeDetail.showTab) _activeDetail.showTab(tab);
    routerSetHash(projectHash(project, tab));
    var sec = document.querySelector('.project-detail-content');
    if (sec) sec.scrollIntoView({ block: 'start', behavior: 'smooth' });
  });

  fetchUpcomingRuleChangeInfo(project).then(function (info) {
    if (!info) return;
    var target = Number(info.r && info.r.start);
    if (!(target > Math.floor(Date.now() / 1000))) return;
    var seenConnected = false;
    function updateRulesLink() {
      if (link.isConnected) seenConnected = true;
      else if (seenConnected) { clearInterval(timer); return; }
      var rem = target - Math.floor(Date.now() / 1000);
      if (rem <= 0) {
        clearInterval(timer);
        link.style.display = 'none';
        return;
      }
      time.textContent = relativeFromNow(rem);
      link.style.display = '';
    }
    var timer = setInterval(updateRulesLink, 30000);
    updateRulesLink();
  }).catch(function () {});
  return link;
}

// A verified terminal preview is executable even when it returns zero project tokens. Zero issuance is a valid
// `pay`: the payment still funds the project, while minReturnedTokens is legitimately zero. Keep unavailable or
// incomplete previews blocked so an RPC/terminal failure can never be mistaken for an intentional zero quote.
export function payPreviewCanSubmit(phase, preview) {
  if (phase !== 'ready' || !preview || preview.unavailable || preview.received == null) return false;
  try { return BigInt(preview.received) >= 0n; } catch (_) { return false; }
}

// Keep zero-issuance payments legitimate without presenting meaningless token output. An unavailable preview stays
// visible as an error state; a verified zero/zero quote (or an idle ruleset whose weight is 0) hides token issuance.
export function payTokenOutputVisible(rulesetWeight, phase, preview) {
  if (preview && preview.unavailable) return true;
  if (phase === 'ready' && preview && preview.received != null) {
    try { return BigInt(preview.received) > 0n || BigInt(preview.reserved || 0n) > 0n; } catch (_) { return true; }
  }
  try { return BigInt(rulesetWeight || 0) > 0n; } catch (_) { return true; }
}

// Inline pay card (revnet.app-style) for the project detail page. The project is already known, so it
// only needs a chain (when omnichain), a currency, and an amount. Live feedback — tokens received,
// reserved/splits, and the Issuance-vs-AMM routing tag — comes from the shared computePayPreview.
function renderPayCard(project, cart) {
  var sym = project.tokenSymbol ? project.tokenSymbol : 'tokens';
  cart = cart || makeNftCart();
  var chains = (project.chains && project.chains.length)
    ? project.chains
    : [{ id: project.chainId, name: (CHAINS[project.chainId] && CHAINS[project.chainId].name) || ('Chain ' + project.chainId) }];

  // Pay currencies for a chain. The DIRECT tokens are whatever the project's terminal actually accepts
  // (its accounting contexts) — for an ETH-based project that's native ETH; for a USD-based project (e.g.
  // ART) that's USDC. Tokens the project does NOT accept directly (native ETH and/or USDC) are offered as
  // swap-via-router currencies. The accepted set needs an onchain read, so we start from a sensible sync
  // default and refine once `loadAcceptedTokens` resolves.
  var _tokenCache = {}; // chainId -> resolved token list

  function defaultTokensForChain(chainId) {
    var base = getChainTokens(chainId).map(function (t) {
      return { address: t.address, symbol: t.symbol, decimals: t.decimals, viaRouter: false };
    });
    var usdc = USDC_BY_CHAIN[chainId];
    if (project.isRevnet && usdc && !base.some(function (t) { return t.address.toLowerCase() === usdc.toLowerCase(); })) {
      base.push({ address: usdc, symbol: 'USDC', decimals: 6, viaRouter: true });
    }
    return base;
  }
  function tokensForChain(chainId) { return _tokenCache[chainId] || defaultTokensForChain(chainId); }

  // Read the project's accounting contexts and rebuild the currency list: accepted tokens are direct,
  // native ETH + USDC that aren't accepted directly are added as swap-via-router options.
  function loadAcceptedTokens(chainId) {
    var term = getAddress('JBMultiTerminal', chainId);
    state.contextsReady = false;
    state.contextsError = false;
    if (!term) { state.contextsError = true; return; }
    Promise.all([
      resolveAcctTokens(chainId, BigInt(project.id)),
      readProjectPaymentSurface(project, chainId).catch(function () { return null; }),
    ]).then(function (loaded) {
        var ctxs = loaded[0], surface = loaded[1];
        if (state.chainId !== chainId) return;
        if (!ctxs || !ctxs.length) { state.contextsError = true; renderTerminalNotice(); return; }
        var usdc = USDC_BY_CHAIN[chainId];
        var list = ctxs.map(function (ctx) {
          return { address: ctx.address, symbol: ctx.symbol, name: ctx.name || '', decimals: Number(ctx.decimals), currency: Number(ctx.currency), viaRouter: false };
        });
        var has = function (a) { return list.some(function (t) { return t.address.toLowerCase() === a.toLowerCase(); }); };
        // Offer swap currencies only when the router registry/direct router is one of this project's terminals
        // AND the router can actually route that token into the project right now. A listed router with no
        // pool/feed path (e.g. a project accepting only its own custom token) reverts at pay time — offering
        // ETH/USDC there is a trap, not a convenience.
        if (surface) { state.terminalSurface = surface; state.terminalSurfaceChain = chainId; }
        var routerCandidates = [];
        if (surface && surface.hasRouter) {
          if (!has(NATIVE_TOKEN)) routerCandidates.push({ address: NATIVE_TOKEN, symbol: 'ETH', name: 'Ether', decimals: 18, viaRouter: true });
          if (usdc && !has(usdc)) routerCandidates.push({ address: usdc, symbol: 'USDC', name: 'USD Coin', decimals: 6, viaRouter: true });
        }
        return Promise.all(routerCandidates.map(function (cand) {
          return routerPayRouteWorks(chainId, project.id, cand.address, cand.decimals).then(function (ok) { return ok ? cand : null; });
        })).then(function (routable) {
          if (state.chainId !== chainId) return;
          routable.filter(Boolean).forEach(function (cand) { list.push(cand); });
          _tokenCache[chainId] = list;
          state.contextsReady = true;
          state.contextsError = false;
          state.tokens = list;
          // Preserve the selection ONLY if the USER picked it — otherwise the initial sync-default (native ETH)
          // would shadow the project's real accounting token (would pay 1 ETH instead of 1 USDC). See chooseRefinedPayToken.
          state.token = chooseRefinedPayToken(list, state.token, state.tokenTouched);
          renderTerminalNotice();
          if (selectedTierIds().length) refreshNftCheckoutRoutes();
          else { rebuildCurrency(); schedulePreview(); }
        });
      }).catch(function () { if (state.chainId === chainId) { state.contextsError = true; renderTerminalNotice(); } });
  }

  var state = {
    chainId: chains[0].id,
    tokens: tokensForChain(chains[0].id),
    token: null,
    tokenTouched: false, // true once the user explicitly picks a pay token (then we stop auto-defaulting)
    amount: '',
    memo: '',
    phase: 'idle',
    preview: null,
    directSwap: null, // { pool, out } when a direct AMM swap beats paying (no split-tax)
    slippageBps: 100, // AMM-route max slippage (default 1%)
    shop: null,       // { hook, tiers, ... } once the strip loads
    mode: 'pay',      // 'pay' (mint tokens) | 'addbalance' (top up balance, mint nothing)
    conversion: null, // { sym, units } router-swap landed amount for add-to-balance
    terminalSurface: null,
    terminalSurfaceChain: null,
    contextsReady: false,
    contextsError: false,
    nftRoutes: {},       // token key -> { supported, pricePerUnit, reason }
    nftRoutesLoading: false,
    nftCredits: 0n,      // per-beneficiary 721 hook credits, denominated in the shop pricing context
    nftCreditsLoading: false,
  };
  state.token = state.tokens[0] || null;
  loadAcceptedTokens(state.chainId); // refine direct-vs-router from the project's accounting contexts

  var previewTimer = null;
  var previewGen = 0;

  // The project's directly-accepted token (the swap target a router top-up lands in).
  function acceptedToken() { return state.tokens.filter(function (t) { return !t.viaRouter; })[0]; }
  function acceptedTokenSym() { var t = acceptedToken(); return t ? (t.symbol || '').replace(/\s*\(native\)/i, '') : ''; }
  function tokenCurrency(t) { return t && t.currency != null ? Number(t.currency) : (t && t.address ? Number(BigInt(t.address) & 0xffffffffn) : 0); }
  function isNativePayToken(t) { return !!(t && t.address && t.address.toLowerCase() === NATIVE_TOKEN.toLowerCase()); }
  function isUsdcPayToken(t) {
    var usdc = USDC_BY_CHAIN[state.chainId];
    return !!(t && t.address && usdc && t.address.toLowerCase() === usdc.toLowerCase());
  }
  function nftPricing() { return pricingContextOf(state.shop, state.chainId); }
  function nftTokenKey(t) {
    return t ? [String(t.address || '').toLowerCase(), t.viaRouter ? 'router' : 'direct', tokenCurrency(t), Number(t.decimals == null ? 18 : t.decimals)].join(':') : '';
  }
  function nftSameCurrency(t, p) {
    if (!t || !p) return false;
    // Match the hook exactly: it only skips JBPrices when the accounting-context currency ID equals the shop
    // currency ID. A token which happens to be USDC/ETH by address is not automatically currency 2/1.
    return tokenCurrency(t) === p.currency;
  }
  function nftRouteForToken(t) { return t ? state.nftRoutes[nftTokenKey(t)] : null; }
  function nftCheckoutTokens() {
    if (!selectedTierIds().length) return state.tokens || [];
    if (state.nftRoutesLoading) return [];
    return (state.tokens || []).filter(function (t) { var route = nftRouteForToken(t); return route && route.supported; });
  }
  function nftPayTokenScore(t) {
    if (!state.shop || !t) return 0;
    var p = nftPricing();
    var directBonus = t.viaRouter ? 1 : 2;
    if (p.currency === 2 && isUsdcPayToken(t)) return 10 + directBonus;
    if ((p.currency === 1 || p.currency === Number(BigInt(NATIVE_TOKEN) & 0xffffffffn)) && isNativePayToken(t)) return 10 + directBonus;
    return tokenCurrency(t) === p.currency ? 8 + directBonus : 0;
  }
  function preferredNftPayToken(candidates) {
    var best = null, bestScore = 0;
    (candidates || state.tokens || []).forEach(function (t) { var score = nftPayTokenScore(t); if (score > bestScore) { best = t; bestScore = score; } });
    return best || ((candidates || [])[0]) || null;
  }
  function nftRestrictedWei() {
    var s = 0n, sel = cart.entries();
    Object.keys(sel).forEach(function (id) {
      var t = nftTierById(Number(id));
      if (t && t.flags && t.flags.cantBuyWithCredits) s += tierEffectivePrice(t.price, t.discountPercent) * BigInt(sel[id]);
    });
    return s;
  }
  function nftCheckoutBreakdown() { return nftCreditBreakdown(nftTotalWei(), nftRestrictedWei(), state.nftCredits); }
  function nftFloorForToken(token) {
    var due = nftCheckoutBreakdown().due;
    if (due <= 0n) return 0n;
    if (!state.shop || !token) return null;
    var p = nftPricing();
    var route = nftRouteForToken(token);
    if (!route || !route.supported || !route.pricePerUnit) return null;
    return nftPaymentAmountFromPricing(due, p.decimals, route.pricePerUnit);
  }
  function nftEnteredPricingValue(token, amount) {
    if (!state.shop || !token) return null;
    var route = nftRouteForToken(token);
    if (!route || !route.supported || !route.pricePerUnit) return null;
    return nftPricingValueFromPayment(amount, nftPricing().decimals, route.pricePerUnit);
  }
  function formatSwapUnits(n) {
    if (!isFinite(n) || n <= 0) return '0';
    if (n >= 1) return n.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
    if (n >= 0.0001) return n.toFixed(6).replace(/0+$/, '').replace(/\.$/, '');
    return n.toPrecision(2);
  }
  // Per-(chain, accepted-token) issuance rate: project tokens minted per 1 whole accepted-token unit.
  // Cached because it's constant on the issuance route; used to back the router swap output out of a pay
  // preview (swap output is identical whether the follow-on op is pay or addToBalance).
  var _rateCache = {};
  function loadAcceptedRate(chainId, acc) {
    var key = chainId + ':' + acc.address.toLowerCase();
    if (_rateCache[key]) return Promise.resolve(_rateCache[key]);
    var unit = 10n ** BigInt(acc.decimals == null ? 18 : acc.decimals);
    return computePayPreview({ chainId: chainId, projectId: project.id, token: acc.address, amount: unit, beneficiary: getAccount() || undefined })
      .then(function (r) {
        if (r && !r.unavailable && r.received != null) {
          var per = (r.received || 0n) + (r.reserved || 0n);
          // Both legs (router input + this reference) pass through the same issuance/buyback curve, so the
          // ratio recovers the landed accepted-token amount on either route — keep the route to compare.
          if (per > 0n) { _rateCache[key] = { per: per, unit: unit, decimals: acc.decimals == null ? 18 : acc.decimals, routing: r.routing }; return _rateCache[key]; }
        }
        return null;
      }).catch(function () { return null; });
  }
  function nftTierById(id) { return state.shop ? state.shop.tiers.filter(function (t) { return t.id === id; })[0] : null; }
  function nftTotalWei() {
    var s = 0n, sel = cart.entries();
    // Charge the DISCOUNTED price the store actually applies at mint, not the raw tier price.
    Object.keys(sel).forEach(function (id) { var t = nftTierById(Number(id)); if (t) s += tierEffectivePrice(t.price, t.discountPercent) * BigInt(sel[id]); });
    return s;
  }
  function selectedTierIds() {
    var a = [], sel = cart.entries();
    Object.keys(sel).forEach(function (id) { for (var i = 0; i < sel[id]; i++) a.push(Number(id)); });
    return a;
  }
  function nftSelectionList() {
    var sel = cart.entries();
    return Object.keys(sel).map(function (id) { return { id: Number(id), qty: sel[id], name: cart.name(id) || ('Item ' + id) }; });
  }
  var nftRouteGeneration = 0;
  function refreshNftCheckoutRoutes() {
    var tierIds = selectedTierIds();
    if (!tierIds.length || !state.shop) {
      state.nftRoutes = {};
      state.nftRoutesLoading = false;
      rebuildCurrency();
      return Promise.resolve();
    }
    var chainId = state.chainId;
    var shop = state.shop;
    var pricing = nftPricing();
    var tokens = (state.tokens || []).slice();
    var gen = ++nftRouteGeneration;
    state.nftRoutesLoading = true;
    rebuildCurrency();
    renderFeedback();
    return Promise.all(tokens.map(function (token) {
      var key = nftTokenKey(token);
      // The router's input token is swapped before the 721 hook sees the payment. Its exact destination context
      // is route-dependent, so this checkout only offers directly accepted currencies whose shop conversion can
      // be proven up front. Plain project payments keep every verified router option.
      if (token.viaRouter) return Promise.resolve([key, { supported: false, reason: 'NFT checkout requires a directly accepted payment currency.' }]);
      var decimals = Number(token.decimals == null ? 18 : token.decimals);
      if (nftSameCurrency(token, pricing)) {
        return Promise.resolve([key, { supported: true, pricePerUnit: 10n ** BigInt(decimals) }]);
      }
      return read(chainId, 'JBPrices', pricePerUnitAbi, 'pricePerUnitOf', [BigInt(project.id), BigInt(tokenCurrency(token)), BigInt(pricing.currency), BigInt(decimals)])
        .then(toBigInt)
        .then(function (price) {
          return [key, price > 0n
            ? { supported: true, pricePerUnit: price }
            : { supported: false, reason: 'No price feed converts this token into ' + pricing.symbol + '.' }];
        })
        .catch(function () { return [key, { supported: false, reason: 'No price feed converts this token into ' + pricing.symbol + '.' }]; });
    })).then(function (entries) {
      if (gen !== nftRouteGeneration || state.chainId !== chainId || state.shop !== shop) return;
      var routes = {};
      entries.forEach(function (entry) { routes[entry[0]] = entry[1]; });
      state.nftRoutes = routes;
      state.nftRoutesLoading = false;
      var supported = nftCheckoutTokens();
      if (!supported.some(function (t) { return t === state.token; })) {
        state.token = preferredNftPayToken(supported);
        state.tokenTouched = false;
      }
      rebuildCurrency();
      syncNftAmountForSelection();
      renderFeedback();
      schedulePreview();
    });
  }

  var nftCreditGeneration = 0;
  function refreshNftCredits() {
    var acct = getAccount();
    var shop = state.shop;
    var gen = ++nftCreditGeneration;
    if (!acct || !shop || !shop.hook) {
      state.nftCredits = 0n;
      state.nftCreditsLoading = false;
      if (selectedTierIds().length) syncNftAmountForSelection();
      renderFeedback();
      return Promise.resolve(0n);
    }
    state.nftCreditsLoading = true;
    renderFeedback();
    return clientFor(state.chainId).readContract({ address: shop.hook, abi: TIER721_PAY_CREDITS_ABI, functionName: 'payCreditsOf', args: [acct] })
      .then(toBigInt)
      .catch(function () { return 0n; })
      .then(function (credits) {
        var currentAccount = getAccount();
        if (gen !== nftCreditGeneration || state.shop !== shop || !currentAccount || currentAccount.toLowerCase() !== acct.toLowerCase()) return credits;
        state.nftCredits = credits;
        state.nftCreditsLoading = false;
        if (selectedTierIds().length) {
          syncNftAmountForSelection();
          schedulePreview();
        }
        renderFeedback();
        return credits;
      });
  }
  function syncNftAmountForSelection() {
    var floor = nftFloorForToken(state.token);
    if (floor != null) {
      amtInput.value = formatAmount(floor, state.token && state.token.decimals != null ? state.token.decimals : 18);
      state.amount = amtInput.value.trim();
    } else {
      amtInput.value = '';
      state.amount = '';
    }
  }
  // Selecting NFTs drives the pay flow: use the 721 hook's pricing context, not a hard-coded ETH amount.
  function onNftChange() {
    if (selectedTierIds().length) {
      refreshNftCheckoutRoutes();
      refreshNftCredits();
      return;
    }
    state.nftRoutes = {};
    state.nftRoutesLoading = false;
    rebuildCurrency();
    schedulePreview();
  }

  var card = el('div', 'detail-card paybox');

  // Absolute start of the project's first ruleset. When in the future, the Pay button idles
  // behind a live countdown (paying before start reverts in the terminal).
  var startsAt = Number((project.ruleset && project.ruleset.start) || 0);

  // Open the Shop tab (and scroll it into view). Used by the strip's "All →" link.
  function openShopTab() {
    if (!_activeDetail || !_activeDetail.showTab) return;
    _activeDetail.showTab('Shop');
    routerSetHash(projectHash(project, 'Shop'));
    requestAnimationFrame(function () {
      var sec = document.querySelector('.project-detail-content');
      if (sec) sec.scrollIntoView({ block: 'start', behavior: 'smooth' });
    });
  }

  // Clicking a strip item switches to the Shop tab (without scrolling — the user stays where they are).
  function focusShopTier(id) {
    if (!_activeDetail || !_activeDetail.showTab) return;
    _activeDetail.showTab('Shop');
    routerSetHash(projectHash(project, 'Shop'));
  }

  // Mini-shop first: if the project has 721 tiers, surface a compact selectable strip atop the Pay card.
  // Both the strip and the Shop tab share `cart`; keep the pay amount/feedback in sync with either.
  cart.subscribe(function () { onNftChange(); });
  cart.onName(function () { renderFeedback(); });
  card.appendChild(renderPayShopStrip(project, cart, {
    onShop: function (shop) {
      state.shop = shop;
      refreshNftCredits();
      if (selectedTierIds().length) refreshNftCheckoutRoutes();
    },
    focusInShop: focusShopTier,
    onViewAll: openShopTab,
  }));

  // Row 1: "[Pay ▾] on <chain>" — the leading word is the action toggle (Pay / Add to balance).
  var topRow = el('div', 'paybox-top');
  var payOn = el('div', 'paybox-payon');
  // Action picker as the sentence's first word.
  var modeSel = el('select', 'paybox-select paybox-mode');
  [['pay', 'Pay'], ['addbalance', 'Add to balance']].forEach(function (m) {
    var o = document.createElement('option'); o.value = m[0]; o.textContent = m[1]; modeSel.appendChild(o);
  });
  modeSel.value = state.mode;
  modeSel.addEventListener('change', function () {
    state.mode = modeSel.value;
    sizeSelectToText(modeSel);
    updateModeUi();
    schedulePreview();
  });
  payOn.appendChild(modeSel);
  var payOnLabel = el('span', 'paybox-payon-label');
  payOnLabel.textContent = 'on';
  payOn.appendChild(payOnLabel);
  payOn.appendChild(document.createTextNode(' ')); // real space so it reads as a sentence
  if (chains.length > 1) {
    var chainSel = el('select', 'paybox-select');
    chains.forEach(function (c) {
      var o = document.createElement('option');
      o.value = String(c.id);
      o.textContent = c.name;
      chainSel.appendChild(o);
    });
    chainSel.addEventListener('change', function () {
      state.chainId = Number(chainSel.value);
      state.contextsReady = false; state.contextsError = false;
      state.nftRoutes = {}; state.nftRoutesLoading = false;
      state.nftCredits = 0n;
      state.tokenTouched = false; // a new chain re-defaults to that chain's accounting token
      state.tokens = tokensForChain(state.chainId);
      state.token = state.tokens[0] || null;
      sizeSelectToText(chainSel);
      rebuildCurrency();
      loadPaymentSurface(state.chainId);
      schedulePreview();
      loadAcceptedTokens(state.chainId); // refine for the newly-selected chain
      refreshNftCredits();
    });
    payOn.appendChild(chainSel);
    sizeSelectToText(chainSel);
  } else {
    var chainStatic = el('span', 'paybox-chain-static');
    chainStatic.textContent = chains[0].name;
    payOn.appendChild(chainStatic);
  }
  topRow.appendChild(payOn);
  card.appendChild(topRow);
  sizeSelectToText(modeSel);

  // Currency control lives inline inside the amount field (appended to the amount row below).
  var currWrap = el('div', 'paybox-curr-wrap');

  function rebuildCurrency() {
    currWrap.innerHTML = '';
    var shownTokens = nftCheckoutTokens();
    if (selectedTierIds().length && state.nftRoutesLoading) {
      var checking = el('span', 'paybox-curr-static'); checking.textContent = 'Checking…'; currWrap.appendChild(checking);
      if (payBtn) payBtn.disabled = true;
      return;
    }
    if (selectedTierIds().length && !shownTokens.length) {
      var unavailable = el('span', 'paybox-curr-static'); unavailable.textContent = 'Unavailable'; currWrap.appendChild(unavailable);
      if (payBtn) payBtn.disabled = true;
      return;
    }
    if (payBtn && startsAt <= Math.floor(Date.now() / 1000)) payBtn.disabled = false;
    if (shownTokens.length > 1) {
      var sel = el('select', 'paybox-select');
      // Value by INDEX (not address) — a project can offer the same address both directly and via-router, and
      // we must keep the displayed option in lock-step with state.token (else the user sees USDC but pays ETH).
      shownTokens.forEach(function (t, i) {
        var o = document.createElement('option');
        o.value = String(i);
        o.textContent = currencyLabel(t.symbol);
        o.title = (t.name ? t.name + ' | ' : '') + t.address;
        sel.appendChild(o);
      });
      var curIdx = shownTokens.indexOf(state.token);
      if (curIdx >= 0) sel.value = String(curIdx); // sync the shown option to the actual selected token
      sel.addEventListener('change', function () {
        var t = shownTokens[Number(sel.value)];
        if (t) { state.token = t; state.tokenTouched = true; }
        sizeSelectToText(sel, 13);
        renderTerminalNotice();
        if (selectedTierIds().length) syncNftAmountForSelection();
        schedulePreview();
      });
      currWrap.appendChild(sel);
      sizeSelectToText(sel, 13);
    } else {
      var s = el('span', 'paybox-curr-static');
      if (shownTokens.length === 1 && state.token !== shownTokens[0]) state.token = shownTokens[0];
      s.textContent = state.token ? currencyLabel(state.token.symbol) : 'ETH';
      if (state.token && state.token.address) s.title = (state.token.name ? state.token.name + ' | ' : '') + state.token.address;
      currWrap.appendChild(s);
    }
  }
  rebuildCurrency();

  // Row 2: [ amount  currency ▾ ] [ Pay ] — amount auto-sizes so the currency hugs the number.
  var amountRow = el('div', 'paybox-amount-row');
  var field = el('div', 'paybox-field');
  var amtInput = el('input', 'paybox-amount');
  amtInput.type = 'number';
  amtInput.placeholder = '0.00';
  amtInput.addEventListener('input', function () { state.amount = amtInput.value.trim(); schedulePreview(); });
  field.appendChild(amtInput);
  field.appendChild(currWrap); // currency dropdown, stuck to the right of the field, left of Pay
  amountRow.appendChild(field);
  var payBtn = el('button', 'paybox-btn');
  payBtn.textContent = 'Pay';
  payBtn.addEventListener('click', doPay);
  amountRow.appendChild(payBtn);
  card.appendChild(amountRow);

  // Reflect the selected action across the button label (Pay → Add) and feedback. NFTs only mint on a Pay.
  function updateModeUi() {
    if (startsAt > Math.floor(Date.now() / 1000)) { payBtn.textContent = 'Not started'; renderFeedback(); return; }
    payBtn.textContent = state.mode === 'addbalance' ? 'Add' : 'Pay';
    renderFeedback();
  }

  // Memo — subtle, optional, directly under the amount/Pay row.
  var memo = el('input', 'paybox-memo');
  memo.type = 'text';
  memo.placeholder = 'Add a note (optional)';
  memo.addEventListener('input', function () { state.memo = memo.value; });
  card.appendChild(memo);

  // Feedback block — "You get" / routing tag / AMM subtext / "Splits get".
  var feedback = el('div', 'paybox-feedback');
  card.appendChild(feedback);

  var status = el('div', 'paybox-status');
  card.appendChild(status);

  var terminalNotice = el('div', 'paybox-contract-warning');
  card.appendChild(terminalNotice);

  function renderTerminalNotice() {
    terminalNotice.innerHTML = '';
    terminalNotice.style.display = 'none';
    if (state.contextsError) {
      terminalNotice.style.display = '';
      terminalNotice.className = 'paybox-contract-warning blocked';
      terminalNotice.textContent = 'Could not verify this project’s accepted tokens. Payments are disabled until the accounting contexts can be read.';
      return;
    }
    var surface = state.terminalSurfaceChain === state.chainId ? state.terminalSurface : null;
    if (!surface) return;
    var target = state.token && state.token.viaRouter ? routerTerminalFor(state.chainId) : getAddress('JBMultiTerminal', state.chainId);
    if (target && !paySurfaceAllows(surface, target)) {
      terminalNotice.style.display = '';
      terminalNotice.className = 'paybox-contract-warning blocked';
      terminalNotice.textContent = paySurfaceBlockedMessage(surface, target, state.chainId);
      return;
    }
    if (surface.unknown && surface.unknown.length) {
      terminalNotice.style.display = '';
      terminalNotice.className = 'paybox-contract-warning';
      terminalNotice.textContent = 'This project also lists unknown payment terminal'
        + (surface.unknown.length > 1 ? 's' : '') + ': '
        + surface.unknown.map(truncAddr).join(', ')
        + '. This form only sends to a recognized Juicebox terminal.';
    }
  }

  function loadPaymentSurface(chainId) {
    readProjectPaymentSurface(project, chainId).then(function (surface) {
      if (!card.isConnected || state.chainId !== chainId) return;
      state.terminalSurface = surface;
      state.terminalSurfaceChain = chainId;
      renderTerminalNotice();
    }).catch(function () {
      if (!card.isConnected || state.chainId !== chainId) return;
      state.terminalSurface = null;
      state.terminalSurfaceChain = null;
      renderTerminalNotice();
    });
  }
  loadPaymentSurface(state.chainId);

  // The selected NFTs, listed under "You get" with a small preview thumbnail (juicy-vision "+ Original").
  function nftBlock() {
    var sel = nftSelectionList();
    if (!sel.length) return null;
    var box = el('div', 'paybox-nft-list');
    sel.forEach(function (s) {
      var row = el('div', 'paybox-nft-row');
      var plus = el('span', 'paybox-nft-plus'); plus.textContent = '+'; row.appendChild(plus);
      var thumb = el('span', 'paybox-nft-thumb');
      var url = cart.image(s.id);
      if (url) { var im = document.createElement('img'); im.loading = 'lazy'; im.src = url; im.alt = s.name; thumb.appendChild(im); }
      row.appendChild(thumb);
      var label = el('span', 'paybox-nft-label'); label.textContent = s.name + (s.qty > 1 ? ' ×' + s.qty : ''); row.appendChild(label);
      box.appendChild(row);
    });
    return box;
  }

  function nftCheckoutSummary() {
    if (!selectedTierIds().length || !state.shop) return null;
    var pricing = nftPricing();
    var breakdown = nftCheckoutBreakdown();
    var box = el('div', 'paybox-nft-summary');
    function row(labelText, valueText, cls) {
      var r = el('div', 'paybox-nft-summary-row' + (cls ? ' ' + cls : ''));
      var label = el('span', 'paybox-nft-summary-label'); label.textContent = labelText; r.appendChild(label);
      var value = el('span', 'paybox-nft-summary-value'); value.textContent = valueText; r.appendChild(value);
      box.appendChild(r);
    }
    row('Items', formatShopPrice(state.shop, breakdown.subtotal, state.chainId));
    if (!getAccount()) {
      row('Shop credit', 'Connect wallet to check', 'muted');
    } else if (state.nftCreditsLoading) {
      row('Shop credit', 'Checking…', 'muted');
    } else if (breakdown.applied > 0n) {
      row('Shop credit applied', '−' + formatShopPrice(state.shop, breakdown.applied, state.chainId), 'credit');
    } else {
      row('Shop credit', formatShopPrice(state.shop, state.nftCredits, state.chainId), 'muted');
    }
    if (breakdown.restrictedCost > 0n) {
      row('Fresh payment required', formatShopPrice(state.shop, breakdown.restrictedCost, state.chainId), 'muted');
    }
    row('Amount due', formatShopPrice(state.shop, breakdown.due, state.chainId), 'total');

    if (state.nftRoutesLoading) {
      row('Entered value', 'Checking payment currencies…', 'muted');
      return box;
    }
    var entered = null;
    try {
      if (state.token && state.amount !== '') entered = parseAmount(state.amount, state.token.decimals == null ? 18 : state.token.decimals);
    } catch (_) {}
    if (entered != null && state.token) {
      var shopValue = nftEnteredPricingValue(state.token, entered);
      if (shopValue != null) {
        var enteredPayment = formatBalance(entered, state.token.decimals == null ? 18 : state.token.decimals, currencyLabel(state.token.symbol));
        var shortfall = breakdown.due > shopValue ? breakdown.due - shopValue : 0n;
        row('Entered value', enteredPayment + ' = ' + formatShopPrice(state.shop, shopValue, state.chainId), shortfall > 0n ? 'short' : 'enough');
        if (shortfall > 0n) row('Still needed', formatShopPrice(state.shop, shortfall, state.chainId), 'short');
      }
    }
    return box;
  }

  function renderFeedback() {
    feedback.innerHTML = '';
    var p = state.preview;
    var isAmm = !!(p && p.routing === 'amm');

    // Add-to-balance mints nothing — describe the balance effect rather than a meaningless "You get 0 tokens".
    // For a swap-via-router top-up, show how much of the project's accepted token lands onchain after the swap.
    if (state.mode === 'addbalance') {
      if (state.token && state.token.viaRouter) {
        var conv = el('div', 'paybox-conv');
        if (state.phase === 'previewing') conv.textContent = 'Estimating swap…';
        else if (state.conversion) conv.textContent = '≈ ' + state.conversion.amount + ' ' + state.conversion.sym + ' lands onchain after the swap';
        else if (p && p.unavailable) { conv.className = 'paybox-conv muted'; conv.textContent = 'Swaps into ' + (acceptedTokenSym() || 'the project token') + ' onchain'; }
        else { conv.className = 'paybox-conv muted'; conv.textContent = 'Swaps into ' + (acceptedTokenSym() || 'the project token') + ' onchain'; }
        feedback.appendChild(conv);
      }
      var abal = el('div', 'paybox-splits');
      abal.textContent = 'Adds to the project balance — nothing else.';
      feedback.appendChild(abal);
      return;
    }

    var checkoutSummary = nftCheckoutSummary();
    if (checkoutSummary) feedback.appendChild(checkoutSummary);

    // Direct AMM swap beats paying: the buyback hook would skim the reserved % even on its swap route, so
    // we route the buy through Uniswap directly — the user keeps 100% of the output, splits get nothing.
    var ds = state.directSwap;
    if (ds && state.phase === 'ready' && p && p.received != null) {
      var dLabel = el('div', 'paybox-yg-label'); dLabel.textContent = 'You get at least'; feedback.appendChild(dLabel);
      var dRow = el('div', 'paybox-yg-row');
      var dVal = el('div', 'paybox-yg-val');
      dVal.textContent = formatTokenCount(quotedOutputFloor(ds.out, 10000 - (state.slippageBps || 0))) + ' ' + sym;
      dRow.appendChild(dVal);
      var dTag = el('span', 'paybox-route-tag paybox-route-direct'); dTag.textContent = 'SWAP';
      dTag.title = 'Bought straight from the Uniswap pool, bypassing pay — so the reserved % / splits take nothing';
      dRow.appendChild(dTag);
      feedback.appendChild(dRow);
      var dNote = el('div', 'paybox-splits');
      var extra = ds.out > p.received ? ' (+' + formatTokenCount(ds.out - p.received) + ' vs paying)' : '';
      dNote.textContent = 'Swapped from the market — splits take 0 ' + sym + extra + '.';
      feedback.appendChild(dNote);
      return;
    }

    // A verified payment can intentionally mint no project tokens (for example, a balance-funding project with
    // weight 0). Keep selected NFT receipts, but omit "0 tokens" and "Splits get 0 tokens" entirely.
    if (!payTokenOutputVisible(project.ruleset && project.ruleset.weight, state.phase, p)) {
      var zeroNfts = nftBlock();
      if (zeroNfts) feedback.appendChild(zeroNfts);
      return;
    }

    var label = el('div', 'paybox-yg-label');
    label.textContent = isAmm ? 'You get at least' : 'You get';
    feedback.appendChild(label);

    var valRow = el('div', 'paybox-yg-row');
    var val = el('div', 'paybox-yg-val');
    if (p && p.unavailable) {
      val.className = 'paybox-yg-val muted';
      val.textContent = 'preview unavailable';
      valRow.appendChild(val);
      feedback.appendChild(valRow);
      var nbU = nftBlock(); if (nbU) feedback.appendChild(nbU);
      return;
    }
    if (state.phase === 'previewing') val.textContent = '…';
    else if (p && p.received != null) val.textContent = formatTokenCount(payMinTokens(p, state.slippageBps)) + ' ' + sym;
    else val.textContent = '0.00 ' + sym;
    valRow.appendChild(val);
    if (p && p.routing) valRow.appendChild(renderRoutingTag(p.routing));
    feedback.appendChild(valRow);

    var nb = nftBlock(); if (nb) feedback.appendChild(nb);

    var splits = el('div', 'paybox-splits');
    splits.textContent = 'Splits get ' + (p && p.reserved != null ? formatTokenCount(p.reserved) : '0') + ' ' + sym;
    feedback.appendChild(splits);

    // AMM route: where it filled + how the AMM quote compares to plain issuance (why this route won).
    if (isAmm && p.amm) {
      var fill = el('div', 'paybox-amm-fill');
      fill.appendChild(document.createTextNode('Filled via Uniswap pool '));
      // A Uniswap V4 poolId is a hash, not a contract — link to the chain's V4 PoolManager (where the pool
      // lives) on the block explorer.
      var pmAddr = POOL_MANAGER_BY_CHAIN[state.chainId];
      var explorer = CHAINS[state.chainId] && CHAINS[state.chainId].blockExplorers && CHAINS[state.chainId].blockExplorers.default && CHAINS[state.chainId].blockExplorers.default.url;
      if (pmAddr && explorer) {
        var a = document.createElement('a');
        a.href = explorer.replace(/\/$/, '') + '/address/' + pmAddr;
        a.target = '_blank'; a.rel = 'noopener';
        a.textContent = shortHex(p.amm.poolId);
        a.title = 'Uniswap V4 PoolManager ' + pmAddr + ' — V4 pools live in the singleton (the poolId is a hash, not an address)';
        fill.appendChild(a);
      } else {
        fill.appendChild(document.createTextNode(shortHex(p.amm.poolId)));
      }
      feedback.appendChild(fill);
      if (p.amm.wouldMintByIssuance != null) {
        // Both sides as the BENEFICIARY's "You get" (excludes splits). The AMM side already is
        // (p.received = minimumBeneficiaryTokenCount); `wouldMintByIssuance` is GROSS issuance (incl.
        // reserved), so scale it by the same beneficiary fraction the swap split exposes.
        var benef = p.received || 0n, reserved = p.reserved || 0n, swapTotal = benef + reserved;
        var issuanceBenef = swapTotal > 0n ? (p.amm.wouldMintByIssuance * benef / swapTotal) : p.amm.wouldMintByIssuance;
        var cmp = el('div', 'paybox-amm-cmp');
        cmp.textContent = 'AMM: ' + formatTokenCount(payMinTokens(p, state.slippageBps)) + ' ' + sym
          + ' vs. Issuance: ' + formatTokenCount(issuanceBenef) + ' ' + sym;
        feedback.appendChild(cmp);
      }
    }
  }

  function schedulePreview() {
    if (previewTimer) clearTimeout(previewTimer);
    state.preview = null;
    state.directSwap = null;
    state.phase = 'idle';
    renderFeedback();
    previewTimer = setTimeout(loadPreview, 400);
  }

  // Decide whether a direct AMM swap beats paying (which skims the reserved % even on the swap route).
  // Only for plain native-token buys (no NFTs, not add-to-balance) where a buyback pool exists. When
  // previewPay already routed AMM, the full output = received + reserved (pay would split it); otherwise
  // the V4 Quoter gives the true hook-routed output (null at 0 liquidity → stays on pay, no change).
  function maybeOfferDirectSwap(gen, amt, p) {
    if (state.mode === 'addbalance' || selectedTierIds().length) return;
    // Input must be a directly-accepted token (a swap-via-router currency isn't the pool's pair).
    if (!state.token || state.token.viaRouter) return;
    if (!p || p.unavailable || p.received == null) return;
    var payOut = p.received;
    var isNativeIn = state.token.address.toLowerCase() === NATIVE_TOKEN.toLowerCase();
    var inputCur = isNativeIn ? ZERO_ADDRESS : state.token.address.toLowerCase();
    directSwapPoolFor(project, state.chainId).then(function (pool) {
      // Only when the paid token IS the pool's pair token (native for ETH pools, USDC for USDC pools).
      if (gen !== previewGen || !pool || pool.pairAddr !== inputCur) return;
      function decide(directOut) {
        if (gen !== previewGen) return;
        if (directOut != null && directOut > payOut) { state.directSwap = { pool: pool, out: directOut }; renderFeedback(); }
      }
      var ammFull = (p.routing === 'amm' && p.reserved != null) ? (p.received + p.reserved) : null;
      if (ammFull != null && ammFull > payOut) { decide(ammFull); return; }
      quoteDirectSwap(state.chainId, pool, amt).then(decide);
    }).catch(function () {});
  }

  function loadPreview() {
    if (!state.amount || !state.token) return;
    var amt;
    try { amt = parseAmount(state.amount, state.token.decimals == null ? 18 : state.token.decimals); } catch (_) { return; }
    var previewTierIds = state.mode === 'pay' ? selectedTierIds() : [];
    if (previewTierIds.length && (!nftRouteForToken(state.token) || !nftRouteForToken(state.token).supported)) {
      state.preview = { received: null, reserved: null, unavailable: true, reason: 'This payment currency cannot be converted into the shop pricing currency.' };
      state.phase = 'ready';
      renderFeedback();
      return;
    }
    if (amt === 0n && !previewTierIds.length) { state.preview = null; renderFeedback(); return; }
    var previewMetadata = previewTierIds.length && state.shop
      ? buildTierMintMetadata(state.shop.idTarget || state.shop.hook, previewTierIds)
      : '0x';

    state.phase = 'previewing';
    renderFeedback();

    var gen = ++previewGen;
    computePayPreview({
      chainId: state.chainId,
      projectId: project.id,
      token: state.token.address,
      amount: amt,
      beneficiary: getAccount() || undefined,
      terminal: state.token.viaRouter ? routerTerminalFor(state.chainId) : undefined,
      metadata: previewMetadata,
      allowZero: previewTierIds.length > 0,
    }).then(function (p) {
      if (gen !== previewGen) return;
      state.phase = 'ready';
      state.preview = p;
      state.conversion = null;
      state.directSwap = null;
      renderFeedback();
      maybeOfferDirectSwap(gen, amt, p);
      // Add-to-balance via router: derive the accepted-token amount that lands after the swap. The
      // simulated pay's total mint ÷ the per-unit issuance rate = the swap output (route must be issuance).
      var acc = acceptedToken();
      if (state.mode === 'addbalance' && state.token.viaRouter && acc && p && !p.unavailable && p.received != null) {
        var accSym = (acc.symbol || '').replace(/\s*\(native\)/i, '');
        var accUnit = Number(10n ** BigInt(acc.decimals == null ? 18 : acc.decimals));
        if (p.routing === 'amm' && p.amm && p.amm.quotedAmountToSwapWith != null) {
          // AMM route: the buyback's swap input IS the accepted-token amount that landed from the router swap.
          state.conversion = { sym: accSym, amount: formatSwapUnits(Number(p.amm.quotedAmountToSwapWith) / accUnit) };
          renderFeedback();
        } else if (p.routing === 'issuance') {
          // Issuance route: recover the landed amount from the per-unit mint rate (same route both sides).
          var total = (p.received || 0n) + (p.reserved || 0n);
          loadAcceptedRate(state.chainId, acc).then(function (rate) {
            if (gen !== previewGen || !rate || rate.per === 0n || rate.routing !== 'issuance') return;
            state.conversion = { sym: accSym, amount: formatSwapUnits(Number(total) / Number(rate.per)) };
            renderFeedback();
          });
        }
      }
    }).catch(function () {
      if (gen !== previewGen) return;
      state.phase = 'ready';
      state.preview = null;
      state.conversion = null;
      renderFeedback();
    });
  }

  function doPay() {
    status.className = 'paybox-status';
    status.textContent = '';
    // Idle until the project's first ruleset starts — paying earlier reverts in the terminal.
    if (startsAt > Math.floor(Date.now() / 1000)) { return; }
    if (!state.contextsReady) { status.textContent = state.contextsError ? 'Could not verify the project’s accepted tokens.' : 'Accepted tokens are still loading…'; return; }
    if (state.amount === '' || !state.token) { status.textContent = selectedTierIds().length ? 'No supported payment currency is available for these items.' : 'Enter an amount'; return; }
    var amt;
    try { amt = parseAmount(state.amount, state.token.decimals == null ? 18 : state.token.decimals); } catch (_) { status.textContent = 'Invalid amount'; return; }

    var addBalance = state.mode === 'addbalance';

    // Selected 721 tiers mint via the pay metadata; the amount must cover their pricing-context total.
    // Add-to-balance mints nothing, so NFTs are ignored entirely on that path.
    var tierIds = addBalance ? [] : selectedTierIds();
    var metadata = '0x';
    if (tierIds.length && state.shop) {
      if (state.nftRoutesLoading) { status.textContent = 'Payment currencies are still being checked…'; return; }
      if (state.nftCreditsLoading) { status.textContent = 'Your shop credit is still loading…'; return; }
      var nftRoute = nftRouteForToken(state.token);
      if (!nftRoute || !nftRoute.supported) {
        status.textContent = 'This payment token cannot be converted into the shop’s pricing currency. Choose a supported currency.';
        return;
      }
      var nftFloor = nftFloorForToken(state.token);
      if (nftFloor == null) {
        status.textContent = 'Could not verify this payment token’s value in the shop’s pricing currency.';
        return;
      }
      if (amt < nftFloor) {
        amt = nftFloor;
        state.amount = formatAmount(amt, state.token.decimals == null ? 18 : state.token.decimals);
        amtInput.value = state.amount;
        schedulePreview();
        status.textContent = 'Amount adjusted to cover the selected NFTs. Review the refreshed quote, then click Pay again.';
        return;
      }
      metadata = buildTierMintMetadata(state.shop.idTarget || state.shop.hook, tierIds);
    }
    if (amt === 0n && !tierIds.length) { status.textContent = 'Enter an amount'; return; }

    var beneficiary = getAccount();
    if (!beneficiary) {
      connect().then(function () {
        schedulePreview();
        status.textContent = 'Wallet connected. Review the quote for this beneficiary, then click Pay again.';
      }).catch(function () {});
      return;
    }

    var willDirectSwap = !!(state.directSwap && !addBalance && !tierIds.length);
    // USDC and other swap currencies route through the router (JBRouterTerminalRegistry); direct tokens go to the terminal.
    var terminal = state.token.viaRouter ? routerTerminalFor(state.chainId) : getAddress('JBMultiTerminal', state.chainId);
    if (!willDirectSwap && !terminal) { status.textContent = 'No router terminal on this chain'; return; }

    var isNative = state.token.address.toLowerCase() === NATIVE_TOKEN.toLowerCase();
    var viaRouter = !!state.token.viaRouter; // swap currency → authorize via a gasless Permit2 signature, not a router approve
    if (addBalance && viaRouter) {
      status.textContent = 'Add to balance only supports tokens the project accepts directly; router swaps have no onchain minimum-output field for this action.';
      return;
    }
    if (!addBalance && !payPreviewCanSubmit(state.phase, state.preview)) {
      status.textContent = tierIds.length
        ? 'A verified live quote is required before buying these items. Wait for the preview and try again.'
        : 'A verified live quote is required before paying. Wait for the preview and try again.';
      schedulePreview();
      return;
    }
    // Freeze the exact form state before any balance/terminal reads. A slow response from the old chain or token
    // must not combine an amount parsed in one token's decimals with another token/route.
    var reviewedChainId = state.chainId;
    var reviewedToken = state.token;
    var reviewedMode = state.mode;
    var reviewedMemo = state.memo || '';
    var reviewedPreview = state.preview;
    var reviewedDirectSwap = state.directSwap;
    var reviewedSlippage = state.slippageBps || 0;
    var reviewedTierKey = tierIds.join(',');
    var reviewedConversion = state.conversion;
    var reviewedNfts = tierIds.length ? nftSelectionList() : [];
    var reviewedNftCheckout = tierIds.length ? nftCheckoutBreakdown() : null;
    var reviewedNftCredits = state.nftCredits;
    function payInputsUnchanged() {
      var current;
      try { current = parseAmount(state.amount, reviewedToken.decimals == null ? 18 : reviewedToken.decimals); } catch (_) { current = -1n; }
      return state.chainId === reviewedChainId && state.mode === reviewedMode && (state.memo || '') === reviewedMemo
        && state.token && state.token.address.toLowerCase() === reviewedToken.address.toLowerCase()
        && !!state.token.viaRouter === !!reviewedToken.viaRouter && current === amt
        && selectedTierIds().join(',') === reviewedTierKey && (state.slippageBps || 0) === reviewedSlippage
        && (!tierIds.length || state.nftCredits === reviewedNftCredits)
        && (addBalance || (state.preview === reviewedPreview && state.directSwap === reviewedDirectSwap))
        && state.contextsReady && getAccount() && getAccount().toLowerCase() === beneficiary.toLowerCase();
    }
    function requirePayInputs() {
      if (payInputsUnchanged()) return true;
      status.className = 'paybox-status error';
      status.textContent = 'Payment inputs, chain, quote, or connected account changed while the preflight was loading. Review and click again.';
      return false;
    }

    function checkBalanceThenProceed() {
      // Pre-flight: block amounts the wallet can't cover before sending the user to confirm / their wallet.
      var preSym = (reviewedToken.symbol || '').replace(/\s*\(native\)/i, '');
      var preChain = (chains.find(function (c) { return c.id === reviewedChainId; }) || {}).name || ('Chain ' + reviewedChainId);
      status.className = 'paybox-status pending'; status.textContent = 'Checking your balance…';
      readWalletTokenBalance(reviewedChainId, reviewedToken.address, beneficiary).then(function (walletBal) {
        if (!requirePayInputs()) return;
        if (walletBal == null) throw new Error('Could not verify your wallet balance on this chain.');
        if (walletBal != null && amt > walletBal) {
          status.className = 'paybox-status error';
          status.textContent = 'Not enough ' + preSym + ' — you have ' + formatBalance(walletBal, reviewedToken.decimals == null ? 18 : reviewedToken.decimals, preSym) + ' on ' + preChain + '.';
          return;
        }
        status.className = 'paybox-status'; status.textContent = '';
        proceed();
      }).catch(function (error) { status.className = 'paybox-status error'; status.textContent = errMessage(error, 'Could not verify your wallet balance. Try again.'); });
    }

    if (willDirectSwap) {
      checkBalanceThenProceed();
      return;
    }

    status.className = 'paybox-status pending'; status.textContent = 'Checking project terminal…';
    readProjectPaymentSurface(project, reviewedChainId).then(function (surface) {
      if (!requirePayInputs()) return;
      state.terminalSurface = surface;
      state.terminalSurfaceChain = reviewedChainId;
      renderTerminalNotice();
      if (!paySurfaceAllows(surface, terminal)) {
        status.className = 'paybox-status error';
        status.textContent = paySurfaceBlockedMessage(surface, terminal, reviewedChainId);
        return;
      }
      checkBalanceThenProceed();
    }).catch(function () {
      status.className = 'paybox-status error';
      status.textContent = 'Could not verify this project’s payment terminal. Review the project contracts before paying.';
      loadPaymentSurface(reviewedChainId);
    });
    return;

    function proceed() {
    if (!requirePayInputs()) return;
    // Direct AMM swap: bypass `pay` (which skims the reserved % even on its swap route) and swap the pool
    // directly via Uniswap's Universal Router, so the user keeps 100% of the output. Only for plain native
    // buys with no NFTs; the buyback hook still routes the swap at the best of AMM vs issuance. The swap's
    // amountOutMinimum makes an adverse move revert (not lose funds).
    if (reviewedDirectSwap && !addBalance && !tierIds.length) {
      var ds = reviewedDirectSwap;
      var dsMinOut = quotedOutputFloor(ds.out, 10000 - reviewedSlippage);
      var dChain = (chains.find(function (c) { return c.id === reviewedChainId; }) || {}).name || ('Chain ' + reviewedChainId);
      var dSymClean = (reviewedToken.symbol || (isNative ? 'ETH' : 'token')).replace(/\s*\(native\)/i, '');
      var dHuman = formatAmount(amt, reviewedToken.decimals == null ? 18 : reviewedToken.decimals) + ' ' + dSymClean;
      // Native swaps are fully determined before review, so reuse this exact call after confirmation and expose
      // its calldata to txlink. ERC-20 swaps still need a wallet-bound Permit2 signature and cannot be shared yet.
      var directReviewTx = isNative ? buildDirectSwapNativeTx(reviewedChainId, ds.pool, amt, dsMinOut, beneficiary) : null;
      openPayConfirm({
        chain: dChain,
        chainId: reviewedChainId,
        contract: 'Uniswap Universal Router',
        address: UNIVERSAL_ROUTER_BY_CHAIN[reviewedChainId],
        'function': 'execute',
        abi: abiSignature(urExecuteAbi, 'execute'),
        calldata: directReviewTx ? encodeFunctionData({ abi: directReviewTx.abi, functionName: directReviewTx.functionName, args: directReviewTx.args }) : undefined,
        txlinkUnavailableReason: directReviewTx ? null : 'This swap needs a Permit2 signature bound to the connected wallet before its exact calldata exists.',
        value: isNative ? (amt.toString() + ' wei (' + dHuman + ')') : '0',
        erc20Approval: isNative ? null : { token: reviewedToken.address, authorize: 'Permit2 signature (gasless); one-time approval to Permit2 only if needed', spender: UNIVERSAL_ROUTER_BY_CHAIN[reviewedChainId] },
        args: {
          action: 'Direct AMM swap — bypasses pay so splits/reserved take nothing',
          buy: sym,
          amountIn: amt.toString() + ' (' + dHuman + ')',
          minReturnedTokens: dsMinOut.toString() + ' (' + formatTokenCount(dsMinOut) + ' ' + sym + ', ' + (reviewedSlippage / 100) + '% max slippage)',
          beneficiary: beneficiary,
          note: 'Swaps the buyback pool directly via the Universal Router; the hook fills at the best of AMM vs issuance.',
        },
      }, function send() {
        if (!getAccount() || getAccount().toLowerCase() !== beneficiary.toLowerCase()) { status.className = 'paybox-status error'; status.textContent = 'Connected account changed. Review the payment again.'; return; }
        if (isNative) { sendPay(directReviewTx, { addBalance: false }); return; }
        // ERC-20 (USDC) input → Permit2 approval/signature, then PERMIT2_PERMIT + V4_SWAP in one tx.
        var statusCb = function (m, kind) { status.className = 'paybox-status' + (kind === 'pending' ? ' pending' : ''); status.textContent = m; };
        buildDirectSwapErc20Tx(reviewedChainId, ds.pool, reviewedToken.address, amt, dsMinOut, beneficiary, statusCb)
          .then(function (tx) { sendPay(tx, { addBalance: false }); })
          .catch(function (e) { status.className = 'paybox-status error'; status.textContent = errMessage(e, 'Could not authorize the swap.'); });
      });
      return;
    }

    // A normal pay never proceeds without a live non-zero quote (guarded above). Issuance is exact; AMM
    // routes use the user's slippage setting. Add-to-balance has no returned-token floor by design.
    var minTokens = addBalance ? 0n : payMinTokens(reviewedPreview, reviewedSlippage);

    // pay(projectId, token, amount, beneficiary, minReturnedTokens, memo, metadata) — metadata at index 6.
    // addToBalanceOf(projectId, token, amount, shouldReturnHeldFees, memo, metadata) — metadata at index 5.
    var fnName = addBalance ? 'addToBalanceOf' : 'pay';
    var fnAbi = addBalance ? addToBalanceAbi : payAbi;
    var args = addBalance
      ? [BigInt(project.id), reviewedToken.address, amt, false, reviewedMemo, metadata]
      : [BigInt(project.id), reviewedToken.address, amt, beneficiary, minTokens, reviewedMemo, metadata];
    var metaIdx = addBalance ? 5 : 6;
    var txParams = {
      chainId: reviewedChainId,
      address: terminal,
      abi: fnAbi,
      functionName: fnName,
      args: args,
      value: isNative ? amt : 0n,
      // Direct ERC20 pays approve the terminal inline; swap-via-router pays authorize through Permit2 (below).
      tokenAddr: (isNative || viaRouter) ? null : reviewedToken.address,
      spenderAddr: (isNative || viaRouter) ? null : terminal,
      approvalAmount: (isNative || viaRouter) ? null : amt,
    };

    // Confirm the exact data before signing.
    var chainName = (chains.find(function (c) { return c.id === reviewedChainId; }) || {}).name || ('Chain ' + reviewedChainId);
    var symClean = (reviewedToken.symbol || '').replace(/\s*\(native\)/i, '');
    var human = formatAmount(amt, reviewedToken.decimals == null ? 18 : reviewedToken.decimals) + ' ' + symClean;
    // Human-readable summary of the NFTs this pay will mint (the raw `metadata` hex below is unreadable),
    // surfaced near the top of the args so the NFT purchase is clearly visible in the confirm preview.
    // selectedTierIds() repeats each id by qty, so tierIds.length is the total NFT count.
    var confirmArgs = { projectId: project.id, token: reviewedToken.address };
    if (tierIds.length) {
      confirmArgs.mints = reviewedNfts.map(function (s) { return s.name + ' ×' + s.qty; }).join(', ')
        + ' — ' + tierIds.length + ' NFT' + (tierIds.length > 1 ? 's' : '') + ' minted by the 721 hook';
      confirmArgs.itemTotal = formatShopPrice(state.shop, reviewedNftCheckout.subtotal, reviewedChainId);
      if (reviewedNftCheckout.applied > 0n) confirmArgs.shopCreditApplied = formatShopPrice(state.shop, reviewedNftCheckout.applied, reviewedChainId);
      confirmArgs.amountDue = formatShopPrice(state.shop, reviewedNftCheckout.due, reviewedChainId);
    }
    confirmArgs.amount = amt.toString() + ' (' + human + ')';
    if (addBalance) {
      confirmArgs.shouldReturnHeldFees = false;
      if (viaRouter && reviewedConversion) confirmArgs.landsOnChain = '≈ ' + reviewedConversion.amount + ' ' + reviewedConversion.sym + ' after swap';
    } else {
      confirmArgs.beneficiary = beneficiary;
      confirmArgs.minReturnedTokens = minTokens.toString() + (minTokens > 0n
        ? ' (' + formatTokenCount(minTokens) + ' ' + sym
          + (reviewedPreview && reviewedPreview.routing === 'amm' ? ', ' + (reviewedSlippage / 100) + '% max slippage' : '')
          + ')'
        : '');
    }
    confirmArgs.memo = reviewedMemo;
    confirmArgs.metadata = (viaRouter && !isNative) ? 'Permit2 single-allowance signature (added when you sign)' : metadata;
    openPayConfirm({
      chain: chainName,
      chainId: reviewedChainId,
      contract: viaRouter ? 'JBRouterTerminalRegistry' : 'JBMultiTerminal',
      address: terminal,
      'function': fnName,
      abi: abiSignature(fnAbi, fnName),
      calldata: (viaRouter && !isNative) ? undefined : encodeFunctionData({ abi: fnAbi, functionName: fnName, args: args }),
      txlinkUnavailableReason: (viaRouter && !isNative) ? 'This routed payment needs a Permit2 signature bound to the connected wallet before its exact calldata exists.' : null,
      value: isNative ? (amt.toString() + ' wei (' + human + ')') : '0',
      erc20Approval: isNative ? null
        : (viaRouter
          ? { token: reviewedToken.address, authorize: 'Permit2 signature (gasless); one-time approval to Permit2 only if needed', spender: terminal }
          : { token: reviewedToken.address, spender: terminal, amount: amt.toString() }),
      args: confirmArgs,
    }, function send() {
      if (!getAccount() || getAccount().toLowerCase() !== beneficiary.toLowerCase()) { status.className = 'paybox-status error'; status.textContent = 'Connected account changed. Review the payment again.'; return; }
      // Native ETH (even via the router) is paid with msg.value — no Permit2. Only ERC20 swap currencies
      // authorize through Permit2; reading allowance on the native pseudo-address returns "0x".
      if (!viaRouter || isNative) { sendPay(txParams, { addBalance: addBalance, clearCartOnSuccess: tierIds.length > 0 }); return; }
      // Swap-via-router: authorize with a Permit2 signature (replaces the scary router-approve tx), then send.
      var statusCb = function (m, kind) { status.className = 'paybox-status' + (kind === 'pending' ? ' pending' : ''); status.textContent = m; };
      buildRouterPermit2Metadata(reviewedChainId, reviewedToken.address, beneficiary, terminal, amt, statusCb)
        .then(function (meta) {
          var p = Object.assign({}, txParams);
          p.args = args.slice();
          p.args[metaIdx] = meta;
          sendPay(p, { addBalance: addBalance, clearCartOnSuccess: tierIds.length > 0 });
        })
        .catch(function (e) { status.className = 'paybox-status error'; status.textContent = errMessage(e, 'Could not authorize the payment.'); });
    });
    } // proceed()
  }

  // Render a pay status line with an Etherscan tx link once a hash exists; plain text otherwise.
  function setPayStatus(cls, message, meta) {
    status.className = cls;
    if (meta && meta.hash) {
      status.innerHTML = '';
      status.appendChild(document.createTextNode(message + ' | TX: '));
      status.appendChild(renderExplorerTxLink(meta.chainId, meta.hash, truncAddr(meta.hash)));
    } else {
      status.textContent = message;
    }
  }

  function clearPurchasedNfts() {
    amtInput.value = '';
    state.amount = '';
    state.preview = null;
    state.directSwap = null;
    state.phase = 'idle';
    if (cart && cart.clear) cart.clear();
    renderFeedback();
  }

  function sendPay(txParams, opts) {
    opts = opts || {};
    var add = !!opts.addBalance;
    var processing = add ? 'Adding to balance' : 'Payment processing';
    var confirmed = add ? 'Added to balance' : 'Payment confirmed';
    executeTransaction(Object.assign({}, txParams, {
      skipConfirm: true, // already confirmed via openPayConfirm
      onStatus: function (m, kind, meta) {
        var cls = 'paybox-status' + (kind === 'pending' ? ' pending' : '');
        if (meta && meta.phase === 'submitted') setPayStatus(cls, processing, meta);
        else { status.className = cls; status.textContent = m; }
      },
      onSuccess: function (m, meta) {
        setPayStatus('paybox-status success', confirmed, meta);
        if (opts.clearCartOnSuccess) clearPurchasedNfts();
        if (opts.clearCartOnSuccess) refreshNftCredits();
        status.dispatchEvent(new CustomEvent('jb:project-updated', { bubbles: true }));
      },
      onError: function (m) { status.className = 'paybox-status error'; status.textContent = m; },
    }));
  }

  // Countdown banner above the pay box for projects whose first ruleset hasn't started.
  // The Pay button idles ("Not started") and doPay early-returns until the start passes.
  if (startsAt > Math.floor(Date.now() / 1000)) {
    var countdown = el('div', 'paybox-countdown paybox-countdown-start');
    var cdLabel = el('span', 'paybox-countdown-label');
    cdLabel.textContent = 'Starts in';
    var cdTime = el('span', 'paybox-countdown-time');
    countdown.appendChild(cdLabel);
    countdown.appendChild(cdTime);
    card.insertBefore(countdown, card.firstChild);
    payBtn.disabled = true;
    payBtn.classList.add('paybox-btn-idle');
    payBtn.textContent = 'Not started';

    var cdTimer = setInterval(function () {
      if (!card.isConnected) { clearInterval(cdTimer); return; }
      var rem = startsAt - Math.floor(Date.now() / 1000);
      if (rem <= 0) {
        clearInterval(cdTimer);
        if (countdown.parentNode) countdown.parentNode.removeChild(countdown);
        payBtn.disabled = false;
        payBtn.classList.remove('paybox-btn-idle');
        updateModeUi();
        return;
      }
      cdTime.textContent = fmtCountdown(rem);
    }, 1000);
    cdTime.textContent = fmtCountdown(startsAt - Math.floor(Date.now() / 1000));
  }

  onWalletChange(function () {
    if (!card.isConnected) return;
    refreshNftCredits();
    if (selectedTierIds().length) refreshNftCheckoutRoutes();
    else schedulePreview();
  });
  renderFeedback();
  card.appendChild(promptFoot('Pay', 'pay'));
  return card;
}

// Minimum project tokens to require back from a pay (the `minReturnedTokens` arg). Issuance is exact
// (the quote is deterministic); the AMM route discounts the quote by the chosen slippage. The terminal
// enforces this against the beneficiary's realized balance delta (mint OR swap output), so it's a valid
// floor for both routes.
function payMinTokens(p, slippageBps) {
  if (!p || p.received == null) return 0n;
  return quotedOutputFloor(p.received, p.routing === 'amm' ? 10000 - (slippageBps || 0) : 10000);
}

// Compact rich header: symbol + name + chains, a balance/supply stat line, and an owner/operator/site line.
function renderDetailHeader(project) {
  var header = el('div', 'project-detail-header');

  // Top: logo + project title, vertically centered to each other.
  var topRow = el('div', 'detail-head-top');
  topRow.appendChild(renderLogo(project, 'detail-logo'));
  var titleCol = el('div', 'detail-head-titlecol');

  var nameRow = el('div', 'detail-name-row');
  if (project.tokenSymbol) {
    var symEl = el('span', 'detail-sym');
    symEl.textContent = project.tokenSymbol;
    nameRow.appendChild(symEl);
  }
  var name = el('span', 'detail-name');
  name.textContent = project.name;
  nameRow.appendChild(name);
  titleCol.appendChild(nameRow);

  // Tagline between the title and the stat line (when set).
  if (project.tagline) {
    var tagEl = el('div', 'detail-tagline'); tagEl.textContent = project.tagline; titleCol.appendChild(tagEl);
  }

  // Stat line: balance | supply (under the title). Balance is the cross-chain USD total; hover breaks
  // it down into the actual tokens stored on each chain.
  var statLine = el('div', 'detail-head-stats');
  statLine.appendChild(mountUsdBalance(project, { suffix: ' balance' }));
  if (project.isRevnet) {
    // Revnet header: just Balance | Owners (unique holders, matching the Owners tab).
    var sepSpan = el('span', 'detail-head-sep'); sepSpan.textContent = '|'; statLine.appendChild(sepSpan);
    var oStrong = el('strong'); oStrong.textContent = '…'; statLine.appendChild(oStrong);
    var oLabel = document.createTextNode(' owners'); statLine.appendChild(oLabel);
    fetchOwnersCount(project).then(function (n) {
      n = (n == null) ? 0 : n;
      oStrong.textContent = String(n);
      oLabel.textContent = n === 1 ? ' owner' : ' owners';
    }).catch(function () { oStrong.textContent = '0'; });
  } else {
    // Indexed activity (Bendystraw): volume raised + payment/contributor counts.
    appendIndexedStats(statLine, project.indexedStats);
  }
  titleCol.appendChild(statLine);
  topRow.appendChild(titleCol);
  header.appendChild(topRow);

  // Meta line: type | chains | owner/operator | site.
  var lbl = function (text) { var s = el('span', 'detail-head-lbl'); s.textContent = text; return s; };
  var mkPair = function (labelText, nodes) {
    var p = el('span', 'detail-head-pair');
    p.appendChild(lbl(labelText));
    nodes.forEach(function (n) { p.appendChild(n); });
    return p;
  };
  // "Flavor | On | Operator | Site" on one row (the "|" is a ::after bar BETWEEN pairs); each pair is inline +
  // nowrap as a UNIT, so the row stays on one line on desktop and only wraps whole key:val pairs to the next
  // line when the viewport is too narrow (mobile) — a label never separates from its value.
  var ownerWarn = el('span', 'detail-head-ownerwarn');
  var row1 = el('div', 'detail-head-meta');
  var typeVal = el('span', 'detail-head-val'); typeVal.textContent = project.isRevnet ? 'REVNET' : 'CUSTOM';
  row1.appendChild(mkPair('Flavor: ', [typeVal]));
  if (project.chains && project.chains.length) {
    row1.appendChild(document.createTextNode(' '));
    var logos = el('span', 'detail-chain-logos');
    for (var c = 0; c < project.chains.length; c++) logos.appendChild(projectChainLogo(project, project.chains[c]));
    row1.appendChild(mkPair('On: ', [logos]));
  }
  row1.appendChild(document.createTextNode(' '));
  row1.appendChild(mkPair(projectAuthorityLabel(project) + ': ', [addressLinkNode(projectAuthorityAddress(project), project.chainId || (project.chains && project.chains[0] && project.chains[0].id)), ownerWarn]));
  if (project.infoUri) {
    var href = project.infoUri.indexOf('http') === 0 ? project.infoUri : ('https://' + project.infoUri);
    var a = document.createElement('a'); a.href = href; a.target = '_blank'; a.rel = 'noopener';
    a.className = 'detail-head-url';
    a.textContent = project.infoUri.replace(/^https?:\/\//, '');
    row1.appendChild(document.createTextNode(' '));
    row1.appendChild(mkPair('Site: ', [a]));
  }
  header.appendChild(row1);
  // Flag when the controlling account is not the same on every chain (owner for custom projects, operator for revnets).
  if ((project.chains || []).length > 1) {
    fetchAuthorityPerChain(project).then(function (res) { if (res.diverged && ownerWarn.isConnected) ownerWarn.textContent = ' differs by chain'; }).catch(function () {});
  }
  return header;
}

// About tab: the editable project profile (logo, tagline, description, links — one Edit), then Other
// info (per-chain IDs + operator). The Token card now lives atop the holders view (Tokens/Owners tab).
function renderAboutSection(project) {
  var section = el('div', 'detail-section');
  section.appendChild(renderAboutCard(project));
  section.appendChild(renderOtherInfoPanel(project));
  return section;
}

// Unified project profile — everything the "Edit project" modal writes, stacked, with a single Edit CTA.
function renderAboutCard(project) {
  var card = el('div', 'detail-card');
  var t = el('div', 'detail-card-title'); t.textContent = 'About'; card.appendChild(t);
  var body = el('div', 'detail-card-body');

  if (project.logoUri) {
    var logo = document.createElement('img'); logo.className = 'detail-about-logo'; logo.alt = project.name || '';
    setMediaSource(logo, project.logoUri, function () { logo.style.display = 'none'; });
    body.appendChild(logo);
  }
  if (project.tagline) {
    var tag = el('div', 'detail-about-tagline'); tag.textContent = project.tagline; body.appendChild(tag);
  }
  var d = el('div', 'detail-about-desc');
  if (project.descriptionHtml) {
    renderRichTextInto(d, project.descriptionHtml);
  } else if (project.description) {
    project.description.split(/\n{2,}/).forEach(function (para) {
      if (!para.trim()) return;
      var p = el('p', 'detail-about-para'); p.textContent = para.trim(); d.appendChild(p);
    });
  } else {
    var empty = el('p', 'detail-about-para detail-about-empty'); empty.textContent = 'No description yet.'; d.appendChild(empty);
  }
  body.appendChild(d);

  var links = renderProjectLinks(project);
  if (links) body.appendChild(links);
  card.appendChild(body);

  var foot = el('div', 'detail-about-foot');
  var edit = el('a', 'operator-cta'); edit.textContent = 'Edit'; edit.href = '#';
  edit.title = 'Edit the project — logo, tagline, description, links (operator only)';
  edit.addEventListener('click', function (e) { e.preventDefault(); openEditProjectModal(project); });
  foot.appendChild(edit);
  card.appendChild(foot);
  return card;
}

// Website + socials as a row of small underlined links. Returns null when none are set.
function renderProjectLinks(project) {
  var entries = [];
  if (project.infoUri) entries.push(['Website', project.infoUri.indexOf('http') === 0 ? project.infoUri : ('https://' + project.infoUri)]);
  if (project.twitter) { var h = String(project.twitter).replace(/^@/, ''); entries.push(['X', /^https?:/.test(h) ? h : ('https://x.com/' + h)]); }
  if (project.discord) entries.push(['Discord', /^https?:/.test(project.discord) ? project.discord : ('https://' + String(project.discord).replace(/^\/+/, ''))]);
  if (project.telegram) { var tg = String(project.telegram); entries.push(['Telegram', /^https?:/.test(tg) ? tg : (tg.indexOf('t.me') === 0 ? 'https://' + tg : 'https://t.me/' + tg.replace(/^@/, ''))]); }
  if (!entries.length) return null;
  var row = el('div', 'detail-about-links');
  entries.forEach(function (e) {
    var item = el('div', 'about-link-row');
    var k = el('span', 'about-link-key'); k.textContent = e[0] + ':'; item.appendChild(k);
    var a = document.createElement('a'); a.className = 'about-link-url'; a.href = e[1]; a.target = '_blank'; a.rel = 'noopener'; a.textContent = e[1];
    item.appendChild(a);
    row.appendChild(item);
  });
  return row;
}

// Token card — "TOKEN" header, then a single content line (name | symbol | type | truncated address,
// full on hover | on-chains), then its operator Edit (deploy or rename the ERC-20) beneath.
export function tokenUiCapabilities(project) {
  var tokenAddress = project && project.tokenAddress;
  var hasErc20 = !!tokenAddress && String(tokenAddress).toLowerCase() !== ZERO_ADDRESS.toLowerCase();
  return {
    hasErc20: hasErc20,
    // Internal Juicebox credits are the project-token balance before an ERC-20 is deployed. They remain
    // cash out eligible; only an external ERC-20 market/LP position depends on deployment.
    canCashOut: true,
    canAddMarketLiquidity: hasErc20,
    showMarket: hasErc20,
  };
}

var JB_PERMISSION_DEPLOY_ERC20 = 8;
var JB_PERMISSION_SET_TOKEN_METADATA = 22;

async function accountCanManageProjectToken(project, account, permissionId) {
  if (!project || !account || !isAddr(account)) return false;
  var accountKey = account.toLowerCase();
  var authority = projectAuthorityAddress(project);

  // Delegated operators call the controller directly. Verify the relevant permission against the live owner on
  // every project chain because the token edit/deploy flow deliberately fans the same change across all chains.
  var pid = BigInt(project.id);
  var chains = projectChains(project);
  var allowed = await Promise.all(chains.map(function (chain) {
    return read(chain.id, 'JBProjects', ownerOfAbi, 'ownerOf', [pid]).then(function (owner) {
      if (owner && owner.toLowerCase() === accountKey) return true;
      if (!owner) return false;
      return read(chain.id, 'JBPermissions', jbHasPermissionAbi, 'hasPermission', [
        account, owner, pid, BigInt(permissionId), true, true,
      ]).then(Boolean).catch(function () { return false; });
    }).catch(function () { return false; });
  }));
  if (allowed.length > 0 && allowed.every(Boolean)) return true;

  // A Safe signer can propose the owner/operator call even though the signer itself is not the project owner.
  if (authority) {
    var safe = await fetchSafeInfo(authority, project.chainId).catch(function () { return null; });
    if (safe && safe.owners.some(function (owner) { return owner.toLowerCase() === accountKey; })) return true;
  }
  return false;
}

async function ensureProjectTokenManager(project, permissionId, setStatus) {
  var account = getAccount();
  if (!account) {
    setStatus('Connecting wallet…', 'pending');
    account = await connect().then(getAccount).catch(function () { return null; });
  }
  if (!account) { setStatus('Connect a wallet to continue', 'error'); return null; }
  setStatus('Checking token permissions…', 'pending');
  if (!await accountCanManageProjectToken(project, account, permissionId)) {
    setStatus('This wallet is not the project owner and does not have the required token permission on every project chain.', 'error');
    return null;
  }
  return account;
}

function renderTokenPanel(project) {
  var card = el('div', 'detail-card token-line-card');
  var title = el('div', 'detail-card-title'); title.textContent = 'Token'; card.appendChild(title);
  var capabilities = tokenUiCapabilities(project);
  var row = el('div', 'token-line');

  // Each value is preceded by its key label.
  function seg(key, valNode) {
    var s = el('span', 'token-line-seg');
    var k = el('span', 'token-line-key'); k.textContent = key + ':'; s.appendChild(k);
    if (typeof valNode === 'string') { var v = el('span', 'token-line-val'); v.textContent = valNode; s.appendChild(v); }
    else { valNode.classList.add('token-line-val'); s.appendChild(valNode); }
    return s;
  }

  if (!capabilities.hasErc20) {
    var empty = el('div', 'token-empty-state');
    var emptyTitle = el('div', 'token-empty-title'); emptyTitle.textContent = 'No ERC-20 yet'; empty.appendChild(emptyTitle);
    var emptyCopy = el('div', 'token-empty-copy');
    emptyCopy.textContent = 'Project balances remain internal Juicebox credits and can still be cashed out. Deploying an ERC-20 makes them claimable as a transferable token and enables market liquidity.';
    empty.appendChild(emptyCopy);
    card.appendChild(empty);
  } else {
    var name = el('span'); name.textContent = project.tokenName || project.tokenSymbol || 'Token';
    row.appendChild(seg('Name', name));

    if (project.tokenSymbol) {
      row.appendChild(boSep());
      row.appendChild(seg('Symbol', project.tokenSymbol));
    }

    row.appendChild(boSep());
    row.appendChild(seg('Type', 'ERC-20'));

    // Address — truncated, full address reveals instantly on hover. JB omnichain ERC-20s share a
    // deterministic CREATE2 address, so this one applies on every chain.
    row.appendChild(boSep());
    row.appendChild(seg('Address', addressNode(project.tokenAddress)));
    // "On" — the chains the token lives on, each linking to its address on that chain's explorer.
    var onIds = orderedProjectChainIds(project);
    if (onIds.length) {
      row.appendChild(boSep());
      var onWrap = el('span', 'token-on-chains token-line-on');
      onIds.forEach(function (id) { onWrap.appendChild(chainAddrBubble(id, project.tokenAddress)); });
      row.appendChild(seg('On', onWrap));
    }
    card.appendChild(row);
  }

  // Always-visible CTA, matching the other owner/operator actions ("Queue ruleset", splits Edit):
  // the permission requirement is stated inside the modal (operator-gate note), not by hiding the entry point.
  var foot = el('div', 'detail-about-foot');
  var edit = el('a', 'operator-cta'); edit.textContent = capabilities.hasErc20 ? 'Edit' : 'Deploy ERC-20'; edit.href = '#';
  edit.title = capabilities.hasErc20 ? 'Edit the token name & symbol' : 'Deploy a transferable ERC-20 for this project';
  edit.addEventListener('click', function (e) { e.preventDefault(); openEditTokenModal(project); });
  foot.appendChild(edit);
  card.appendChild(foot);
  return card;
}

export function authorityRowsDiverged(rows) {
  var known = (rows || []).filter(function (r) { return r.owner; });
  var first = known.length ? known[0].owner.toLowerCase() : null;
  return known.some(function (r) { return r.owner.toLowerCase() !== first; });
}

function projectChains(project) {
  var chains = (project.chains && project.chains.length) ? project.chains : [{ id: project.chainId, name: chainNameOf(project.chainId) }];
  return chains.map(function (c) { return { id: c.id, name: c.name || chainNameOf(c.id) }; });
}

// Read JBProjects.ownerOf(projectId) on every chain and report whether the owner diverges.
// { rows:[{chainId,name,owner}], diverged }.
function fetchOwnersPerChain(project) {
  var pid = BigInt(project.id);
  var chains = projectChains(project);
  return Promise.all(chains.map(function (c) {
    return read(c.id, 'JBProjects', ownerOfAbi, 'ownerOf', [pid])
      .then(function (o) { return { chainId: c.id, name: c.name, owner: o }; })
      .catch(function () { return { chainId: c.id, name: c.name, owner: null }; });
  })).then(function (rows) {
    return { rows: rows, diverged: authorityRowsDiverged(rows) };
  });
}

// Read the revnet operator on every chain. The operator is not exposed as a direct REVOwner getter, so this
// uses the same indexed permission-holder source as revnetOperatorOf(), but per chain instead of one primary.
function fetchOperatorsPerChain(project) {
  var chains = projectChains(project);
  return Promise.all(chains.map(function (c) {
    return revnetOperatorOf(project.id, c.id)
      .then(function (o) { return { chainId: c.id, name: c.name, owner: o }; })
      .catch(function () { return { chainId: c.id, name: c.name, owner: null }; });
  })).then(function (rows) {
    return { rows: rows, diverged: authorityRowsDiverged(rows) };
  });
}

function fetchAuthorityPerChain(project) {
  return project && project.isRevnet ? fetchOperatorsPerChain(project) : fetchOwnersPerChain(project);
}

// Other info — per-chain project IDs + the operator/owner address. Read-only.
function renderOtherInfoPanel(project) {
  var card = el('div', 'detail-card');
  var title = el('div', 'detail-card-title'); title.textContent = 'Other info'; card.appendChild(title);
  var grid = el('div', 'detail-info-grid');

  var idChains = (project.chains && project.chains.length)
    ? project.chains
    : [{ id: project.chainId, name: (CHAINS[project.chainId] && CHAINS[project.chainId].name) || ('chain ' + project.chainId) }];
  var idsHead = el('div', 'detail-info-head');
  idsHead.textContent = idChains.length > 1 ? 'Project IDs' : 'Project ID';
  grid.appendChild(idsHead);
  idChains.forEach(function (ch) {
    var item = el('div', 'detail-info-chainrow detail-info-chain');
    item.appendChild(chainLogo(ch.id, null));
    var nm = el('span', 'detail-info-chainname'); nm.textContent = ch.name; item.appendChild(nm);
    var idv = el('span', 'detail-info-chainid'); idv.textContent = '#' + project.id; item.appendChild(idv);
    item.title = 'Open #' + project.id + ' on ' + ch.name;
    item.addEventListener('click', function () {
      var tab = _activeDetail ? _activeDetail.current : null;
      location.hash = '#' + slugForChain(ch.id) + ':' + project.id + (tab ? '/' + tab.toLowerCase() : '');
    });
    grid.appendChild(item);
  });

  // Token info — read-only here (the editable copy lives atop the holders view). Name / symbol / type /
  // address / on-chains, no Edit.
  var tnVal = el('span', 'info-token-name'); tnVal.textContent = project.tokenName || '—';
  grid.appendChild(infoItem('Token name', tnVal));
  // No symbol row while the token is still credits — there is no symbol until an ERC-20 exists.
  if (project.tokenAddress && project.tokenSymbol) {
    var tsVal = el('span', 'info-token-symbol'); tsVal.textContent = project.tokenSymbol;
    grid.appendChild(infoItem('Token symbol', tsVal));
  }
  if (project.tokenAddress) {
    // "Token on" sits above "Token address"; "Token type" drops to the row beside Operator.
    var onIds = orderedProjectChainIds(project);
    if (onIds.length) {
      var onWrap = el('span', 'token-on-chains');
      onIds.forEach(function (id) { onWrap.appendChild(chainAddrBubble(id, project.tokenAddress)); });
      grid.appendChild(infoItem('Token on', onWrap));
    }
    grid.appendChild(infoItem('Token address', fullAddressNode(project.tokenAddress)));
    grid.appendChild(infoItem('Token type', 'ERC-20'));
  } else {
    grid.appendChild(infoItem('Token type', 'Credits'));
  }

  // Operator/owner — ENS-resolved, with a transfer CTA below (revnets only — REVOwner.setOperatorOf).
  var opItem = el('div', 'detail-info-item');
  var opLbl = el('div', 'detail-info-label'); opLbl.textContent = projectAuthorityLabel(project); opItem.appendChild(opLbl);
  var opVal = el('div', 'detail-info-value info-operator-val'); opVal.appendChild(fullAddressNode(projectAuthorityAddress(project), true, project.chainId)); opItem.appendChild(opVal);
  // If ownership/operator control isn't uniform across chains, replace the single value with a per-chain breakdown.
  if (idChains.length > 1) {
    fetchAuthorityPerChain(project).then(function (res) {
      if (!res.diverged || !opVal.isConnected) return;
      opVal.innerHTML = '';
      var warn = el('div', 'detail-owner-warn'); warn.textContent = projectAuthorityLabel(project) + ' differs by chain'; opVal.appendChild(warn);
      res.rows.forEach(function (r) {
        var row = el('div', 'detail-owner-chainrow');
        row.appendChild(chainLogo(r.chainId, r.name));
        var nm = el('span', 'detail-info-chainname'); nm.textContent = ' ' + r.name + ' '; row.appendChild(nm);
        if (r.owner) row.appendChild(fullAddressNode(r.owner, false, r.chainId)); else { var dash = el('span'); dash.textContent = '—'; row.appendChild(dash); }
        opVal.appendChild(row);
      });
    }).catch(function () {});
  }
  // (Transfer operator/ownership lives in the Owner/Operator tab's Account card now.)
  grid.appendChild(opItem);
  card.appendChild(grid);
  return card;
}

// JBProjects is an ERC-721; project ownership transfers by moving the NFT.
var jbProjectsTransferAbi = [{
  type: 'function', name: 'transferFrom', stateMutability: 'nonpayable', outputs: [],
  inputs: [{ name: 'from', type: 'address' }, { name: 'to', type: 'address' }, { name: 'tokenId', type: 'uint256' }],
}];

// Run an owner/operator-only action across chains, routing by the authority's account type: a Safe →
// propose to its per-chain queue (multichain, one payment to execute later); an EOA → Relayr (sign per
// chain, pay once). Returns { queued, skipped, cancelled } for the Safe path, { relayr:true } for EOA, or null.
async function runAuthorityActionAcrossChains(project, chains, authorityAddr, buildCall, opts, setStatus) {
  opts = opts || {};
  var homeChainId = (chains && chains[0] && chains[0].id) || project.chainId;
  var safeInfo = await fetchSafeInfo(authorityAddr, homeChainId).catch(function () { return null; });
  if (safeInfo) {
    var signer = getAccount();
    if (!signer) { setStatus('Connecting wallet…', 'pending'); signer = await connect().then(getAccount).catch(function () { return null; }); }
    if (!signer) { setStatus('Connect a wallet to continue', 'error'); return null; }
    if (!safeInfo.owners.some(function (o) { return o.toLowerCase() === signer.toLowerCase(); })) {
      setStatus('Connected wallet isn’t a signer of the Safe (' + truncAddr(authorityAddr) + ').', 'error'); return null;
    }
    return proposeSafeAcrossChains(project, authorityAddr, signer, buildCall, { title: opts.title, replaces: opts.replaces, chains: chains, queueTab: opts.queueTab });
  }
  var account = await ensureOperatorAccount(project, authorityAddr, setStatus);
  if (!account) return null;
  await runRelayrAcrossChains(chains, account, buildCall, opts.gas || 500000n, setStatus, { label: opts.label, title: opts.title });
  return { relayr: true };
}

// Transfer operator (revnet) / ownership (custom) across the requested chain group, routed by authority type.
function openTransferAuthorityModal(project, opts) {
  opts = opts || {};
  var isRev = project.isRevnet;
  var authorityAddr = opts.authorityAddr || projectAuthorityAddress(project);
  var chains = (opts.chains && opts.chains.length)
    ? opts.chains
    : ((project.chains && project.chains.length) ? project.chains : [{ id: project.chainId, name: chainNameOf(project.chainId) }]);
  var homeChainId = (chains[0] && chains[0].id) || project.chainId;
  var chainListText = chains.map(function (c) { return c.name || chainNameOf(c.id); }).join(', ');
  var content = el('div', 'modal-body operator-edit');
  content.appendChild(operatorGateNode((projectAuthorityLabel(project) || (isRev ? 'Operator' : 'Owner')).toLowerCase(), authorityAddr, isRev ? 'to transfer the operator role.' : 'to transfer ownership.', homeChainId));
  var warn = el('div', 'operator-edit-across');
  warn.textContent = isRev
    ? 'Hands over operator control on ' + chainListText + '. Use the zero address to relinquish operator powers permanently. Does not move funds or change rulesets.'
    : 'Transfers project ownership (the JBProjects NFT) on ' + chainListText + '. The new owner controls owner-only actions there. Does not move funds or change rulesets.';
  content.appendChild(warn);
  var nlbl = el('div', 'operator-edit-label'); nlbl.style.marginTop = '12px'; nlbl.textContent = isRev ? 'New operator' : 'New owner'; content.appendChild(nlbl);
  var addrInput = el('input', 'operator-edit-jwt'); addrInput.type = 'text'; addrInput.placeholder = '0x… new ' + (isRev ? 'operator' : 'owner') + ' address'; content.appendChild(addrInput);
  var addrHint = el('div', 'operator-edit-token-name'); content.appendChild(addrHint);
  var authorityValueOf = attachAddressRecognition(addrInput, addrHint, homeChainId, { label: isRev ? 'New operator' : 'New owner' });
  var status = el('div', 'operator-edit-status'); content.appendChild(status);
  var actions = el('div', 'operator-edit-actions');
  var submit = el('a', 'operator-cta operator-edit-submit'); submit.href = '#'; submit.textContent = isRev ? 'Transfer operator' : 'Transfer ownership';
  actions.appendChild(submit); content.appendChild(actions);
  var modal = openModal(isRev ? 'Transfer operator' : 'Transfer ownership', content);
  function setStatus(m, k) { status.className = 'operator-edit-status' + (k ? ' ' + k : ''); status.textContent = m; }
  var busy = false;
  submit.addEventListener('click', function (e) {
    e.preventDefault(); if (busy) return; busy = true;
    (async function () {
      var to;
      try { to = authorityValueOf(); }
      catch (err0) { setStatus(err0.message || String(err0), 'error'); busy = false; return; }
      var buildCall = isRev
        ? function (cid) { var revOwner = getAddress('REVOwner', cid); if (!revOwner) throw new Error('No REVOwner on ' + chainNameOf(cid)); return { to: revOwner, data: encodeFunctionData({ abi: setOperatorOfAbi, functionName: 'setOperatorOf', args: [BigInt(project.id), to] }) }; }
        : function (cid) { var jbp = getAddress('JBProjects', cid); if (!jbp) throw new Error('No JBProjects on ' + chainNameOf(cid)); return { to: jbp, data: encodeFunctionData({ abi: jbProjectsTransferAbi, functionName: 'transferFrom', args: [authorityAddr, to, BigInt(project.id)] }) }; };
      var res = await runAuthorityActionAcrossChains(project, chains, authorityAddr, buildCall, { label: isRev ? 'Transfer operator' : 'Transfer ownership', title: isRev ? 'Transfer operator' : 'Transfer ownership' }, setStatus)
        .catch(function (err) { setStatus(errMessage(err, 'Could not complete the transfer.'), 'error'); return null; });
      busy = false;
      if (!res) return;
      if (res.cancelled) { setStatus('Cancelled', ''); return; }
      if (res.relayr) {
        setStatus((isRev ? 'Operator' : 'Ownership') + ' transferred on ' + chains.length + ' chain' + (chains.length > 1 ? 's' : '') + '.', 'success');
        if (isRev && chains.some(function (c) { return Number(c.id) === Number(project.chainId); })) project.operator = to;
        setTimeout(function () { modal.close(); }, 1400); return;
      }
      setStatus('Queued on ' + res.queued + ' chain' + (res.queued === 1 ? '' : 's') + (res.skipped && res.skipped.length ? ' (skipped ' + res.skipped.join(', ') + ')' : '') + ' — confirm + execute in the ' + (isRev ? 'Operator' : 'Owner') + ' tab.', 'success');
      setTimeout(function () { modal.close(); }, 2400);
    })();
  });
}

// Operator-only: edit the project's identity metadata — name, tagline, logo, description, website and
// socials — then push the new IPFS URI to every chain via relayr (one ERC-2771 `setUriOf` per chain).
function openEditProjectModal(project) {
  var authorityLabel = (projectAuthorityLabel(project) || 'Operator').toLowerCase();
  var operatorAddr = projectAuthorityAddress(project);
  var chains = (project.chains && project.chains.length)
    ? project.chains
    : [{ id: project.chainId, name: (CHAINS[project.chainId] && CHAINS[project.chainId].name) || ('Chain ' + project.chainId) }];

  var content = el('div', 'modal-body operator-edit');

  content.appendChild(operatorGateNode(authorityLabel, operatorAddr, 'to edit the project.'));

  function field(label, placeholder, value, topGap) {
    var l = el('div', 'operator-edit-label'); l.style.marginTop = (topGap == null ? 10 : topGap) + 'px'; l.textContent = label; content.appendChild(l);
    var i = el('input', 'operator-edit-jwt'); i.type = 'text'; i.placeholder = placeholder || ''; i.value = value || '';
    content.appendChild(i);
    return i;
  }

  var nameInput = field('Name', 'Project name', project.name || '', 0);
  var taglineInput = field('Tagline', 'One-line summary', project.tagline || '');

  // Logo — current preview + replace-with-file. Pinned on submit only if a new file is chosen.
  var logoLbl = el('div', 'operator-edit-label'); logoLbl.style.marginTop = '10px'; logoLbl.textContent = 'Logo'; content.appendChild(logoLbl);
  var logoRow = el('div', 'operator-edit-logo');
  var logoPrev = document.createElement('img'); logoPrev.className = 'operator-edit-logo-prev';
  if (project.logoUri) setMediaSource(logoPrev, project.logoUri); else logoPrev.style.visibility = 'hidden';
  logoRow.appendChild(logoPrev);
  var logoFile = document.createElement('input'); logoFile.type = 'file'; logoFile.accept = 'image/*'; logoFile.className = 'operator-edit-logo-file';
  logoFile.addEventListener('change', function () {
    var f = logoFile.files && logoFile.files[0];
    if (f) { logoPrev.style.visibility = 'visible'; logoPrev.src = URL.createObjectURL(f); }
  });
  logoRow.appendChild(logoFile);
  content.appendChild(logoRow);

  var dlbl = el('div', 'operator-edit-label'); dlbl.style.marginTop = '10px'; dlbl.textContent = 'Description'; content.appendChild(dlbl);
  var ta = el('textarea', 'operator-edit-textarea'); ta.rows = 6; ta.value = project.description || ''; content.appendChild(ta);

  var websiteInput = field('Website', 'https://…', project.infoUri || '');
  var twitterInput = field('X / Twitter', 'handle (without @)', '');
  var discordInput = field('Discord', 'invite or handle', '');
  var telegramInput = field('Telegram', 'handle or link', '');

  // Store categories — names for the 721 store's category numbers (category 0 is always "Default").
  // Each row keeps a stable id so existing tier→category links don't shift when rows are added/removed.
  var catLbl = el('div', 'operator-edit-label'); catLbl.style.marginTop = '10px';
  catLbl.innerHTML = 'Store categories <span class="operator-edit-hint">— label the shop item categories.</span>';
  content.appendChild(catLbl);
  var catRowsBox = el('div', 'splits-edit-rows'); content.appendChild(catRowsBox);
  var catRows = [];
  function nextCatId() { var mx = 0; catRows.forEach(function (r) { if (r.id > mx) mx = r.id; }); return mx + 1; }
  function addCatRow(id, name) {
    var row = el('div', 'splits-edit-row');
    var idTag = el('span', 'cat-id'); idTag.textContent = id + ' is'; row.appendChild(idTag);
    var nameIn = el('input', 'splits-edit-addr'); nameIn.type = 'text'; nameIn.placeholder = 'category name'; nameIn.value = name || '';
    var rm = el('a', 'splits-edit-rm'); rm.href = '#'; rm.textContent = '✕'; rm.title = 'Remove';
    var rec = { id: id, name: nameIn };
    rm.addEventListener('click', function (e) { e.preventDefault(); catRows = catRows.filter(function (x) { return x !== rec; }); row.remove(); });
    row.appendChild(nameIn); row.appendChild(rm);
    catRowsBox.appendChild(row); catRows.push(rec);
  }
  Object.keys(project.storeCategories || {}).map(Number).filter(function (n) { return n > 0; }).sort(function (a, b) { return a - b; })
    .forEach(function (n) { addCatRow(n, project.storeCategories[n]); });
  var addCat = el('a', 'operator-cta splits-edit-add'); addCat.href = '#'; addCat.textContent = '+ Add category';
  addCat.addEventListener('click', function (e) { e.preventDefault(); addCatRow(nextCatId(), ''); }); content.appendChild(addCat);

  // Backfill socials/tagline from the live metadata (project.* doesn't carry them) so we don't wipe values.
  var loadedMeta = null;
  (function () {
    var pc = (chains[0] && chains[0].id) || project.chainId;
    controllerAddressFor(pc, project.id).then(function (controller) {
      return clientFor(pc).readContract({ address: controller, abi: uriOfAbi, functionName: 'uriOf', args: [BigInt(project.id)] });
    })
      .then(function (uri) { return uri ? fetchMetadata(uri) : null; })
      .then(function (m) {
        if (!m) return; loadedMeta = m;
        if (!twitterInput.value) twitterInput.value = m.twitter || '';
        if (!discordInput.value) discordInput.value = m.discord || '';
        if (!telegramInput.value) telegramInput.value = m.telegram || '';
        if (!taglineInput.value) taglineInput.value = m.projectTagline || m.tagline || '';
      }).catch(function () {});
  })();

  var across = el('div', 'operator-edit-across'); across.style.marginTop = '12px';
  across.textContent = 'Saves across ' + chains.length + ' chain' + (chains.length > 1 ? 's' : '')
    + ': ' + chains.map(function (c) { return c.name || ('Chain ' + c.id); }).join(', ') + '.';
  content.appendChild(across);

  var jwtInput = null;
  if (!hasPinata()) {
    var jlbl = el('div', 'operator-edit-label'); jlbl.style.marginTop = '12px';
    jlbl.innerHTML = 'Pinata JWT <span class="operator-edit-hint">— to pin the updated metadata to IPFS. '
      + '<a href="https://app.pinata.cloud/developers/api-keys" target="_blank" rel="noopener">Get one</a>; stored only in this browser.</span>';
    content.appendChild(jlbl);
    jwtInput = el('input', 'operator-edit-jwt');
    jwtInput.type = 'password'; jwtInput.placeholder = 'pinata JWT'; jwtInput.autocomplete = 'off'; jwtInput.spellcheck = false;
    content.appendChild(jwtInput);
  }

  var status = el('div', 'operator-edit-status'); content.appendChild(status);
  var actions = el('div', 'operator-edit-actions');
  var submit = el('a', 'operator-cta operator-edit-submit'); submit.href = '#'; submit.textContent = 'Save changes';
  actions.appendChild(submit);
  content.appendChild(actions);

  var modal = openModal('Edit project', content);
  var setStatus = makeStatusSetter(status, 'operator-edit-status');
  var busy = false;
  submit.addEventListener('click', function (e) {
    e.preventDefault();
    if (busy) return;
    if (jwtInput && jwtInput.value.trim()) setPinataJwt(jwtInput.value.trim());
    var form = {
      name: nameInput.value, tagline: taglineInput.value, description: ta.value, website: websiteInput.value,
      twitter: twitterInput.value, discord: discordInput.value, telegram: telegramInput.value,
      storeCategories: (function () { var m = {}; catRows.forEach(function (r) { var n = (r.name.value || '').trim(); if (n) m[r.id] = n; }); return m; })(),
      logoFile: (logoFile.files && logoFile.files[0]) || null, preloadedMeta: loadedMeta,
    };
    submitProjectEdit(project, chains, operatorAddr, form, setStatus, modal).catch(function (err) {
      busy = false;
      setStatus(errMessage(err, 'Could not save the changes.'), 'error');
    });
    busy = true;
  });
}

// Shared operator-gate banner: "You must be the operator (ens-or-0x…) <action>." Resolves the ENS
// name asynchronously, falling back to the truncated address.
function operatorGateNode(authorityLabel, operatorAddr, actionText, chainId) {
  var gate = el('div', 'operator-gate');
  gate.appendChild(document.createTextNode('You must be the ' + authorityLabel + ' ('));
  var addrSpan = el('span', 'operator-gate-addr'); addrSpan.textContent = operatorAddr ? truncAddr(operatorAddr) : '…';
  if (operatorAddr) {
    addrSpan.title = operatorAddr;
    ensNameOf(operatorAddr).then(function (n) { if (n) addrSpan.textContent = n; }).catch(function () {});
  }
  gate.appendChild(addrSpan);
  gate.appendChild(document.createTextNode(') ' + actionText));
  // Safe-aware: if the owner is a Safe, the action is QUEUED for the Safe (not blocked on a single wallet).
  if (operatorAddr && chainId) {
    fetchSafeInfo(operatorAddr, chainId).then(function (info) {
      if (!info || !gate.isConnected) return;
      var acc = getAccount && getAccount();
      var isSigner = acc && info.owners.some(function (o) { return o.toLowerCase() === acc.toLowerCase(); });
      gate.className = 'operator-gate' + (isSigner ? ' ok' : '');
      gate.textContent = isSigner
        ? 'Owner is a ' + info.threshold + '-of-' + info.owners.length + ' Safe — you’re a signer, so this is proposed to the Safe’s queue (approve + execute in the Owner tab).'
        : 'Owner is a ' + info.threshold + '-of-' + info.owners.length + ' Safe (' + truncAddr(operatorAddr) + '). Connect one of its signers to propose this.';
    }).catch(function () {});
  }
  return gate;
}

// Plain text -> minimal rich-text HTML (paragraphs), matching the format other Juicebox clients render.
function descriptionTextToHtml(text) {
  var esc = function (s) { return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'); };
  var paras = String(text || '').split(/\n{2,}/).map(function (p) { return p.trim(); }).filter(Boolean);
  if (!paras.length) return '';
  return paras.map(function (p) { return '<p>' + esc(p).replace(/\n/g, '<br>') + '</p>'; }).join('');
}

// Shared: require a connected wallet equal to the project's operator/owner. Returns the account or null.
async function ensureOperatorAccount(project, operatorAddr, setStatus) {
  var account = getAccount();
  if (!account) { setStatus('Connecting wallet…', 'pending'); account = await connect().then(getAccount).catch(function () { return null; }); }
  if (!account) { setStatus('Connect a wallet to continue', 'error'); return null; }
  if (operatorAddr && account.toLowerCase() !== operatorAddr.toLowerCase()) {
    setStatus('Connected wallet is not the ' + (projectAuthorityLabel(project) || 'operator').toLowerCase() + '. Switch to ' + truncAddr(operatorAddr) + '.', 'error');
    return null;
  }
  return account;
}

// Shared: sign one ERC-2771 call per chain, quote the relayr bundle, take one payment, poll to completion.
// buildCall(chainId) -> { to, data }. Resolves when every chain reports Success.
async function runRelayrAcrossChains(chains, account, buildCall, gas, setStatus, confirmOpts) {
  confirmOpts = confirmOpts || {};
  // Build each chain's call first so we can show the exact onchain target + calldata before anything is signed.
  var calls = [];
  for (var i = 0; i < chains.length; i++) {
    var cid = chains[i].id;
    var call = buildCall(cid);
    if (!call || !call.to) throw new Error('No target contract on ' + (chains[i].name || cid));
    calls.push({ cid: cid, name: chains[i].name || ('chain ' + cid), to: call.to, data: call.data });
  }
  var ok = await confirmTransactionModal({
    via: 'Relayr — one prepaid payment relays the same change to every chain below',
    action: confirmOpts.label || 'Cross-chain update',
    chains: calls.map(function (c) { var nm = resolveContractName(c.to, c.cid); return nm ? { chain: c.name, chainId: c.cid, contract: nm, address: c.to, calldata: c.data } : { chain: c.name, chainId: c.cid, contract: c.to, calldata: c.data }; }),
  }, { title: confirmOpts.title || 'Confirm cross-chain transaction', confirmText: 'Confirm & send' });
  if (!ok) { setStatus('Cancelled', ''); throw new Error('Cancelled'); }

  setStatus('Sign the change for ' + chains.length + ' chain' + (chains.length > 1 ? 's' : '') + '…', 'pending');
  var txs = [];
  for (var j = 0; j < calls.length; j++) {
    txs.push(await buildForwardedTx(calls[j].cid, account, calls[j].to, calls[j].data, gas || 400000n));
  }
  setStatus('Requesting Relayr quote…', 'pending');
  var bundle = await relayrPostBundle(txs);
  var payments = bundle.payment_info || [];
  if (!payments.length) throw new Error('Relayr returned no payment option.');
  var connectedChainId = await getWalletClient().getChainId().catch(function () { return null; });
  var payment = payments.filter(function (p) { return p.chain === connectedChainId; })[0] || payments[0];
  if (payment.chain !== connectedChainId) {
    setStatus('Switch your wallet to ' + (CHAINS[payment.chain] && CHAINS[payment.chain].name || payment.chain) + ' to pay…', 'pending');
    await switchChain(payment.chain);
  }
  setStatus('Confirm the Relayr payment…', 'pending');
  await relayrPay(payment, account);
  setStatus('Payment sent — relaying to ' + chains.length + ' chain' + (chains.length > 1 ? 's' : '') + '…', 'pending');
  await relayrPoll(bundle.bundle_uuid, function (records) {
    var done = records.filter(function (t) { return t.status && t.status.state === 'Success'; }).length;
    setStatus('Relaying… ' + done + '/' + records.length + ' chains confirmed', 'pending');
  });
}

async function submitProjectEdit(project, chains, operatorAddr, form, setStatus, modal) {
  var account = await ensureOperatorAccount(project, operatorAddr, setStatus);
  if (!account) return;
  if (!hasPinata()) { setStatus('Enter a Pinata JWT above to pin the updated metadata.', 'error'); return; }

  // Start from the live metadata so every field we don't edit (tags, payDisclosure, version, …) is preserved.
  var primaryChain = (chains[0] && chains[0].id) || project.chainId;
  var controllers = await controllerMapFor(chains, project.id);
  var meta = form.preloadedMeta;
  if (!meta) {
    setStatus('Reading current metadata…', 'pending');
    var curUri = await clientFor(primaryChain).readContract({
      address: controllers[primaryChain], abi: uriOfAbi, functionName: 'uriOf', args: [BigInt(project.id)],
    }).catch(function () { return null; });
    meta = curUri ? (await fetchMetadata(curUri)) : null;
  }
  meta = meta ? Object.assign({}, meta) : {};

  // New logo (if chosen) is pinned first, then referenced by the metadata JSON.
  var newLogoUri = null;
  if (form.logoFile) {
    setStatus('Pinning logo…', 'pending');
    newLogoUri = await pinFile(form.logoFile, (form.name || project.name || 'logo'));
    meta.logoUri = newLogoUri;
  }
  var trim = function (s) { return (s || '').trim(); };
  meta.name = trim(form.name);
  meta.projectTagline = trim(form.tagline);
  meta.description = descriptionTextToHtml(form.description);
  meta.infoUri = trim(form.website);
  meta.twitter = trim(form.twitter);
  meta.discord = trim(form.discord);
  meta.telegram = trim(form.telegram);
  if (form.storeCategories) { if (Object.keys(form.storeCategories).length) meta.storeCategories = form.storeCategories; else delete meta.storeCategories; }

  setStatus('Pinning updated metadata…', 'pending');
  var newUri = await pinJson(meta, (meta.name || 'project') + '-metadata');

  await runRelayrAcrossChains(chains, account, function (cid) {
    return { to: controllers[cid], data: encodeFunctionData({ abi: setUriOfAbi, functionName: 'setUriOf', args: [BigInt(project.id), newUri] }) };
  }, 400000n, setStatus, { label: 'Edit project details', title: 'Confirm edit' });

  setStatus('Project updated across ' + chains.length + ' chain' + (chains.length > 1 ? 's' : '') + '.', 'success');
  // Reflect changes in memory + the live card without a reload.
  project.name = meta.name; project.tagline = meta.projectTagline;
  project.descriptionHtml = meta.description || null; project.description = htmlToText(meta.description);
  project.infoUri = meta.infoUri || null;
  project.storeCategories = meta.storeCategories || {};
  if (newLogoUri) project.logoUri = ipfsToHttp(newLogoUri);
  var liveDesc = document.querySelector('.detail-about-desc');
  if (liveDesc) { liveDesc.innerHTML = ''; renderRichTextInto(liveDesc, meta.description); }
  var liveName = document.querySelector('.detail-name'); if (liveName && meta.name) liveName.textContent = meta.name;
  var liveLogo = document.querySelector('img.detail-logo'); if (liveLogo && project.logoUri) setMediaSource(liveLogo, project.logoUri);
  setTimeout(function () { modal.close(); }, 1400);
}

// Operator-only: set the project token's name & symbol on every chain, via relayr. If the ERC-20 is
// already deployed it's renamed (setTokenMetadataOf → JBERC20.setMetadata — name/symbol ARE mutable);
// if the project still uses credits, the ERC-20 is deployed (deployERC20For) with the chosen name/symbol.
function openEditTokenModal(project) {
  var authorityLabel = (projectAuthorityLabel(project) || 'Operator').toLowerCase();
  var operatorAddr = projectAuthorityAddress(project);
  var chains = (project.chains && project.chains.length)
    ? project.chains
    : [{ id: project.chainId, name: (CHAINS[project.chainId] && CHAINS[project.chainId].name) || ('Chain ' + project.chainId) }];
  var deployed = tokenUiCapabilities(project).hasErc20;
  var permissionId = deployed ? JB_PERMISSION_SET_TOKEN_METADATA : JB_PERMISSION_DEPLOY_ERC20;

  var content = el('div', 'modal-body operator-edit');
  var permissionGate = el('div', 'operator-gate');
  permissionGate.textContent = 'Requires the project ' + authorityLabel + ' or an operator with '
    + (deployed ? 'SET_TOKEN_METADATA' : 'DEPLOY_ERC20') + ' permission on every project chain.';
  content.appendChild(permissionGate);
  function refreshPermissionGate() {
    var account = getAccount && getAccount();
    if (!account) return;
    accountCanManageProjectToken(project, account, permissionId).then(function (allowed) {
      if (!permissionGate.isConnected) return;
      permissionGate.className = 'operator-gate' + (allowed ? ' ok' : '');
      permissionGate.textContent = allowed
        ? 'Connected wallet is authorized to ' + (deployed ? 'edit this token.' : 'deploy this project’s ERC-20.')
        : 'This wallet is not authorized. Connect the project ' + authorityLabel + ' or an operator with '
          + (deployed ? 'SET_TOKEN_METADATA' : 'DEPLOY_ERC20') + ' permission.';
    }).catch(function () {});
  }
  refreshPermissionGate();
  onWalletChange(function () { if (permissionGate.isConnected) refreshPermissionGate(); });

  var nlbl = el('div', 'operator-edit-label'); nlbl.textContent = 'Token name'; content.appendChild(nlbl);
  var nameInput = el('input', 'operator-edit-jwt'); nameInput.type = 'text'; nameInput.placeholder = 'e.g. My Project Token';
  nameInput.value = project.tokenName || project.name || '';
  content.appendChild(nameInput);

  var slbl = el('div', 'operator-edit-label'); slbl.style.marginTop = '10px'; slbl.textContent = 'Symbol'; content.appendChild(slbl);
  var symInput = el('input', 'operator-edit-jwt'); symInput.type = 'text'; symInput.placeholder = 'e.g. TOKEN'; symInput.maxLength = 11;
  symInput.value = project.tokenSymbol || '';
  content.appendChild(symInput);

  var across = el('div', 'operator-edit-across');
  across.textContent = deployed
    ? 'Renames the ERC-20 on ' + chains.length + ' chain' + (chains.length > 1 ? 's' : '')
      + ': ' + chains.map(function (c) { return c.name || ('Chain ' + c.id); }).join(', ')
      + '. Only the name & symbol change — the contract address stays the same on every chain.'
    : 'Deploys one ERC-20 (same address) across ' + chains.length + ' chain' + (chains.length > 1 ? 's' : '')
      + ': ' + chains.map(function (c) { return c.name || ('Chain ' + c.id); }).join(', ') + '.';
  content.appendChild(across);

  var status = el('div', 'operator-edit-status'); content.appendChild(status);
  var actions = el('div', 'operator-edit-actions');
  var submit = el('a', 'operator-cta operator-edit-submit'); submit.href = '#'; submit.textContent = deployed ? 'Save token' : 'Deploy token';
  actions.appendChild(submit);
  content.appendChild(actions);

  var modal = openModal(deployed ? 'Edit token name & symbol' : 'Set token name & symbol', content);
  var setStatus = makeStatusSetter(status, 'operator-edit-status');
  var busy = false;
  submit.addEventListener('click', function (e) {
    e.preventDefault();
    if (busy) return;
    submitTokenEdit(project, chains, operatorAddr, deployed, nameInput.value, symInput.value, setStatus, modal).catch(function (err) {
      busy = false;
      setStatus((err && (err.shortMessage || err.message)) || (deployed ? 'Could not save the changes.' : 'Deploy failed'), 'error');
    });
    busy = true;
  });
}

async function submitTokenEdit(project, chains, operatorAddr, deployed, name, symbol, setStatus, modal) {
  name = (name || '').trim(); symbol = (symbol || '').trim();
  if (!name || !symbol) { setStatus('Enter a token name and symbol', 'error'); return; }
  setStatus('Verifying project controllers…', 'pending');
  var controllers = await controllerMapFor(chains, project.id);

  // The deterministic salt makes the ERC-20 deploy to the same address on every chain.
  var salt = keccak256(encodeAbiParameters([{ type: 'uint256' }, { type: 'string' }], [BigInt(project.id), symbol]));
  var buildCall = function (cid) {
    return deployed
      ? { to: controllers[cid], data: encodeFunctionData({ abi: setTokenMetadataAbi, functionName: 'setTokenMetadataOf', args: [BigInt(project.id), name, symbol] }) }
      : { to: controllers[cid], data: encodeFunctionData({ abi: deployErc20Abi, functionName: 'deployERC20For', args: [BigInt(project.id), name, symbol, salt] }) };
  };

  // If the owner is a Safe, Relayr can't sign for it — propose the call to each chain's Safe queue instead.
  var safeInfo = await fetchSafeInfo(operatorAddr, project.chainId).catch(function () { return null; });
  if (safeInfo) {
    var signer = getAccount();
    if (!signer) { setStatus('Connecting wallet…', 'pending'); signer = await connect().then(getAccount).catch(function () { return null; }); }
    if (!signer) { setStatus('Connect a wallet to continue', 'error'); return; }
    if (!safeInfo.owners.some(function (o) { return o.toLowerCase() === signer.toLowerCase(); })) {
      setStatus('Connected wallet isn’t a signer of the owner Safe (' + truncAddr(operatorAddr) + ').', 'error'); return;
    }
    var res = await proposeSafeAcrossChains(project, operatorAddr, signer, buildCall, { title: deployed ? 'Queue token rename on Safe' : 'Queue token deploy on Safe', queueTab: project.isRevnet ? 'Operator' : 'Owner' });
    if (!res || res.cancelled) { setStatus('Cancelled', ''); return; }
    var readyCount = (res.readyExecs && res.readyExecs.length) || 0;
    var tabName = project.isRevnet ? 'Operator' : 'Owner';
    var skippedNote = res.skipped.length ? ' (skipped ' + res.skipped.join(', ') + ' — add the Safe there first)' : '';
    if (res.executedReady) setStatus('Queued and executed on ' + res.executedReady + ' chain' + (res.executedReady === 1 ? '' : 's') + skippedNote + '.', 'success');
    else if (readyCount) setStatus('Queued on ' + res.queued + ' chain' + (res.queued === 1 ? '' : 's') + skippedNote + ' — ' + readyCount + ' ready to execute from the ' + tabName + ' tab.', 'success');
    else setStatus('Queued on ' + res.queued + ' chain' + (res.queued === 1 ? '' : 's') + skippedNote + ' — confirm + execute in the ' + tabName + ' tab or the Safe app.', 'success');
    setTimeout(function () { modal.close(); }, 2400);
    return;
  }

  // EOA owner → the existing Relayr cross-chain path (the wallet itself is the owner).
  var account = await ensureProjectTokenManager(project, deployed ? JB_PERMISSION_SET_TOKEN_METADATA : JB_PERMISSION_DEPLOY_ERC20, setStatus);
  if (!account) return;
  await runRelayrAcrossChains(chains, account, buildCall, deployed ? 300000n : 1500000n, setStatus,
    { label: deployed ? 'Rename token' : 'Deploy ERC-20 token', title: deployed ? 'Confirm token rename' : 'Confirm token deploy' });

  setStatus((deployed ? 'Token renamed on ' : 'Token deployed across ') + chains.length + ' chain' + (chains.length > 1 ? 's' : '') + '', 'success');
  project.tokenName = name; project.tokenSymbol = symbol;
  var liveName = document.querySelector('.info-token-name'); if (liveName) liveName.textContent = name;
  var liveSym = document.querySelector('.info-token-symbol'); if (liveSym) liveSym.textContent = symbol;
  var headSym = document.querySelector('.detail-sym'); if (headSym) headSym.textContent = symbol;
  setTimeout(function () { modal.close(); }, 1400);
}

// Run a set of pre-built Relayr entries ({chain,target,data,value}) as one bundle: quote → user picks a
// pay chain → pay once → poll. Used to execute many Safe txs across chains in a single payment. Resolves
// { done, cancelled }.
function runRelayrBundle(entries, opts) {
  opts = opts || {};
  return new Promise(function (resolve) {
    var wrap = el('div', 'modal-body');
    var pvStatus = []; // per-chain status spans, indexed in submission order (matches relayr poll order)
    function previewParts(p) {
      var label = p.details || p.label || '';
      var nonce = p.nonce;
      if ((nonce == null || nonce === '') && label) {
        var m = label.match(/\s*\(#(\d+)\)\s*$/);
        if (m) { nonce = m[1]; label = label.slice(0, m.index); }
      }
      return { nonce: nonce == null || nonce === '' ? '—' : String(nonce), details: label };
    }
    // Preview of what will run on each chain (opts.preview: [{chain,nonce,details}]), so it's not a black box.
    if (opts.preview && opts.preview.length) {
      var pv = el('div', 'relayr-preview');
      var head = el('div', 'relayr-preview-head');
      ['Chain', 'Nonce', 'Tx details'].forEach(function (h) { var c = el('div'); c.textContent = h; head.appendChild(c); });
      pv.appendChild(head);
      opts.preview.forEach(function (p) {
        var parts = previewParts(p);
        var r = el('div', 'relayr-preview-row');
        var chainCell = el('div', 'relayr-preview-chain');
        chainCell.appendChild(chainLogo(p.cid || 0, p.chain));
        var s = el('span'); s.textContent = p.chain || 'Chain'; chainCell.appendChild(s);
        r.appendChild(chainCell);
        var nonceCell = el('div', 'relayr-preview-nonce'); nonceCell.textContent = parts.nonce; r.appendChild(nonceCell);
        var details = el('div', 'relayr-preview-details');
        var l = el('span', 'relayr-preview-label'); l.textContent = parts.details; details.appendChild(l);
        var st = el('span', 'relayr-preview-status'); details.appendChild(st); // per-chain execution status (filled on poll)
        r.appendChild(details);
        pvStatus.push(st);
        pv.appendChild(r);
      });
      wrap.appendChild(pv);
    }
    var status = el('div', 'modal-status pending'); status.textContent = 'Requesting a Relayr quote…'; wrap.appendChild(status);
    var choiceWrap = el('div', 'relayr-choice'); choiceWrap.style.display = 'none'; wrap.appendChild(choiceWrap);
    var foot = el('div', 'modal-foot');
    var cancel = el('button', 'create-btn ghost'); cancel.textContent = 'Cancel'; foot.appendChild(cancel);
    wrap.appendChild(foot);
    var modal = openModal(opts.title || 'Pay once, execute on all chains', wrap);
    var done = false; function finish(r) { if (done) return; done = true; modal.close(); resolve(r); }
    cancel.addEventListener('click', function () { finish({ done: false, cancelled: true }); });

    relayrPostBundle(entries).then(function (quote) {
      var options = (quote.payment_info || []).slice().sort(function (a, b) { return BigInt(a.amount) < BigInt(b.amount) ? -1 : 1; });
      if (!options.length) { status.className = 'modal-status'; status.textContent = 'Relayr returned no payment option.'; return; }
      status.className = 'modal-status';
      status.textContent = 'Pay gas once on a chain of your choice — relayers then execute on all ' + entries.length + ' chains.';
      choiceWrap.style.display = '';
      var sel = el('select', 'field create-input');
      options.forEach(function (o, i) { var op = el('option'); op.value = String(i); op.textContent = chainNameOf(o.chain) + ' — ~' + (+formatEther(BigInt(o.amount))).toFixed(5) + ' ETH'; sel.appendChild(op); });
      choiceWrap.appendChild(sel);
      var pay = el('button', 'modal-submit'); pay.textContent = 'Pay & execute'; foot.appendChild(pay);
      pay.addEventListener('click', function () {
        var o = options[Number(sel.value) || 0];
        pay.disabled = true; cancel.disabled = true; sel.disabled = true;
        (async function () {
          try {
            status.className = 'modal-status pending';
            var wallet = getWalletClient(); var cur = await wallet.getChainId().catch(function () { return null; });
            if (cur !== o.chain) { status.textContent = 'Switching to ' + chainNameOf(o.chain) + '…'; await switchChain(o.chain); }
            status.textContent = 'Confirm the payment in your wallet…';
            var payHash = await relayrPay(o);
            status.textContent = 'Paid | ' + truncAddr(payHash) + ' — relayers executing on each chain…';
            await relayrPoll(quote.bundle_uuid, function (txList) {
              // Relayr returns results in submission order → index maps to our preview rows.
              (txList || []).forEach(function (t, i) {
                if (!pvStatus[i]) return;
                var s = t.status && t.status.state;
                if (s === 'Success' || s === 'Completed') { pvStatus[i].textContent = 'done'; pvStatus[i].className = 'relayr-preview-status ok'; }
                else if (s === 'Failed') { pvStatus[i].textContent = 'failed'; pvStatus[i].className = 'relayr-preview-status err'; }
                else { pvStatus[i].textContent = 'executing…'; pvStatus[i].className = 'relayr-preview-status pending'; }
              });
              var n = (txList || []).filter(function (t) { return t.status && (t.status.state === 'Success' || t.status.state === 'Completed'); }).length;
              status.textContent = 'Executing… ' + n + '/' + entries.length;
            });
            status.className = 'modal-status success'; status.textContent = 'Executed on ' + entries.length + ' chains.';
            document.dispatchEvent(new CustomEvent('jb:bridge-updated'));
            setTimeout(function () { finish({ done: true }); }, 1600);
          } catch (e) { pay.disabled = false; cancel.disabled = false; sel.disabled = false; status.className = 'modal-status'; status.textContent = (e && (e.shortMessage || e.message)) || String(e); }
        })();
      });
    }).catch(function (e) { status.className = 'modal-status'; status.textContent = 'Could not get a Relayr quote: ' + ((e && e.message) || e); });
  });
}

function executeReadySafeTransactions(readyExecs, opts) {
  opts = opts || {};
  readyExecs = readyExecs || [];
  var entries = readyExecs.map(function (r) { return safeExecRelayrTx(r.cid, r.safe, r.tx); });
  var preview = readyExecs.map(function (r) {
    return {
      cid: r.cid,
      chain: r.chain,
      nonce: r.tx.nonce,
      details: labelForQueuedTx(r.tx) + ' → ' + (resolveContractName(r.tx.to, r.cid) || r.tx.to),
    };
  });
  return runRelayrBundle(entries, {
    title: opts.title || ('Execute ' + readyExecs.length + ' transaction' + (readyExecs.length === 1 ? '' : 's')),
    preview: preview,
  });
}

// Suggested next onchain nonce per (safe, chain, signer), bumped each time this signer approves an onchain tx so a
// run of separate operator actions defaults to sequential nonces (N, N+1, N+2…) instead of all colliding at the
// current nonce. Persisted to localStorage so it survives a page reload mid-queue (the default is still
// max(currentNonce, hint), so a stale-low hint is harmless).
var _onchainNonceHint = (function () { try { return JSON.parse(localStorage.getItem('jb-onchain-nonce-hint') || '{}'); } catch (_) { return {}; } })();
function _saveOnchainNonceHint() { try { localStorage.setItem('jb-onchain-nonce-hint', JSON.stringify(_onchainNonceHint)); } catch (_) {} }

// Open a Safe-proposal modal: per chain, show the decoded call + a nonce picker, queue on each chain the
// Safe is actually deployed on (same address), and clearly flag chains where it isn't yet. Resolves with
// { queued, skipped:[names], cancelled, readyExecs }.
function proposeSafeAcrossChains(project, safe, signer, buildCall, opts) {
  opts = opts || {};
  return new Promise(function (resolve) {
    var chains = (opts.chains && opts.chains.length)
      ? opts.chains
      : ((project.chains && project.chains.length) ? project.chains : [{ id: project.chainId, name: chainNameOf(project.chainId) }]);
    var queueTabName = opts.queueTab || (project && project.isRevnet ? 'Operator' : 'Owner');
    var wrap = el('div', 'modal-body');
    var intro = el('div', 'modal-balance');
    intro.textContent = 'Apply this change on each chain’s Safe. Chains with a hosted Safe service are queued for the multisig (sign once; co-sign + execute from the ' + queueTabName + ' tab). Chains without one are approved + executed onchain right here. One “Sign & queue” does your part on every chain.';
    wrap.appendChild(intro);
    if (chains.some(function (c) { return !hasSafeService(c.id); })) {
      var coNote = el('div', 'modal-balance');
      coNote.innerHTML = '<strong>Co-signing someone else’s transaction?</strong> Enter the <strong>exact</strong> values they gave you AND set the same <strong>nonce</strong> — the status under each chain without a Safe service reads “matches a tx approved by …” when both match a pending approval (0 = they differ, and you’d start a separate tx). The first signer can queue several onchain txs at sequential nonces; the Safe runs them lowest-nonce-first, and this modal executes the one whose nonce is current (click again to run the next).';
      coNote.style.marginTop = '6px';
      wrap.appendChild(coNote);
    }
    var sigBanner = el('div', 'create-banner');
    sigBanner.textContent = 'It’s a multisig — you sign/approve once per chain. If a chain needs more signers, switch wallets and click again; chains without a Safe service execute automatically once the threshold is met.';
    wrap.appendChild(sigBanner);
    var listEl = el('div', 'safe-propose-list'); wrap.appendChild(listEl);
    var status = el('div', 'modal-status'); wrap.appendChild(status);
    var foot = el('div', 'modal-foot');
    var cancel = el('button', 'create-btn ghost'); cancel.textContent = 'Cancel';
    var btn = el('button', 'modal-submit'); btn.textContent = 'Sign & queue';
    foot.appendChild(cancel); foot.appendChild(btn); wrap.appendChild(foot);
    var modal = openModal(opts.title || 'Queue on Safe', wrap);
    // Replace the input modal rather than stacking a second one over it — the review reads as the "next page".
    if (opts.replaces && opts.replaces.close) { try { opts.replaces.close(); } catch (_) {} }
    var done = false, mode = 'sign', lastResult = null, readyExecs = [];
    function finish(res) { if (done) return; done = true; modal.close(); resolve(res); }

    var rows = [];
    chains.forEach(function (c) {
      var call = buildCall(c.id);
      var block = el('div', 'safe-propose-chain');
      var head = el('div', 'safe-propose-head'); head.appendChild(chainLogo(c.id, c.name)); var nm = el('span'); nm.textContent = ' ' + c.name; head.appendChild(nm); block.appendChild(head);
      block.appendChild(renderTxReview({ chain: c.name, chainId: c.id, contract: resolveContractName(call.to, c.id) || call.to, address: call.to, calldata: call.data, value: '0' }));
      var st = el('div', 'safe-propose-hint'); st.style.marginTop = '6px'; st.textContent = 'checking Safe…'; block.appendChild(st);
      listEl.appendChild(block);
      var rec = { cid: c.id, chain: c.name, to: call.to, data: call.data, deployed: false, onChain: false, st: st, block: block };
      rows.push(rec);

      fetchSafeInfo(safe, c.id).then(function (info) {
        if (!info) {
          block.classList.add('safe-propose-skip'); st.innerHTML = '';
          st.appendChild(document.createTextNode('Safe not deployed on ' + c.name + ' — '));
          // Deploy the SAME-address Safe here by replaying its original creation (works even where the Safe app has
          // no UI, e.g. Arbitrum Sepolia). On success, re-check the chain so it's queue-able without reopening.
          var dep = el('a', 'operator-cta'); dep.href = '#'; dep.textContent = 'deploy it here (same address)';
          dep.addEventListener('click', function (e) {
            e.preventDefault();
            st.innerHTML = ''; st.appendChild(document.createTextNode('Reading the Safe’s deployment config…'));
            fetchSafeCreation(safe).then(function (creation) {
              if (!creation) throw new Error('couldn’t read the Safe’s creation config (needs a chain where it already exists + a Safe service)');
              st.textContent = 'Deploying the Safe on ' + c.name + ' — confirm in your wallet…';
              return deploySafeSameAddress(c.id, creation, safe);
            }).then(function () {
              block.classList.remove('safe-propose-skip'); rec.nInput = null;
              return fetchSafeInfo(safe, c.id).then(function (info2) {
                if (!info2) { st.textContent = 'Deploy on ' + c.name + ' successful — reopen this action to queue there.'; return; }
                rec.deployed = true; rec.threshold = info2.threshold; rec.owners = info2.owners; rec.onChain = true;
                return refreshOnChainStatus(rec);
              });
            }).catch(function (err) {
              st.innerHTML = ''; st.appendChild(document.createTextNode('Safe not deployed on ' + c.name + ' — ' + ((err && (err.shortMessage || err.message)) || String(err))));
            });
          });
          st.appendChild(dep);
          st.appendChild(document.createTextNode(' | or '));
          var a = document.createElement('a'); a.href = safeHomeLink(c.id, safe); a.target = '_blank'; a.rel = 'noopener'; a.textContent = 'the Safe app ↗'; st.appendChild(a);
          st.appendChild(document.createTextNode('. Skipped for now.')); return;
        }
        rec.deployed = true; rec.threshold = info.threshold; rec.owners = info.owners;
        if (hasSafeService(c.id)) {
          st.textContent = 'Safe service | ' + info.threshold + '-of-' + info.owners.length + ' multisig.';
          return Promise.all([getSafeNextNonce(c.id, safe), listPendingSafeTxs(c.id, safe).catch(function () { return []; })]).then(function (rr) {
            var next = rr[0] != null ? rr[0] : 0;
            var queuedNonces = (rr[1] || []).map(function (t) { return Number(t.nonce); }).filter(function (v, i, a) { return a.indexOf(v) === i; }).sort(function (a, b) { return a - b; });
            var def = queuedNonces.length ? Math.max(next, queuedNonces[queuedNonces.length - 1] + 1) : next;
            var nrow = el('div', 'safe-propose-nonce'); nrow.style.marginTop = '4px';
            var nlbl = el('span', 'safe-propose-noncelbl'); nlbl.textContent = 'Nonce '; nrow.appendChild(nlbl);
            var nInput = el('input', 'safe-nonce-input'); nInput.type = 'number'; nInput.min = '0'; nInput.value = String(def); nrow.appendChild(nInput);
            var nhint = el('span', 'safe-propose-hint'); nhint.textContent = queuedNonces.length ? (' next ' + def + ' | queued #' + queuedNonces.join(', #') + ' — reuse one to replace it') : ' next nonce'; nrow.appendChild(nhint);
            rec.block.appendChild(nrow); rec.nInput = nInput;
          });
        }
        rec.onChain = true;
        return refreshOnChainStatus(rec);
      }).catch(function () { block.classList.add('safe-propose-skip'); rec.deployed = false; st.textContent = 'Could not read the Safe here — skipped.'; });
    });

    // (Re-)read an onchain chain's approvals AT THE CHOSEN NONCE and paint its status. On first call it renders an
    // editable nonce input defaulting to the next sequential slot (current Safe nonce, bumped by _onchainNonceHint as
    // this signer queues more txs) so the first signer can queue several onchain txs without colliding at one nonce.
    // The Safe executes in strict nonce order, so the hash is computed at the CHOSEN nonce; the submit loop only
    // executes the tx whose chosen nonce == the Safe's current nonce.
    function refreshOnChainStatus(rec) {
      return safeOnChainContext(rec.cid, safe).then(function (ctx) {
        rec.ctx = ctx;
        // Key the sequential-nonce hint by the CONNECTED SIGNER, not just safe:chain. The hint bumps as this signer
        // queues txs (so their next tx defaults to N+1); keying it per-signer means a second owner co-signing in the
        // SAME browser session starts with an empty hint → defaults to the current nonce (the pending tx to match),
        // instead of inheriting the first signer's queue advancement and landing on a non-matching nonce.
        var key = safe.toLowerCase() + ':' + rec.cid + ':' + (((getAccount && getAccount()) || '') + '').toLowerCase();
        if (!rec.nInput) {
          var def = Math.max(Number(ctx.nonce), _onchainNonceHint[key] || 0);
          var nrow = el('div', 'safe-propose-nonce'); nrow.style.marginTop = '4px';
          var nlbl = el('span', 'safe-propose-noncelbl'); nlbl.textContent = 'Nonce '; nrow.appendChild(nlbl);
          var nInput = el('input', 'safe-nonce-input'); nInput.type = 'number'; nInput.min = String(ctx.nonce); nInput.value = String(def); nrow.appendChild(nInput);
          var nHint = el('span', 'safe-propose-hint'); nrow.appendChild(nHint); rec.nHint = nHint;
          rec.block.appendChild(nrow); rec.nInput = nInput;
          nInput.addEventListener('change', function () { refreshOnChainStatus(rec); });
        }
        var chosen = Number(rec.nInput.value); rec.chosenNonce = chosen;
        var ahead = chosen - Number(ctx.nonce);
        rec.nHint.textContent = ahead < 0 ? ' below current nonce ' + ctx.nonce + ' — already used; pick ≥ ' + ctx.nonce
          : ahead === 0 ? ' current — this one executes next'
          : ahead === 1 ? ' +1 — queued behind nonce ' + ctx.nonce
          : ' +' + ahead + ' — queued behind nonces ' + ctx.nonce + '-' + (chosen - 1);
        rec.hash = safeTxHashForCall(rec.cid, safe, { to: rec.to, data: rec.data, value: 0, nonce: chosen });
        return safeApprovalsOf(rec.cid, safe, rec.hash, ctx.owners).then(function (ap) {
          rec.approved = ap;
          // approvals read for THIS exact tx at the CHOSEN nonce → a non-zero count is the "your values (and nonce)
          // match a pending approval" signal for a co-signer.
          var note = ap.length >= ctx.threshold
            ? (ahead === 0 ? ' — ready to execute' : ' — fully approved; executes once nonce ' + ctx.nonce + '-' + (chosen - 1) + ' clear')
            : ap.length > 0
              ? ' — matches a tx approved by ' + ap.length + ' signer' + (ap.length > 1 ? 's' : '')
              : ' — none yet at nonce ' + chosen + '. Co-signing? match the first signer’s values AND nonce, or this starts a separate tx';
          rec.st.textContent = 'No Safe service | nonce ' + chosen + ' | ' + ap.length + ' / ' + ctx.threshold + ' approvals' + note;
        });
      });
    }

    function setStatus(m, k) { status.className = 'modal-status' + (k ? ' ' + k : ''); status.textContent = m; }
    cancel.addEventListener('click', function () { finish(lastResult || { queued: 0, skipped: [], cancelled: true }); });
    // One CTA does the connected signer's part on EVERY chain: service chains get sign+queue; onchain chains get
    // approveHash, then execTransaction automatically once the threshold is met. Chains that still need more
    // signers stay pending — switch wallets and click again (already-done chains are skipped). All in one flow.
    btn.addEventListener('click', function () {
      if (mode === 'executeReady') {
        if (!readyExecs.length) return;
        btn.disabled = true; cancel.disabled = true;
        setStatus('Preparing execution…', 'pending');
        executeReadySafeTransactions(readyExecs, { title: 'Execute ' + readyExecs.length + ' transaction' + (readyExecs.length === 1 ? '' : 's') }).then(function (res) {
          if (res && res.done) {
            readyExecs.forEach(function (r) { if (r.rec && r.rec.st) r.rec.st.textContent = 'Executed'; });
            if (lastResult) { lastResult.executedReady = readyExecs.length; lastResult.readyExecs = []; }
            document.dispatchEvent(new CustomEvent('jb:bridge-updated'));
            setStatus('Executed on ' + readyExecs.length + ' chain' + (readyExecs.length === 1 ? '' : 's') + '.', 'success');
            setTimeout(function () { finish(lastResult || { queued: 0, executedReady: readyExecs.length, skipped: [], cancelled: false }); }, 1400);
          } else {
            btn.disabled = false; cancel.disabled = false;
            setStatus('Cancelled — queued transactions are still available in the ' + queueTabName + ' tab or Safe app.', '');
          }
        }).catch(function (e) {
          btn.disabled = false; cancel.disabled = false;
          setStatus(errMessage(e, 'Could not execute the transactions.'), 'error');
        });
        return;
      }
      var acct = (getAccount && getAccount()) || null;
      var live = rows.filter(function (r) { return r.deployed; });
      var skipped = rows.filter(function (r) { return !r.deployed; }).map(function (r) { return r.chain; });
      if (!live.length) { setStatus('The Safe isn’t deployed (or readable) on any selected chain. Add it on those chains in the Safe app first.', 'error'); return; }
      if (!acct) { setStatus('Connect a signer wallet to continue.', 'error'); connect().catch(function () {}); return; }
      btn.disabled = true; cancel.disabled = true;
      (async function () {
        var queued = 0, executed = 0, pending = 0, approvedThisRun = 0, notOwner = 0, pendingExec = 0, staleNonce = 0;
        try {
          for (var i = 0; i < live.length; i++) {
            var r = live[i];
            if (r.done) continue; // already queued/executed in a prior run (re-click after a wallet switch)
            var isOwner = (r.owners || []).some(function (o) { return o.toLowerCase() === acct.toLowerCase(); });
            if (!isOwner) { r.st.textContent = 'Connected wallet ' + acct.slice(0, 6) + '… isn’t a signer of this Safe — skipped.'; notOwner++; continue; }
            if (!r.onChain) {
              var nonce = r.nInput ? Number(r.nInput.value) : 0;
              if (!(nonce >= 0)) throw new Error('Enter a valid nonce for ' + r.chain);
              setStatus('Queueing on ' + r.chain + ' (' + (i + 1) + '/' + live.length + ') — sign in your wallet…', 'pending');
              var proposed = await proposeSafeTx({ chainId: r.cid, safe: safe, to: r.to, data: r.data, value: 0, signer: acct, nonce: nonce });
              r.done = true; queued++;
              var qtx = Object.assign({}, proposed.tx || {}, { confirmationsRequired: r.threshold });
              if (safeUsableConfirmationCount(qtx) >= Number(r.threshold || 1)) {
                readyExecs.push({ cid: r.cid, chain: r.chain, safe: safe, tx: qtx, rec: r });
                r.st.textContent = 'Queued — ready to execute now.';
              } else {
                r.st.textContent = 'Queued — co-sign + execute it in the ' + queueTabName + ' tab’s “Pending Multisig Transactions”.';
              }
            } else {
              await refreshOnChainStatus(r); // re-read at the chosen nonce so a co-signer's earlier approval counts
              var chosen = r.chosenNonce, current = Number(r.ctx.nonce);
              if (chosen < current) { r.st.textContent = 'Nonce ' + chosen + ' already used on ' + r.chain + ' — set it to ≥ ' + current + '.'; staleNonce++; continue; }
              var iApproved = (r.approved || []).some(function (o) { return o.toLowerCase() === acct.toLowerCase(); });
              if (!iApproved) {
                setStatus('Approving on ' + r.chain + ' at nonce ' + chosen + ' (' + (i + 1) + '/' + live.length + ') — confirm in your wallet…', 'pending');
                await approveSafeHashOnChain(r.cid, safe, r.hash);
                r.approved = (r.approved || []).concat([acct]); approvedThisRun++;
                _onchainNonceHint[safe.toLowerCase() + ':' + r.cid + ':' + acct.toLowerCase()] = chosen + 1; _saveOnchainNonceHint(); // this signer's next onchain tx here defaults to the next nonce
              }
              if ((r.approved || []).length >= r.ctx.threshold) {
                if (chosen === current) {
                  setStatus('Executing on ' + r.chain + ' at nonce ' + chosen + ' (' + (i + 1) + '/' + live.length + ') — confirm in your wallet…', 'pending');
                  await executeSafeTx(r.cid, safe, { to: r.to, value: 0, data: r.data, operation: 0, safeTxGas: 0, baseGas: 0, gasPrice: 0, gasToken: ZERO_ADDRESS, refundReceiver: ZERO_ADDRESS, confirmations: r.approved.map(function (o) { return { owner: o }; }) });
                  r.done = true; r.st.textContent = 'Executed (nonce ' + chosen + ')'; executed++;
                } else {
                  // Fully approved but not next in line — the Safe executes in strict nonce order, so lower nonces
                  // run first. Left un-done so a later click (once the nonce is current) picks it up and executes it.
                  r.st.textContent = 'Fully approved at nonce ' + chosen + ' — executes after nonce ' + current + '-' + (chosen - 1) + ' run. Click again once they clear.'; pendingExec++;
                }
              } else {
                r.st.textContent = 'Approved ' + r.approved.length + ' / ' + r.ctx.threshold + ' at nonce ' + chosen + ' — needs ' + (r.ctx.threshold - r.approved.length) + ' more signer(s). Switch wallets and click again.'; pending++;
              }
            }
          }
          document.dispatchEvent(new CustomEvent('jb:safe-queued'));
          document.dispatchEvent(new CustomEvent('jb:bridge-updated'));
          btn.disabled = false; cancel.disabled = false;
          var summary = [];
          if (executed) summary.push('executed on ' + executed);
          if (queued) summary.push('queued on ' + queued);
          if (approvedThisRun) summary.push('approved on ' + approvedThisRun);
          if (pendingExec) summary.push(pendingExec + ' awaiting nonce order');
          var didSomething = (queued + executed + approvedThisRun) > 0;
          var base = (summary.join(' | ') || 'No new actions') + (skipped.length ? ' | skipped ' + skipped.join(', ') : '') + '.';
          lastResult = { queued: queued, executed: executed, skipped: skipped, cancelled: false, readyExecs: readyExecs.slice() };
          if (!didSomething && !pending && !pendingExec && !staleNonce && notOwner) {
            // Nothing happened because the connected wallet signs for none of these Safes — say so loudly.
            setStatus('Connected wallet ' + acct.slice(0, 6) + '… isn’t a signer of this Safe on ' + notOwner + ' selected chain' + (notOwner > 1 ? 's' : '') + '. Switch to an owner’s wallet and try again.', 'error');
          } else if (staleNonce) {
            // Chosen nonce is below the Safe's current nonce (already used) — actionable, so keep the modal open
            // with an error rather than the green-success + auto-close path.
            setStatus(base + ' ' + staleNonce + ' chain' + (staleNonce > 1 ? 's have' : ' has') + ' a stale nonce — raise it to the current value and click again.', 'error');
          } else if (readyExecs.length) {
            mode = 'executeReady';
            btn.textContent = readyExecs.length > 1 ? 'Execute all' : 'Execute';
            cancel.textContent = 'Do later';
            setStatus(base + ' ' + readyExecs.length + ' ready to execute now' + (pending ? '; ' + pending + ' still need another signer' : '') + '.', 'success');
          } else if (!pending && !pendingExec) {
            setStatus(base, 'success');
            setTimeout(function () { finish(lastResult); }, 2200);
          } else if (pending) {
            // Chains still short of threshold need a DIFFERENT signer — make clear the connected wallet is done.
            setStatus(base + (didSomething
              ? ' Your part is done — ' + pending + ' chain' + (pending > 1 ? 's' : '') + ' still need another signer. Switch to a different owner’s wallet, then click below.'
              : ' You’ve already approved every chain you can with this wallet. Switch to a different owner’s wallet to add their approval — ' + pending + ' remaining.'), didSomething ? 'success' : '');
            btn.textContent = 'Approve as another signer';
          } else {
            // pendingExec only: fully approved, but the Safe runs txs in strict nonce order — lower nonces execute
            // first. Keep the modal open so a later click executes the next once earlier nonces have cleared.
            setStatus(base + ' Fully approved — the Safe runs txs in nonce order; click again to execute the next once earlier nonces clear.', 'success');
            btn.textContent = 'Execute next in order';
          }
        } catch (e) {
          if (typeof console !== 'undefined') console.error('[safe-apply]', e);
          btn.disabled = false; cancel.disabled = false;
          var msg = (e && (e.shortMessage || e.message)) || String(e);
          // A wallet SUBMISSION-RPC failure (HTTP/internal error while broadcasting), NOT a contract revert or fee
          // problem — maxFeePerGas is already over-capped. Point the signer at the real fix (switch the chain's RPC in
          // their wallet) so they don't keep bumping gas in vain.
          if (/HTTP client error|internal error|RPC submit|InternalRpcError|-32603/i.test(msg)) {
            msg += ' — this is your wallet’s RPC failing to broadcast (not a gas/fee issue). Switch this chain’s RPC in your wallet (Base Sepolia → https://sepolia.base.org | Arbitrum Sepolia → https://sepolia-rollup.arbitrum.io/rpc) and click again.';
          }
          setStatus(msg, 'error');
        }
      })();
    });
  });
}

// A label-over-value cell for the onchain info grid.
function infoItem(label, valueNode) {
  var item = el('div', 'detail-info-item');
  var lbl = el('div', 'detail-info-label'); lbl.textContent = label; item.appendChild(lbl);
  var val = el('div', 'detail-info-value');
  if (typeof valueNode === 'string') val.textContent = valueNode; else val.appendChild(valueNode);
  item.appendChild(val);
  return item;
}

// ── Skeleton loaders ────────────────────────────────────────────────────────
// Ghost blocks that shimmer in the same layout the real data will fill — graceful, low-jank loading.
function skel(w, h, cls) {
  var b = el('div', 'skel' + (cls ? ' ' + cls : ''));
  if (w) b.style.width = w;
  if (h) b.style.height = h;
  return b;
}
// Whole-page detail ghost — mirrors renderProjectDetail's layout (header + two columns) so a direct
// project-route load shows the page shape immediately instead of a blank screen during the fetch.
function renderDetailSkeleton() {
  var wrap = el('div', 'project-detail detail-spacious');
  var back = el('button', 'detail-back'); back.textContent = '←'; back.title = 'Back to projects';
  back.addEventListener('click', function () { showProjectGrid(false); });
  wrap.appendChild(back);

  // Header: logo + two lines (name, then a wider subtitle) — kept minimal to avoid a noisy stack.
  var header = el('div', 'project-detail-header');
  var top = el('div', 'detail-head-top');
  top.appendChild(skel('64px', '64px'));
  var titleCol = el('div', 'detail-head-titlecol');
  titleCol.style.flex = '1'; titleCol.style.minWidth = '0'; // skel blocks are % width, so the column needs to claim the row
  titleCol.appendChild(skel('38%', '22px'));
  var tg = skel('64%', '12px'); tg.style.marginTop = '10px'; titleCol.appendChild(tg);
  top.appendChild(titleCol);
  header.appendChild(top);
  wrap.appendChild(header);

  var cols = el('div', 'project-detail-columns');

  // Left column: the Pay card as ONE block + a couple activity rows (avatar + single line).
  var left = el('div', 'project-detail-left');
  var payGhost = el('div', 'detail-card'); payGhost.appendChild(skel('100%', '170px')); left.appendChild(payGhost);
  var actGhost = el('div'); actGhost.style.marginTop = '22px';
  for (var a = 0; a < 3; a++) {
    var row = el('div'); row.style.display = 'flex'; row.style.alignItems = 'center'; row.style.gap = '10px'; row.style.margin = '14px 0';
    var av = skel('24px', '24px', 'skel-circle'); av.style.flex = '0 0 24px'; row.appendChild(av);
    row.appendChild(skel((58 - a * 8) + '%', '12px'));
    actGhost.appendChild(row);
  }
  left.appendChild(actGhost);
  cols.appendChild(left);

  // Right column: tab row + 3 price chips + one big chart block (dropped the noisy range-button row).
  var right = el('div', 'project-detail-right');
  var tabs = el('div', 'project-detail-tabs');
  for (var i = 0; i < 4; i++) { var t = skel('56px', '14px'); t.style.marginRight = '20px'; tabs.appendChild(t); }
  right.appendChild(tabs);
  var content = el('div', 'project-detail-content');
  var chips = el('div'); chips.style.display = 'flex'; chips.style.gap = '10px';
  for (var k = 0; k < 3; k++) { chips.appendChild(skel('32%', '46px')); }
  content.appendChild(chips);
  var chart = skel('100%', '320px'); chart.style.marginTop = '16px'; content.appendChild(chart);
  right.appendChild(content);
  cols.appendChild(right);
  wrap.appendChild(cols);
  return wrap;
}
// Ops-style table ghost: real header text up top, shimmer cells below (You / Settlement).
function skelOpsTable(headers, nRows) {
  var colClass = headers.length === 3 ? ' detail-ops-3' : (headers.length === 5 ? ' detail-ops-5' : '');
  var table = el('div', 'detail-ops-table skel-table');
  var head = el('div', 'detail-ops-row detail-ops-head' + colClass);
  headers.forEach(function (h) { var c = el('span', 'detail-ops-cell'); c.textContent = h; head.appendChild(c); });
  table.appendChild(head);
  for (var i = 0; i < nRows; i++) {
    var row = el('div', 'detail-ops-row' + colClass);
    headers.forEach(function (_, j) { var c = el('span', 'detail-ops-cell'); c.appendChild(skel(j === 0 ? '52%' : '60%', '11px')); row.appendChild(c); });
    table.appendChild(row);
  }
  return table;
}
// Owner-distribution ghost: a donut placeholder beside the holder table.
function skelOwnersDistribution() {
  var w = el('div', 'owners-distribution');
  var panel = el('div', 'owners-chart-panel');
  var donut = skel('170px', '170px', 'skel-circle'); donut.style.margin = '0 auto';
  panel.appendChild(donut);
  w.appendChild(panel);
  var wrap = el('div', 'owners-table-wrap');
  var table = el('div', 'owners-table');
  var head = el('div', 'owners-row owners-head');
  ['Account', 'Share', 'Chains', 'Paid'].forEach(function (h) { var c = el('span'); c.textContent = h; head.appendChild(c); });
  table.appendChild(head);
  for (var i = 0; i < 4; i++) {
    var row = el('div', 'owners-row');
    ['58%', '40%', '34%', '48%'].forEach(function (cw) { var c = el('span'); c.appendChild(skel(cw, '11px')); row.appendChild(c); });
    table.appendChild(row);
  }
  wrap.appendChild(table); w.appendChild(wrap);
  return w;
}
// Activity-feed ghost rows (avatar circle + meta + description). Returns a fragment to drop into the feed.
function skelActivityRows(n) {
  var frag = document.createDocumentFragment();
  for (var i = 0; i < n; i++) {
    var row = el('div', 'activity-row');
    var av = skel('24px', '24px', 'skel-circle'); av.style.flex = '0 0 24px'; av.style.marginTop = '2px';
    row.appendChild(av);
    var main = el('div', 'activity-main');
    main.appendChild(skel('26%', '9px'));
    var d = skel((62 - (i % 3) * 9) + '%', '11px'); d.style.marginTop = '7px'; main.appendChild(d);
    row.appendChild(main);
    frag.appendChild(row);
  }
  return frag;
}
// Generic class-driven table ghost (Auto issue / Bridges / Movement).
function skelGenericTable(tableCls, rowCls, headCls, headers, widths, nRows) {
  var table = el('div', tableCls);
  var head = el('div', rowCls + ' ' + headCls);
  headers.forEach(function (h) { var c = el('span'); c.textContent = h; head.appendChild(c); });
  table.appendChild(head);
  for (var i = 0; i < nRows; i++) {
    var row = el('div', rowCls);
    widths.forEach(function (cw) { var c = el('span'); c.appendChild(skel(cw, '11px')); row.appendChild(c); });
    table.appendChild(row);
  }
  return table;
}

// Friendly labels for the activity event-type filter (keyed by the `type` set in activityRowFromEvent).
var ACTIVITY_TYPE_LABELS = {
  pay: 'Payments', cash_out: 'Cash outs', bridge: 'Bridges', payout: 'Payouts',
  reserved: 'Reserved distributions', auto_issue: 'Auto-issuance', borrow: 'Loans',
  repay: 'Loan repayments', liquidate: 'Liquidations', mint_nft: 'NFT mints',
  deploy_erc20: 'Token deploys', create: 'Project creation', add_to_balance: 'Add to balance',
  queue_ruleset: 'Ruleset changes', set_uri: 'Info updates', transfer: 'Ownership transfers',
  operator_perms: 'Permission changes', add_tier: 'Shop items added', remove_tier: 'Shop items removed',
  swap: 'Buyback swaps', buyback_pool: 'Buyback pools', bridge_claim: 'Bridge claims',
};
function activityTypeLabel(t) { return ACTIVITY_TYPE_LABELS[t] || String(t || 'activity').replace(/_/g, ' '); }

// A native <select> sizes to its WIDEST option, so a short selected label leaves a big gap before the
// caret. Shrink the select to fit just the selected option's text (+ room for the custom caret).
function fitSelectWidth(sel) {
  var opt = sel.options[sel.selectedIndex];
  if (!opt) return;
  var cs = getComputedStyle(sel);
  var meas = document.createElement('span');
  meas.style.cssText = 'position:absolute;visibility:hidden;white-space:pre;';
  meas.style.fontFamily = cs.fontFamily; meas.style.fontSize = cs.fontSize;
  meas.style.fontWeight = cs.fontWeight; meas.style.letterSpacing = cs.letterSpacing;
  meas.textContent = opt.text;
  document.body.appendChild(meas);
  var w = meas.getBoundingClientRect().width;
  document.body.removeChild(meas);
  sel.style.width = (Math.ceil(w) + 15) + 'px';
}

// Multi-select chain filter for the activity feed: a caret trigger that opens a checkbox popover, one
// row per chain the project is deployed on. `selected()` returns null when all (or none) are checked
// — the caller treats null as "no chain filter". onChange fires on every toggle.
// Generic checkbox-dropdown multi-select for the activity filters. config:
//   { allLabel, unit, trigger: 'logos'|'text', onChange }
// items (set via setItems) are { value, label, logo?:()=>node }. Defaults to all-selected; `selected()`
// returns null when all (or none) are checked — the caller treats null as "no filter". Selections are
// preserved by value across setItems() calls so a post-tx refresh doesn't reset the user's picks.
function makeMultiselect(config) {
  var items = [];
  var sel = {};
  var wrap = el('div', 'activity-ms');
  var trigger = el('button', 'activity-filter-select activity-ms-trigger');
  var menu = el('div', 'activity-chain-menu'); menu.style.display = 'none';
  wrap.appendChild(trigger); wrap.appendChild(menu);

  function count() { var n = 0; items.forEach(function (it) { if (sel[it.value]) n++; }); return n; }
  function isAll() { var n = count(); return n === 0 || n === items.length; }
  function refreshTrigger() {
    var chosen = isAll() ? items : items.filter(function (it) { return sel[it.value]; });
    trigger.title = isAll() ? config.allLabel : (chosen.length === 1 ? chosen[0].label : chosen.length + ' ' + config.unit);
    trigger.innerHTML = '';
    if (config.trigger === 'logos') {
      var stack = el('span', 'activity-chain-stack');
      chosen.forEach(function (it, i) {
        var logo = it.logo ? it.logo() : el('span');
        logo.style.position = 'relative';
        logo.style.zIndex = String(chosen.length - i); // leftmost on top
        stack.appendChild(logo);
      });
      trigger.appendChild(stack);
    } else {
      trigger.textContent = isAll() ? config.allLabel : (chosen.length === 1 ? chosen[0].label : chosen.length + ' ' + config.unit);
    }
  }
  function buildMenu() {
    menu.innerHTML = '';
    var all = el('label', 'activity-chain-opt activity-chain-all');
    var allCb = el('input', ''); allCb.type = 'checkbox'; allCb.checked = count() === items.length;
    allCb.addEventListener('change', function () {
      items.forEach(function (it) { sel[it.value] = allCb.checked; });
      buildMenu(); refreshTrigger(); config.onChange();
    });
    all.appendChild(allCb);
    var allTxt = el('span', ''); allTxt.textContent = config.allLabel; all.appendChild(allTxt);
    menu.appendChild(all);
    items.forEach(function (it) {
      var row = el('label', 'activity-chain-opt');
      var cb = el('input', ''); cb.type = 'checkbox'; cb.checked = !!sel[it.value];
      cb.addEventListener('change', function () { sel[it.value] = cb.checked; refreshTrigger(); config.onChange(); allCb.checked = count() === items.length; });
      row.appendChild(cb);
      if (it.logo) row.appendChild(it.logo());
      var nm = el('span', ''); nm.textContent = it.label; row.appendChild(nm);
      menu.appendChild(row);
    });
  }
  function outside(e) { if (!wrap.contains(e.target)) close(); }
  function open() { buildMenu(); menu.style.display = 'block'; document.addEventListener('mousedown', outside); }
  function close() { menu.style.display = 'none'; document.removeEventListener('mousedown', outside); }
  trigger.addEventListener('click', function (e) {
    e.preventDefault();
    if (menu.style.display === 'none') open(); else close();
  });

  refreshTrigger();
  return {
    el: wrap,
    setItems: function (newItems) {
      var prev = sel;
      items = newItems;
      sel = {};
      items.forEach(function (it) { sel[it.value] = (it.value in prev) ? prev[it.value] : true; });
      refreshTrigger();
    },
    selected: function () {
      if (isAll()) return null;
      return items.filter(function (it) { return sel[it.value]; }).map(function (it) { return it.value; });
    },
  };
}

function renderActivityCard(project, opts) {
  var card = el('div', 'detail-card');
  // Header row: title on the left, filter controls right-aligned.
  var head = el('div', 'activity-head');
  var title = el('div', 'detail-card-title');
  // When the card IS the "Activity" subtab (phones), the tab already says ACTIVITY — name the card "Recent".
  title.textContent = (opts && opts.asTab) ? 'Recent' : 'Activity';
  head.appendChild(title);
  // Filter controls (chain + event-type combos). Hidden until rows load and there's >1 value to pick.
  // Chain filter is a MULTI-select over every chain the project is deployed on; type is single-select.
  var filters = el('div', 'activity-filters'); filters.style.display = 'none';
  var typeMs = makeMultiselect({ allLabel: 'All', unit: 'events', trigger: 'text', onChange: function () { applyFilters(); } });
  var chainMs = makeMultiselect({ allLabel: 'All chains', unit: 'chains', trigger: 'logos', onChange: function () { applyFilters(); } });
  // Chain options follow the canonical order (DISCOVER_CHAINS / the project "On:" logos), deduped.
  var projChainIds = orderedProjectChainIds(project);
  chainMs.setItems(projChainIds.map(function (id) {
    return { value: id, label: chainById(id).name, logo: function () { return chainLogo(id, chainById(id).name); } };
  }));
  filters.appendChild(typeMs.el);
  filters.appendChild(chainMs.el);
  head.appendChild(filters);
  card.appendChild(head);

  var body = el('div', 'activity-feed');
  body.appendChild(skelActivityRows(5));
  card.appendChild(body);

  var allRows = [];

  function rebuildFilterOptions() {
    var types = [];
    allRows.forEach(function (r) { if (types.indexOf(r.type) === -1) types.push(r.type); });
    typeMs.setItems(types.map(function (t) { return { value: t, label: activityTypeLabel(t) }; }));
    typeMs.el.style.display = types.length > 1 ? '' : 'none';
    var multiChain = projChainIds.length > 1;
    chainMs.el.style.display = multiChain ? '' : 'none';
    filters.style.display = (multiChain || types.length > 1) ? '' : 'none';
  }

  function applyFilters() {
    var chainsSel = chainMs.selected(); // null = all chains
    var typesSel = typeMs.selected();   // null = all events
    // Type filter is per-row; group across chains FIRST so each merged row keeps its FULL chain set,
    // then keep groups that fired on at least one selected chain — the row still shows every chain it
    // ran on (including chains not in the filter), since the point is "this happened on my chain(s)".
    var typed = allRows.filter(function (r) { return !typesSel || typesSel.indexOf(r.type) !== -1; });
    var rows = groupActivityRows(typed).filter(function (g) {
      return !chainsSel || g.chains.some(function (c) { return chainsSel.indexOf(c.chainId) !== -1; });
    });
    body.innerHTML = '';
    if (!rows.length) {
      body.className = 'detail-card-body activity-empty';
      body.textContent = allRows.length ? 'No activity matches this filter.' : 'No indexed V6 activity yet.';
      return;
    }
    body.className = 'activity-feed';
    rows.forEach(function (row) { body.appendChild(renderActivityRow(row, project)); });
    if (opts && opts.onContent) opts.onContent();
  }

  // Load the sucker map first so the feed can relabel under-the-hood sucker cash outs as bridges.
  // `keepOnEmpty` (used by refreshes) leaves existing rows in place when a refetch returns nothing
  // yet — the indexer lags the chain by a few seconds after a tx confirms.
  function load(keepOnEmpty) {
    return fetchProjectSuckerMap(project).then(function (map) {
      project._suckerMap = map;
      return fetchProjectActivity(project);
    }).then(function (rows) {
      if (!body.isConnected) return rows;
      if (!rows.length) {
        if (keepOnEmpty) return rows;
        allRows = [];
        filters.style.display = 'none';
        body.innerHTML = '';
        body.className = 'detail-card-body activity-empty';
        body.textContent = 'No indexed V6 activity yet.';
        return rows;
      }
      allRows = rows;
      rebuildFilterOptions();
      applyFilters();
      return rows;
    }).catch(function () {
      if (!body.isConnected || keepOnEmpty) return [];
      body.className = 'detail-card-body activity-empty';
      body.textContent = 'Could not load activity from Bendystraw.';
      return [];
    });
  }

  // Refresh after a tx confirms. The indexer trails the chain, so retry a few times with backoff
  // until a new top row appears (or the attempts run out).
  card._refresh = function () {
    var before = body.querySelector('.activity-row');
    var beforeKey = before ? before.getAttribute('data-tx') : null;
    var attempt = 0;
    function poll() {
      attempt++;
      load(true).then(function () {
        var first = body.querySelector('.activity-row');
        var changed = first && first.getAttribute('data-tx') !== beforeKey;
        if (!changed && attempt < 5 && body.isConnected) setTimeout(poll, 2500);
      });
    }
    poll();
  };

  load(false);
  return card;
}

// Canonical chain display order — matches DISCOVER_CHAINS (the project "On:" logos and the filter).
// Chains not in the active network list sort last (by id) so nothing is ever dropped.
function chainOrderIndex(chainId) {
  for (var i = 0; i < DISCOVER_CHAINS.length; i++) if (DISCOVER_CHAINS[i].id === Number(chainId)) return i;
  return DISCOVER_CHAINS.length + Number(chainId);
}
// Project's chain ids in canonical order, deduped (project.chains is already DISCOVER_CHAINS-ordered).
function orderedProjectChainIds(project) {
  var ids = (project.chains || []).map(function (c) { return c.id; });
  if (!ids.length && project.chainId) ids = [Number(project.chainId)];
  var seen = {};
  return ids.filter(function (id) { if (seen[id]) return false; seen[id] = true; return true; })
    .sort(function (a, b) { return chainOrderIndex(a) - chainOrderIndex(b); });
}

// Collapse the same logical event replicated across chains (omnichain project creation, token deploy,
// etc.) into ONE row carrying many chain bubbles. Two rows merge when every display field matches AND
// they're on DIFFERENT chains — so genuinely-distinct same-chain events stay separate. Rows arrive
// timestamp-desc; first-fit bucketing preserves that order and the merged row shows the latest time.
function groupActivityRows(rows) {
  var buckets = {}, order = [];
  rows.forEach(function (r) {
    var key = [r.type, (r.account || r.from || '').toLowerCase(), r.action, r.tokenAmount || '', r.baseAmount || '', r.memo || ''].join('|');
    var list = buckets[key] || (buckets[key] = []);
    var g = null;
    for (var i = 0; i < list.length; i++) { if (!list[i]._seen[r.chainId]) { g = list[i]; break; } }
    if (!g) { g = { row: r, chains: [], _seen: {}, timestamp: r.timestamp }; list.push(g); order.push(g); }
    g.chains.push({ chainId: r.chainId, txHash: r.txHash });
    g._seen[r.chainId] = true;
    if (Number(r.timestamp) > Number(g.timestamp)) g.timestamp = r.timestamp;
  });
  order.forEach(function (g) { g.chains.sort(function (a, b) { return chainOrderIndex(a.chainId) - chainOrderIndex(b.chainId); }); });
  order.sort(function (a, b) { return Number(b.timestamp) - Number(a.timestamp); });
  return order.map(function (g) { g.row.chains = g.chains; g.row.timestamp = g.timestamp; return g.row; });
}

// A chain logo that links to this event's tx on that chain's explorer (plain logo if no explorer/tx).
function chainTxBubble(chainId, txHash) {
  var logo = chainLogo(chainId, chainById(chainId).name + (txHash ? ' — view transaction' : ''));
  var url = txUrl(chainId, txHash);
  if (!url) return logo;
  var a = document.createElement('a');
  a.href = url; a.target = '_blank'; a.rel = 'noopener noreferrer';
  a.className = 'activity-chain-link';
  a.appendChild(logo);
  return a;
}

// A chain logo that links to an address on that chain's explorer (plain logo if no explorer/address).
function chainAddrBubble(chainId, address) {
  var logo = chainLogo(chainId, chainById(chainId).name + (address ? ' — view on explorer' : ''));
  var base = CHAINS[chainId] && CHAINS[chainId].blockExplorers && CHAINS[chainId].blockExplorers.default && CHAINS[chainId].blockExplorers.default.url;
  if (!base || !address) return logo;
  var a = document.createElement('a');
  a.href = base.replace(/\/$/, '') + '/address/' + address;
  a.target = '_blank'; a.rel = 'noopener noreferrer';
  a.className = 'activity-chain-link';
  a.appendChild(logo);
  return a;
}

function renderActivityRow(row, project) {
  var item = el('div', 'activity-row');
  var chains = (row.chains && row.chains.length) ? row.chains : [{ chainId: row.chainId, txHash: row.txHash }];
  // Identity key for refresh diffing — all tx hashes in this (possibly merged) row.
  item.setAttribute('data-tx', chains.map(function (c) { return (c.txHash || '') + ':' + c.chainId; }).join(','));
  var avatar = el('span', 'activity-avatar');
  avatar.style.background = identGradient(row.account || row.from || row.txHash || String(row.timestamp || '0'));
  item.appendChild(avatar);

  var main = el('div', 'activity-main');
  var meta = el('div', 'activity-meta');
  // Single chain: the time itself links to the tx. Multiple: time is plain text (bubbles carry the links).
  if (chains.length === 1) {
    meta.appendChild(renderExplorerTxLink(chains[0].chainId, chains[0].txHash, timeAgo(row.timestamp)));
  } else {
    var t = el('span', 'activity-time'); t.textContent = timeAgo(row.timestamp); meta.appendChild(t);
  }
  var side = el('span', 'activity-side');
  if (row.baseAmount) {
    var amt = el('span', 'activity-base-amount');
    amt.textContent = row.baseAmount;
    side.appendChild(amt);
  }
  // Only fund flows get an in/out tag: IN = inbound payments & fees, OUT = outbound funds
  // (cash outs, loans). Token-only events (issuance, reserved, ERC20 deploy, project create) get none.
  if (row.direction === 'in' || row.direction === 'out') {
    var tag = el('span', 'activity-tag activity-tag--' + row.direction);
    tag.textContent = row.direction;
    side.appendChild(tag);
  }
  // One chain bubble per chain this event fired on, each linking to its own tx — packed side-by-side.
  var chainsWrap = el('span', 'activity-chains');
  chains.forEach(function (c) { chainsWrap.appendChild(chainTxBubble(c.chainId, c.txHash)); });
  side.appendChild(chainsWrap);
  meta.appendChild(side);
  main.appendChild(meta);

  var line = el('div', 'activity-line');
  // Until the ERC-20 is deployed, the project's tokens are non-transferable credits — say so.
  var unit = (project.tokenSymbol || 'tokens') + (project.tokenAddress ? '' : ' credits');
  if (row.system) {
    // No actor (synthesized from chain state, e.g. ruleset queueing) — the action stands alone.
    line.appendChild(document.createTextNode(row.action + (row.tokenAmount ? (' ' + row.tokenAmount + ' ' + unit) : '')));
  } else {
    line.appendChild(addressNode(row.account || row.from));
    line.appendChild(document.createTextNode(' ' + row.action + (row.tokenAmount ? (' ' + row.tokenAmount + ' ' + unit) : '')));
  }
  main.appendChild(line);

  if (row.memo) {
    var memo = el('div', 'activity-memo');
    memo.textContent = row.memo;
    main.appendChild(memo);
  }

  item.appendChild(main);
  return item;
}

function activityRowFromEvent(event, project) {
  var sym = project.tokenSymbol || 'tokens';
  var chainId = Number(event.chainId);
  if (event.payEvent) {
    var pay = event.payEvent;
    var minted = toBigInt(pay.newlyIssuedTokenCount);
    return {
      type: 'pay',
      direction: 'in',
      chainId: chainId,
      txHash: pay.txHash || event.txHash,
      timestamp: Number(pay.timestamp || event.timestamp),
      account: pay.beneficiary || event.from || pay.from,
      from: pay.from || event.from,
      baseAmount: indexedActivityAmount(pay.amountUsd),
      tokenAmount: minted > 0n ? formatCompactTokenAmount(minted) : '',
      action: minted > 0n ? 'got' : 'paid into ' + sym,
      memo: pay.memo || '',
    };
  }
  if (event.cashOutTokensEvent) {
    var cash = event.cashOutTokensEvent;
    // A sucker cashes out under the hood when it bridges (prepare()). Relabel that as a bridge so users
    // don't see a confusing "cashed out" — the cash out is an internal abstraction. Detect by the actor
    // being one of the project's local suckers; the map value is the destination chain.
    // Bendystraw may set `from` to the EOA caller while holder/beneficiary are the sucker — so test ALL.
    // Key by this event's chain (suckers share addresses across chains; the remote differs per source chain).
    var smap = (project._suckerMap && project._suckerMap[chainId]) || {};
    var bridgeRemote = null, bridgeActor = null;
    [cash.holder, cash.beneficiary, cash.from, event.from].forEach(function (cand) {
      if (bridgeRemote == null && cand && smap[cand.toLowerCase()] != null) { bridgeRemote = smap[cand.toLowerCase()]; bridgeActor = cand; }
    });
    if (bridgeRemote != null) {
      return {
        type: 'bridge', direction: 'out', chainId: chainId,
        txHash: cash.txHash || event.txHash, timestamp: Number(cash.timestamp || event.timestamp),
        account: bridgeActor, from: bridgeActor, baseAmount: '', tokenAmount: '',
        // This event is the bridge PREPARE (the under-the-hood cash out) — the tokens are queued, not yet
        // shipped. The actual send happens on toRemote (tracked in the Movement table). Label accordingly.
        action: 'sending ' + formatCompactTokenAmount(toBigInt(cash.cashOutCount)) + ' ' + sym + ' to ' + moveChainName(bridgeRemote),
        memo: '',
      };
    }
    return {
      type: 'cash_out',
      direction: 'out',
      chainId: chainId,
      txHash: cash.txHash || event.txHash,
      timestamp: Number(cash.timestamp || event.timestamp),
      account: cash.beneficiary || cash.holder || cash.from || event.from,
      from: cash.from || event.from,
      baseAmount: indexedActivityAmount(cash.reclaimAmountUsd),
      tokenAmount: formatCompactTokenAmount(toBigInt(cash.cashOutCount)),
      action: 'cashed out',
      memo: '',
    };
  }
  if (event.mintTokensEvent) {
    // mintTokensOf fires for pays too; only surface the ones a SUCKER caller minted — those are the
    // destination side of a bridge ("received from {source}"). Skip the rest (pays already show via payEvent).
    var mt = event.mintTokensEvent;
    var msmap = (project._suckerMap && project._suckerMap[chainId]) || {};
    var mintCaller = (mt.caller || mt.from || event.from || '').toLowerCase();
    var bridgeSrc = msmap[mintCaller];
    if (bridgeSrc == null) return null;
    return {
      type: 'bridge', direction: 'in', chainId: chainId,
      txHash: mt.txHash || event.txHash, timestamp: Number(mt.timestamp || event.timestamp),
      account: mt.beneficiary || event.from, from: mt.beneficiary || event.from, baseAmount: '', tokenAmount: '',
      action: 'got ' + formatCompactTokenAmount(toBigInt(mt.beneficiaryTokenCount)) + ' ' + sym + ' from ' + moveChainName(bridgeSrc),
      memo: '',
    };
  }
  if (event.sendPayoutsEvent) {
    var po = event.sendPayoutsEvent;
    return {
      type: 'payout', direction: 'out', chainId: chainId,
      txHash: po.txHash || event.txHash, timestamp: Number(po.timestamp || event.timestamp),
      account: po.caller || po.from || event.from, from: po.from || event.from,
      // The event does not identify its source token. Bendystraw's indexed USD value is the only exact
      // common denomination, so never label the raw amount with the project's primary accounting token.
      baseAmount: indexedActivityAmount(po.amountPaidOutUsd),
      tokenAmount: '', action: 'paid out', memo: '',
    };
  }
  if (event.sendReservedTokensToSplitsEvent) {
    var rs = event.sendReservedTokensToSplitsEvent;
    return {
      type: 'reserved', direction: '', chainId: chainId,
      txHash: rs.txHash || event.txHash, timestamp: Number(rs.timestamp || event.timestamp),
      account: rs.from || event.from, from: rs.from || event.from,
      baseAmount: '', tokenAmount: formatCompactTokenAmount(toBigInt(rs.tokenCount)),
      action: 'distributed reserved', memo: '',
    };
  }
  if (event.autoIssueEvent) {
    var ai = event.autoIssueEvent;
    return {
      // Token-only mint (no fund flow) → no in/out tag, like issuance/reserved.
      type: 'auto_issue', direction: null, chainId: chainId,
      txHash: ai.txHash || event.txHash, timestamp: Number(ai.timestamp || event.timestamp),
      account: ai.beneficiary || ai.from || event.from, from: ai.from || event.from,
      baseAmount: '', tokenAmount: formatCompactTokenAmount(toBigInt(ai.count)),
      action: 'auto-issued', memo: '',
    };
  }
  if (event.borrowLoanEvent) {
    var bo = event.borrowLoanEvent;
    return {
      type: 'borrow', direction: 'out', chainId: chainId,
      txHash: bo.txHash || event.txHash, timestamp: Number(bo.timestamp || event.timestamp),
      account: bo.beneficiary || bo.from || event.from, from: bo.from || event.from,
      baseAmount: formatSourceTokenAmount(bo.borrowAmount, bo.token, chainId, project),
      tokenAmount: '', action: 'borrowed against ' + formatCompactTokenAmount(toBigInt(bo.collateral)) + ' ' + sym, memo: '',
    };
  }
  if (event.repayLoanEvent) {
    var rp = event.repayLoanEvent;
    return {
      type: 'repay', direction: 'in', chainId: chainId,
      txHash: rp.txHash || event.txHash, timestamp: Number(rp.timestamp || event.timestamp),
      account: rp.from || event.from, from: rp.from || event.from,
      // RepayLoan does not index the loan's source token. Showing an unlabeled amount is safer than
      // attributing it to the project's first accounting context.
      baseAmount: '',
      tokenAmount: '', action: 'repaid loan', memo: '',
    };
  }
  if (event.liquidateLoanEvent) {
    var lq = event.liquidateLoanEvent;
    return {
      type: 'liquidate', direction: 'out', chainId: chainId,
      txHash: lq.txHash || event.txHash, timestamp: Number(lq.timestamp || event.timestamp),
      account: lq.from || event.from, from: lq.from || event.from,
      baseAmount: '',
      tokenAmount: '', action: 'loan liquidated', memo: '',
    };
  }
  if (event.mintNftEvent) {
    var nft = event.mintNftEvent;
    return {
      type: 'mint_nft', direction: 'in', chainId: chainId,
      txHash: nft.txHash || event.txHash, timestamp: Number(nft.timestamp || event.timestamp),
      account: nft.beneficiary || nft.from || event.from, from: nft.from || event.from,
      baseAmount: '',
      tokenAmount: '', action: 'minted NFT (item #' + nft.tierId + ')', memo: '',
    };
  }
  if (event.deployErc20Event) {
    var dep = event.deployErc20Event;
    return {
      type: 'deploy_erc20', direction: '', chainId: chainId,
      txHash: dep.txHash || event.txHash, timestamp: Number(dep.timestamp || event.timestamp),
      account: dep.from || event.from, from: dep.from || event.from,
      baseAmount: '', tokenAmount: '',
      action: 'deployed token ' + (dep.symbol || ''), memo: '',
    };
  }
  if (event.projectCreateEvent) {
    var pc = event.projectCreateEvent;
    return {
      type: 'create', direction: '', chainId: chainId,
      txHash: pc.txHash || event.txHash, timestamp: Number(pc.timestamp || event.timestamp),
      account: pc.from || event.from, from: pc.from || event.from,
      baseAmount: '', tokenAmount: '', action: 'created the project', memo: '',
    };
  }
  if (event.addToBalanceEvent) {
    var atb = event.addToBalanceEvent;
    return {
      // Inbound funds with no token mint → IN tag, no token amount.
      type: 'add_to_balance', direction: 'in', chainId: chainId,
      txHash: atb.txHash || event.txHash, timestamp: Number(atb.timestamp || event.timestamp),
      account: atb.from || event.from, from: atb.from || event.from,
      baseAmount: '',
      tokenAmount: '', action: 'added to balance', memo: atb.memo || '',
    };
  }
  // --- New indexed project-config / shop / market / bridge events (bendystraw PR #14, #12). ---
  if (event.setUriEvent) {
    var su = event.setUriEvent;
    return { type: 'set_uri', direction: '', chainId: chainId, txHash: su.txHash || event.txHash, timestamp: Number(su.timestamp || event.timestamp),
      account: su.from || su.caller || event.from, from: su.from || event.from, baseAmount: '', tokenAmount: '', action: 'updated project info', memo: '' };
  }
  if (event.projectTransferEvent) {
    var pt = event.projectTransferEvent;
    return { type: 'transfer', direction: '', chainId: chainId, txHash: pt.txHash || event.txHash, timestamp: Number(pt.timestamp || event.timestamp),
      account: pt.previousOwner || pt.from || event.from, from: pt.from || event.from, baseAmount: '', tokenAmount: '',
      action: 'transferred ownership' + (pt.owner ? ' to ' + truncAddr(pt.owner) : ''), memo: '' };
  }
  if (event.operatorPermissionsSetEvent) {
    var op = event.operatorPermissionsSetEvent;
    return { type: 'operator_perms', direction: '', chainId: chainId, txHash: op.txHash || event.txHash, timestamp: Number(op.timestamp || event.timestamp),
      account: op.from || op.caller || event.from, from: op.from || event.from, baseAmount: '', tokenAmount: '',
      action: 'set ' + (op.isRevnetOperator ? 'revnet operator' : 'operator') + ' permissions' + (op.operator ? ' for ' + truncAddr(op.operator) : ''), memo: '' };
  }
  if (event.addNftTierEvent) {
    var at = event.addNftTierEvent;
    return { type: 'add_tier', direction: '', chainId: chainId, txHash: at.txHash || event.txHash, timestamp: Number(at.timestamp || event.timestamp),
      account: at.from || at.caller || event.from, from: at.from || event.from, baseAmount: '', tokenAmount: '', action: 'added shop item #' + Number(at.tierId), memo: '' };
  }
  if (event.removeNftTierEvent) {
    var rt = event.removeNftTierEvent;
    return { type: 'remove_tier', direction: '', chainId: chainId, txHash: rt.txHash || event.txHash, timestamp: Number(rt.timestamp || event.timestamp),
      account: rt.from || rt.caller || event.from, from: rt.from || event.from, baseAmount: '', tokenAmount: '', action: 'removed shop item #' + Number(rt.tierId), memo: '' };
  }
  if (event.swapEvent) {
    var sw = event.swapEvent;
    return { type: 'swap', direction: 'in', chainId: chainId, txHash: sw.txHash || event.txHash, timestamp: Number(sw.timestamp || event.timestamp),
      account: sw.from || sw.caller || event.from, from: sw.from || event.from,
      baseAmount: '', tokenAmount: sw.projectTokenAmount ? formatCompactTokenAmount(toBigInt(sw.projectTokenAmount)) : '',
      action: 'bought ' + sym + ' via the buyback pool', memo: '' };
  }
  if (event.buybackPoolEvent) {
    var bp = event.buybackPoolEvent;
    return { type: 'buyback_pool', direction: '', chainId: chainId, txHash: bp.txHash || event.txHash, timestamp: Number(bp.timestamp || event.timestamp),
      account: bp.from || bp.caller || event.from, from: bp.from || event.from, baseAmount: '', tokenAmount: '', action: 'set up a buyback pool', memo: '' };
  }
  if (event.bridgeClaimEvent) {
    var bc = event.bridgeClaimEvent;
    return { type: 'bridge_claim', direction: 'in', chainId: chainId, txHash: bc.txHash || event.txHash, timestamp: Number(bc.timestamp || event.timestamp),
      account: bc.beneficiary || bc.from || event.from, from: bc.from || event.from,
      baseAmount: '', tokenAmount: bc.projectTokenCount ? formatCompactTokenAmount(toBigInt(bc.projectTokenCount)) : '',
      action: 'claimed ' + sym + ' from ' + moveChainName(Number(bc.peerChainId)), memo: '' };
  }
  var label = String(event.type || 'activity').replace(/_/g, ' ').toLowerCase();
  return {
    type: label,
    direction: '',
    chainId: chainId,
    txHash: event.txHash,
    timestamp: Number(event.timestamp),
    account: event.from,
    from: event.from,
    baseAmount: '',
    tokenAmount: '',
    action: label,
    memo: '',
  };
}


var WEIGHT_CUT_DEN = 1000000000; // 1e9

// Full decoded ruleset rows grouped by section. r = ruleset tuple, m = decoded metadata tuple.
function rulesetRows(r, m, project) {
  var baseUnit = currencyUnitLabel(m.baseCurrency, project);
  return [
    ['CYCLE', 'Duration', Number(r.duration) ? formatDuration(r.duration) : 'Not set'],
    ['CYCLE', 'Start time', formatStartTime(r.start)],
    ['CYCLE', 'Rule change deadline', (r.approvalHook && r.approvalHook !== ZERO_ADDRESS) ? truncAddr(r.approvalHook) : 'No deadline'],
    ['TOKEN', 'Total issuance rate', (Number(r.weight) === 0 ? '0' : formatAmount(r.weight, 18)) + ' / ' + baseUnit],
    ['TOKEN', 'Reserved rate', percentFromRuleset(m.reservedPercent)],
    ['TOKEN', 'Issuance cut percent', (Number(r.weightCutPercent) / 1e7).toFixed(2) + '%'],
    ['TOKEN', 'Cash out tax rate', percentFromRuleset(m.cashOutTaxRate)],
    ['TOKEN', 'Cash outs use total surplus', m.useTotalSurplusForCashOuts ? 'Enabled' : 'Disabled'],
    ['TOKEN', 'Base currency', baseUnit],
    ['TOKEN', 'Owner token minting', m.allowOwnerMinting ? 'Enabled' : 'Disabled'],
    ['TOKEN', 'Token transfers', m.pauseCreditTransfers ? 'Disabled' : 'Enabled'],
    ['OTHER RULES', 'Payments to this project', m.pausePay ? 'Disabled' : 'Enabled'],
    ['OTHER RULES', 'Hold fees', m.holdFees ? 'Enabled' : 'Disabled'],
    ['OTHER RULES', 'Owner must send payouts', m.ownerMustSendPayouts ? 'Enabled' : 'Disabled'],
    ['OTHER RULES', 'Set payment terminals', m.allowSetTerminals ? 'Enabled' : 'Disabled'],
    ['OTHER RULES', 'Set controller', m.allowSetController ? 'Enabled' : 'Disabled'],
    ['OTHER RULES', 'Migrate payment terminal', m.allowTerminalMigration ? 'Enabled' : 'Disabled'],
    ['OTHER RULES', 'Set custom token', m.allowSetCustomToken ? 'Enabled' : 'Disabled'],
    ['OTHER RULES', 'Add accounting context', m.allowAddAccountingContext ? 'Enabled' : 'Disabled'],
    ['OTHER RULES', 'Add price feed', m.allowAddPriceFeed ? 'Enabled' : 'Disabled'],
    ['EXTENSION', 'Data hook', (m.dataHook && m.dataHook !== ZERO_ADDRESS) ? truncAddr(m.dataHook) : 'None'],
    ['EXTENSION', 'Use for payments', m.useDataHookForPay ? 'Enabled' : 'Disabled'],
    ['EXTENSION', 'Use for cash outs', m.useDataHookForCashOut ? 'Enabled' : 'Disabled'],
  ];
}

function formatDateTime(sec) {
  try { return new Date(Number(sec) * 1000).toLocaleString('en-US', { dateStyle: 'medium', timeStyle: 'short' }); }
  catch (e) { return '—'; }
}

// Coarse single-unit relative time, word form: "2 days" / "3 hours" / "1 minute".
function relativeFromNow(secs) {
  var s = Math.max(0, Number(secs));
  if (s >= 86400) { var d = Math.round(s / 86400); return d + (d === 1 ? ' day' : ' days'); }
  if (s >= 3600) { var h = Math.round(s / 3600); return h + (h === 1 ? ' hour' : ' hours'); }
  var m = Math.max(1, Math.round(s / 60)); return m + (m === 1 ? ' minute' : ' minutes');
}

// Start time: a future start (upcoming / projected cycles) leads with "In <relative>", with the absolute
// date alongside; a past/current start shows the absolute date only.
function formatStartTime(sec) {
  var s = Number(sec); var now = Math.floor(Date.now() / 1000);
  return s > now ? ('In ' + relativeFromNow(s - now) + ' (' + formatDateTime(s) + ')') : formatDateTime(s);
}

// Date only (no time) — e.g. "Feb 20, 2025" — for compact table cells.
function formatDateShort(sec) {
  try { return new Date(Number(sec) * 1000).toLocaleDateString('en-US', { dateStyle: 'medium' }); }
  catch (e) { return '—'; }
}

function normalizeUpcomingRuleset(res) {
  if (!res) return null;
  if (res.r && res.m) return res;
  if (res[0] && Number(res[0].id) !== 0) return { r: res[0], m: res[1] };
  return null;
}

function ruleChangeRows(curR, curM, nextR, nextM, project) {
  if (!curR || !curM || !nextR || !nextM) return [];
  try {
    var curRows = rulesetRows(curR, curM, project);
    var nextRows = rulesetRows(nextR, nextM, project);
    var out = [];
    nextRows.forEach(function (row, i) {
      if (!curRows[i] || row[1] === 'Start time') return;
      if (curRows[i][2] !== row[2]) out.push({ section: row[0], label: row[1], from: curRows[i][2], to: row[2] });
    });
    return out;
  } catch (_) { return []; }
}

function upcomingRuleChangeInfo(project, res) {
  var up = normalizeUpcomingRuleset(res);
  if (!up || !project || !project.ruleset || !project.metadata) return null;
  if (String(up.r.id) === String(project.ruleset.id)) return null;
  var changes = ruleChangeRows(project.ruleset, project.metadata, up.r, up.m, project);
  if (!changes.length) return null;
  return { r: up.r, m: up.m, changes: changes };
}

function fetchUpcomingRuleChangeInfo(project) {
  if (!project || !project.ruleset || !project.metadata || !project.chainId || project.id == null) return Promise.resolve(null);
  return controllerRead(project.chainId, project.id, upcomingRulesetAbi, 'upcomingRulesetOf', [BigInt(project.id)])
    .then(function (res) { return upcomingRuleChangeInfo(project, res); })
    .catch(function () { return null; });
}

function ruleChangeTimeText(r) {
  var start = Number(r && r.start) || 0;
  var now = Math.floor(Date.now() / 1000);
  if (start > now) return 'Rules change in ' + relativeFromNow(start - now) + ' (' + formatDateTime(start) + ')';
  return 'Rules change when the queued cycle starts';
}

// Project a ruleset to a cycle offset by decaying/un-decaying weight per cycle (rules unchanged).
function cycleRuleset(r, offset) {
  var cut = Number(r.weightCutPercent);
  var dur = Number(r.duration);
  var factor = Math.pow((WEIGHT_CUT_DEN - cut) / WEIGHT_CUT_DEN, offset);
  var w = BigInt(Math.round(Number(r.weight) * factor));
  return {
    cycleNumber: Math.max(1, Number(r.cycleNumber) + offset),
    id: r.id, basedOnId: r.basedOnId,
    start: BigInt(Number(r.start) + offset * dur),
    duration: r.duration, weight: w, weightCutPercent: r.weightCutPercent,
    approvalHook: r.approvalHook, metadata: r.metadata,
  };
}

// "Rulesets & Funds" tab for owned (non-revnet) projects.
function renderRulesetsFundsSection(project) {
  var section = el('div', 'detail-section');
  if (!project.ruleset || !project.metadata) {
    section.appendChild(emptyCard('Rulesets', 'No active ruleset found onchain.'));
    return section;
  }
  var cur = { r: project.ruleset, m: project.metadata };
  var upcoming = null; // {r, m} once fetched
  var curRows = rulesetRows(cur.r, cur.m, project);

  // Per-cycle funds-access limits (payout limit + surplus allowance), keyed by ruleset id and cached
  // so stepping back and forth doesn't re-read. Config is per-ruleset, so it tracks the displayed cycle.
  var faPid = BigInt(project.id);
  var faTerminal = getAddress('JBMultiTerminal', project.chainId);
  var faLimits = getAddress('JBFundAccessLimits', project.chainId);
  var faSplits = getAddress('JBSplits', project.chainId);
  var faKindsP = acctKindsForFunds(project); // funds access + payout splits are per accounting context
  var faHome = project.chainId;
  var faCache = {};
  // Reserved-token splits are token-agnostic (group 1) — one set per ruleset.
  function loadReservedSplits(rid) {
    var key = 'res:' + rid;
    if (faCache[key]) return faCache[key];
    faCache[key] = faSplits
      ? read(faHome, 'JBSplits', splitsOfAbi, 'splitsOf', [faPid, BigInt(rid), RESERVED_TOKEN_SPLIT_GROUP])
      : Promise.reject(new Error('Splits contract unavailable.'));
    return faCache[key];
  }
  // Per-accounting-context funds access (payout limit + surplus allowance) + that token's payout splits.
  function loadFundsAccessForKind(rid, kind) {
    var tok = kind.addrForChain(faHome);
    var key = rid + ':' + kind.key;
    if (faCache[key]) return faCache[key];
    if (!(faLimits && faTerminal) || !tok) { faCache[key] = Promise.resolve(null); return faCache[key]; }
    var payoutGroup = BigInt(tok); // payout split group = uint256(uint160(token))
    var acct = { address: tok, decimals: kind.decimals, symbol: kind.symbol, currency: tokenCurrencyIdForAccounting(tok) };
    function formatLimits(values) {
      if (!values || !values.length) return 'None';
      return values.map(function (limit) {
        var meta = currencyMeta(limit.currency, acct);
        return toBigInt(limit.amount) >= (2n ** 200n) ? ('Unlimited ' + meta.symbol) : formatCurrencyAmount(limit.amount, meta);
      }).join(' + ');
    }
    faCache[key] = Promise.all([
      read(faHome, 'JBFundAccessLimits', payoutLimitsAbi, 'payoutLimitsOf', [faPid, BigInt(rid), faTerminal, tok]),
      read(faHome, 'JBFundAccessLimits', surplusAllowancesAbi, 'surplusAllowancesOf', [faPid, BigInt(rid), faTerminal, tok]),
      faSplits ? read(faHome, 'JBSplits', splitsOfAbi, 'splitsOf', [faPid, BigInt(rid), payoutGroup]) : Promise.reject(new Error('Splits contract unavailable.')),
    ]).then(function (r) {
      return {
        payout: formatLimits(r[0]),
        allowance: formatLimits(r[1]),
        payoutSplits: r[2] || [],
        payoutGroupId: payoutGroup,
      };
    });
    return faCache[key];
  }

  // ---- Rulesets viewer ----
  var rulesCard = el('div', 'detail-card');
  var headRow = el('div', 'rf-head');
  var headLeft = el('div', 'rf-headleft');
  var hTitle = el('div', 'detail-card-title'); hTitle.textContent = 'Rulesets'; hTitle.style.borderBottom = 'none'; hTitle.style.margin = '0';
  headLeft.appendChild(hTitle);
  var chainCtl = el('span', 'rf-chainctl'); headLeft.appendChild(chainCtl);
  headRow.appendChild(headLeft);
  // Queue a new ruleset (owner/operator-gated inside the modal).
  var queueBtn = el('button', 'detail-check-btn rf-queue-btn'); queueBtn.textContent = 'Queue ruleset';
  queueBtn.addEventListener('click', function () { openQueueRulesetModal(project); });
  headRow.appendChild(queueBtn);
  // The carousel arrows live inside the title (below) — the title itself is the cycle stepper.
  var prevBtn = document.createElement('button'); prevBtn.className = 'rf-arrow'; prevBtn.textContent = '←'; prevBtn.title = 'Earlier cycle';
  var nextBtn = document.createElement('button'); nextBtn.className = 'rf-arrow'; nextBtn.textContent = '→'; nextBtn.title = 'Later cycle';
  rulesCard.appendChild(headRow);

  var tiles = el('div', 'rf-titlebar'); rulesCard.appendChild(tiles);
  var upcomingNotice = el('div', 'rf-upcoming-notice'); rulesCard.appendChild(upcomingNotice);
  var rulesBox = el('div', 'rf-rulesbox'); rulesCard.appendChild(rulesBox);
  section.appendChild(rulesCard);

  var offset = 0; // 0 = current; 1 = upcoming; ± = projected cycles

  function viewAt(off) {
    if (off <= 0) {
      var base = cur;
      return { r: off === 0 ? base.r : cycleRuleset(base.r, off), m: base.m, projected: off !== 0 };
    }
    // off >= 1: base on the upcoming ruleset when available, else project the current one.
    if (upcoming) {
      return { r: off === 1 ? upcoming.r : cycleRuleset(upcoming.r, off - 1), m: upcoming.m, projected: off > 1 };
    }
    return { r: cycleRuleset(cur.r, off), m: cur.m, projected: true };
  }

  function render() {
    var v = viewAt(offset);
    var now = Math.floor(Date.now() / 1000);
    var cycleCtx = offset === 0 ? 'Current' : (offset === 1 ? 'Upcoming' : (offset > 0 ? 'Projected (+' + offset + ')' : 'Projected (' + offset + ')'));
    var remaining = '—';
    if (offset === 0 && Number(v.r.duration) > 0) {
      var end = Number(v.r.start) + Number(v.r.duration);
      remaining = end > now ? formatCountdown(end - now) : 'Ended';
    } else if (Number(v.r.duration) > 0) {
      remaining = formatDuration(v.r.duration);
    }
    // Title-like header that doubles as the cycle carousel: "← Cycle #1 Current →".
    var statusTxt = (v.r.approvalHook && v.r.approvalHook !== ZERO_ADDRESS) ? 'Approval hook' : 'Unlocked';
    var remLabel = offset === 0 ? 'Remaining' : 'Duration';
    tiles.innerHTML = '';
    // 2-col grid: ← arrow in col 1 (centered against the title line); the cycle line + meta in col 2,
    // so the meta aligns under "Cycle #N" (not under the arrow) while both arrows center on the title.
    var tmain = el('div', 'rf-title-main');
    tmain.appendChild(prevBtn);
    var tline = el('div', 'rf-title-line');
    var big = el('span', 'rf-title-cycle'); big.textContent = 'Cycle #' + String(v.r.cycleNumber); tline.appendChild(big);
    var ctxEl = el('span', 'rf-title-ctx'); ctxEl.textContent = cycleCtx; tline.appendChild(ctxEl);
    tline.appendChild(nextBtn);
    tmain.appendChild(tline);
    var meta = el('div', 'rf-title-meta');
    var st = el('span'); st.textContent = statusTxt; meta.appendChild(st);
    meta.appendChild(boSep());
    var rm = el('span'); rm.textContent = remLabel + ': ' + remaining; meta.appendChild(rm);
    // Ruleset ID — the onchain id (queue timestamp). Only real for an actual ruleset (projected cycles have id 0).
    if (Number(v.r.id) > 0) { meta.appendChild(boSep()); var idEl = el('span'); idEl.textContent = 'ID: ' + String(v.r.id); meta.appendChild(idEl); }
    tmain.appendChild(meta);
    tiles.appendChild(tmain);
    renderUpcomingNotice();

    // Can't project earlier than the first cycle — disable the back arrow at cycle #1.
    prevBtn.disabled = Number(v.r.cycleNumber) <= 1;
    // No real next cycle when this ruleset doesn't auto-cycle (duration 0) AND no distinct upcoming is
    // queued — don't let the user step into a phantom "Cycle #N". (`upcoming` null = not yet fetched.)
    var autoCycles = Number(v.r.duration) > 0;
    var hasQueuedUpcoming = upcoming && upcoming.r && Number(upcoming.r.id) !== 0;
    nextBtn.disabled = offset >= 0 && !autoCycles && upcoming !== null && !(offset === 0 && hasQueuedUpcoming);

    // Rules detail (with diff vs current when not the current cycle).
    rulesBox.innerHTML = '';
    var rows = rulesetRows(v.r, v.m, project);
    // Group rows by section. Sections are placed into two columns by NAME (not round-robin) so the
    // split sub-sections sit with their parents: RESERVED TOKEN SPLITS under TOKEN, PAYOUT SPLITS under
    // FUNDS ACCESS. A single full-width list would strand each value ~1500px from its label.
    var groups = [], gIdx = {};
    rows.forEach(function (row, i) {
      var g = gIdx[row[0]];
      if (g === undefined) { g = gIdx[row[0]] = groups.length; groups.push({ name: row[0], items: [] }); }
      groups[g].items.push({ row: row, i: i });
    });
    var byName = {}; groups.forEach(function (g) { byName[g.name] = g; });
    var grid = el('div', 'rf-grid'); rulesBox.appendChild(grid);
    var leftCol = el('div', 'rf-col'); grid.appendChild(leftCol);
    var rightCol = el('div', 'rf-col'); grid.appendChild(rightCol);
    var placed = {};
    function renderGroup(col, name) {
      var g = byName[name]; if (!g) return; placed[name] = true;
      var sh = el('div', 'rf-section'); sh.textContent = g.name; col.appendChild(sh);
      g.items.forEach(function (it) {
        // Start time always differs cycle-to-cycle (it's the cycle's own start), so the red before-value is
        // just noise — show ONLY the green new value (highlighted) for a non-current cycle, plain otherwise.
        if (it.row[1] === 'Start time') {
          col.appendChild(offset !== 0 ? rfNewRow(it.row[1], it.row[2]) : kvRow(it.row[1], it.row[2]));
        } else {
          var changed = offset !== 0 && curRows[it.i] && curRows[it.i][2] !== it.row[2];
          col.appendChild(changed ? rfDiffRow(it.row[1], curRows[it.i][2], it.row[2]) : kvRow(it.row[1], it.row[2]));
        }
      });
    }

    // Split sub-section header + recipient box (filled async by loadFundsAccess).
    function splitsSection(col, title) {
      var sh = el('div', 'rf-section'); sh.textContent = title; col.appendChild(sh);
      var box = el('div'); box.appendChild(kvRow('Recipients', '…')); col.appendChild(box);
      return { sh: sh, box: box };
    }
    // Subtle "Edit" CTA under a splits section (operator-gated inside the modal).
    function splitEditLink(col, onClick) {
      var foot = el('div', 'detail-about-foot'); foot.style.marginTop = '6px';
      var a = el('a', 'operator-cta'); a.href = '#'; a.textContent = 'Edit';
      a.addEventListener('click', function (e) { e.preventDefault(); onClick(); });
      foot.appendChild(a); col.appendChild(foot);
      return foot;
    }

    // LEFT: CYCLE | OTHER RULES | FUNDS ACCESS (+ payout splits beneath it).
    renderGroup(leftCol, 'CYCLE');
    renderGroup(leftCol, 'OTHER RULES');
    // LEFT FUNDS ACCESS — one "<TOKEN> FUNDS ACCESS" section per accounting context (USDC, ETH, …):
    // payout limit + surplus allowance + that token's payout splits. Filled async once kinds resolve.
    var faContainer = el('div', 'rf-fa'); faContainer.appendChild(kvRow('Payout limit per cycle', '…')); leftCol.appendChild(faContainer);

    // RIGHT: TOKEN (+ reserved token splits beneath it) | EXTENSION.
    renderGroup(rightCol, 'TOKEN');
    var rs = splitsSection(rightCol, 'RESERVED TOKEN SPLITS'); var rsBox = rs.box;
    var rsReserved = null;
    if (offset === 0) {
      splitEditLink(rightCol, function () {
        openEditSplitsModal(project, { groupId: RESERVED_TOKEN_SPLIT_GROUP, title: 'Edit reserved recipients', prefill: rsReserved || undefined, gateText: 'to edit reserved recipients.', note: 'Editing reserved token recipients for this ruleset cycle.' });
      });
    }
    renderGroup(rightCol, 'EXTENSION');
    // Any section rulesetRows adds in future that we didn't place explicitly → left column.
    groups.forEach(function (g) { if (!placed[g.name]) renderGroup(leftCol, g.name); });

    function fillSplits(box, splits, kind) {
      box.innerHTML = '';
      var sum = 0;
      (splits || []).forEach(function (sp) {
        var pct = Number(sp.percent) / 1e9 * 100; sum += pct;
        box.appendChild(splitConfigRow(splitAccountNode(sp, project, project.chainId, { kind: kind }), pct));
      });
      var leftover = 100 - sum;
      if (!splits || !splits.length || leftover > 0.0001) {
        var oNode = el('span'); oNode.textContent = 'Project’s owner';
        if (project.owner) { oNode.innerHTML = ''; oNode.appendChild(addressNode(project.owner, project.chainId)); }
        box.appendChild(splitConfigRow(oNode, (splits && splits.length) ? leftover : 100));
      }
    }

    // Reserved-token splits (single, token-agnostic).
    loadReservedSplits(v.r.id).then(function (splits) { rsReserved = splits; fillSplits(rsBox, splits, 'reserved'); }).catch(function () { rsBox.innerHTML = ''; rsBox.textContent = 'Could not verify reserved-token splits.'; });

    // Per-accounting-context funds access + payout splits.
    faKindsP.then(function (kinds) {
    faContainer.innerHTML = '';
      if (!kinds.length) { faContainer.remove(); return; }
      kinds.forEach(function (kind) {
        var secHead = el('div', 'rf-section'); secHead.textContent = kind.symbol + ' FUNDS ACCESS'; faContainer.appendChild(secHead);
        var faPayout = kvRow('Payout limit per cycle', '…'); faContainer.appendChild(faPayout);
        var faAllow = kvRow('Surplus allowance', '…'); faContainer.appendChild(faAllow);
        var psSh = el('div', 'rf-section'); psSh.textContent = kind.symbol + ' PAYOUT SPLITS'; faContainer.appendChild(psSh);
        var psBox = el('div'); psBox.appendChild(kvRow('Recipients', '…')); faContainer.appendChild(psBox);
        var foot = el('div', 'detail-about-foot'); foot.style.marginTop = '6px';
        var editA = el('a', 'operator-cta'); editA.href = '#'; editA.textContent = 'Edit'; foot.appendChild(editA);
        if (offset === 0) faContainer.appendChild(foot);
        loadFundsAccessForKind(v.r.id, kind).then(function (fa) {
          if (!fa) { secHead.remove(); faPayout.remove(); faAllow.remove(); psSh.remove(); psBox.remove(); foot.remove(); return; }
          faPayout.querySelector('.detail-ruleset-val').textContent = fa.payout;
          faAllow.querySelector('.detail-ruleset-val').textContent = fa.allowance;
          fillSplits(psBox, fa.payoutSplits, 'payout');
          if (offset === 0) editA.addEventListener('click', function (e) { e.preventDefault(); openEditSplitsModal(project, { groupId: fa.payoutGroupId, groupIdForChain: function (cid) { var token = kind.addrForChain(cid); return token ? BigInt(token) : null; }, title: 'Edit ' + kind.symbol + ' payout splits', prefill: fa.payoutSplits, gateText: 'to edit payout splits.', note: 'Editing ' + kind.symbol + ' payout recipients for this ruleset cycle.' }); });
        }).catch(function () {
          faPayout.querySelector('.detail-ruleset-val').textContent = '—';
          faAllow.querySelector('.detail-ruleset-val').textContent = '—';
          psBox.innerHTML = ''; psBox.textContent = 'Could not verify payout splits.'; foot.remove();
        });
      });
    }).catch(function () { faContainer.remove(); });
  }

  function renderUpcomingNotice() {
    upcomingNotice.innerHTML = '';
    var info = upcomingRuleChangeInfo(project, upcoming);
    if (offset !== 0 || !info) { upcomingNotice.style.display = 'none'; return; }
    upcomingNotice.style.display = '';
    var head = el('div', 'rf-upcoming-head');
    var title = el('div', 'rf-upcoming-title'); title.textContent = 'Upcoming rule changes'; head.appendChild(title);
    var when = el('div', 'rf-upcoming-time'); when.textContent = ruleChangeTimeText(info.r); head.appendChild(when);
    var view = el('button', 'detail-check-btn rf-upcoming-view'); view.textContent = 'View upcoming';
    view.addEventListener('click', function () { offset = 1; render(); });
    head.appendChild(view);
    upcomingNotice.appendChild(head);
    var diff = el('div', 'rf-upcoming-diff');
    info.changes.forEach(function (ch) {
      diff.appendChild(rfDiffRow(ch.section + ' | ' + ch.label, ch.from, ch.to));
    });
    upcomingNotice.appendChild(diff);
  }

  prevBtn.addEventListener('click', function () { if (prevBtn.disabled) return; offset -= 1; render(); });
  nextBtn.addEventListener('click', function () { if (nextBtn.disabled) return; offset += 1; ensureUpcoming(render); });

  function ensureUpcoming(cb) {
    if (upcoming !== null) { cb(); return; }
    controllerRead(project.chainId, project.id, upcomingRulesetAbi, 'upcomingRulesetOf', [BigInt(project.id)])
      .then(function (res) {
        // res = [ruleset, metadata]; treat a zero-id as "no distinct upcoming".
        if (res && res[0] && Number(res[0].id) !== 0) upcoming = { r: res[0], m: res[1] };
        else upcoming = false;
        cb();
      }).catch(function () { upcoming = false; cb(); });
  }

  render();
  // Resolve the upcoming ruleset up front so the next-arrow's disabled state (no real next cycle) is
  // accurate without a click — re-renders once known.
  ensureUpcoming(render);

  // Per-chain comparison: a chain dropdown if the ruleset's characteristics differ across chains,
  // else "Synced across all chains". Compares config (rules/flags), ignoring timing (start/cycle/weight).
  var pchains = project.chains || [];
  if (pchains.length > 1) {
    chainCtl.textContent = '…';
    var chainRs = {};
    chainRs[project.chainId] = cur;
    Promise.all(pchains.map(function (c) {
      if (chainRs[c.id]) return Promise.resolve();
      return controllerRead(c.id, project.id, currentRulesetAbi, 'currentRulesetOf', [BigInt(project.id)])
        .then(function (res) { if (res && res[0]) chainRs[c.id] = { r: res[0], m: res[1] }; }).catch(function () {});
    })).then(function () {
      var sigs = pchains.map(function (c) { return chainRs[c.id] ? rulesetSignature(chainRs[c.id].r, chainRs[c.id].m) : null; }).filter(Boolean);
      chainCtl.innerHTML = '';
      if (sigs.length > 1 && sigs.every(function (s) { return s === sigs[0]; })) {
        var syn = el('span', 'rf-synced'); syn.textContent = 'Synced across all chains'; chainCtl.appendChild(syn);
      } else {
        var sel = el('select', 'rf-chainselect');
        pchains.forEach(function (c) {
          if (!chainRs[c.id]) return;
          var o = document.createElement('option'); o.value = String(c.id); o.textContent = c.name;
          if (c.id === project.chainId) o.selected = true;
          sel.appendChild(o);
        });
        sel.addEventListener('change', function () {
          var cid = Number(sel.value);
          if (chainRs[cid]) { cur = chainRs[cid]; curRows = rulesetRows(cur.r, cur.m, project); offset = 0; upcoming = null; render(); }
        });
        chainCtl.appendChild(sel);
      }
    });
  }

  return section;
}

// Funds as its own tab (the funds card wrapped in a section).
function renderFundsSection(project) {
  var section = el('div', 'detail-section');
  section.appendChild(renderFundsCard(project));
  return section;
}

function renderProjectPayerAddresses(project) {
  var wrap = el('div', 'extras-payers');
  var head = el('div', 'extras-payers-head');
  var title = el('div', 'detail-subsection-title'); title.textContent = 'Deployed payer addresses'; head.appendChild(title);
  wrap.appendChild(head);
  var body = el('div', 'extras-payers-body');
  body.textContent = 'Loading payer addresses from Bendystraw…';
  wrap.appendChild(body);

  function countsText(row) {
    var pays = Number(row.paymentsCount || 0);
    var balances = Number(row.addToBalanceCount || 0);
    var parts = [];
    if (pays) parts.push(pays + ' pay');
    if (balances) parts.push(balances + ' balance');
    return parts.length ? parts.join(' | ') : 'No payments yet';
  }

  function facilitatedText(row) {
    var usd = usdFromScaled(row.totalFacilitatedUsd);
    if (usd && usd > 0) return formatUsd(usd);
    // Bendystraw's raw aggregate adds payment-token base units. Project payers can forward several tokens
    // with different decimals, so only the indexed USD aggregate has an honest common denomination.
    return toBigInt(row.totalFacilitated) > 0n ? 'Unpriced' : '$0';
  }

  function renderRows(rows) {
    body.innerHTML = '';
    if (!rows.length) {
      body.textContent = 'No deployed payer addresses indexed yet.';
      return;
    }
    var table = el('div', 'extras-payers-table');
    var header = el('div', 'extras-payers-row extras-payers-row--head');
    ['Chain', 'Address', 'Behavior', 'Facilitated'].forEach(function (label) {
      var cell = el('div'); cell.textContent = label; header.appendChild(cell);
    });
    table.appendChild(header);

    rows.forEach(function (row) {
      var r = el('div', 'extras-payers-row');
      var chain = el('div', 'extras-payers-chain');
      chain.appendChild(chainLogo(row.chainId, chainNameOf(row.chainId)));
      var cn = el('span'); cn.textContent = chainNameOf(row.chainId); chain.appendChild(cn);
      r.appendChild(chain);

      var addr = el('div', 'extras-payers-address');
      addr.appendChild(addressNode(row.address));
      var meta = el('div', 'extras-payers-sub');
      meta.textContent = row.createdAt ? ('Created ' + timeAgo(row.createdAt)) : '';
      addr.appendChild(meta);
      r.appendChild(addr);

      var behavior = el('div');
      var mode = el('div', 'extras-payers-main');
      mode.textContent = row.defaultAddToBalance ? 'Add to balance' : 'Pay';
      behavior.appendChild(mode);
      // Where minted tokens go — the routing detail payers differ by most often.
      var benef = el('div', 'extras-payers-sub');
      var benefAddr = row.defaultBeneficiary && !/^0x0{40}$/i.test(row.defaultBeneficiary) ? row.defaultBeneficiary : null;
      if (row.defaultAddToBalance) benef.textContent = 'No tokens minted';
      else if (benefAddr) {
        benef.textContent = 'Tokens mint to ' + truncAddr(benefAddr);
        benef.title = benefAddr;
        ensNameOf(benefAddr).then(function (n) { if (n && benef.isConnected) benef.textContent = 'Tokens mint to ' + n; }).catch(function () {});
      } else benef.textContent = 'Tokens mint to the sender';
      behavior.appendChild(benef);
      var count = el('div', 'extras-payers-sub'); count.textContent = countsText(row); behavior.appendChild(count);
      r.appendChild(behavior);

      var facilitated = el('div', 'extras-payers-amount');
      var amount = el('div', 'extras-payers-main'); amount.textContent = facilitatedText(row); facilitated.appendChild(amount);
      var last = el('div', 'extras-payers-sub');
      last.textContent = row.lastUsedAt ? ('Last used ' + timeAgo(row.lastUsedAt)) : 'Never used';
      facilitated.appendChild(last);
      r.appendChild(facilitated);

      table.appendChild(r);
    });
    body.appendChild(table);
  }

  async function load() {
    body.innerHTML = '';
    body.textContent = 'Loading payer addresses from Bendystraw…';
    try {
      var rows = await fetchProjectPayerRows(project);
      renderRows(rows);
    } catch (e) {
      body.innerHTML = '';
      body.textContent = 'Could not load payer addresses from Bendystraw.';
    }
  }

  wrap._refresh = load;
  load();
  return wrap;
}

async function runProjectPayerRelayrDeploys(calls, setStatus) {
  var ok = await confirmTransactionModal({
    via: 'Relayr — one prepaid payment calls the permissionless project-payer deployer on each chain below',
    action: 'Deploy payer address',
    chains: calls.map(function (c) {
      var nm = resolveContractName(c.to, c.chainId);
      return nm
        ? { chain: chainNameOf(c.chainId), chainId: c.chainId, contract: nm, address: c.to, calldata: c.data }
        : { chain: chainNameOf(c.chainId), chainId: c.chainId, contract: c.to, calldata: c.data };
    }),
  }, { title: 'Confirm payer address deployment', confirmText: 'Confirm & send' });
  if (!ok) { setStatus('Cancelled', ''); throw new Error('Cancelled'); }

  setStatus('Requesting Relayr quote…', 'pending');
  var bundle = await relayrPostBundle(calls.map(projectPayerRelayrEntry));
  var payments = bundle.payment_info || [];
  if (!payments.length) throw new Error('Relayr returned no payment option');
  var wallet = getWalletClient();
  var connectedChainId = wallet ? await wallet.getChainId().catch(function () { return null; }) : null;
  var payment = payments.filter(function (p) { return p.chain === connectedChainId; })[0] || payments[0];
  if (payment.chain !== connectedChainId) {
    setStatus('Switch your wallet to ' + (CHAINS[payment.chain] && CHAINS[payment.chain].name || payment.chain) + ' to pay…', 'pending');
    await switchChain(payment.chain);
  }
  setStatus('Confirm the Relayr payment…', 'pending');
  await relayrPay(payment);
  setStatus('Payment sent — relaying to ' + calls.length + ' chain' + (calls.length === 1 ? '' : 's') + '...', 'pending');
  await relayrPoll(bundle.bundle_uuid, function (records) {
    var done = records.filter(function (t) { return t.status && t.status.state === 'Success'; }).length;
    setStatus('Relaying… ' + done + '/' + records.length + ' chains confirmed', 'pending');
  });
}

// ---------------------------------------------------------------------------
// Existing project -> canonical .jb create draft
// ---------------------------------------------------------------------------

var PROJECT_DRAFT_SPLITS_TOTAL = 1000000000;
var PROJECT_DRAFT_UNLIMITED = 2n ** 200n;
var PROJECT_DRAFT_721_META_ABI = [
  { type: 'function', name: 'name', stateMutability: 'view', inputs: [], outputs: [{ type: 'string' }] },
  { type: 'function', name: 'symbol', stateMutability: 'view', inputs: [], outputs: [{ type: 'string' }] },
];
var PROJECT_DRAFT_721_FLAGS_ABI = [{
  type: 'function', name: 'flagsOf', stateMutability: 'view', inputs: [{ type: 'address' }],
  outputs: [{ type: 'tuple', components: [
    { name: 'noNewTiersWithReserves', type: 'bool' }, { name: 'noNewTiersWithVotes', type: 'bool' },
    { name: 'noNewTiersWithOwnerMinting', type: 'bool' }, { name: 'preventOverspending', type: 'bool' },
    { name: 'issueTokensForSplits', type: 'bool' },
  ] }],
}];
var PROJECT_DRAFT_SUCKER_PAIRS_ABI = [{
  type: 'function', name: 'suckerPairsOf', stateMutability: 'view', inputs: [{ name: 'projectId', type: 'uint256' }],
  outputs: [{ type: 'tuple[]', components: [
    { name: 'local', type: 'address' }, { name: 'remote', type: 'bytes32' }, { name: 'remoteChainId', type: 'uint256' },
  ] }],
}];
var PROJECT_DRAFT_SUCKER_DEPLOYER_ABI = [{ type: 'function', name: 'deployer', stateMutability: 'view', inputs: [], outputs: [{ type: 'address' }] }];

function draftFingerprint(value) {
  return JSON.stringify(value, function (_, v) { return typeof v === 'bigint' ? v.toString() : v; });
}

function draftCanonChainId(chainId) {
  var map = { 11155111: 1, 11155420: 10, 84532: 8453, 421614: 42161 };
  return map[Number(chainId)] || Number(chainId);
}

function draftPerChainSet(state, chainId, key, value) {
  var cid = draftCanonChainId(chainId);
  if (!state.perChain[cid]) state.perChain[cid] = {};
  if (!state.perChain[cid].addr) state.perChain[cid].addr = {};
  state.perChain[cid].addr[key] = value;
}

function draftRecipientFromSplit(split, percent, amount) {
  var projectId = Number(split && split.projectId || 0);
  if (!Number.isSafeInteger(projectId)) throw new Error('A split project ID is too large for the .jb editor.');
  var rec = {
    percent: Number(percent || 0), amountEth: amount || '', lockedUntil: Number(split && split.lockedUntil || 0),
    preferAddToBalance: !!(split && split.preferAddToBalance), projectId: projectId,
  };
  var hook = split && split.hook;
  if (hook && !isZeroishAddress(hook)) {
    rec.type = 'customhook'; rec.hookAddress = hook; rec.address = split.beneficiary || ZERO_ADDRESS;
  } else if (projectId > 0) {
    rec.type = 'project'; rec.address = split.beneficiary || ZERO_ADDRESS;
  } else {
    rec.type = 'wallet'; rec.address = (split && split.beneficiary) || ZERO_ADDRESS;
  }
  return rec;
}

function draftDeadlineFor(address, chainId) {
  if (isZeroishAddress(address)) return { key: 'none', address: '' };
  for (var i = 0; i < DEADLINE_OPTIONS.length; i++) {
    var option = DEADLINE_OPTIONS[i];
    var known = option.contract && getAddress(option.contract, chainId);
    if (known && sameAddr(known, address)) return { key: option.key, address: '' };
  }
  return { key: 'custom', address: address };
}

function draftStageFromLive(ruleset, metadata, reservedSplits, chainId) {
  var stage = createStage();
  stage.expanded = true;
  stage.durationSeconds = Number(ruleset.duration || 0);
  var weight = toBigInt(ruleset.weight || 0);
  stage.tokenMode = weight > 0n ? 'custom' : 'none';
  stage.weight = weight > 0n ? formatEther(weight) : '0';
  stage.weightCutPercent = Number(ruleset.weightCutPercent || 0) / 1e7;
  stage.issuanceCutOn = stage.weightCutPercent > 0;
  stage.baseCurrency = Number(metadata.baseCurrency || 1);
  stage.cashOutEnabled = Number(metadata.cashOutTaxRate || 0) < 10000;
  stage.cashOutTaxRate = Number(metadata.cashOutTaxRate || 0) / 100;
  stage.allowOwnerMinting = !!metadata.allowOwnerMinting;
  stage.pauseTransfers = !!metadata.pauseCreditTransfers;
  stage.pausePay = !!metadata.pausePay;
  stage.holdFees = !!metadata.holdFees;
  stage.allowSetTerminals = !!metadata.allowSetTerminals;
  stage.allowSetController = !!metadata.allowSetController;
  stage.allowTerminalMigration = !!metadata.allowTerminalMigration;
  stage.allowSetCustomToken = !!metadata.allowSetCustomToken;
  stage.allowAddAccountingContext = !!metadata.allowAddAccountingContext;
  stage.allowAddPriceFeed = !!metadata.allowAddPriceFeed;
  var deadline = draftDeadlineFor(ruleset.approvalHook, chainId);
  stage.deadline = deadline.key;
  var reservedRate = Number(metadata.reservedPercent || 0) / 100;
  stage.reservedRecipients = (reservedSplits || []).map(function (split) {
    return draftRecipientFromSplit(split, Number(split.percent || 0) / PROJECT_DRAFT_SPLITS_TOTAL * reservedRate, '');
  });
  return { stage: stage, customApproval: deadline.address };
}

function draftPayoutState(limit, splits, decimals, owner) {
  if (!limit || toBigInt(limit.amount) === 0n) return { mode: 'none', recipients: [] };
  var total = toBigInt(limit.amount);
  if (total >= PROJECT_DRAFT_UNLIMITED) {
    return { mode: 'unlimited', recipients: (splits || []).map(function (split) {
      return draftRecipientFromSplit(split, Number(split.percent || 0) / PROJECT_DRAFT_SPLITS_TOTAL * 100, '');
    }) };
  }
  var recipients = [], allocated = 0n;
  (splits || []).forEach(function (split) {
    var amount = total * toBigInt(split.percent || 0) / BigInt(PROJECT_DRAFT_SPLITS_TOTAL);
    allocated += amount;
    if (amount > 0n) recipients.push(draftRecipientFromSplit(split, 0, formatAmount(amount, decimals)));
  });
  // A finite payout's unallocated group remainder goes to the owner. Make it explicit in the new draft so
  // the reconstructed payout limit remains byte-for-byte the same total instead of silently shrinking.
  if (allocated < total) {
    recipients.push({ type: 'wallet', address: owner || ZERO_ADDRESS, projectId: 0, percent: 0,
      amountEth: formatAmount(total - allocated, decimals), lockedUntil: 0, preferAddToBalance: false,
      _ownerRemainder: true });
  }
  return { mode: 'limited', recipients: recipients };
}

async function draftLiveProjectChain(project, chain) {
  var chainId = Number(chain.id), pid = BigInt(project.id);
  var controller = await controllerAddressFor(chainId, pid);
  var canonicalController = getAddress('JBController', chainId);
  if (!canonicalController || !sameAddr(controller, canonicalController)) {
    throw new Error('This project uses a non-standard controller on ' + (chain.name || chainNameOf(chainId)) + ', which the create wizard cannot reproduce.');
  }
  var current = await clientFor(chainId).readContract({ address: controller, abi: currentRulesetAbi, functionName: 'currentRulesetOf', args: [pid] });
  if (!current || !current[0] || toBigInt(current[0].id || 0) === 0n) {
    current = await clientFor(chainId).readContract({ address: controller, abi: upcomingRulesetAbi, functionName: 'upcomingRulesetOf', args: [pid] });
  }
  if (!current || !current[0] || toBigInt(current[0].id || 0) === 0n || !current[1]) throw new Error('No live ruleset could be verified on ' + (chain.name || chainNameOf(chainId)) + '.');
  var contexts = await resolveAcctTokens(chainId, pid);
  var terminals = await read(chainId, 'JBDirectory', terminalsOfAbi, 'terminalsOf', [pid]);
  var owner = project.isRevnet
    ? await revnetOperatorOf(project.id, chainId)
    : await read(chainId, 'JBProjects', ownerOfAbi, 'ownerOf', [pid]);
  return { chain: chain, chainId: chainId, controller: controller, ruleset: current[0], metadata: current[1], contexts: contexts, terminals: terminals || [], owner: owner };
}

async function draftUpcomingProjectChain(source, project) {
  var upcoming = await clientFor(source.chainId).readContract({ address: source.controller, abi: upcomingRulesetAbi, functionName: 'upcomingRulesetOf', args: [BigInt(project.id)] });
  if (!upcoming || !upcoming[0] || toBigInt(upcoming[0].id || 0) === 0n || String(upcoming[0].id) === String(source.ruleset.id)) return null;
  return Object.assign({}, source, { ruleset: upcoming[0], metadata: upcoming[1] });
}

function draftContextKind(context, chainId) {
  if (sameAddr(context.address, NATIVE_TOKEN)) return 'eth';
  if (USDC_BY_CHAIN[chainId] && sameAddr(context.address, USDC_BY_CHAIN[chainId])) return 'usdc';
  return 'custom';
}

function draftRulesetFingerprint(source) {
  var r = source.ruleset, m = source.metadata;
  var hookRole = isZeroishAddress(m.dataHook) ? 'none'
    : (sameAddr(m.dataHook, getAddress('REVOwner', source.chainId)) ? 'revowner'
      : (sameAddr(m.dataHook, getAddress('JBOmnichainDeployer', source.chainId)) ? 'omnichain' : 'direct'));
  return draftFingerprint({
    duration: r.duration, weight: r.weight, weightCutPercent: r.weightCutPercent,
    approval: draftDeadlineFor(r.approvalHook, source.chainId).key,
    metadata: {
      reservedPercent: m.reservedPercent, cashOutTaxRate: m.cashOutTaxRate, baseCurrency: m.baseCurrency,
      pausePay: m.pausePay, pauseCreditTransfers: m.pauseCreditTransfers, allowOwnerMinting: m.allowOwnerMinting,
      allowSetCustomToken: m.allowSetCustomToken, allowTerminalMigration: m.allowTerminalMigration,
      allowSetTerminals: m.allowSetTerminals, allowSetController: m.allowSetController,
      allowAddAccountingContext: m.allowAddAccountingContext, allowAddPriceFeed: m.allowAddPriceFeed,
      ownerMustSendPayouts: m.ownerMustSendPayouts, holdFees: m.holdFees,
      scopeCashOutsToLocalBalances: m.useTotalSurplusForCashOuts, metadata: m.metadata,
      useDataHookForPay: m.useDataHookForPay, useDataHookForCashOut: m.useDataHookForCashOut, hookRole: hookRole,
    },
    contexts: source.contexts.map(function (ctx) { var kind = draftContextKind(ctx, source.chainId); return [kind, kind === 'custom' ? String(ctx.address).toLowerCase() : '', ctx.decimals]; })
      .sort(function (a, b) { return a[0].localeCompare(b[0]); }),
  });
}

function draftSplitFingerprint(split) {
  return [String(split.percent || 0), String(split.projectId || 0), String(split.beneficiary || '').toLowerCase(),
    !!split.preferAddToBalance, String(split.lockedUntil || 0), String(split.hook || '').toLowerCase()];
}

// Read each ruleset's fund-access state once. The same verified snapshot is used for both cross-chain
// comparison and draft construction, avoiding a second identical batch of splits/limits RPC calls.
export async function readDraftFunds(project, source, readContract) {
  readContract = readContract || read;
  var pid = BigInt(project.id), rid = toBigInt(source.ruleset.id), terminal = getAddress('JBMultiTerminal', source.chainId);
  var reserved = await readContract(source.chainId, 'JBSplits', splitsOfAbi, 'splitsOf', [pid, rid, RESERVED_TOKEN_SPLIT_GROUP]);
  var funds = await Promise.all(source.contexts.map(async function (context) {
    var values = await Promise.all([
      readContract(source.chainId, 'JBFundAccessLimits', payoutLimitsAbi, 'payoutLimitsOf', [pid, rid, terminal, context.address]),
      readContract(source.chainId, 'JBFundAccessLimits', surplusAllowancesAbi, 'surplusAllowancesOf', [pid, rid, terminal, context.address]),
      readContract(source.chainId, 'JBSplits', splitsOfAbi, 'splitsOf', [pid, rid, BigInt(context.address)]),
    ]);
    return { context: context, payouts: values[0] || [], allowances: values[1] || [], splits: values[2] || [] };
  }));
  return { reserved: reserved || [], funds: funds };
}

function draftFundsFingerprint(source, snapshot) {
  var rows = snapshot.funds.map(function (fund) {
    var context = fund.context;
    var tokenCurrency = tokenCurrencyIdForAccounting(context.address);
    function limits(list) { return (list || []).map(function (limit) {
      return [String(limit.amount), toBigInt(limit.currency) === tokenCurrency ? 'token' : String(limit.currency)];
    }); }
    var kind = draftContextKind(context, source.chainId);
    return { kind: kind, custom: kind === 'custom' ? String(context.address).toLowerCase() : '',
      payouts: limits(fund.payouts), allowances: limits(fund.allowances), splits: fund.splits.map(draftSplitFingerprint) };
  });
  rows.sort(function (a, b) { return a.kind.localeCompare(b.kind); });
  return draftFingerprint({ reserved: snapshot.reserved.map(draftSplitFingerprint), rows: rows });
}

function applyDraftOwnerRemainders(state, sources, project) {
  if (!state.stages || !state.stages.length || sources.length < 2) return;
  state.stages.forEach(function (stage, stageIndex) {
    (stage.reservedRecipients || []).forEach(function (recipient, index) {
      if (!recipient._ownerRemainder) return;
      sources.slice(1).forEach(function (source) {
        var owner = project.isRevnet ? getAddress('REVOwner', source.chainId) : source.owner;
        if (!sameAddr(owner, recipient.address)) draftPerChainSet(state, source.chainId, 'r:' + stageIndex + ':' + index, owner || ZERO_ADDRESS);
      });
      delete recipient._ownerRemainder;
    });
    (stage.payoutRecipients || []).forEach(function (recipient, index) {
      if (!recipient._ownerRemainder) return;
      sources.slice(1).forEach(function (source) {
        if (!sameAddr(source.owner, sources[0].owner)) draftPerChainSet(state, source.chainId, 'p:' + stageIndex + ':' + index, source.owner || ZERO_ADDRESS);
      });
      delete recipient._ownerRemainder;
    });
    Object.keys(stage.payoutByKind || {}).forEach(function (kind) {
      ((stage.payoutByKind[kind] || {}).recipients || []).forEach(function (recipient, index) {
        if (!recipient._ownerRemainder) return;
        sources.slice(1).forEach(function (source) {
          if (!sameAddr(source.owner, sources[0].owner)) draftPerChainSet(state, source.chainId, 'pk:' + kind + ':' + index, source.owner || ZERO_ADDRESS);
        });
        delete recipient._ownerRemainder;
      });
    });
  });
}

function applyDraftDetails(state, project) {
  var meta = project.projectMetadata || {};
  state.details.name = meta.name || project.name || '';
  state.details.ticker = String(meta.symbol || meta.ticker || project.tokenSymbol || project.metaSymbol || '').replace(/^\$/, '');
  state.details.tagline = meta.projectTagline || meta.tagline || project.tagline || '';
  state.details.description = meta.description || project.descriptionHtml || project.description || '';
  state.details.logoUri = meta.logoUri || '';
  state.details.coverImageUri = meta.coverImageUri || '';
  state.details.website = meta.infoUri || meta.domain || project.infoUri || '';
  state.details.twitter = meta.twitter || project.twitter || '';
  state.details.discord = meta.discord || project.discord || '';
  state.details.telegram = meta.telegram || project.telegram || '';
  state.details.whatsapp = meta.whatsapp || project.whatsapp || '';
  state.details.payDisclosure = meta.payDisclosure || project.payDisclosure || '';
  state.details.tags = Array.isArray(meta.tags) ? meta.tags.slice() : (project.tags || []).slice();
  state.storeCategories = Object.keys(project.storeCategories || {}).map(Number).filter(function (id) { return id > 0; })
    .sort(function (a, b) { return a - b; }).map(function (id) { return { id: id, name: String(project.storeCategories[id]) }; });
}

async function applyDraftAccountingAndTerminals(state, project, sources) {
  var home = sources[0];
  var kinds = home.contexts.map(function (ctx) { return draftContextKind(ctx, home.chainId); });
  if (kinds.filter(function (kind) { return kind === 'custom'; }).length) {
    if (home.contexts.length !== 1 || kinds[0] !== 'custom') throw new Error('The project mixes a custom accounting token with other contexts, which the .jb editor cannot reproduce.');
    state.accepts = ['custom'];
    state.customToken = { address: home.contexts[0].address, symbol: home.contexts[0].symbol || '', name: '', decimals: home.contexts[0].decimals, status: 'ok', error: '' };
  } else {
    state.accepts = ['eth', 'usdc'].filter(function (kind) { return kinds.indexOf(kind) !== -1; });
  }
  if (!state.accepts.length) throw new Error('No supported accounting context was found.');

  var routerModes = await Promise.all(sources.map(async function (source) {
    var multi = getAddress('JBMultiTerminal', source.chainId);
    var router = getAddress('JBRouterTerminalRegistry', source.chainId);
    var lower = source.terminals.map(function (address) { return String(address).toLowerCase(); });
    if (!multi || lower.indexOf(multi.toLowerCase()) === -1) throw new Error('The canonical terminal is missing on ' + (source.chain.name || chainNameOf(source.chainId)) + '.');
    var allowed = [multi.toLowerCase()]; if (router) allowed.push(router.toLowerCase());
    var unknown = lower.filter(function (address) { return allowed.indexOf(address) === -1; });
    if (unknown.length) throw new Error('The project uses a custom terminal on ' + (source.chain.name || chainNameOf(source.chainId)) + ', which the .jb editor cannot reproduce.');
    var usesRouter = !!(router && lower.indexOf(router.toLowerCase()) !== -1);
    if (usesRouter) {
      var target = await read(source.chainId, 'JBRouterTerminalRegistry', terminalOfAbi, 'terminalOf', [BigInt(project.id)]);
      var canonicalTarget = getAddress('JBRouterTerminal', source.chainId);
      if (!canonicalTarget || !sameAddr(target, canonicalTarget)) throw new Error('The project uses a custom router-terminal target on ' + (source.chain.name || chainNameOf(source.chainId)) + '.');
    }
    return usesRouter;
  }));
  if (routerModes.some(function (mode) { return mode !== routerModes[0]; })) throw new Error('Router-terminal use differs by chain, which one .jb draft cannot reproduce.');
  state.swapRouter = routerModes[0];
}

function draftChainFamily(chainId) {
  chainId = Number(chainId);
  if (chainId === 1 || chainId === 11155111) return 'ETH';
  if (chainId === 10 || chainId === 11155420) return 'OP';
  if (chainId === 8453 || chainId === 84532) return 'BASE';
  if (chainId === 42161 || chainId === 421614) return 'ARB';
  return '';
}

function draftSuckerDeployer(chainId, remoteChainId, type) {
  var localFamily = draftChainFamily(chainId), remoteFamily = draftChainFamily(remoteChainId);
  if (!localFamily || !remoteFamily) return null;
  if (type === 'native') {
    if (localFamily !== 'ETH' && remoteFamily !== 'ETH') return null;
    var rollup = localFamily === 'ETH' ? remoteFamily : localFamily;
    var name = rollup === 'OP' ? 'JBOptimismSuckerDeployer' : rollup === 'BASE' ? 'JBBaseSuckerDeployer' : rollup === 'ARB' ? 'JBArbitrumSuckerDeployer' : null;
    return name ? getAddress(name, chainId) : null;
  }
  var testnet = [11155111, 11155420, 84532, 421614].indexOf(Number(remoteChainId)) !== -1;
  return getAddress('JBCCIPSuckerDeployer__' + remoteFamily + (testnet ? '_SEP' : ''), chainId) || null;
}

async function applyDraftSuckers(state, project, sources, warnings) {
  var pid = BigInt(project.id), sourceIds = sources.map(function (source) { return source.chainId; });
  var rows = await Promise.all(sources.map(async function (source) {
    var registry = getAddress('JBSuckerRegistry', source.chainId);
    if (!registry) return { source: source, pairs: [] };
    var pairs = await clientFor(source.chainId).readContract({ address: registry, abi: PROJECT_DRAFT_SUCKER_PAIRS_ABI, functionName: 'suckerPairsOf', args: [pid] });
    var classified = await Promise.all((pairs || []).map(async function (pair) {
      var remoteId = Number(pair.remoteChainId);
      if (sourceIds.indexOf(remoteId) === -1) throw new Error('An active bridge points outside the project’s exported chain set.');
      // Suckers expose their factory directly; unlike 721/split-hook clones they predate Address Registry
      // registration, so this is the instance-native provenance proof for their bridge family.
      var deployer = await clientFor(source.chainId).readContract({ address: pair.local, abi: PROJECT_DRAFT_SUCKER_DEPLOYER_ABI, functionName: 'deployer', args: [] });
      var type = sameAddr(deployer, draftSuckerDeployer(source.chainId, remoteId, 'native')) ? 'native'
        : (sameAddr(deployer, draftSuckerDeployer(source.chainId, remoteId, 'ccip')) ? 'ccip' : null);
      if (!type) throw new Error('An active bridge instance was not produced by a known native or CCIP sucker deployer.');
      return { remoteId: remoteId, type: type };
    }));
    return { source: source, pairs: classified };
  }));
  if (sources.length === 1) {
    if (rows[0].pairs.length) throw new Error('The project has active bridges outside its visible chain set.');
    return;
  }
  var types = {};
  rows.forEach(function (row) { row.pairs.forEach(function (pair) { types[pair.type] = true; }); });
  state.suckerType = types.native && types.ccip ? 'both' : (types.ccip ? 'ccip' : (types.native ? 'native' : ''));
  if (!state.suckerType) throw new Error('The project spans multiple chains but has no reproducible active bridge topology.');
  rows.forEach(function (row) {
    var actual = row.pairs.map(function (pair) { return pair.remoteId + ':' + pair.type; }).sort();
    var expected = [];
    sourceIds.filter(function (remoteId) { return remoteId !== row.source.chainId; }).forEach(function (remoteId) {
      (state.suckerType === 'both' ? ['native', 'ccip'] : [state.suckerType]).forEach(function (type) {
        if (draftSuckerDeployer(row.source.chainId, remoteId, type)) expected.push(remoteId + ':' + type);
      });
    });
    expected.sort();
    if (draftFingerprint(actual) !== draftFingerprint(expected)) throw new Error('The active bridge topology cannot be reproduced by one .jb bridge setting.');
  });
  warnings.push('The .jb recreates the verified active bridge types; later custom token-mapping or deprecation changes are not included.');
}

function applyDraftFunds(state, project, source, stage, snapshot) {
  var reserved = snapshot.reserved;
  var built = draftStageFromLive(source.ruleset, source.metadata, reserved, source.chainId);
  Object.assign(stage, built.stage);
  if (built.customApproval) {
    if (state.approvalAddress && !sameAddr(state.approvalAddress, built.customApproval)) throw new Error('Rulesets use different custom approval-hook addresses, which one .jb draft cannot reproduce.');
    state.approvalAddress = built.customApproval;
  }
  var reservedShare = (reserved || []).reduce(function (sum, split) { return sum + Number(split.percent || 0); }, 0);
  var reservedRate = Number(source.metadata.reservedPercent || 0) / 100;
  if (reservedRate > 0 && reservedShare < PROJECT_DRAFT_SPLITS_TOTAL) {
    var reserveOwner = project.isRevnet ? getAddress('REVOwner', source.chainId) : source.owner;
    stage.reservedRecipients.push({ type: 'wallet', address: reserveOwner || ZERO_ADDRESS, projectId: 0,
      percent: (PROJECT_DRAFT_SPLITS_TOTAL - reservedShare) / PROJECT_DRAFT_SPLITS_TOTAL * reservedRate,
      amountEth: '', lockedUntil: 0, preferAddToBalance: false, _ownerRemainder: true });
  }

  var fundRows = snapshot.funds.map(function (fund) {
    if (fund.payouts.length > 1 || fund.allowances.length > 1) throw new Error('A ruleset has multiple fund-access currencies for one token, which the .jb editor cannot reproduce.');
    return { context: fund.context, kind: draftContextKind(fund.context, source.chainId),
      limit: fund.payouts[0], allowance: fund.allowances[0], splits: fund.splits };
  });
  if (Number(stage.durationSeconds || 0) <= 0 && [reserved].concat(fundRows.map(function (row) { return row.splits; }))
    .some(function (rows) { return (rows || []).some(function (split) { return Number(split.lockedUntil || 0) > 0; }); })) {
    throw new Error('A flexible live ruleset contains locked splits, which the .jb editor cannot preserve.');
  }

  var perToken = state.projectType === 'custom' && (state.accepts.length > 1 || state.accepts[0] === 'custom');
  if (perToken) {
    var allowanceModes = [];
    fundRows.forEach(function (row) {
      var expectedCurrency = tokenCurrencyIdForAccounting(row.context.address);
      if (row.limit && toBigInt(row.limit.amount) > 0n && toBigInt(row.limit.currency) !== expectedCurrency) {
        throw new Error('A per-token payout limit uses a different pricing currency, which the .jb editor cannot reproduce.');
      }
      var key = row.kind === 'custom' ? 'custom' : row.kind;
      stage.payoutByKind[key] = draftPayoutState(row.limit, row.splits, row.context.decimals, source.owner);
      var allowanceAmount = row.allowance ? toBigInt(row.allowance.amount) : 0n;
      if (allowanceAmount > 0n && allowanceAmount < PROJECT_DRAFT_UNLIMITED) throw new Error('A finite per-token surplus allowance cannot be reproduced by the .jb editor.');
      allowanceModes.push(allowanceAmount >= PROJECT_DRAFT_UNLIMITED);
    });
    if (allowanceModes.some(function (on) { return on !== allowanceModes[0]; })) throw new Error('Surplus allowance settings differ by accounting token.');
    stage.surplusAllowanceOn = !!allowanceModes[0]; stage.surplusAllowanceUnlimited = !!allowanceModes[0];
  } else {
    // The create flow configures revnet fund access against its first accounting context. Do not silently
    // discard live limits/splits on another accepted token which the .jb form cannot express.
    var row = fundRows.find(function (candidate) { return candidate.kind === state.accepts[0]; }) || fundRows[0];
    var unrepresentable = fundRows.filter(function (candidate) { return candidate !== row; }).some(function (candidate) {
      return (candidate.limit && toBigInt(candidate.limit.amount) > 0n)
        || (candidate.allowance && toBigInt(candidate.allowance.amount) > 0n)
        || (candidate.splits && candidate.splits.length);
    });
    if (unrepresentable) throw new Error('This revnet has fund access or payout splits on more than one accounting token, which the .jb editor cannot reproduce.');
    var payoutDecimals = row && row.limit ? fundAccessAmountDecimals(row.limit.currency, row.context) : row.context.decimals;
    var payout = draftPayoutState(row.limit, row.splits, payoutDecimals, source.owner);
    stage.payoutMode = payout.mode; stage.payoutRecipients = payout.recipients;
    if (row.limit) stage.payoutCurrency = Number(row.limit.currency);
    if (row.allowance && toBigInt(row.allowance.amount) > 0n) {
      stage.surplusAllowanceOn = true;
      stage.surplusAllowanceUnlimited = toBigInt(row.allowance.amount) >= PROJECT_DRAFT_UNLIMITED;
      stage.surplusAllowanceCurrency = Number(row.allowance.currency);
      if (!stage.surplusAllowanceUnlimited) {
        stage.surplusAllowanceAmount = formatAmount(row.allowance.amount, fundAccessAmountDecimals(row.allowance.currency, row.context));
      }
    }
  }
  return { reserved: reserved, funds: fundRows };
}

function draftTierFingerprint(tier) {
  return draftFingerprint({ id: tier.id, price: tier.price, initial: tier.initial, category: tier.category,
    encodedIpfsUri: tier.encodedIpfsUri, discountPercent: tier.discountPercent, reserveFrequency: tier.reserveFrequency,
    votingUnits: tier.votingUnits, reserveBeneficiary: String(tier.reserveBeneficiary || '').toLowerCase(),
    splitPercent: tier.splitPercent, flags: tier.flags });
}

async function applyDraftShop(state, project, sources, warnings) {
  var chainProjects = sources.map(function (source) { return Object.assign({}, project, { chainId: source.chainId }); });
  var shops = await Promise.all(chainProjects.map(function (p) { return fetchProjectTiers(p); }));
  var any = shops.some(Boolean);
  if (!any) {
    if (!project.isRevnet && sources.some(function (source) { return !isZeroishAddress(source.metadata.dataHook); })) throw new Error('The project uses a custom data hook which the .jb editor cannot reproduce.');
    return;
  }
  if (shops.some(function (shop) { return !shop; })) throw new Error('The shop is not present on every project chain.');
  var home = shops[0];
  var knownShops = await Promise.all(shops.map(function (shop, index) {
    return isKnown721HookClone(shop.hook, sources[index].chainId, project.id);
  }));
  if (knownShops.some(function (known) { return !known; })) {
    throw new Error('A shop hook is not a verified 721 instance from a known deployer in the Address Registry.');
  }
  // The shared display query is intentionally capped. Refuse to clone a possibly truncated shop instead of
  // exporting a draft which could omit tier #201 or later.
  if (home.tiers.length >= 200) throw new Error('This shop has at least 200 active items; the .jb exporter cannot verify that every item was enumerated.');
  shops.slice(1).forEach(function (shop) {
    if (Number(shop.pricing.currency) !== Number(home.pricing.currency) || Number(shop.pricing.decimals) !== Number(home.pricing.decimals)
      || draftFingerprint(shop.tiers.map(draftTierFingerprint)) !== draftFingerprint(home.tiers.map(draftTierFingerprint))) {
      throw new Error('The shop configuration differs by chain, which one .jb draft cannot reproduce.');
    }
  });

  var expectedShopDecimals = Number(home.pricing.currency) === 1 ? 18 : (Number(home.pricing.currency) === 2 ? 6 : null);
  if (state.accepts[0] === 'custom' && Number(home.pricing.currency) === Number(tokenCurrencyIdForAccounting(state.customToken.address))) {
    expectedShopDecimals = Number(state.customToken.decimals);
  }
  if (home.tiers.length && expectedShopDecimals == null) throw new Error('The shop uses a pricing currency the .jb editor cannot reproduce.');
  if (home.tiers.length && Number(home.pricing.decimals) !== expectedShopDecimals) throw new Error('The shop uses non-standard pricing decimals which the .jb editor cannot reproduce.');

  // Verify the per-tier permanent split groups on every chain too; tier structs only carry splitPercent, not
  // the destinations. Omitting this check could silently clone the right prices with the wrong recipients.
  var tierSplitFingerprints = await Promise.all(shops.map(async function (shop, sourceIndex) {
    var source = sources[sourceIndex];
    var rows = await Promise.all(shop.tiers.map(async function (tier) {
      if (!tier.splitPercent) return [tier.id, []];
      var group = BigInt(shop.hook) | (BigInt(tier.id) << 160n);
      var splits = await read(source.chainId, 'JBSplits', splitsOfAbi, 'splitsOf', [BigInt(project.id), 0n, group]);
      return [tier.id, (splits || []).map(draftSplitFingerprint)];
    }));
    return draftFingerprint(rows);
  }));
  if (tierSplitFingerprints.some(function (fingerprint) { return fingerprint !== tierSplitFingerprints[0]; })) {
    throw new Error('Shop item split recipients differ by chain, which one .jb draft cannot reproduce safely.');
  }

  if (project.isRevnet) {
    sources.forEach(function (source) {
      var expected = getAddress('REVOwner', source.chainId);
      if (!expected || !sameAddr(source.metadata.dataHook, expected)) throw new Error('The revnet data hook is not the verified REVOwner on ' + (source.chain.name || chainNameOf(source.chainId)) + '.');
    });
    var permissionRows = await Promise.all(sources.map(function (source) {
      var revOwner = getAddress('REVOwner', source.chainId);
      return read(source.chainId, 'JBPermissions', jbPermissionsOfAbi, 'permissionsOf', [source.owner || ZERO_ADDRESS, revOwner, BigInt(project.id)]);
    }));
    var permissionFingerprint = permissionRows.map(function (packed) {
      var bits = toBigInt(packed || 0); return [24, 25, 26, 27].map(function (id) { return ((bits >> BigInt(id)) & 1n) === 1n; });
    });
    if (permissionFingerprint.slice(1).some(function (row) { return draftFingerprint(row) !== draftFingerprint(permissionFingerprint[0]); })) {
      throw new Error('Revnet shop operator permissions differ by chain.');
    }
    state.collection.opCanAdjustTiers = permissionFingerprint[0][0];
    state.collection.opCanUpdateMetadata = permissionFingerprint[0][1];
    state.collection.opCanMint = permissionFingerprint[0][2];
    state.collection.opCanIncreaseDiscount = permissionFingerprint[0][3];
  } else {
    var redemptionModes = await Promise.all(sources.map(async function (source, index) {
      var dataHook = source.metadata.dataHook, omni = getAddress('JBOmnichainDeployer', source.chainId), shop = shops[index];
      if (omni && sameAddr(dataHook, omni)) {
        var extra = await clientFor(source.chainId).readContract({ address: omni, abi: OMNI_EXTRA_HOOK_ABI, functionName: 'extraDataHookOf', args: [BigInt(project.id), toBigInt(source.ruleset.id)] });
        var extraHook = extra && (extra.dataHook || extra[0]);
        if (!isZeroishAddress(extraHook)) throw new Error('This shop is composed with another custom data hook, which the .jb editor cannot reproduce.');
        var tierCfg = await clientFor(source.chainId).readContract({ address: omni, abi: OMNI_TIERED_HOOK_ABI, functionName: 'tiered721HookOf', args: [BigInt(project.id), toBigInt(source.ruleset.id)] });
        var configuredHook = tierCfg && (tierCfg.hook || tierCfg[0]);
        if (!sameAddr(configuredHook, shop.hook)) throw new Error('The omnichain wrapper’s shop hook could not be verified.');
        return !!(tierCfg && (tierCfg.useDataHookForCashOut != null ? tierCfg.useDataHookForCashOut : tierCfg[1]));
      }
      if (!sameAddr(dataHook, shop.hook)) throw new Error('The live data hook is not the verified shop hook.');
      return !!source.metadata.useDataHookForCashOut;
    }));
    if (redemptionModes.some(function (mode) { return mode !== redemptionModes[0]; })) throw new Error('Shop cash out behavior differs by chain.');
    state.collection.useForRedemptions = redemptionModes[0];
  }

  var metas = await Promise.all(shops.map(function (shop, index) {
    var client = clientFor(sources[index].chainId);
    return Promise.all([
      client.readContract({ address: shop.hook, abi: PROJECT_DRAFT_721_META_ABI, functionName: 'name', args: [] }).catch(function () { return ''; }),
      client.readContract({ address: shop.hook, abi: PROJECT_DRAFT_721_META_ABI, functionName: 'symbol', args: [] }).catch(function () { return ''; }),
      client.readContract({ address: shop.store, abi: PROJECT_DRAFT_721_FLAGS_ABI, functionName: 'flagsOf', args: [shop.hook] }).catch(function () { return null; }),
    ]);
  }));
  if (metas.slice(1).some(function (meta) { return draftFingerprint(meta) !== draftFingerprint(metas[0]); })) throw new Error('Shop collection metadata or flags differ by chain.');
  var meta = metas[0];
  state.shopEnabled = true; state.storePricingCurrency = Number(home.pricing.currency);
  state.collection.name = meta[0] || ''; state.collection.symbol = meta[1] || '';
  state.collection.nameTouched = !!meta[0]; state.collection.symbolTouched = !!meta[1];
  var flags = meta[2] || {};
  ['noNewTiersWithReserves', 'noNewTiersWithVotes', 'noNewTiersWithOwnerMinting', 'preventOverspending', 'issueTokensForSplits'].forEach(function (key) { state.collection[key] = !!flags[key]; });

  state.nfts = await Promise.all(home.tiers.map(async function (tier) {
    var media = await resolveTierMedia(home, tier, sources[0].chainId).catch(function () { return {}; });
    if (!media.name && !media.description && !media.image && !media.animationUrl) {
      warnings.push('Metadata for shop item #' + tier.id + ' could not be resolved. Its encoded IPFS value is preserved, but review the item name and media before deploying.');
    }
    var splitRows = [];
    if (tier.splitPercent > 0) {
      var group = BigInt(home.hook) | (BigInt(tier.id) << 160n);
      // 721 tier split groups are permanent shop configuration and are stored under ruleset ID 0.
      var splits = await read(sources[0].chainId, 'JBSplits', splitsOfAbi, 'splitsOf', [BigInt(project.id), 0n, group]);
      var splitShare = (splits || []).reduce(function (sum, split) { return sum + Number(split.percent || 0); }, 0);
      if (splitShare !== PROJECT_DRAFT_SPLITS_TOTAL) {
        throw new Error('Shop item #' + tier.id + ' has an implicit split remainder, which the .jb shop editor cannot reproduce.');
      }
      splitRows = (splits || []).map(function (split) {
        if (!isZeroishAddress(split.hook) || split.preferAddToBalance || Number(split.lockedUntil || 0) > 0) {
          throw new Error('Shop item #' + tier.id + ' uses advanced split behavior which the .jb shop editor cannot reproduce.');
        }
        var pct = Number(tier.splitPercent) / PROJECT_DRAFT_SPLITS_TOTAL * 100 * Number(split.percent) / PROJECT_DRAFT_SPLITS_TOTAL;
        return { pct: pct, recip: Number(split.projectId || 0) > 0 ? String(split.projectId) : (split.beneficiary || ZERO_ADDRESS), benef: Number(split.projectId || 0) > 0 ? (split.beneficiary || ZERO_ADDRESS) : '' };
      });
    }
    var unlimited = Number(tier.initial) >= TIER_UNLIMITED_SUPPLY;
    var effectiveVotes = toBigInt(tier.votingUnits || 0);
    if (toBigInt(tier.price || 0) > 0n && effectiveVotes === 0n) {
      throw new Error('Shop item #' + tier.id + ' explicitly has zero voting units, which the .jb shop editor cannot reproduce.');
    }
    // The store returns effective voting units, not the `useVotingUnits` flag. Bendystraw retains the raw
    // AddTier votingUnits value, so use it to disambiguate an explicit value from price-based voting and
    // verify it against the live result. If the index row is unavailable, only infer cases which are provable.
    var indexedVotes = tier.indexedMetadata && tier.indexedMetadata.votingUnits != null
      ? toBigInt(tier.indexedMetadata.votingUnits) : null;
    var explicitVotes;
    if (indexedVotes != null) {
      explicitVotes = indexedVotes > 0n;
      var expectedVotes = explicitVotes ? indexedVotes : toBigInt(tier.price || 0);
      if (expectedVotes !== effectiveVotes) throw new Error('Indexed voting units for shop item #' + tier.id + ' do not match the live hook.');
    } else if (effectiveVotes > 0xffffffffn) {
      explicitVotes = false; // explicit values are stored as uint32
    } else if (effectiveVotes !== toBigInt(tier.price || 0)) {
      explicitVotes = true;
    } else {
      throw new Error('Shop item #' + tier.id + ' has ambiguous voting-unit configuration and no indexed creation value; exporting would risk changing it.');
    }
    return {
      expanded: false, advOpen: false, name: media.name || ('Item ' + tier.id), description: media.description || '',
      imageUri: media.image || media.animationUrl || '', mediaType: media.mediaType || '', metaUri: '', encodedIpfsUri: tier.encodedIpfsUri || '',
      price: formatAmount(tier.price, home.pricing.decimals), limited: !unlimited, supply: unlimited ? '' : String(tier.initial),
      splitOn: tier.splitPercent > 0, splitRecipients: splitRows,
      discountOn: Number(tier.discountPercent || 0) > 0, discountPct: String(Number(tier.discountPercent || 0) / 2), category: Number(tier.category || 0),
      reserveOn: Number(tier.reserveFrequency || 0) > 0, reserveFrequency: String(tier.reserveFrequency || ''), reserveBeneficiary: tier.reserveBeneficiary || '',
      votingOn: explicitVotes, votingUnits: explicitVotes ? String(effectiveVotes) : '',
      flags: { allowOwnerMint: !!(tier.flags && tier.flags.allowOwnerMint), transfersPausable: !!(tier.flags && tier.flags.transfersPausable),
        cantBeRemoved: !!(tier.flags && tier.flags.cantBeRemoved), allowCredits: !(tier.flags && tier.flags.cantBuyWithCredits),
        ownerCanEditDiscount: !(tier.flags && tier.flags.cantIncreaseDiscountPercent) },
      _resolvedCategoryName: media.category || '',
    };
  }));
  state.nfts.forEach(function (item) {
    var categoryId = Number(item.category || 0), resolvedCategoryName = String(item._resolvedCategoryName || '').trim();
    var categoryName = resolvedCategoryName || (categoryId > 0 ? ('Category ' + categoryId) : '');
    if (categoryId > 0 && categoryName && !state.storeCategories.some(function (entry) { return Number(entry.id) === categoryId; })) {
      state.storeCategories.push({ id: categoryId, name: categoryName });
      if (!resolvedCategoryName) warnings.push('No stored label was available for shop category #' + categoryId + '; the .jb uses “' + categoryName + '” as an editable fallback.');
    }
    delete item._resolvedCategoryName;
  });
  state.storeCategories.sort(function (a, b) { return Number(a.id) - Number(b.id); });
  if (home.resolver) warnings.push('Dynamic shop resolver output was copied as the current item name/media; review those fields before deploying.');
}

// Reconstruct the configuration which the current create wizard can faithfully represent. Transaction-critical
// values come from contracts; Bendystraw-first project metadata is used only for display fields.
export async function buildProjectCreateDraft(project) {
  var state = newCreateDraftState(), warnings = [];
  var chains = projectChains(project);
  var testnetIds = [11155111, 11155420, 84532, 421614];
  var testnetCount = chains.filter(function (chain) { return testnetIds.indexOf(Number(chain.id)) !== -1; }).length;
  if (testnetCount && testnetCount !== chains.length) throw new Error('A .jb draft cannot mix mainnet and testnet chains.');
  state.network = testnetCount ? 'testnet' : 'mainnet';
  state.chainIds = chains.map(function (chain) { return Number(chain.id); });
  state.projectType = project.isRevnet ? 'revnet' : 'custom';
  applyDraftDetails(state, project);
  var sources = await Promise.all(chains.map(function (chain) { return draftLiveProjectChain(project, chain); }));
  if (sources.slice(1).some(function (source) { return draftRulesetFingerprint(source) !== draftRulesetFingerprint(sources[0]); })) {
    throw new Error('Ruleset or accounting configuration differs by chain, which one .jb draft cannot reproduce safely.');
  }
  await applyDraftAccountingAndTerminals(state, project, sources);
  await applyDraftSuckers(state, project, sources, warnings);
  var fundSnapshots = await Promise.all(sources.map(function (source) { return readDraftFunds(project, source); }));
  var fundFingerprints = sources.map(function (source, index) { return draftFundsFingerprint(source, fundSnapshots[index]); });
  if (fundFingerprints.some(function (fingerprint) { return fingerprint !== fundFingerprints[0]; })) {
    throw new Error('Fund access, reserved splits, or payout splits differ by chain, which one .jb draft cannot reproduce safely.');
  }
  state.details.owner = sources[0].owner || '';
  state.revOperator = sources[0].owner || '';
  sources.slice(1).forEach(function (source) {
    if (!sameAddr(source.owner, sources[0].owner)) draftPerChainSet(state, source.chainId, project.isRevnet ? 'op' : 'owner', source.owner || '');
  });
  var stageSourceSets = [sources];

  if (project.isRevnet) {
    // The current stage is reproducible from the live ruleset. Earlier stage history is useful context but cannot
    // enumerate unclaimed auto-issuance beneficiaries, so keep one current stage and disclose that limitation.
    var currentStage = createStage();
    applyDraftFunds(state, project, sources[0], currentStage, fundSnapshots[0]);
    currentStage.cutFreqDays = String(Number(currentStage.durationSeconds || 0) / 86400);
    currentStage.issuanceCutOn = Number(currentStage.durationSeconds || 0) > 0;
    currentStage.autoIssuances = [];
    state.stages = [currentStage]; state.afterMode = currentStage.durationSeconds > 0 ? 'cycle' : 'wait';
    state.revBaseCurrency = Number(sources[0].metadata.baseCurrency || 1);
    warnings.push('Revnet auto-issuance beneficiaries and earlier completed stages are not enumerable from the current ruleset, so this .jb starts from the live stage.');
    warnings.push('Any later revnet buyback-pool or registry-routing changes are not part of the .jb create form; review the new revnet’s market setup after deployment.');
  } else {
    var stage = createStage();
    applyDraftFunds(state, project, sources[0], stage, fundSnapshots[0]);
    state.stages = [stage]; state.afterMode = stage.durationSeconds > 0 ? 'cycle' : 'wait';
    var upcomingSources = await Promise.all(sources.map(function (source) { return draftUpcomingProjectChain(source, project); }));
    var upcomingCount = upcomingSources.filter(Boolean).length;
    if (upcomingCount && upcomingCount !== sources.length) throw new Error('The queued upcoming ruleset is not present on every project chain.');
    if (upcomingCount) {
      if (Number(stage.durationSeconds || 0) <= 0) throw new Error('A distinct ruleset is queued after a flexible current ruleset, which the .jb sequencer cannot reproduce safely.');
      if (upcomingSources.slice(1).some(function (source) { return draftRulesetFingerprint(source) !== draftRulesetFingerprint(upcomingSources[0]); })) {
        throw new Error('The queued upcoming ruleset differs by chain.');
      }
      var upcomingFundSnapshots = await Promise.all(upcomingSources.map(function (source) { return readDraftFunds(project, source); }));
      var upcomingFundFingerprints = upcomingSources.map(function (source, index) { return draftFundsFingerprint(source, upcomingFundSnapshots[index]); });
      if (upcomingFundFingerprints.some(function (fingerprint) { return fingerprint !== upcomingFundFingerprints[0]; })) throw new Error('Upcoming fund access or splits differ by chain.');
      sources.forEach(function (currentSource, index) {
        var nextSource = upcomingSources[index];
        var currentRole = isZeroishAddress(currentSource.metadata.dataHook) ? 'none'
          : (sameAddr(currentSource.metadata.dataHook, getAddress('JBOmnichainDeployer', currentSource.chainId)) ? 'omnichain' : 'direct');
        var nextRole = isZeroishAddress(nextSource.metadata.dataHook) ? 'none'
          : (sameAddr(nextSource.metadata.dataHook, getAddress('JBOmnichainDeployer', nextSource.chainId)) ? 'omnichain' : 'direct');
        if (currentRole !== nextRole || !!currentSource.metadata.useDataHookForPay !== !!nextSource.metadata.useDataHookForPay
          || !!currentSource.metadata.useDataHookForCashOut !== !!nextSource.metadata.useDataHookForCashOut
          || (currentRole === 'direct' && !sameAddr(currentSource.metadata.dataHook, nextSource.metadata.dataHook))) {
          throw new Error('The queued ruleset changes data-hook behavior, which the .jb create form cannot reproduce.');
        }
      });
      await Promise.all(upcomingSources.map(async function (nextSource, index) {
        var omni = getAddress('JBOmnichainDeployer', nextSource.chainId);
        if (!omni || !sameAddr(nextSource.metadata.dataHook, omni)) return;
        var currentSource = sources[index];
        var configs = await Promise.all([
          clientFor(nextSource.chainId).readContract({ address: omni, abi: OMNI_EXTRA_HOOK_ABI, functionName: 'extraDataHookOf', args: [BigInt(project.id), toBigInt(nextSource.ruleset.id)] }),
          clientFor(nextSource.chainId).readContract({ address: omni, abi: OMNI_TIERED_HOOK_ABI, functionName: 'tiered721HookOf', args: [BigInt(project.id), toBigInt(currentSource.ruleset.id)] }),
          clientFor(nextSource.chainId).readContract({ address: omni, abi: OMNI_TIERED_HOOK_ABI, functionName: 'tiered721HookOf', args: [BigInt(project.id), toBigInt(nextSource.ruleset.id)] }),
        ]);
        var extraHook = configs[0] && (configs[0].dataHook || configs[0][0]);
        var currentHook = configs[1] && (configs[1].hook || configs[1][0]);
        var nextHook = configs[2] && (configs[2].hook || configs[2][0]);
        var currentRedeem = !!(configs[1] && (configs[1].useDataHookForCashOut != null ? configs[1].useDataHookForCashOut : configs[1][1]));
        var nextRedeem = !!(configs[2] && (configs[2].useDataHookForCashOut != null ? configs[2].useDataHookForCashOut : configs[2][1]));
        if (!isZeroishAddress(extraHook) || !sameAddr(currentHook, nextHook) || currentRedeem !== nextRedeem) {
          throw new Error('The queued ruleset changes omnichain hook composition, which the .jb create form cannot reproduce.');
        }
      }));
      var nextStage = createStage();
      applyDraftFunds(state, project, upcomingSources[0], nextStage, upcomingFundSnapshots[0]);
      state.stages.push(nextStage); state.afterMode = nextStage.durationSeconds > 0 ? 'cycle' : 'wait';
      stageSourceSets.push(upcomingSources);
    }
  }
  if (state.stages.some(function (stage) { return stage.deadline === 'custom'; })) {
    var customApprovalByChain = {};
    stageSourceSets.forEach(function (sourceSet) {
      sourceSet.forEach(function (source) {
        if (draftDeadlineFor(source.ruleset.approvalHook, source.chainId).key !== 'custom') return;
        var prior = customApprovalByChain[source.chainId];
        if (prior && !sameAddr(prior, source.ruleset.approvalHook)) throw new Error('Custom approval hooks differ between rulesets on one chain.');
        customApprovalByChain[source.chainId] = source.ruleset.approvalHook;
      });
    });
    sources.slice(1).forEach(function (source) {
      var address = customApprovalByChain[source.chainId];
      if (address && !sameAddr(address, state.approvalAddress)) draftPerChainSet(state, source.chainId, 'approval', address);
    });
  }
  applyDraftOwnerRemainders(state, sources, project);
  if (sources[0].metadata.ownerMustSendPayouts) throw new Error('The live ruleset requires owner-sent payouts, a flag the .jb editor cannot reproduce.');
  if (sources[0].metadata.useTotalSurplusForCashOuts) throw new Error('The live ruleset scopes cash outs differently than the .jb editor supports.');
  if (Number(sources[0].metadata.metadata || 0) !== 0) warnings.push('The live ruleset contains custom metadata bits which are not editable in the create wizard.');
  await applyDraftShop(state, project, sources, warnings);
  if (state.shopEnabled && state.collection.useForRedemptions) state.stages.forEach(function (stage) { stage.cashOutEnabled = false; });
  state.step = 0; state.tos = false;
  return { state: state, warnings: warnings };
}

function renderProjectDraftExport(project) {
  var card = el('div', 'detail-card extras-export-card');
  var title = el('div', 'detail-card-title'); title.textContent = 'Copy this project'; card.appendChild(title);
  var body = el('div', 'detail-card-body extras-body');
  var intro = el('div', 'extras-payer-copy');
  intro.textContent = 'Take the project’s configuration as a .jb file, import it when creating a new project, and make any edits you want before deploying.';
  body.appendChild(intro);
  var status = el('div', 'operator-edit-status'); body.appendChild(status);
  var actions = el('div', 'operator-edit-actions extras-actions');
  var button = el('a', 'operator-cta operator-edit-submit'); button.href = '#'; button.textContent = 'Export .jb'; actions.appendChild(button);
  body.appendChild(actions); card.appendChild(body);
  var busy = false;
  button.addEventListener('click', function (event) {
    event.preventDefault(); if (busy) return; busy = true; button.classList.add('disabled');
    status.className = 'operator-edit-status pending'; status.textContent = 'Verifying live rules, funds, splits, terminals, and shop…';
    buildProjectCreateDraft(project).then(function (result) {
      if (result.warnings.length && !window.confirm(result.warnings.join('\n\n') + '\n\nExport this editable .jb anyway?')) {
        status.className = 'operator-edit-status'; status.textContent = 'Cancelled'; return;
      }
      exportDraftFile(result.state);
      status.className = 'operator-edit-status success'; status.textContent = 'Exported .jb. Import it from New project to review and edit.';
    }).catch(function (error) {
      status.className = 'operator-edit-status error'; status.textContent = errMessage(error, 'Could not safely reconstruct this project.');
    }).finally(function () { busy = false; button.classList.remove('disabled'); });
  });
  return card;
}

function renderExtrasSection(project) {
  var section = el('div', 'detail-section');
  section.appendChild(renderProjectDraftExport(project));
  var card = el('div', 'detail-card extras-card');
  var title = el('div', 'detail-card-title'); title.textContent = 'Payer address'; card.appendChild(title);

  var body = el('div', 'detail-card-body extras-body');
  var intro = el('div', 'extras-payer-copy');
  intro.textContent = 'Pay this project by sending the native token (ETH) to a dedicated payer address. Sending ERC-20 tokens directly to it does not trigger a payment. Anyone can create any number of payer addresses.';
  body.appendChild(intro);

  var tokenLabel = project.tokenSymbol || project.tokenName || 'Token';

  var modeLabel = el('div', 'operator-edit-label extras-label'); modeLabel.textContent = 'Behavior'; body.appendChild(modeLabel);
  var modeSelect = el('select', 'operator-edit-jwt extras-select extras-behavior-select');
  var payOpt = document.createElement('option'); payOpt.value = 'pay'; payOpt.textContent = 'Pay';
  var balanceOpt = document.createElement('option'); balanceOpt.value = 'balance'; balanceOpt.textContent = 'Add to balance';
  modeSelect.appendChild(payOpt); modeSelect.appendChild(balanceOpt);
  body.appendChild(modeSelect);
  var modeHint = el('div', 'extras-payer-sub');
  body.appendChild(modeHint);
  function syncModeHint() {
    modeHint.textContent = modeSelect.value === 'balance'
      ? 'Adds funds to the project without minting tokens.'
      : 'Pays the project and mints ' + tokenLabel + ' to the beneficiary.';
  }
  modeSelect.addEventListener('change', syncModeHint);
  syncModeHint();

  var beneficiaryLabel = el('div', 'operator-edit-label extras-label'); beneficiaryLabel.textContent = tokenLabel + ' beneficiary'; body.appendChild(beneficiaryLabel);
  var originalRow = el('label', 'extras-checkbox-row');
  var originalCb = document.createElement('input'); originalCb.type = 'checkbox'; originalCb.checked = true;
  originalRow.appendChild(originalCb);
  var originalText = el('span'); originalText.textContent = 'Original payer'; originalRow.appendChild(originalText);
  body.appendChild(originalRow);
  var beneficiaryFields = el('div', 'extras-conditional-fields');
  var beneficiaryShared = el('div', 'extras-shared-address');
  var beneficiaryInput = el('input', 'operator-edit-jwt extras-address');
  beneficiaryInput.type = 'text';
  beneficiaryInput.placeholder = '0x… or name.eth';
  beneficiaryInput.value = '';
  beneficiaryShared.appendChild(beneficiaryInput);
  var beneficiaryHint = el('div', 'operator-edit-token-name'); beneficiaryShared.appendChild(beneficiaryHint);
  beneficiaryFields.appendChild(beneficiaryShared);
  var beneficiaryValueOf = attachAddressRecognition(beneficiaryInput, beneficiaryHint, project.chainId, {
    label: 'Default beneficiary',
    projectId: project.id,
    projectSymbol: project.tokenSymbol,
    zeroLabel: 'Original payer receives tokens',
    unknownLabel: function (addr) { return 'Custom beneficiary ' + truncAddr(addr); },
    ensLabel: function (name) { return name; },
  });

  var chains = projectChains(project);
  var beneficiaryPerChain = makePerChainAddressControl(chains, beneficiaryValueOf, {
    label: 'Default beneficiary',
    placeholder: '0x… or name.eth',
    projectId: project.id,
    projectSymbol: project.tokenSymbol,
    zeroLabel: 'Original payer receives tokens',
    defaultRaw: function () { return beneficiaryInput.value || ''; },
    unknownLabel: function (addr) { return 'Custom beneficiary ' + truncAddr(addr); },
    ensLabel: function (name) { return name; },
    onOpen: function () { beneficiaryShared.style.display = 'none'; },
    onClose: function () { beneficiaryShared.style.display = ''; },
  });
  beneficiaryFields.appendChild(beneficiaryPerChain.node);
  body.appendChild(beneficiaryFields);
  function syncBeneficiaryFields() {
    beneficiaryFields.style.display = originalCb.checked ? 'none' : '';
  }
  originalCb.addEventListener('change', syncBeneficiaryFields);
  syncBeneficiaryFields();

  var memoLabel = el('div', 'operator-edit-label extras-label'); memoLabel.textContent = 'Default memo'; body.appendChild(memoLabel);
  var memoInput = el('input', 'operator-edit-jwt extras-memo');
  memoInput.type = 'text';
  memoInput.placeholder = 'optional memo attached to payments';
  memoInput.value = '';
  body.appendChild(memoInput);

  var editableRow = el('label', 'extras-checkbox-row extras-editable-row');
  var editableCb = document.createElement('input'); editableCb.type = 'checkbox'; editableCb.checked = false;
  editableRow.appendChild(editableCb);
  var editableText = el('span'); editableText.textContent = 'Editable'; editableRow.appendChild(editableText);
  body.appendChild(editableRow);
  var ownerFields = el('div', 'extras-conditional-fields extras-owner-fields');
  var ownerShared = el('div', 'extras-shared-address');
  var ownerInput = el('input', 'operator-edit-jwt extras-address');
  ownerInput.type = 'text';
  ownerInput.placeholder = '0x… or name.eth';
  ownerInput.value = getAccount() || '';
  ownerShared.appendChild(ownerInput);
  var ownerHint = el('div', 'operator-edit-token-name'); ownerShared.appendChild(ownerHint);
  ownerFields.appendChild(ownerShared);
  var ownerValueOf = attachAddressRecognition(ownerInput, ownerHint, project.chainId, {
    label: 'Address admin',
    zeroLabel: 'Zero address cannot administer the payer address',
    ensLabel: function (name) { return name; },
  });
  var ownerPerChain = makePerChainAddressControl(chains, ownerValueOf, {
    label: 'Address admin',
    placeholder: '0x… or name.eth',
    zeroLabel: 'Zero address cannot administer the payer address',
    defaultRaw: function () { return ownerInput.value || getAccount() || ''; },
    ensLabel: function (name) { return name; },
    onOpen: function () { ownerShared.style.display = 'none'; },
    onClose: function () { ownerShared.style.display = ''; },
  });
  ownerFields.appendChild(ownerPerChain.node);
  var ownerExplainer = el('div', 'extras-payer-sub');
  ownerExplainer.textContent = 'The address admin can later change this payer address’s destination project, Pay/Add to Balance behavior, beneficiary, memo, and metadata, or transfer or renounce the admin role. The role does not receive payments or control either project.';
  ownerFields.appendChild(ownerExplainer);
  body.appendChild(ownerFields);
  var immutableExplainer = el('div', 'extras-payer-sub');
  immutableExplainer.textContent = 'Off by default: no address admin. This payer address’s destination project, Pay/Add to Balance behavior, beneficiary, memo, and metadata are permanent.';
  body.appendChild(immutableExplainer);
  function syncEditableFields() {
    ownerFields.style.display = editableCb.checked ? '' : 'none';
    immutableExplainer.style.display = editableCb.checked ? 'none' : '';
  }
  editableCb.addEventListener('change', syncEditableFields);
  syncEditableFields();

  var advanced = document.createElement('details');
  advanced.className = 'extras-more';
  var advancedSummary = document.createElement('summary');
  advancedSummary.textContent = 'Extra options ▸';
  advanced.appendChild(advancedSummary);
  advanced.addEventListener('toggle', function () {
    advancedSummary.textContent = 'Extra options ' + (advanced.open ? '▾' : '▸');
  });
  var metadataLabel = el('div', 'operator-edit-label extras-label'); metadataLabel.textContent = 'Default metadata'; advanced.appendChild(metadataLabel);
  var metadataInput = el('input', 'operator-edit-jwt extras-memo');
  metadataInput.type = 'text';
  metadataInput.placeholder = '0x';
  metadataInput.value = '0x';
  metadataInput.spellcheck = false;
  advanced.appendChild(metadataInput);
  var metadataHint = el('div', 'extras-payer-sub'); metadataHint.textContent = 'Hex bytes forwarded to pay/addToBalance. Leave 0x unless you need custom terminal metadata.';
  advanced.appendChild(metadataHint);
  body.appendChild(advanced);

  var clbl = el('div', 'operator-edit-label extras-label'); clbl.textContent = 'Deploy on'; body.appendChild(clbl);
  var chainBox = el('div', 'splits-edit-chains');
  var chainChecks = chains.map(function (c) {
    var deployer = getAddress('JBProjectPayerDeployer', c.id);
    var row = el('label', 'splits-edit-chain' + (deployer ? '' : ' extras-chain-disabled'));
    var cb = document.createElement('input');
    cb.type = 'checkbox';
    cb.checked = !!deployer;
    cb.disabled = !deployer;
    cb.value = String(c.id);
    row.appendChild(cb);
    row.appendChild(chainLogo(c.id, c.name));
    var nm = el('span'); nm.textContent = c.name || chainNameOf(c.id); row.appendChild(nm);
    if (!deployer) {
      var miss = el('span', 'extras-chain-missing'); miss.textContent = 'no deployer'; row.appendChild(miss);
    }
    chainBox.appendChild(row);
    return { chain: c, cb: cb, deployer: deployer };
  });
  body.appendChild(chainBox);

  // Surface identical already-deployed payers so nobody redeploys one they could just reuse — matching
  // behavior + beneficiary on any selected chain. Skipped while an ENS beneficiary hasn't resolved.
  var dupNote = el('div', 'create-banner'); dupNote.style.display = 'none'; body.appendChild(dupNote);
  var existingPayerRows = [];
  function syncDuplicateNote() {
    var wantBalance = modeSelect.value === 'balance';
    var formBenef;
    if (originalCb.checked) formBenef = '';
    else {
      var raw = (beneficiaryInput.value || '').trim();
      formBenef = isAddr(raw) ? raw.toLowerCase() : null; // null = can't compare yet
    }
    var selectedIds = chainChecks.filter(function (r) { return r.cb.checked && !r.cb.disabled; }).map(function (r) { return Number(r.chain.id); });
    var matches = formBenef === null ? [] : existingPayerRows.filter(function (row) {
      if (selectedIds.indexOf(Number(row.chainId)) === -1) return false;
      if (!!row.defaultAddToBalance !== wantBalance) return false;
      var rowBenef = row.defaultBeneficiary && !/^0x0{40}$/i.test(row.defaultBeneficiary) ? row.defaultBeneficiary.toLowerCase() : '';
      return rowBenef === formBenef;
    });
    if (!matches.length) { dupNote.style.display = 'none'; return; }
    dupNote.textContent = 'This project already has a payer address with these settings: '
      + matches.map(function (row) { return chainNameOf(row.chainId) + ' ' + truncAddr(row.address); }).join(', ')
      + '. Anyone can pay it directly — deploying again creates another address that behaves the same.';
    dupNote.style.display = '';
  }
  fetchProjectPayerRows(project).then(function (rows) { existingPayerRows = rows || []; syncDuplicateNote(); }).catch(function () {});
  modeSelect.addEventListener('change', syncDuplicateNote);
  originalCb.addEventListener('change', syncDuplicateNote);
  beneficiaryInput.addEventListener('input', syncDuplicateNote);
  chainChecks.forEach(function (r) { r.cb.addEventListener('change', syncDuplicateNote); });

  var status = el('div', 'operator-edit-status'); body.appendChild(status);
  var actions = el('div', 'operator-edit-actions extras-actions');
  var deployRelayr = el('a', 'operator-cta extras-relayr-submit');
  deployRelayr.href = '#';
  deployRelayr.textContent = 'Use Relayr';
  var deploy = el('a', 'operator-cta operator-edit-submit'); deploy.href = '#'; deploy.textContent = 'Deploy payer address';
  actions.appendChild(deployRelayr);
  actions.appendChild(deploy);
  body.appendChild(actions);
  var payerList = renderProjectPayerAddresses(project);
  body.appendChild(payerList);
  card.appendChild(body);
  section.appendChild(card);

  var setStatus = makeStatusSetter(status, 'operator-edit-status');
  var busy = false;
  function selectedChains() {
    return chainChecks.filter(function (r) { return r.cb.checked && !r.cb.disabled; }).map(function (r) { return r.chain; });
  }
  function syncDeployActions() {
    var selected = selectedChains();
    deploy.textContent = selected.length > 1 ? 'Deploy payer addresses' : 'Deploy payer address';
    deployRelayr.style.display = selected.length === 1 ? '' : 'none';
  }
  chainChecks.forEach(function (r) { r.cb.addEventListener('change', syncDeployActions); });
  syncDeployActions();

  function submitDeploy(forceRelayr) {
    if (busy) return;
    var selected = selectedChains();
    if (!selected.length) { setStatus('Select at least one chain', 'error'); return; }
    var account = getAccount && getAccount();
    (async function () {
      if (!account) { setStatus('Connecting wallet…', 'pending'); account = await connect().then(getAccount).catch(function () { return null; }); }
      if (!account) { setStatus('Connect a wallet to deploy payer addresses.', 'error'); return; }
      if (editableCb.checked && !ownerInput.value.trim()) {
        ownerInput.value = account;
        ownerInput.dispatchEvent(new Event('input'));
      }
      var beneficiary = originalCb.checked ? ZERO_ADDRESS : beneficiaryPerChain.snapshot();
      var payerOwner = editableCb.checked ? ownerPerChain.snapshot() : ZERO_ADDRESS;
      var metadata = normalizeProjectPayerMetadata(metadataInput.value);
      var addToBalance = modeSelect.value === 'balance';
      setStatus('Preparing payer address deployments…', 'pending');
      var calls = selected.map(function (chain) {
        var cid = chain.id;
        var ben = materializeChainValue(beneficiary, cid);
        var own = materializeChainValue(payerOwner, cid);
        if (editableCb.checked && String(own).toLowerCase() === ZERO_ADDRESS.toLowerCase()) {
          throw new Error('Editable payer addresses need a nonzero address admin on ' + (chain.name || chainNameOf(cid)) + '.');
        }
        return buildProjectPayerDeployCall(cid, project.id, ben, memoInput.value, metadata, addToBalance, own);
      });
      if (calls.length === 1 && !forceRelayr) {
        await new Promise(function (resolve, reject) {
          var call = calls[0];
          executeTransaction({
            chainId: call.chainId,
            address: call.to,
            abi: call.abi,
            functionName: call.functionName,
            args: call.args,
            contractName: 'JBProjectPayerDeployer',
            label: 'Deploy payer address',
            confirmTitle: 'Confirm payer address deployment',
            onStatus: function (m, k) { setStatus(m, k); },
            onError: function (m) { reject(new Error(m)); },
            onSuccess: function () { resolve(); },
          });
        });
      } else {
        await runProjectPayerRelayrDeploys(calls, setStatus);
      }
      setStatus('Payer address deployment complete on ' + selected.length + ' chain' + (selected.length === 1 ? '' : 's') + '.', 'success');
      if (payerList && payerList._refresh) payerList._refresh();
      document.dispatchEvent(new CustomEvent('jb:bridge-updated'));
    })().catch(function (err) {
      setStatus(errMessage(err, 'Could not deploy the payer address.'), 'error');
    }).finally(function () {
      busy = false;
      deploy.classList.remove('disabled');
      deployRelayr.classList.remove('disabled');
    });
    busy = true;
    deploy.classList.add('disabled');
    deployRelayr.classList.add('disabled');
  }
  deploy.addEventListener('click', function (e) {
    e.preventDefault();
    submitDeploy(false);
  });
  deployRelayr.addEventListener('click', function (e) {
    e.preventDefault();
    submitDeploy(true);
  });

  return section;
}

// Label a queued Safe tx by its calldata selector (the owner-only JB calls the site can propose).
var SAFE_QUEUE_LABELS = {
  '0x58178191': 'Deploy ERC-20 token',
  '0xfac3a6a2': 'Rename token',
  '0xcfaf5839': 'Send payouts',
  '0x090db2f1': 'Distribute reserved tokens',
};
// Friendly names for the JB functions we queue, keyed by decoded function name.
var SAFE_FN_LABELS = {
  deployERC20For: 'Deploy ERC-20 token', setTokenMetadataOf: 'Rename token',
  sendPayoutsOf: 'Send payouts', sendReservedTokensToSplitsOf: 'Distribute reserved tokens',
};
function labelForQueuedTx(tx) {
  // Decode via the target contract's ABI (same as the confirm modal) → real function name.
  var d = decodeCallForDisplay({ address: tx.to, calldata: tx.data });
  if (d && d.fn) return SAFE_FN_LABELS[d.fn] || d.fn;
  var sel = (tx.data || '').slice(0, 10).toLowerCase();
  return SAFE_QUEUE_LABELS[sel] || ('Contract call' + (sel ? ' ' + sel : ''));
}
// Show the FULL decoded call before a co-signer approves OR executes a queued Safe tx — the one-line label
// hides the recipient/amount/target a malicious co-signer could slip in. Folds the DELEGATECALL / ETH-value /
// unrecognized-target warnings into the same review. Returns the user's confirm/cancel as a promise.
function reviewQueuedSafeTx(cid, chainName, tx, actionLabel) {
  var nm = resolveContractName(tx.to, cid);
  var warns = [];
  if (Number(tx.operation) === 1) warns.push('DELEGATECALL — runs arbitrary code in the Safe’s own context (it can move any of the Safe’s assets).');
  var ethVal; try { ethVal = BigInt(tx.value || 0); } catch (_) { ethVal = 0n; }
  if (ethVal > 0n) warns.push('Sends ' + formatBalance(ethVal, 18, 'ETH') + ' from the Safe.');
  if (!nm) warns.push('Targets an UNRECOGNIZED contract (' + tx.to + ') — not a known Juicebox/Revnet contract. Review the raw data below before approving.');
  var viewOnly = actionLabel === 'View';
  var desc = warns.join(' ') || null;
  if (viewOnly) desc = (desc ? (desc + ' ') : '') + 'This details view is read-only. To sign, use the Sign button on the transaction row, or open the transaction in the Safe app.';
  return confirmTransactionModal(
    { chain: chainName, chainId: cid, contract: nm || tx.to, address: tx.to, calldata: tx.data, value: tx.value },
    { title: viewOnly ? ('Transaction #' + tx.nonce + ' details') : ((actionLabel || 'Review') + ' Safe transaction #' + tx.nonce),
      confirmText: viewOnly ? 'Close' : (actionLabel || 'Confirm'), description: desc, hideCancel: viewOnly }
  );
}

// Safe queue: a Safe-owned project's per-chain multisig queue. Signers confirm queued owner-only txs
// here (or open them in the Safe app); proposing happens from the action modals (Deploy token, etc.).
// The styled "|" separator used in the Owner tab rows.
function boSep() { var s = el('span', 'bo-sep'); s.textContent = '|'; return s; }

// Classify an owner address on a chain: Safe (read its policy/signers), EOA (no code), Known contract
// (has code + in our registry), or Unknown contract. Returns { type, safe }.
function classifyOwner(chainId, addr) {
  return fetchSafeInfo(addr, chainId).then(function (safe) {
    if (safe) return { type: 'Safe Multisig', safe: safe };
    var client = clientFor(chainId);
    if (!client) return { type: 'Unknown', safe: null };
    return client.getCode({ address: addr }).then(function (code) {
      if (!code || code === '0x') return { type: 'EOA', safe: null };
      var name = resolveContractName(addr, chainId);
      return { type: name ? ('Known contract (' + name + ')') : 'Unknown contract', safe: null };
    }).catch(function () { return { type: 'Contract', safe: null }; });
  }).catch(function () { return { type: 'Unknown', safe: null }; });
}

// A key/value row with a bold value (string or node).
function ownerKv(label, value) {
  var row = el('div', 'account-kvrow');
  var k = el('span', 'account-k'); k.textContent = label + ': '; row.appendChild(k);
  var v = el('strong', 'account-v');
  if (typeof value === 'string') v.textContent = value; else v.appendChild(value);
  row.appendChild(v);
  return row;
}

// "Account" card: the project's owner address on each chain + its type; Safe details (policy + signers) inline.
function renderAccountCard(project) {
  var card = el('div', 'detail-card');
  var title = el('div', 'detail-card-title'); title.textContent = 'Account'; card.appendChild(title);
  var body = el('div'); body.appendChild(skel('100%', '60px')); card.appendChild(body);
  var pid = BigInt(project.id);
  var ids = orderedProjectChainIds(project);
  var chains = ids.length ? ids.map(function (id) { return { id: id, name: chainNameOf(id) }; }) : [{ id: project.chainId, name: chainNameOf(project.chainId) }];
  // For a revnet, the JBProjects owner is the REVDeployer — the controlling account is the OPERATOR; show
  // that instead. For custom projects, the owner IS the controlling account (read per chain via ownerOf).
  var isRev = project.isRevnet;
  var addrLabel = isRev ? 'Operator' : 'Owner';
  var authorityRowsP = isRev
    ? fetchOperatorsPerChain(project).then(function (res) {
      var byChain = {};
      res.rows.forEach(function (r) { byChain[r.chainId] = r.owner; });
      return chains.map(function (c) { return { c: c, owner: byChain[c.id] || null }; });
    })
    : Promise.all(chains.map(function (c) {
      return read(c.id, 'JBProjects', ownerOfAbi, 'ownerOf', [pid])
        .then(function (owner) { return { c: c, owner: owner }; })
        .catch(function () { return { c: c, owner: null }; });
    }));
  authorityRowsP.then(function (authorityRows) {
    return Promise.all(authorityRows.map(function (row) {
      var c = row.c, owner = row.owner;
      if (!owner) return { c: c, owner: null, type: '—', safe: null };
      return classifyOwner(c.id, owner).then(function (info) { return { c: c, owner: owner, type: info.type, safe: info.safe }; });
    }));
  }).then(function (rows) {
    body.innerHTML = '';
    if (authorityRowsDiverged(rows)) {
      var warn = el('div', 'detail-owner-warn');
      warn.textContent = addrLabel + ' differs by chain';
      body.appendChild(warn);
    }
    // Collapse chains that share the same owner/type/policy/signers into one entry (logos listed together).
    var groups = [], byKey = {};
    rows.forEach(function (r) {
      var key = (r.owner || '∅').toLowerCase() + '|' + r.type + '|' + (r.safe ? (r.safe.threshold + '/' + r.safe.owners.map(function (o) { return o.toLowerCase(); }).sort().join(',')) : '');
      var g = byKey[key];
      if (!g) { g = byKey[key] = { rep: r, chains: [] }; groups.push(g); }
      g.chains.push(r.c);
    });
    // Addresses that ARE a deployed Safe on at least one chain — so the same address showing as "EOA" elsewhere is
    // really the SAME Safe, just not deployed there yet (deployable via createProxyWithNonce replay).
    var safeByAddr = {}; groups.forEach(function (g) { if (g.rep.safe && g.rep.owner) safeByAddr[g.rep.owner.toLowerCase()] = g.rep.safe; });
    groups.forEach(function (g) {
      var r = g.rep;
      var block = el('div', 'account-chain');
      var head = el('div', 'account-head');
      g.chains.forEach(function (c) { head.appendChild(chainLogo(c.id, c.name)); });
      var nm = el('span', 'account-chainname'); nm.textContent = ' ' + g.chains.map(function (c) { return c.name; }).join(', '); head.appendChild(nm);
      block.appendChild(head);
      var kv = el('div', 'account-kv');
      // Truncated (click-to-copy, hover-full) so it sits inline with the label instead of wrapping to a new
      // row — the full address is one click/hover away, and Type/Safe details already identify the account.
      kv.appendChild(ownerKv(addrLabel, r.owner ? addressNode(r.owner) : document.createTextNode('—')));
      // A non-Safe whose SAME address is a deployed Safe elsewhere is an undeployed Safe, not an EOA — label it so.
      var undeployedSafe = !r.safe && r.owner && safeByAddr[r.owner.toLowerCase()];
      kv.appendChild(ownerKv('Type', undeployedSafe ? 'Safe Multisig (not deployed here yet)' : r.type));
      if (r.safe) {
        kv.appendChild(ownerKv('Policy', 'Requires ' + r.safe.threshold + ' of ' + r.safe.owners.length + ' signatures'));
        var sv = el('span', 'account-signers');
        r.safe.owners.forEach(function (o, i) { if (i) sv.appendChild(document.createTextNode(', ')); sv.appendChild(addressNode(o, r.c.id)); });
        kv.appendChild(ownerKv('Signers', sv));
      } else if (undeployedSafe) {
        // Same address is a deployed Safe elsewhere → an UNDEPLOYED Safe here (the Safe app can't add every chain).
        // Show its policy (same Safe) and offer to deploy it per chain by replaying its original creation.
        var sinfo = safeByAddr[r.owner.toLowerCase()];
        kv.appendChild(ownerKv('Policy', 'Requires ' + sinfo.threshold + ' of ' + sinfo.owners.length + ' signatures (once deployed)'));
        var note = el('div', 'account-kvrow'); note.style.opacity = '0.85';
        note.appendChild(document.createTextNode('Same Safe address — deploy it to activate here.')); kv.appendChild(note);
        g.chains.forEach(function (ch) {
          var drow = el('div', 'account-kvrow');
          var db = el('a', 'operator-cta'); db.href = '#'; db.textContent = 'Deploy Safe on ' + ch.name;
          var stat = el('span'); stat.style.marginLeft = '8px'; stat.style.opacity = '0.85';
          db.addEventListener('click', function (e) {
            e.preventDefault(); stat.textContent = 'reading config…';
            fetchSafeCreation(r.owner).then(function (creation) {
              if (!creation) throw new Error('couldn’t read the Safe’s creation config');
              stat.textContent = 'deploying on ' + ch.name + ' — confirm in your wallet…';
              return deploySafeSameAddress(ch.id, creation, r.owner);
            }).then(function () {
              stat.textContent = 'Deploy on ' + ch.name + ' successful'; db.remove();
              try { delete _safeCache[ch.id + ':' + r.owner.toLowerCase()]; } catch (_) {}
            }).catch(function (err) { stat.textContent = '— ' + ((err && (err.shortMessage || err.message)) || String(err)); });
          });
          drow.appendChild(db); drow.appendChild(stat); kv.appendChild(drow);
        });
      }
      block.appendChild(kv);
      if (r.owner) {
        var actions = el('div', 'account-actions');
        var xfer = el('a', 'operator-cta'); xfer.href = '#'; xfer.textContent = isRev ? 'Transfer operator' : 'Transfer ownership';
        xfer.title = (isRev ? 'Transfer the operator role on ' : 'Transfer project ownership on ') + g.chains.map(function (c) { return c.name; }).join(', ');
        xfer.addEventListener('click', function (e) {
          e.preventDefault();
          openTransferAuthorityModal(project, { authorityAddr: r.owner, chains: g.chains });
        });
        actions.appendChild(xfer);
        block.appendChild(actions);
      }
      body.appendChild(block);
    });
  }).catch(function () { body.innerHTML = ''; body.textContent = 'Could not read ownership.'; });
  return card;
}

function appendPendingSafeTxsCard(section, safe, chains, homeChainId, contextLabel) {
  if (!safe) return null;
  var safeCard = renderPendingSafeTxsCard(safe, chains, homeChainId, contextLabel);
  section.appendChild(safeCard);
  fetchSafeInfo(safe, homeChainId).then(function (info) { if (!info && safeCard.parentNode) safeCard.parentNode.removeChild(safeCard); }).catch(function () {});
  return safeCard;
}

function safeQueueNonce(tx) {
  var n = Number(tx && tx.nonce);
  return Number.isFinite(n) ? n : null;
}

export function safeQueueExecutionPlan(txs, readyFlags) {
  txs = txs || [];
  readyFlags = readyFlags || [];
  var nonces = txs.map(safeQueueNonce);
  var finite = nonces.filter(function (n) { return n != null; });
  var frontNonce = finite.length ? Math.min.apply(null, finite) : null;
  var byNonce = {}, counts = {};
  nonces.forEach(function (n, i) {
    if (n == null) return;
    if (!byNonce[n]) byNonce[n] = [];
    byNonce[n].push(i);
    counts[n] = (counts[n] || 0) + 1;
  });
  var directByIndex = txs.map(function (_, i) { return nonces[i] != null && nonces[i] === frontNonce; });
  var duplicateNonceByIndex = txs.map(function (_, i) { return nonces[i] != null && counts[nonces[i]] > 1; });
  var batchByIndex = txs.map(function () { return false; });
  if (frontNonce != null) {
    var expected = frontNonce;
    Object.keys(byNonce).map(Number).sort(function (a, b) { return a - b; }).some(function (n) {
      if (n !== expected) return true;
      var idxs = byNonce[n] || [];
      if (idxs.length !== 1) return true; // Same-nonce alternatives require an explicit per-row choice.
      var idx = idxs[0];
      if (!readyFlags[idx]) return true;
      batchByIndex[idx] = true;
      expected += 1;
      return false;
    });
  }
  return { frontNonce: frontNonce, directByIndex: directByIndex, batchByIndex: batchByIndex, duplicateNonceByIndex: duplicateNonceByIndex };
}

function renderRevnetPendingSafeTxs(project, mount) {
  fetchOperatorsPerChain(project).then(function (res) {
    if (!mount.isConnected) return;
    var byOp = {}, groups = [];
    res.rows.forEach(function (r) {
      if (!r.owner) return;
      var key = r.owner.toLowerCase();
      var g = byOp[key];
      if (!g) { g = byOp[key] = { owner: r.owner, chains: [] }; groups.push(g); }
      g.chains.push({ id: r.chainId, name: r.name });
    });
    groups.forEach(function (g) {
      appendPendingSafeTxsCard(mount, g.owner, g.chains, g.chains[0].id, 'Operator');
    });
  }).catch(function () {});
}

function renderBackOfficeSection(project) {
  var section = el('div', 'detail-section');
  var safe = projectAuthorityAddress(project);
  var chains = (project.chains && project.chains.length) ? project.chains : [{ id: project.chainId, name: chainNameOf(project.chainId) }];
  // Account card: who owns the project on each chain + what kind of account it is.
  section.appendChild(renderAccountCard(project));
  // The Safe queue/sign card is only meaningful when the controlling account is a Safe — an EOA controller
  // executes directly via relayr (no queue to sign). Render it optimistically, then drop it if the authority
  // isn't a Safe. Skipped entirely when the operator can't be resolved (indexer down → `safe` is null).
  if (project.isRevnet) {
    var safeMount = el('div', 'operator-safe-groups');
    section.appendChild(safeMount);
    renderRevnetPendingSafeTxs(project, safeMount);
  } else if (safe) {
    appendPendingSafeTxsCard(section, safe, chains, project.chainId, 'Owner');
  }

  // Powers / Permissions. Revnet: the controlling account is an OPERATOR with a fixed granted permission set
  // (not the ruleset-flag owner powers, which it doesn't hold) — show those actual powers, read-only. Custom:
  // the owner exercises the ruleset-gated owner powers (Powers card) AND can manage operators (Permissions card).
  if (project.isRevnet) {
    section.appendChild(renderEditsCard(project));
    section.appendChild(renderBuybackRouterCard(project));
    section.appendChild(renderPermissionsCard(project));
  } else {
    section.appendChild(renderEditsCard(project));
    section.appendChild(renderPowersCard(project));
    section.appendChild(renderBuybackRouterCard(project));
    section.appendChild(renderPermissionsCard(project));
  }
  return section;
}

// Reusable "Pending Multisig Transactions" card: lists each chain's Safe queue for `safe`, lets signers Sign /
// Execute per tx and Execute-all ready txs in one Relayr payment. Used by the project Owner/Operator tab and the
// protocol Admin tab. `homeChainId` is the chain used to read the Safe's signers/threshold; `contextLabel` =
// 'Owner' | 'Operator' | 'Admin' for the intro copy. Assumes the same Safe address across `chains` (the norm).
function renderPendingSafeTxsCard(safe, chains, homeChainId, contextLabel) {
  var card = el('div', 'detail-card');
  var title = el('div', 'detail-card-title'); title.textContent = 'Pending Multisig Transactions'; card.appendChild(title);
  var intro = el('div', 'detail-card-body backoffice-intro'); card.appendChild(intro);
  var body = el('div'); body.appendChild(skel('100%', '60px')); card.appendChild(body);

  function loadQueues(info) {
    body.innerHTML = '';
    var acc = getAccount && getAccount();
    var isSigner = acc && info.owners.some(function (o) { return o.toLowerCase() === acc.toLowerCase(); });
    var batchBar = el('div', 'backoffice-batch'); body.appendChild(batchBar);
    var ready = []; // { cid, chain, tx } across all chains
    var readyAlternativesExcluded = 0;
    var readyBlockedExcluded = 0;
    var chainLoads = chains.map(function (c) {
      var block = el('div', 'backoffice-chain');
      var h = el('div', 'backoffice-chain-head'); h.appendChild(chainLogo(c.id, c.name)); var t = el('span'); t.textContent = ' ' + c.name; h.appendChild(t);
      var ql = safeQueueLink(c.id, safe);
      if (ql) { var qa = document.createElement('a'); qa.className = 'backoffice-chain-link'; qa.href = ql; qa.target = '_blank'; qa.rel = 'noopener'; qa.textContent = '↗'; qa.title = 'Open this chain’s Safe queue'; h.appendChild(qa); }
      block.appendChild(h);
      var list = el('div', 'backoffice-list'); list.appendChild(skel('100%', '20px')); block.appendChild(list);
      body.appendChild(block);
      // No hosted Safe service on this chain (e.g. Arbitrum/OP Sepolia) → there's no offchain queue to list.
      // Operator/owner txs there are coordinated onchain (approve + execute via the action panels), not here.
      if (!hasSafeService(c.id)) {
        list.innerHTML = '';
        var nos = el('div', 'backoffice-none'); nos.textContent = 'No hosted Safe service on ' + c.name + ' — no offchain queue here. A second signer completes a pending tx by re-running the same operator action (e.g. Buyback & swap router → Set buyback hook): it reads the onchain approvals and lets them approve + execute.';
        list.appendChild(nos); return Promise.resolve();
      }
      return listPendingSafeTxs(c.id, safe).then(function (txs) {
        list.innerHTML = '';
        if (!txs.length) {
          var none = el('div', 'backoffice-none'); none.textContent = 'No pending transactions.';
          list.appendChild(none); return;
        }
        var txStates = txs.map(function (tx) {
          var nconf = safeUsableConfirmationCount(tx), need = tx.confirmationsRequired || info.threshold;
          return { nconf: nconf, need: need, ready: nconf >= need };
        });
        var execPlan = safeQueueExecutionPlan(txs, txStates.map(function (s) { return s.ready; }));
        txs.forEach(function (tx, txIdx) {
          var txState = txStates[txIdx];
          var nconf = txState.nconf, need = txState.need;
          var row = el('div', 'backoffice-row');
          var main = el('div', 'backoffice-main');
          var lab = el('div', 'backoffice-label');
          var nspan = el('span'); nspan.textContent = '#' + tx.nonce; lab.appendChild(nspan);
          lab.appendChild(boSep()); var fnspan = el('span'); fnspan.textContent = labelForQueuedTx(tx); lab.appendChild(fnspan);
          main.appendChild(lab);
          var sub = el('div', 'backoffice-sub');
          sub.appendChild(document.createTextNode(nconf + '/' + need + ' signatures'));
          if (nconf >= need) { sub.appendChild(boSep()); sub.appendChild(document.createTextNode('ready to execute')); }
          if (execPlan.duplicateNonceByIndex[txIdx]) { sub.appendChild(boSep()); sub.appendChild(document.createTextNode('same nonce alternative')); }
          // Surface the two things a label-only view hides: a DELEGATECALL (runs arbitrary code in the Safe's
          // context) and any ETH the tx sends. Both are WYSIWYS-critical before a signer approves.
          var isDelegate = Number(tx.operation) === 1;
          var ethVal = (function () { try { return BigInt(tx.value || 0); } catch (_) { return 0n; } })();
          if (isDelegate) { sub.appendChild(boSep()); var dc = el('span', 'backoffice-warn'); dc.textContent = 'DELEGATECALL'; sub.appendChild(dc); }
          if (ethVal > 0n) { sub.appendChild(boSep()); sub.appendChild(document.createTextNode('sends ' + formatBalance(ethVal, 18, 'ETH'))); }
          main.appendChild(sub);
          // Show WHO has signed (and who's still needed), so a coordinator can chase the exact missing signer(s)
          // instead of guessing from a bare count. Confirmations come from the Safe tx-service (hosted chains).
          // Each owner renders as its truncated address, upgraded to its ENS name (mainnet reverse-resolve) if any.
          var signedList = (tx.confirmations || []).map(function (cf) { return cf.owner; }).filter(Boolean);
          var signedSet = {}; signedList.forEach(function (o) { signedSet[o.toLowerCase()] = true; });
          function appendOwners(parent, addrs) {
            addrs.forEach(function (o, i) {
              if (i) parent.appendChild(document.createTextNode(', '));
              var suf = (acc && o.toLowerCase() === acc.toLowerCase()) ? ' (you)' : '';
              var s = el('span'); s.textContent = truncAddr(o) + suf; parent.appendChild(s);
              ensNameOf(o).then(function (n) { if (n) s.textContent = n + suf; }).catch(function () {});
            });
          }
          var who = el('div', 'backoffice-sub'); who.style.opacity = '0.85'; who.style.marginTop = '2px';
          who.appendChild(document.createTextNode('signed: '));
          if (signedList.length) appendOwners(who, signedList); else who.appendChild(document.createTextNode('none'));
          if (nconf < need) {
            var missing = (info.owners || []).filter(function (o) { return !signedSet[o.toLowerCase()]; });
            if (missing.length) { who.appendChild(boSep()); var nd = el('span', 'backoffice-warn'); nd.textContent = 'needs: '; who.appendChild(nd); appendOwners(nd, missing); }
          }
          main.appendChild(who);
          // Click the row body to inspect the full decoded tx (contract, function, args, raw calldata) read-only —
          // the same review the Sign/Execute buttons show, without committing to either.
          main.style.cursor = 'pointer';
          main.title = 'View transaction details';
          main.addEventListener('click', function () { reviewQueuedSafeTx(c.id, c.name, tx, 'View'); });
          row.appendChild(main);
          var actions = el('div', 'backoffice-actions');
          var signed = (tx.confirmations || []).some(function (cf) { return acc && cf.owner && cf.owner.toLowerCase() === acc.toLowerCase(); });
          if (isSigner && !signed && nconf < need) {
            var signBtn = el('button', 'detail-check-btn'); signBtn.textContent = 'Sign';
            signBtn.addEventListener('click', function () {
              reviewQueuedSafeTx(c.id, c.name, tx, 'Sign').then(function (ok) {
                if (!ok) return;
                signBtn.disabled = true; signBtn.textContent = 'Signing…';
                confirmSafeTx(c.id, safe, tx, acc).then(function () { signBtn.textContent = 'Signed'; setTimeout(function () { loadQueues(info); }, 1200); })
                  .catch(function (e) { signBtn.disabled = false; signBtn.textContent = 'Sign'; alert((e && e.message) || e); });
              });
            });
            actions.appendChild(signBtn);
          } else if (signed) {
            var done = el('span', 'backoffice-signed'); done.textContent = 'You signed'; actions.appendChild(done);
          }
          // Enough signatures → execute straight from here (connected wallet sends it + pays gas). Safe nonces are
          // strict, but same-nonce proposals are alternatives: executing either current-nonce tx consumes the nonce and
          // replaces the rest. Higher nonces stay gated until the current nonce lands.
          if (nconf >= need) {
            if (execPlan.batchByIndex[txIdx]) ready.push({ cid: c.id, chain: c.name, tx: tx });
            else if (execPlan.duplicateNonceByIndex[txIdx]) readyAlternativesExcluded += 1;
            else readyBlockedExcluded += 1;
            var execBtn = el('button', 'detail-check-btn'); execBtn.textContent = 'Execute';
            if (execPlan.directByIndex[txIdx]) {
              if (execPlan.duplicateNonceByIndex[txIdx]) execBtn.title = 'Executes this nonce and replaces the other #' + tx.nonce + ' alternatives';
              execBtn.addEventListener('click', function () {
                if (!(getAccount && getAccount())) { connect(); return; }
                reviewQueuedSafeTx(c.id, c.name, tx, 'Execute').then(function (ok) {
                  if (!ok) return;
                  execBtn.disabled = true; execBtn.textContent = 'Executing…';
                  executeSafeTx(c.id, safe, tx).then(function () { execBtn.textContent = 'Sent'; setTimeout(function () { loadQueues(info); document.dispatchEvent(new CustomEvent('jb:bridge-updated')); }, 2000); })
                    .catch(function (e) { execBtn.disabled = false; execBtn.textContent = 'Execute'; alert((e && (e.shortMessage || e.message)) || e); });
                });
              });
            } else {
              execBtn.disabled = true;
              execBtn.title = 'Executes after #' + execPlan.frontNonce + ' lands' + (readyAlternativesExcluded ? ' — same-nonce alternatives must be chosen individually' : ' — or use "Execute all" to run unambiguous txs in order in one payment');
            }
            actions.appendChild(execBtn);
          }
          var safeHash = tx.safeTxHash || tx.contractTransactionHash;
          var safeHref = (safeHash && safeTxLink(c.id, safe, safeHash)) || safeQueueLink(c.id, safe);
          if (safeHref) {
            var safeA = document.createElement('a');
            safeA.className = 'operator-cta backoffice-safe-tx';
            safeA.href = safeHref; safeA.target = '_blank'; safeA.rel = 'noopener';
            safeA.textContent = 'Open in Safe';
            safeA.title = 'Sign or inspect this transaction in the Safe app';
            actions.appendChild(safeA);
          }
          row.appendChild(actions);
          list.appendChild(row);
        });
      }).catch(function () {
        list.innerHTML = '';
        var er = el('div', 'backoffice-none'); er.textContent = 'Could not load the Safe queue.';
        list.appendChild(er);
      });
    });

    // Offer to execute unambiguous ready txs in ONE Relayr payment. Same-nonce alternatives are deliberately left out:
    // only an explicit per-row Execute click can choose which tx should consume that nonce.
    Promise.all(chainLoads).then(function () {
      batchBar.innerHTML = '';
      if (ready.length < 2) {
        if (readyAlternativesExcluded || readyBlockedExcluded) {
          var solo = el('span', 'backoffice-batch-note');
          solo.textContent = readyAlternativesExcluded
            ? 'Same-nonce alternatives are not included in Execute all — choose one with its Execute button.'
            : 'Ready higher-nonce transactions are not included in Execute all until earlier nonces clear.';
          batchBar.appendChild(solo);
        }
        return; // a single ready tx → just use its own Execute button
      }
      var nChains = Object.keys(ready.reduce(function (m, r) { m[r.cid] = 1; return m; }, {})).length;
      var note = el('span', 'backoffice-batch-note');
      note.textContent = ready.length + ' unambiguous transactions ready' + (nChains > 1 ? ' across ' + nChains + ' chains' : '') + ' — executed in nonce order in one payment. ' + (readyAlternativesExcluded ? 'Same-nonce alternatives are excluded; choose one individually. ' : '') + (readyBlockedExcluded ? 'Higher-nonce ready transactions wait for earlier nonces. ' : '');
      batchBar.appendChild(note);
      var allBtn = el('button', 'detail-check-btn'); allBtn.textContent = 'Execute all';
      allBtn.addEventListener('click', function () {
        if (!(getAccount && getAccount())) { connect(); return; }
        var entries = ready.map(function (r) { return safeExecRelayrTx(r.cid, safe, r.tx); });
        var preview = ready.map(function (r) { return { cid: r.cid, chain: r.chain, nonce: r.tx.nonce, details: labelForQueuedTx(r.tx) + ' → ' + (resolveContractName(r.tx.to, r.cid) || r.tx.to) }; });
        runRelayrBundle(entries, { title: 'Execute ' + ready.length + ' transaction' + (ready.length > 1 ? 's' : ''), preview: preview }).then(function (res) {
          if (res && res.done) loadQueues(info);
        });
      });
      batchBar.appendChild(allBtn);
    }).catch(function () {});
  }

  function startLoad() {
    fetchSafeInfo(safe, homeChainId).then(function (info) {
      if (!info) { intro.textContent = 'This account isn’t a Safe — there’s no multisig queue.'; body.innerHTML = ''; return; }
      intro.textContent = contextLabel + '-only actions are proposed here per chain; signers confirm + execute.';
      loadQueues(info);
    }).catch(function () { intro.textContent = 'Could not read the Safe.'; body.innerHTML = ''; });
  }
  // Only hit the rate-limited Safe Transaction Service when this card is actually ON SCREEN — i.e. the user is
  // viewing the Owner/Operator/Admin tab. A project detail can sit mounted off-screen (e.g. restored under
  // #discover), and we must NOT poll the Safe API from there. Load once, when the card first scrolls into view.
  var loaded = false;
  function maybeLoad() { if (loaded) return; loaded = true; startLoad(); }
  if (typeof IntersectionObserver === 'function') {
    var io = new IntersectionObserver(function (entries) {
      if (entries.some(function (e) { return e.isIntersecting; })) { io.disconnect(); maybeLoad(); }
    }, { rootMargin: '120px' });
    io.observe(card);
  } else { maybeLoad(); }

  // Refresh when an action queues a new tx from a modal — but only for a card that's been viewed + is connected.
  document.addEventListener('jb:safe-queued', function () {
    if (!loaded || !card.isConnected) return;
    fetchSafeInfo(safe, homeChainId).then(function (info) { if (info) loadQueues(info); }).catch(function () {});
  });
  onWalletChange(function () {
    if (!loaded || !card.isConnected) return;
    fetchSafeInfo(safe, homeChainId).then(function (info) { if (info) loadQueues(info); }).catch(function () {});
  });
  return card;
}

// ── Protocol Admin tab ──────────────────────────────────────────────────────
