function lpBlockHex(n) { return '0x' + BigInt(n).toString(16); }
function lpIndexedAddress(topic) { return String(topic || '').slice(-40).toLowerCase(); }

// Raw eth_getLogs lets the first topic be an OR while retaining the indexed pool-id filter. viem's `events`
// helper drops event args for multi-event filters, which would download every PoolManager pool on the chain.
async function lpPoolLogsRange(primary, fallback, pm, poolId, fromBlock, toBlock, onlyInitialize) {
  var topics = [onlyInitialize ? LP_INITIALIZE_TOPIC : [LP_INITIALIZE_TOPIC, LP_MODIFY_LIQUIDITY_TOPIC], poolId];
  var params = [{ address: pm, topics: topics, fromBlock: lpBlockHex(fromBlock), toBlock: lpBlockHex(toBlock) }];
  try {
    return await primary.request({ method: 'eth_getLogs', params: params });
  } catch (firstError) {
    if (!fallback || fallback === primary) throw firstError;
    return fallback.request({ method: 'eth_getLogs', params: params });
  }
}

async function lpLatestLogBlock(primary, fallback) {
  try { return await primary.getBlockNumber(); }
  catch (firstError) {
    if (!fallback || fallback === primary) throw firstError;
    return fallback.getBlockNumber();
  }
}

export function lpCollectPoolLogs(logs, posm, state) {
  (logs || []).forEach(function (log) {
    var topic0 = String(log.topics && log.topics[0] || '').toLowerCase();
    if (topic0 === LP_INITIALIZE_TOPIC) {
      var block = typeof log.blockNumber === 'bigint' ? log.blockNumber : BigInt(log.blockNumber);
      if (state.initializeBlock == null || block < state.initializeBlock) state.initializeBlock = block;
      return;
    }
    if (topic0 !== LP_MODIFY_LIQUIDITY_TOPIC) return;
    // PoolManager positions created outside the configured PositionManager can use an arbitrary salt. Treating that
    // salt as an NFT id can attribute an unrelated position to this pool, so require the indexed sender to be posm.
    if (lpIndexedAddress(log.topics && log.topics[2]) !== String(posm).slice(2).toLowerCase()) return;
    var data = String(log.data || '');
    if (!/^0x[0-9a-fA-F]{256}$/.test(data)) throw new Error('Malformed ModifyLiquidity log while reading LP positions');
    var tokenId = BigInt('0x' + data.slice(194, 258)); // fourth non-indexed word: bytes32 salt == tokenId
    var block = typeof log.blockNumber === 'bigint' ? log.blockNumber : BigInt(log.blockNumber);
    var known = state.tokenIds[tokenId.toString()];
    if (tokenId > 0n && (!known || block < known.block)) state.tokenIds[tokenId.toString()] = { id: tokenId, block: block };
  });
}

async function lpScanKnownPoolRange(primary, fallback, pm, poolId, posm, fromBlock, toBlock, state) {
  if (fromBlock > toBlock) return;
  // Scan every bounded window even when an RPC accepts a wider request. Some gateways silently truncate large log
  // results instead of rejecting, which would make a successful-looking response incomplete.
  var cursor = fromBlock;
  while (cursor <= toBlock) {
    var ranges = [];
    for (var n = 0; n < LP_LOG_BATCH_WINDOWS && cursor <= toBlock; n++) {
      var hi = cursor + LP_LOG_WINDOW - 1n;
      if (hi > toBlock) hi = toBlock;
      ranges.push({ lo: cursor, hi: hi });
      cursor = hi + 1n;
    }
    var batches = await Promise.all(ranges.map(function (range) {
      return lpPoolLogsRange(primary, fallback, pm, poolId, range.lo, range.hi, false);
    }));
    batches.forEach(function (logs) { lpCollectPoolLogs(logs, posm, state); });
  }
}

// Return every PositionManager NFT id ever used in this pool. The scan stops only at the pool's Initialize event;
// provider failures reject instead of becoming an empty position list. A short overlap keeps the session cache safe
// across shallow reorgs while avoiding a full rescan every time the Owners/You views refresh.
async function lpPoolPositionTokenIds(chainId, pm, posm, poolId) {
  var fallback = clientFor(chainId);
  var primary = lpLogsClient(chainId) || fallback;
  var latest = await lpLatestLogBlock(primary, fallback);
  var cacheKey = chainId + ':' + String(pm).toLowerCase() + ':' + String(posm).toLowerCase() + ':' + String(poolId).toLowerCase();
  var cached = _lpPoolHistoryCache[cacheKey];
  if (cached && latest < cached.throughBlock) cached = null;
  var state = { initializeBlock: cached && cached.initializeBlock, tokenIds: {} };
  if (cached && latest >= cached.initializeBlock) {
    var overlapStart = cached.throughBlock > LP_LOG_REORG_OVERLAP
      ? cached.throughBlock - LP_LOG_REORG_OVERLAP + 1n
      : cached.initializeBlock;
    if (overlapStart < cached.initializeBlock) overlapStart = cached.initializeBlock;
    // Drop ids first seen inside the overlap, then rebuild that tail from canonical logs. Older ids remain even if
    // they were modified in the tail because their mint event is already final enough for this session cache.
    (cached.entries || []).forEach(function (entry) {
      if (entry.block < overlapStart) state.tokenIds[entry.id.toString()] = { id: entry.id, block: entry.block };
    });
    await lpScanKnownPoolRange(primary, fallback, pm, poolId, posm, overlapStart, latest, state);
  } else {
    // A one-shot Initialize lookup is much cheaper when the RPC supports wide indexed ranges.
    try {
      var initializeLogs = await lpPoolLogsRange(primary, fallback, pm, poolId, 0n, latest, true);
      lpCollectPoolLogs(initializeLogs, posm, state);
    } catch (_) {}
    if (state.initializeBlock != null) {
      await lpScanKnownPoolRange(primary, fallback, pm, poolId, posm, state.initializeBlock, latest, state);
    } else {
      // Range-limited RPC: walk backwards in bounded batches until the authoritative Initialize event is found.
      var cursor = latest;
      while (true) {
        var ranges = [];
        for (var n = 0; n < LP_LOG_BATCH_WINDOWS; n++) {
          var lo = cursor >= LP_LOG_WINDOW ? cursor - LP_LOG_WINDOW + 1n : 0n;
          ranges.push({ lo: lo, hi: cursor });
          if (lo === 0n) break;
          cursor = lo - 1n;
        }
        var batches = await Promise.all(ranges.map(function (range) {
          return lpPoolLogsRange(primary, fallback, pm, poolId, range.lo, range.hi, false);
        }));
        batches.forEach(function (logs) { lpCollectPoolLogs(logs, posm, state); });
        if (state.initializeBlock != null) break;
        if (ranges[ranges.length - 1].lo === 0n) throw new Error('Could not verify the complete LP history: pool initialization log not found');
        cursor = ranges[ranges.length - 1].lo - 1n;
      }
    }
  }
  if (state.initializeBlock == null) throw new Error('Could not verify the complete LP history');
  var entries = Object.keys(state.tokenIds).map(function (key) { return state.tokenIds[key]; });
  var tokenIds = entries.map(function (entry) { return entry.id; });
  tokenIds.sort(function (a, b) { return a < b ? -1 : (a > b ? 1 : 0); });
  _lpPoolHistoryCache[cacheKey] = { initializeBlock: state.initializeBlock, throughBlock: latest, entries: entries };
  return tokenIds;
}

async function lpReadPositionDetails(client, posm, tokenIds, expectedPoolId) {
  var details = await Promise.all(tokenIds.map(function (tokenId) {
    var ownerRead = client.readContract({ address: posm, abi: lpPositionViewAbi, functionName: 'ownerOf', args: [tokenId] })
      .then(function (owner) { return { owner: owner }; })
      .catch(function (error) { return { error: error }; });
    return Promise.all([
      client.readContract({ address: posm, abi: lpPositionViewAbi, functionName: 'positionInfo', args: [tokenId] }).then(function (x) { return BigInt(x); }),
      ownerRead,
      client.readContract({ address: posm, abi: lpPositionViewAbi, functionName: 'getPositionLiquidity', args: [tokenId] }).then(function (x) { return BigInt(x); }),
    ]).then(function (result) {
      var info = result[0], ownerResult = result[1], liquidity = result[2];
      // ownerOf legitimately reverts after an NFT is burned. Any owner failure for a live position is incomplete data.
      if (ownerResult.error && info !== 0n && liquidity !== 0n) throw ownerResult.error;
      return { tokenId: tokenId, info: info, owner: ownerResult.owner || null, liquidity: liquidity };
    });
  }));
  if (!expectedPoolId) return details;
  await Promise.all(details.map(function (detail) {
    if (!detail.owner || detail.info === 0n || detail.liquidity === 0n) return null;
    return client.readContract({ address: posm, abi: lpPositionViewAbi, functionName: 'getPoolAndPositionInfo', args: [detail.tokenId] })
      .then(function (result) {
        var key = result && (result.poolKey || result[0]);
        var info = BigInt(result && (result.info != null ? result.info : result[1]));
        if (!key || info !== detail.info) throw new Error('PositionManager returned inconsistent LP position data');
        var actualPoolId = keccak256(encodeAbiParameters(POOLKEY_TUPLE, [[key.currency0, key.currency1, key.fee, key.tickSpacing, key.hooks]]));
        if (actualPoolId.toLowerCase() !== String(expectedPoolId).toLowerCase()) {
          throw new Error('PositionManager token does not belong to the expected pool');
        }
      });
  }));
  return details;
}

// Enumerate this pool's V4 LP positions (provider, range, liquidity → pair-token amounts). Finds the pool's
// position tokenIds from the PoolManager's ModifyLiquidity logs (salt = tokenId), then reads each position.
// Aggregates by owner; totals are exact reserves. Null means no initialized pool; incomplete reads reject.
async function readLpPositions(project, chainId) {
  try {
    var posm = POSITION_MANAGER_BY_CHAIN[chainId];
    var pm = POOL_MANAGER_BY_CHAIN[chainId];
    if (!posm || !pm) return null;
    var st = await readPoolState(project, chainId, { strict: true });
    if (!st || !st.key) return null;
    var key = st.key, sqrtP = st.sqrtP, pair = st.pair;
    // The pair (terminal) token may be currency0 or currency1; everything below is in pair/token terms
    // ("eth" fields hold the PAIR amount — native ETH or USDC — and "rev" the project token).
    var pairIsC0 = ((key.currency0 || '').toLowerCase() === pair.addr);
    var pairDec = pair.decimals;
    var sp = Number(sqrtP) / Math.pow(2, 96), rawP = sp * sp;
    var rawRatio = pairIsC0 ? (rawP > 0 ? 1 / rawP : 0) : rawP;
    var poolPrice = rawRatio * Math.pow(10, 18 - pairDec); // pair per token (human)
    var poolId = keccak256(encodeAbiParameters(POOLKEY_TUPLE, [[key.currency0, key.currency1, key.fee, key.tickSpacing, key.hooks]]));
    var client = clientFor(chainId);
    var empty = { owners: [], totalEth: 0n, totalRev: 0n, poolPrice: poolPrice, count: 0, positions: [], pair: pair, pairIsC0: pairIsC0 };

    var tokenIds = await lpPoolPositionTokenIds(chainId, pm, posm, poolId);
    if (!tokenIds.length) return empty;
    var det = await lpReadPositionDetails(client, posm, tokenIds, poolId);

    var totalEth = 0n, totalRev = 0n, byOwner = {}, positions = [];
    var pairScale = Math.pow(10, pairDec);
    det.forEach(function (p) {
      if (!p.owner || p.liquidity <= 0n || p.info === 0n) return;
      var tickUpper = Number(lpSignExtend24((p.info >> 32n) & 0xffffffn));
      var tickLower = Number(lpSignExtend24((p.info >> 8n) & 0xffffffn));
      var amounts = lpGetAmountsForLiquidity(sqrtP, lpSqrtAtTick(tickLower), lpSqrtAtTick(tickUpper), p.liquidity);
      // amount0/amount1 are currency-ordered; map to pair ("eth") and project token ("rev").
      var pairAmt = pairIsC0 ? amounts.amount0 : amounts.amount1;
      var tokAmt = pairIsC0 ? amounts.amount1 : amounts.amount0;
      totalEth += pairAmt; totalRev += tokAmt;
      positions.push({ tickLower: tickLower, tickUpper: tickUpper, liquidity: p.liquidity, eth: pairAmt, rev: tokAmt });
      var val = Number(pairAmt) / pairScale + (Number(tokAmt) / 1e18) * poolPrice; // value in pair-token terms
      var k = p.owner.toLowerCase();
      if (!byOwner[k]) byOwner[k] = { address: p.owner, valueEth: 0, eth: 0n, rev: 0n, positions: 0 };
      byOwner[k].valueEth += val; byOwner[k].eth += pairAmt; byOwner[k].rev += tokAmt; byOwner[k].positions++;
    });
    var owners = Object.keys(byOwner).map(function (k) { return byOwner[k]; }).sort(function (a, b) { return b.valueEth - a.valueEth; });
    return { owners: owners, totalEth: totalEth, totalRev: totalRev, poolPrice: poolPrice, sqrtP: sqrtP, count: owners.length, positions: positions, pair: pair, pairIsC0: pairIsC0 };
  } catch (e) { throw e; }
}

// V4 liquidity-depth histogram: how much active liquidity sits in each price band. Bars are colored by
// side of the current pool price (below = teal/support, above = orange); dashed markers show the cash out
// floor, current AMM price, and issuance ceiling. Price axis is log-scaled (ranges span orders of magnitude).
export function lpDepthMarkerLabelLayout(markers, width) {
  var gap = 4, charWidth = 7.2, rowRight = [], placed = [];
  (markers || []).forEach(function (marker, index) {
    var label = String(marker.label || '');
    var halfWidth = Math.max(12, label.length * charWidth / 2);
    var labelX = Math.max(halfWidth + 1, Math.min(width - halfWidth - 1, Number(marker.x)));
    placed.push({ index: index, labelX: labelX, left: labelX - halfWidth, right: labelX + halfWidth, row: 0 });
  });
  placed.sort(function (a, b) { return a.left - b.left; }).forEach(function (item) {
    var row = 0;
    while (row < rowRight.length && item.left < rowRight[row] + gap) row++;
    item.row = row; rowRight[row] = item.right;
  });
  placed.sort(function (a, b) { return a.index - b.index; });
  return placed.map(function (item) { return { x: item.labelX, row: item.row }; });
}

function renderLpDepthChart(lp, amm, issuance, cashout, sym) {
  var positions = (lp && lp.positions) || [];
  if (!positions.length) return null;
  var sqrtP = lp.sqrtP;
  // pair (terminal) token per project token, accounting for currency ordering + decimals (ETH pools: factor 1, pair=c0).
  var pairIsC0 = lp.pairIsC0 !== false;
  var pairDec = lp.pair && lp.pair.decimals != null ? lp.pair.decimals : 18;
  var pairSym = (lp.pair && lp.pair.symbol) || 'ETH';
  var decFactor = Math.pow(10, 18 - pairDec);
  var priceAtTick = function (t) { return (pairIsC0 ? 1 / Math.pow(1.0001, t) : Math.pow(1.0001, t)) * decFactor; };
  var tickAtPrice = function (p) { return Math.log(pairIsC0 ? (decFactor / p) : (p / decFactor)) / Math.log(1.0001); };
  var pmin = Infinity, pmax = -Infinity;
  positions.forEach(function (p) { var a = priceAtTick(p.tickLower), b = priceAtTick(p.tickUpper); pmin = Math.min(pmin, a, b); pmax = Math.max(pmax, a, b); });
  [amm, issuance, cashout].forEach(function (v) { if (v && v > 0) { pmin = Math.min(pmin, v); pmax = Math.max(pmax, v); } });
  if (!(pmax > pmin) || !isFinite(pmin) || !isFinite(pmax) || pmin <= 0) return null;
  var lmin = Math.log(pmin), lmax = Math.log(pmax), span = (lmax - lmin) || 1;
  var N = 56;
  // Per band: liquidity (bar height) + the REV/ETH it holds at the current price (hover tooltip).
  var bands = [];
  for (var i = 0; i < N; i++) {
    var pLo = Math.exp(lmin + (i / N) * span), pHi = Math.exp(lmin + ((i + 1) / N) * span);
    var mid = Math.exp(lmin + ((i + 0.5) / N) * span);
    var bTickLo = tickAtPrice(pHi), bTickHi = tickAtPrice(pLo); // price 1/1.0001^tick → tick falls as price rises
    var liq = 0, ethW = 0n, revW = 0n;
    positions.forEach(function (p) {
      var plo = priceAtTick(p.tickUpper), phi = priceAtTick(p.tickLower);
      if (mid >= plo && mid <= phi) liq += Number(p.liquidity);
      var oLo = Math.max(bTickLo, p.tickLower), oHi = Math.min(bTickHi, p.tickUpper);
      if (oLo < oHi && sqrtP) {
        var am = lpGetAmountsForLiquidity(sqrtP, lpSqrtAtTick(Math.round(oLo)), lpSqrtAtTick(Math.round(oHi)), p.liquidity);
        ethW += pairIsC0 ? am.amount0 : am.amount1; revW += pairIsC0 ? am.amount1 : am.amount0;
      }
    });
    bands.push({ mid: mid, pLo: pLo, pHi: pHi, liq: liq, eth: ethW, rev: revW });
  }
  var maxL = Math.max.apply(null, bands.map(function (b) { return b.liq; })) || 1;
  // viewBox aspect ≈ the container (left column ≈ 300px) so the SVG scales ~uniformly — otherwise the
  // <text> labels render horizontally stretched/thin under preserveAspectRatio="none".
  var W = 300, padL = 0, padR = 0, padT = 4, padB = 24;
  var plotW = W - padL - padR;
  var xOf = function (price) { return padL + ((Math.log(price) - lmin) / span) * plotW; };
  var markerSpecs = [
    { price: cashout, color: '#2c2018', label: 'floor' },
    { price: amm, color: '#b8602e', label: 'price' },
    { price: issuance, color: '#6ec4c4', label: 'ceiling' },
  ].filter(function (marker) {
    return marker.price > 0 && marker.price >= pmin * (1 - 1e-9) && marker.price <= pmax * (1 + 1e-9);
  }).map(function (marker) {
    marker.lineX = Math.max(0.8, Math.min(W - 0.8, xOf(marker.price)));
    marker.x = marker.lineX;
    return marker;
  });
  var markerLabels = lpDepthMarkerLabelLayout(markerSpecs, W);
  var labelRows = markerLabels.reduce(function (max, label) { return Math.max(max, label.row + 1); }, 0);
  var labelH = Math.max(20, labelRows * 14 + 4), H = 130 + labelH;
  var plotTop = padT + labelH, plotH = H - plotTop - padB;
  var bw = plotW / N, svg = '<svg viewBox="0 0 ' + W + ' ' + H + '" class="lp-depth-svg" preserveAspectRatio="none" role="img" aria-label="Pool liquidity by price band">';
  for (var j = 0; j < N; j++) {
    if (bands[j].liq <= 0) continue;
    var h = (bands[j].liq / maxL) * plotH, x = padL + j * bw;
    var color = (amm && bands[j].mid < amm) ? '#6ec4c4' : '#cca080'; // below price: teal-light, above: orange-light
    svg += '<rect x="' + x.toFixed(1) + '" y="' + (plotTop + plotH - h).toFixed(1) + '" width="' + Math.max(0.5, bw - 0.5).toFixed(1) + '" height="' + h.toFixed(1) + '" fill="' + color + '" opacity="0.5"/>';
  }
  // Markers: dashed line spans the bars; label sits in the row ABOVE the bars (no overlap).
  function marker(spec, label) {
    return '<line x1="' + spec.lineX.toFixed(1) + '" y1="' + plotTop + '" x2="' + spec.lineX.toFixed(1) + '" y2="' + (plotTop + plotH) + '" stroke="' + spec.color + '" stroke-width="1.5" stroke-dasharray="3 2"/>'
      + '<text x="' + label.x.toFixed(1) + '" y="' + (padT + 11 + label.row * 14) + '" font-size="12" fill="#7d6858" text-anchor="middle">' + spec.label + '</text>';
  }
  markerSpecs.forEach(function (spec, index) { svg += marker(spec, markerLabels[index]); });
  svg += '<text x="' + padL + '" y="' + (H - 7) + '" font-size="12" fill="#7d6858" text-anchor="start">' + formatPrice(Math.exp(lmin)) + '</text>';
  svg += '<text x="' + (W - padR) + '" y="' + (H - 7) + '" font-size="12" fill="#7d6858" text-anchor="end">' + formatPrice(Math.exp(lmax)) + '</text>';
  svg += '</svg>';
  var panel = el('div', 'lp-depth');
  var title = el('div', 'detail-card-title lp-depth-title'); title.textContent = 'Depth'; panel.appendChild(title);
  var holder = el('div', 'lp-depth-holder'); holder.innerHTML = svg;
  var tip = el('div', 'lp-depth-tip'); tip.style.display = 'none'; holder.appendChild(tip);
  holder.addEventListener('mousemove', function (e) {
    var rect = holder.getBoundingClientRect();
    var vx = (e.clientX - rect.left) / rect.width * W;
    var idx = Math.floor((vx - padL) / bw);
    if (idx < 0 || idx >= N) { tip.style.display = 'none'; return; }
    var b = bands[idx];
    var hasLiq = b.eth > 0n || b.rev > 0n || b.liq > 0;
    var sideTxt = amm ? (b.mid < amm ? ' | buy-side' : ' | sell-side') : '';
    // textContent, not innerHTML — `sym`/`pairSym` are project-controlled ERC-20 symbols (XSS sink otherwise).
    tip.textContent = '';
    var tipPrice = el('div', 'lp-depth-tip-price'); tipPrice.textContent = '≈ ' + formatPrice(b.mid) + ' ' + pairSym + '/' + sym + sideTxt;
    var tipAmt = el('div', 'lp-depth-tip-amt'); tipAmt.textContent = hasLiq
      ? (formatCompactTokenAmount(b.rev) + ' ' + sym + ' + ' + formatPrice(Number(b.eth) / Math.pow(10, pairDec)) + ' ' + pairSym)
      : 'no liquidity here';
    tip.appendChild(tipPrice); tip.appendChild(tipAmt);
    tip.style.display = '';
    tip.style.left = Math.max(2, Math.min(rect.width - 150, e.clientX - rect.left + 10)) + 'px';
  });
  holder.addEventListener('mouseleave', function () { tip.style.display = 'none'; });
  panel.appendChild(holder);
  return panel;
}

// Donut of LP ownership — each LP provider's share of the pooled liquidity (by ETH-value). Null if none.
function renderLpOwnersPie(lp) {
  var owners = lp.owners.filter(function (o) { return o.valueEth > 0; });
  if (!owners.length) return null;
  var total = owners.reduce(function (s, o) { return s + o.valueEth; }, 0);
  if (!(total > 0)) return null;
  var panel = el('div', 'owners-chart-panel');
  var svgNS = 'http://www.w3.org/2000/svg';
  var svg = document.createElementNS(svgNS, 'svg');
  svg.setAttribute('viewBox', '0 0 240 240'); svg.setAttribute('class', 'owners-pie-svg'); svg.setAttribute('role', 'img'); svg.setAttribute('aria-label', 'LP owner distribution');
  var cx = 120, cy = 120, outer = 92, inner = 54, angle = 0; // 3 o'clock start → tiny LP slices fan on the right
  // Pink-light fill, borders distinguish slices (matches the owners donut).
  if (owners.length === 1) {
    var ring = document.createElementNS(svgNS, 'path');
    ring.setAttribute('d', donutSlicePath(cx, cy, outer, inner, -Math.PI / 2, -Math.PI / 2 + Math.PI * 2 - 0.001));
    ring.setAttribute('class', 'owners-pie-slice');
    tagPieSlice(ring, owners[0].address, isAmmAddress(owners[0].address), ' (100%)');
    svg.appendChild(ring);
  } else {
    // smallest-first so the tiny LP slices fan out on the RIGHT side (matches the owners donut)
    owners.slice().sort(function (a, b) { return a.valueEth - b.valueEth; }).forEach(function (o) {
      var frac = o.valueEth / total; if (!(frac > 0)) return;
      var next = angle + frac * Math.PI * 2;
      var path = document.createElementNS(svgNS, 'path');
      path.setAttribute('d', donutSlicePath(cx, cy, outer, inner, angle, next));
      path.setAttribute('class', 'owners-pie-slice');
      tagPieSlice(path, o.address, isAmmAddress(o.address), ' (' + (frac * 100).toFixed(1) + '%)');
      svg.appendChild(path); angle = next;
    });
  }
  var cA = document.createElementNS(svgNS, 'text'); cA.setAttribute('x', String(cx)); cA.setAttribute('y', '113'); cA.setAttribute('class', 'owners-pie-center owners-pie-center-main'); cA.textContent = String(owners.length); svg.appendChild(cA);
  var cB = document.createElementNS(svgNS, 'text'); cB.setAttribute('x', String(cx)); cB.setAttribute('y', '132'); cB.setAttribute('class', 'owners-pie-center owners-pie-center-sub'); cB.textContent = owners.length === 1 ? 'LP' : 'LPs'; svg.appendChild(cB);
  panel.appendChild(svg);
  attachPieHover(panel, svg);
  return panel;
}

// Tag a donut slice with the data its hover tooltip shows: address (for ENS), suffix (amount | share),
// and the composed `data-tip` text. No <title> → no slow native tooltip; the custom one reads `data-tip`.
function tagPieSlice(slice, address, isAmm, suffix) {
  slice.setAttribute('data-addr', address);
  slice.setAttribute('data-suffix', suffix);
  if (isAmm) slice.setAttribute('data-amm', '1');
  slice.setAttribute('data-tip', (isAmm ? 'AMM (Uniswap V4 pool) ' : '') + truncAddr(address) + suffix);
}
// Reverse-resolve each slice's address to an ENS name (mainnet, cached) and swap it into the tooltip.
function resolvePieEns(root) {
  var seen = {};
  root.querySelectorAll('.owners-pie-slice[data-addr]').forEach(function (s) {
    var addr = s.getAttribute('data-addr');
    if (!addr || s.getAttribute('data-amm')) return;
    var k = addr.toLowerCase();
    if (!seen[k]) seen[k] = ensNameOf(addr);
    seen[k].then(function (name) {
      if (!name) return;
      root.querySelectorAll('.owners-pie-slice[data-addr="' + addr + '"]').forEach(function (el2) {
        el2.setAttribute('data-tip', name + (el2.getAttribute('data-suffix') || ''));
      });
    });
  });
}
// Immediate styled tooltip on donut hover + pink highlight of the hovered slice. ENS names where available.
function attachPieHover(panel, svg) {
  panel.style.position = 'relative';
  var tip = el('div', 'owners-pie-tip'); tip.style.display = 'none'; panel.appendChild(tip);
  var current = null;
  function clear() { if (current) { current.classList.remove('is-hover'); current = null; } }
  svg.addEventListener('mousemove', function (e) {
    var slice = e.target && e.target.closest && e.target.closest('.owners-pie-slice');
    if (!slice) { clear(); tip.style.display = 'none'; return; }
    if (slice !== current) { clear(); slice.classList.add('is-hover'); current = slice; }
    tip.textContent = slice.getAttribute('data-tip') || '';
    tip.style.display = '';
    var r = panel.getBoundingClientRect();
    tip.style.left = Math.max(4, Math.min(e.clientX - r.left + 10, r.width - tip.offsetWidth - 4)) + 'px';
    tip.style.top = Math.max(4, e.clientY - r.top + 10) + 'px';
  });
  svg.addEventListener('mouseleave', function () { clear(); tip.style.display = 'none'; });
  resolvePieEns(svg);
}

// Table of LP providers (mirrors the owners table) with per-LP position info: ETH, token, share.
function renderLpTable(lp, sym, chainId) {
  var owners = lp.owners.filter(function (o) { return o.valueEth > 0; });
  if (!owners.length) return null;
  var total = owners.reduce(function (s, o) { return s + o.valueEth; }, 0);
  var outer = el('div', 'owners-table-outer lp-pos-table-outer');
  if (owners.length > 8) {
    var search = buildAccountSearch(owners, function (sel) { applyFilter(sel); }, {
      subLabel: function (o) { return (o.valueEth / total * 100).toFixed(1) + '%'; },
    });
    outer.appendChild(search.el);
  }
  var wrap = el('div', 'owners-table-wrap lp-pos-table-wrap');
  var table = el('div', 'owners-table lp-pos-table');
  var pairSym = (lp.pair && lp.pair.symbol) || 'ETH';
  var pairScale = Math.pow(10, lp.pair && lp.pair.decimals != null ? lp.pair.decimals : 18);
  var head = el('div', 'owners-row owners-head');
  ['Account', pairSym, sym, 'Share'].forEach(function (h) { var c = el('span'); c.textContent = h; head.appendChild(c); });
  table.appendChild(head);
  var body = el('div', 'owners-tbody');
  table.appendChild(body);
  function buildLpRow(o) {
    var tr = el('div', 'owners-row');
    var acct = el('span', 'owners-account');
    acct.appendChild(addressNode(o.address));
    if (o.positions > 1) { var pc = el('span', 'lp-pos-count'); pc.textContent = o.positions + ' positions'; acct.appendChild(pc); }
    tr.appendChild(acct);
    var ethC = el('span', 'owners-balance'); ethC.textContent = lpTrimNum(Number(o.eth) / pairScale) + ' ' + pairSym; tr.appendChild(ethC);
    var revC = el('span', 'owners-balance'); revC.textContent = formatCompactTokenAmount(o.rev) + ' ' + sym; tr.appendChild(revC);
    var shareC = el('span'); var st = el('strong'); st.textContent = (o.valueEth / total * 100).toFixed(1) + '%'; shareC.appendChild(st); tr.appendChild(shareC);
    return tr;
  }
  wrap.appendChild(table);
  outer.appendChild(wrap);
  var navHolder = el('div', 'owners-nav-holder');
  outer.appendChild(navHolder);
  function applyFilter(sel) {
    var list = (sel && sel.length) ? owners.filter(function (o) { return sel.indexOf((o.address || '').toLowerCase()) !== -1; }) : owners;
    navHolder.innerHTML = '';
    navHolder.appendChild(attachPagination(body, list, LIST_PAGE_SIZE, buildLpRow));
  }
  applyFilter([]);
  return outer;
}

// Horizontal bar of the pool's pair (ETH/USDC) vs token split (by pair-value). Null if nothing to show.
function renderLpCompositionBar(lp, sym) {
  var pairSym = (lp.pair && lp.pair.symbol) || 'ETH';
  var pairScale = Math.pow(10, lp.pair && lp.pair.decimals != null ? lp.pair.decimals : 18);
  var ethF = Number(lp.totalEth) / pairScale;
  var revVal = (Number(lp.totalRev) / 1e18) * lp.poolPrice;
  var total = ethF + revVal;
  if (!(total > 0)) return null;
  var ethPct = ethF / total * 100, revPct = revVal / total * 100;
  var ethColor = '#6ec4c4', revColor = '#cca080'; // teal-light (pair) / orange-light (REV)
  var wrap = el('div', 'lp-bar-wrap');
  var bar = el('div', 'lp-bar');
  var s0 = el('div', 'lp-bar-seg'); s0.style.width = ethPct + '%'; s0.style.background = ethColor; s0.title = pairSym + ' ' + ethPct.toFixed(1) + '%'; bar.appendChild(s0);
  var s1 = el('div', 'lp-bar-seg'); s1.style.width = revPct + '%'; s1.style.background = revColor; s1.title = sym + ' ' + revPct.toFixed(1) + '%'; bar.appendChild(s1);
  wrap.appendChild(bar);
  var legend = el('div', 'lp-comp-legend lp-comp-legend-h');
  [[pairSym, formatPrice(ethF), ethPct, ethColor], [sym, formatCompactTokenAmount(lp.totalRev), revPct, revColor]].forEach(function (r) {
    var row = el('div', 'lp-comp-legend-row');
    var d = el('span', 'lp-comp-dot'); d.style.background = r[3]; row.appendChild(d);
    var txt = el('span'); txt.textContent = r[0] + ' ' + r[1] + ' (' + r[2].toFixed(1) + '%)'; row.appendChild(txt);
    legend.appendChild(row);
  });
  wrap.appendChild(legend);
  return wrap;
}

// Full V4 mint: derive ticks/liquidity from the range + amounts, do Permit2 approvals, then
// PositionManager.modifyLiquidities (MINT_POSITION, CLOSE c0, CLOSE c1, SWEEP native refund).
// Read-only: derive ticks, liquidity, required amounts, and the encoded modifyLiquidities calldata.
// No wallet/txs — used to build the preview before the user signs.
async function prepareAddLiquidity(opts) {
  var project = opts.project, chainId = opts.chainId;
  var acct = getAccount();
  if (!acct) throw new Error('Connect a wallet');
  var posm = POSITION_MANAGER_BY_CHAIN[chainId];
  if (!posm) throw new Error('No position manager on this chain');

  var st = await readPoolState(project, chainId, { strict: true });
  if (!st || !st.key) throw new Error('Pool not initialized on this chain');
  var key = st.key, sqrtP = st.sqrtP, pair = st.pair;
  var c0 = (key.currency0 || '').toLowerCase();
  var pairIsC0 = (c0 === pair.addr); // else the project token (always ERC-20) is currency0
  var pairDec = pair.decimals;
  // Map the pair/token deposit amounts (raw, in their own decimals) onto currency0/currency1 by ordering.
  var amount0 = pairIsC0 ? opts.pairAmount : opts.tokenAmount;
  var amount1 = pairIsC0 ? opts.tokenAmount : opts.pairAmount;

  var s = Number(key.tickSpacing);
  var maxUsable = Math.trunc(887272 / s) * s, minUsable = Math.trunc(-887272 / s) * s;
  // UI range is in pair-per-token (q). Pool price is raw currency1/currency0:
  //   pair=c0 → P_raw = 10^(18−pairDec)/q ;  token=c0 → P_raw = q·10^(pairDec−18).
  // ticks are monotonic in P_raw, so derive both ends and sort (order-agnostic across the two cases).
  var pRawFromQ = function (q) { return pairIsC0 ? (Math.pow(10, 18 - pairDec) / q) : (q * Math.pow(10, pairDec - 18)); };
  var tA = Math.log(pRawFromQ(opts.pa)) / Math.log(1.0001);
  var tB = Math.log(pRawFromQ(opts.pb)) / Math.log(1.0001);
  var tickLower = Math.max(minUsable, lpAlignDown(Math.floor(Math.min(tA, tB)), s));
  var tickUpper = Math.min(maxUsable, lpAlignUp(Math.ceil(Math.max(tA, tB)), s));
  if (tickUpper <= tickLower) tickUpper = Math.min(maxUsable, tickLower + s);
  // Single-sided deposits: tick-alignment can nudge the CURRENT price just inside the range (e.g. price == the range
  // top, but alignDown drops tickLower below it), so the position would need a sliver of the un-funded token and
  // lpGetLiquidityForAmounts returns min(L, 0) = 0 → "Amounts too small". When only one side is funded, keep the
  // current price OUTSIDE the range: only token0 funded → range entirely above the price (all token0); only token1 →
  // entirely below (all token1). (amount0/amount1 are already mapped to pool currency0/currency1.)
  var curTick = Math.floor(2 * Math.log(Number(sqrtP) / Math.pow(2, 96)) / Math.log(1.0001));
  if (amount1 <= 0n && amount0 > 0n && curTick >= tickLower) tickLower = Math.min(maxUsable, lpAlignUp(curTick + 1, s));
  if (amount0 <= 0n && amount1 > 0n && curTick < tickUpper) tickUpper = Math.max(minUsable, lpAlignDown(curTick, s));
  if (tickUpper <= tickLower) tickUpper = Math.min(maxUsable, tickLower + s);

  var sqrtA = lpSqrtAtTick(tickLower), sqrtB = lpSqrtAtTick(tickUpper);
  var liquidity = lpGetLiquidityForAmounts(sqrtP, sqrtA, sqrtB, amount0, amount1);
  if (liquidity <= 0n) throw new Error('Amounts too small for this range');
  var need = lpGetAmountsForLiquidity(sqrtP, sqrtA, sqrtB, liquidity);
  // 1% headroom over the exact requirement (SWEEP refunds unused native; Permit2/CLOSE pull the exact ERC-20).
  var amount0Max = need.amount0 + need.amount0 / 100n + 1n;
  var amount1Max = need.amount1 + need.amount1 / 100n + 1n;

  // The native side (only ever the pair, when it's ETH) is sent as msg.value; ERC-20 sides go via Permit2.
  var c0Native = pairIsC0 && pair.isNative;
  var c1Native = !pairIsC0 && pair.isNative;
  var value = c0Native ? amount0Max : (c1Native ? amount1Max : 0n);
  var erc20 = [];
  if (!c0Native && amount0Max > 1n) erc20.push({ currency: key.currency0, max: amount0Max });
  if (!c1Native && amount1Max > 1n) erc20.push({ currency: key.currency1, max: amount1Max });

  var mintParams = encodeAbiParameters(
    [
      { type: 'tuple', components: [{ type: 'address' }, { type: 'address' }, { type: 'uint24' }, { type: 'int24' }, { type: 'address' }] },
      { type: 'int24' }, { type: 'int24' }, { type: 'uint256' }, { type: 'uint128' }, { type: 'uint128' }, { type: 'address' }, { type: 'bytes' },
    ],
    [
      [key.currency0, key.currency1, BigInt(key.fee), BigInt(key.tickSpacing), key.hooks],
      BigInt(tickLower), BigInt(tickUpper), liquidity, amount0Max, amount1Max, acct, '0x',
    ]
  );
  var closeC0 = encodeAbiParameters([{ type: 'address' }], [key.currency0]);
  var closeC1 = encodeAbiParameters([{ type: 'address' }], [key.currency1]);
  var parts = [mintParams, closeC0, closeC1];
  var actions = '0x021212'; // MINT_POSITION, CLOSE_CURRENCY(c0), CLOSE_CURRENCY(c1)
  if (pair.isNative) {
    // Refund unused native (sent as msg.value) to the user. ERC-20 sides need no sweep (CLOSE pulls exact).
    var nativeCur = c0Native ? key.currency0 : key.currency1;
    parts.push(encodeAbiParameters([{ type: 'address' }, { type: 'address' }], [nativeCur, acct]));
    actions = '0x02121214'; // … + SWEEP(native)
  }
  var unlockData = encodeAbiParameters([{ type: 'bytes' }, { type: 'bytes[]' }], [actions, parts]);

  return {
    posm: posm, key: key, acct: acct, tickLower: tickLower, tickUpper: tickUpper,
    liquidity: liquidity, need: need, amount0Max: amount0Max, amount1Max: amount1Max, value: value,
    unlockData: unlockData, pairIsC0: pairIsC0, pair: pair, erc20: erc20,
  };
}

// Execute: a one-time exact ERC20→Permit2 approval (if needed), then a GASLESS Permit2 signature batched
// with the mint via PositionManager.multicall — so it's 2 txs + 1 instant signature instead of 3 txs.
// Returns the mint tx hash.
async function runAddLiquidityTxs(chainId, prep, onStatus) {
  var acct = getAccount();
  if (!acct) throw new Error('Connect a wallet');
  if (!prep.acct || acct.toLowerCase() !== prep.acct.toLowerCase()) throw new Error('Connected account changed. Review the liquidity transaction again.');
  var posm = prep.posm;
  var wallet = getWalletClient();
  if (!wallet) throw new Error('Connect a wallet');
  var wc = await wallet.getChainId();
  if (wc !== chainId) { onStatus('Switching network…', 'pending'); await switchChain(chainId); }

  var deadline = BigInt(Math.floor(Date.now() / 1000) + 1200);
  var permitDatas = [];
  var now = Math.floor(Date.now() / 1000);

  // Each ERC-20 side (the project token always; the pair too when it's USDC) needs a Permit2 allowance.
  for (var i = 0; i < (prep.erc20 || []).length; i++) {
    var side = prep.erc20[i];
    // 1. ERC20 → Permit2 (exact, bounded; only when the current allowance is short).
    var erc20Allow = await clientFor(chainId).readContract({ address: side.currency, abi: lpErc20Abi, functionName: 'allowance', args: [acct, PERMIT2_ADDRESS] });
    if (BigInt(erc20Allow) < side.max) {
      onStatus('Approving token for Permit2…', 'pending');
      await lpSendTx(chainId, { account: prep.acct, address: side.currency, abi: lpErc20Abi, functionName: 'approve', args: [PERMIT2_ADDRESS, side.max] });
    }
    // 2. Permit2 → PositionManager allowance. Reuse if still valid; else sign one (gasless) and fold it
    //    into the mint multicall — no separate onchain approval tx.
    var p2 = await clientFor(chainId).readContract({ address: PERMIT2_ADDRESS, abi: lpPermit2Abi, functionName: 'allowance', args: [acct, side.currency, posm] });
    var p2amount = BigInt(p2[0]), p2exp = Number(p2[1]), p2nonce = Number(p2[2]);
    if (!(p2amount >= side.max && p2exp > now)) {
      onStatus('Sign token approval…', 'pending');
      var permitMessage = {
        details: { token: side.currency, amount: side.max, expiration: BigInt(now + 30 * 24 * 3600), nonce: BigInt(p2nonce) },
        spender: posm,
        sigDeadline: BigInt(now + 1800),
      };
      if (!getAccount() || getAccount().toLowerCase() !== prep.acct.toLowerCase()) throw new Error('Connected account changed. Review the liquidity transaction again.');
      var signature = await wallet.signTypedData({
        account: acct,
        domain: { name: 'Permit2', chainId: chainId, verifyingContract: PERMIT2_ADDRESS },
        types: LP_PERMIT2_TYPES,
        primaryType: 'PermitSingle',
        message: permitMessage,
      });
      permitDatas.push(encodeFunctionData({ abi: lpPositionManagerAbi, functionName: 'permit', args: [acct, permitMessage, signature] }));
    }
  }

  onStatus('Adding liquidity…', 'pending');
  if (!getAccount() || getAccount().toLowerCase() !== prep.acct.toLowerCase()) throw new Error('Connected account changed. Review the liquidity transaction again.');
  if (permitDatas.length) {
    var mintData = encodeFunctionData({ abi: lpPositionManagerAbi, functionName: 'modifyLiquidities', args: [prep.unlockData, deadline] });
    return lpSendTx(chainId, { account: prep.acct, address: posm, abi: lpPositionManagerAbi, functionName: 'multicall', args: [permitDatas.concat([mintData])], value: prep.value });
  }
  return lpSendTx(chainId, { account: prep.acct, address: posm, abi: lpPositionManagerAbi, functionName: 'modifyLiquidities', args: [prep.unlockData, deadline], value: prep.value });
}

// Build the "exact transaction" preview payload (mirrors the Pay confirm), for openTxConfirm.
function buildAddLiquidityPayload(chainId, chainName, sym, prep) {
  var pair = prep.pair || { symbol: 'ETH', decimals: 18, isNative: true };
  // amount0Max/amount1Max are currency-ordered; map back to pair vs project token for display.
  var pairMax = prep.pairIsC0 ? prep.amount0Max : prep.amount1Max;
  var tokenMax = prep.pairIsC0 ? prep.amount1Max : prep.amount0Max;
  return {
    chain: chainName,
    chainId: chainId,
    contract: 'Uniswap V4 PositionManager',
    address: prep.posm,
    'function': 'modifyLiquidities',
    txlinkUnavailableReason: 'The final liquidity calldata may include Permit2 signatures bound to the connected wallet, so it does not exist before confirmation.',
    value: prep.value > 0n ? (prep.value.toString() + ' wei (' + formatEth(prep.value) + ')') : '0',
    erc20Approvals: (prep.erc20 || []).map(function (s) {
      return { token: s.currency, via: 'Permit2', spender: prep.posm, amount: s.max.toString() };
    }),
    position: {
      actions: pair.isNative ? 'MINT_POSITION, CLOSE, CLOSE, SWEEP (0x02121214)' : 'MINT_POSITION, CLOSE, CLOSE (0x021212)',
      poolFee: Number(prep.key.fee),
      hooks: prep.key.hooks,
      tickLower: prep.tickLower,
      tickUpper: prep.tickUpper,
      liquidity: prep.liquidity.toString(),
      ['max' + pair.symbol]: formatBalance(pairMax, pair.decimals, pair.symbol),
      maxToken: formatTokens(tokenMax) + ' ' + sym,
      recipient: prep.acct,
    },
    args: { unlockData: prep.unlockData, deadline: 'set at signing (~20 min)' },
  };
}

// --- Remove liquidity: find the connected user's V4 positions (across the CURRENT + OLD buyback pools) and burn them ---

// Scan ONE buyback pool (identified by its hook) for every LP position, keeping tokenId + owner + pool key so a
// specific owner's position can be removed. Mirrors readLpPositions' internals. Rejects if history is incomplete.
async function lpScanPoolPositions(project, chainId, hookAddr, hookIsCurrent) {
  try {
    var posm = POSITION_MANAGER_BY_CHAIN[chainId], pm = POOL_MANAGER_BY_CHAIN[chainId];
    if (!posm || !pm || !hookAddr || hookAddr === ZERO_ADDRESS) return [];
    var client = clientFor(chainId);
    var pair = await lpPairFor(project, chainId, { strict: true });
    var key = await client.readContract({ address: hookAddr, abi: poolKeyOfAbi, functionName: 'poolKeyOf', args: [BigInt(project.id), pair.addr] });
    if (!key || !key.currency0) return [];
    var c0 = (key.currency0 || ZERO_ADDRESS).toLowerCase(), c1 = (key.currency1 || ZERO_ADDRESS).toLowerCase();
    if (c0 === ZERO_ADDRESS && c1 === ZERO_ADDRESS) return [];
    var poolId = keccak256(encodeAbiParameters(POOLKEY_TUPLE, [[key.currency0, key.currency1, key.fee, key.tickSpacing, key.hooks]]));
    var stateSlot = keccak256(encodeAbiParameters([{ type: 'bytes32' }, { type: 'uint256' }], [poolId, 6n]));
    var slot0 = await client.readContract({ address: pm, abi: extsloadAbi, functionName: 'extsload', args: [stateSlot] });
    var sqrtP = BigInt(slot0) & ((1n << 160n) - 1n);
    if (sqrtP === 0n) return [];
    var pairIsC0 = (c0 === pair.addr);
    var sp = Number(sqrtP) / Math.pow(2, 96), rawP = sp * sp;
    var poolPrice = (pairIsC0 ? (rawP > 0 ? 1 / rawP : 0) : rawP) * Math.pow(10, 18 - pair.decimals);
    var tokenIds = await lpPoolPositionTokenIds(chainId, pm, posm, poolId);
    if (!tokenIds.length) return [];
    var det = await lpReadPositionDetails(client, posm, tokenIds, poolId);
    var out = [];
    det.forEach(function (p) {
      if (!p.owner || p.liquidity <= 0n || p.info === 0n) return;
      var tickUpper = Number(lpSignExtend24((p.info >> 32n) & 0xffffffn));
      var tickLower = Number(lpSignExtend24((p.info >> 8n) & 0xffffffn));
      var amt = lpGetAmountsForLiquidity(sqrtP, lpSqrtAtTick(tickLower), lpSqrtAtTick(tickUpper), p.liquidity);
      out.push({ tokenId: p.tokenId, owner: p.owner, key: key, poolId: poolId, hookIsCurrent: hookIsCurrent, oracleHook: key.hooks,
        tickLower: tickLower, tickUpper: tickUpper, liquidity: p.liquidity,
        pairAmt: pairIsC0 ? amt.amount0 : amt.amount1, tokAmt: pairIsC0 ? amt.amount1 : amt.amount0,
        pairIsC0: pairIsC0, poolPrice: poolPrice, pair: pair });
    });
    return out;
  } catch (e) { throw e; }
}

// The connected account's LP positions for a project on a chain, across the CURRENT buyback pool AND the OLD/default
// hook pool (so stranded positions from a prior hook are included). Empty array only when there are genuinely none.
async function readUserLpPositions(project, chainId, account) {
  if (!account) return [];
  var lc = function (a) { return (a || '').toLowerCase(); };
  var newHook = await projectBuybackHook(project, chainId, { strict: true });
  var oldHook = getAddress('JBBuybackHook', chainId);
  var tasks = [];
  if (newHook) tasks.push(lpScanPoolPositions(project, chainId, newHook, true));
  if (oldHook && lc(oldHook) !== lc(newHook)) tasks.push(lpScanPoolPositions(project, chainId, oldHook, false));
  var all = [].concat.apply([], await Promise.all(tasks));
  return all.filter(function (p) { return p.owner && lc(p.owner) === lc(account); });
}

// Encode a full-exit remove: BURN_POSITION(tokenId) + TAKE_PAIR(c0, c1, user). No Permit2/approval needed — the NFT
// owner burns their own position. Each positive side has a 95% floor from the freshly displayed position amounts;
// a large adverse price/composition move therefore reverts instead of returning materially less than reviewed.
function prepareRemoveLiquidity(chainId, pos, acct) {
  var posm = POSITION_MANAGER_BY_CHAIN[chainId];
  if (!posm) throw new Error('No position manager on this chain');
  var pairMin = quotedOutputFloor(pos.pairAmt, 9500);
  var tokenMin = quotedOutputFloor(pos.tokAmt, 9500);
  var amount0Min = pos.pairIsC0 ? pairMin : tokenMin;
  var amount1Min = pos.pairIsC0 ? tokenMin : pairMin;
  var burnParams = encodeAbiParameters([{ type: 'uint256' }, { type: 'uint128' }, { type: 'uint128' }, { type: 'bytes' }], [BigInt(pos.tokenId), amount0Min, amount1Min, '0x']);
  var takeParams = encodeAbiParameters([{ type: 'address' }, { type: 'address' }, { type: 'address' }], [pos.key.currency0, pos.key.currency1, acct]);
  var unlockData = encodeAbiParameters([{ type: 'bytes' }, { type: 'bytes[]' }], ['0x0311', [burnParams, takeParams]]); // BURN_POSITION(0x03), TAKE_PAIR(0x11)
  return { posm: posm, unlockData: unlockData, deadline: BigInt(Math.floor(Date.now() / 1000) + 1200), value: 0n, pairMin: pairMin, tokenMin: tokenMin };
}

// Re-read ownership, liquidity, ticks, and pool price immediately before presenting the exact removal transaction.
// The position table can remain open while the market moves or the NFT transfers; stale values must not become the
// user's expected/minimum-return preview.
async function refreshLpPositionForRemoval(chainId, pos, expectedAccount) {
  var currentAccount = getAccount && getAccount();
  if (!currentAccount || currentAccount.toLowerCase() !== expectedAccount.toLowerCase()) {
    throw new Error('Connected account changed. Reload your LP positions.');
  }
  var posm = POSITION_MANAGER_BY_CHAIN[chainId], pm = POOL_MANAGER_BY_CHAIN[chainId];
  if (!posm || !pm) throw new Error('Liquidity contracts are unavailable on this chain.');
  var client = clientFor(chainId);
  var stateSlot = keccak256(encodeAbiParameters([{ type: 'bytes32' }, { type: 'uint256' }], [pos.poolId, 6n]));
  var reads = await Promise.all([
    lpReadPositionDetails(client, posm, [BigInt(pos.tokenId)], pos.poolId),
    client.readContract({ address: pm, abi: extsloadAbi, functionName: 'extsload', args: [stateSlot] }),
  ]);
  var detail = reads[0][0];
  if (!detail.owner || detail.owner.toLowerCase() !== expectedAccount.toLowerCase()) throw new Error('This wallet no longer owns the position');
  if (detail.info === 0n || detail.liquidity <= 0n) throw new Error('This position no longer has liquidity');
  var sqrtP = BigInt(reads[1]) & ((1n << 160n) - 1n);
  if (sqrtP === 0n) throw new Error('Could not verify the current pool price');
  var tickUpper = Number(lpSignExtend24((detail.info >> 32n) & 0xffffffn));
  var tickLower = Number(lpSignExtend24((detail.info >> 8n) & 0xffffffn));
  var amounts = lpGetAmountsForLiquidity(sqrtP, lpSqrtAtTick(tickLower), lpSqrtAtTick(tickUpper), detail.liquidity);
  return Object.assign({}, pos, {
    owner: detail.owner,
    info: detail.info,
    liquidity: detail.liquidity,
    tickLower: tickLower,
    tickUpper: tickUpper,
    pairAmt: pos.pairIsC0 ? amounts.amount0 : amounts.amount1,
    tokAmt: pos.pairIsC0 ? amounts.amount1 : amounts.amount0,
  });
}

// Modal: the connected wallet's LP positions on a chain (current + old pools), each with a Remove (burn) action.
function openRemoveLiquidityModal(project, chainId, onDone) {
  var sym = project.tokenSymbol || 'tokens';
  var wrap = el('div', 'modal-body');
  var intro = el('div', 'modal-balance');
  intro.textContent = 'Your Uniswap V4 LP positions in this project’s buyback pools. Removing burns the position NFT and returns both tokens to your wallet (no approval needed).';
  wrap.appendChild(intro);
  var list = el('div'); list.appendChild(skel('100%', '50px')); wrap.appendChild(list);
  openModal('Remove liquidity', wrap);
  var acct = getAccount && getAccount();
  if (!acct) { list.innerHTML = ''; var w0 = el('div', 'modal-status'); w0.textContent = 'Connect a wallet to see your positions.'; list.appendChild(w0); return; }
  readUserLpPositions(project, chainId, acct).then(function (positions) {
    list.innerHTML = '';
    if (!positions.length) { var none = el('div', 'modal-status'); none.textContent = 'No LP positions found for your wallet on this chain.'; list.appendChild(none); return; }
    positions.forEach(function (pos) {
      var row = el('div', 'lp-remove-row');
      var info = el('div', 'lp-remove-info');
      var head = el('div', 'lp-remove-head'); head.textContent = 'Position #' + pos.tokenId.toString() + (pos.hookIsCurrent ? ' | current pool' : ' | old pool'); info.appendChild(head);
      var pairH = formatBalance(pos.pairAmt, pos.pair.decimals, pos.pair.symbol), tokH = formatTokens(pos.tokAmt) + ' ' + sym;
      var amts = el('div', 'modal-balance'); amts.textContent = tokH + ' + ' + pairH + ' | oracle ' + truncAddr(pos.oracleHook); info.appendChild(amts);
      var rmStatus = el('div', 'modal-status'); rmStatus.style.display = 'none'; info.appendChild(rmStatus);
      row.appendChild(info);
      var rm = el('button', 'detail-check-btn'); rm.textContent = 'Remove';
      rm.addEventListener('click', function () {
        if (rm.disabled) return;
        rm.disabled = true; rm.textContent = 'Refreshing…'; rmStatus.textContent = ''; rmStatus.className = 'modal-status'; rmStatus.style.display = 'none';
        refreshLpPositionForRemoval(chainId, pos, acct).then(function (fresh) {
          pos = fresh;
          pairH = formatBalance(pos.pairAmt, pos.pair.decimals, pos.pair.symbol);
          tokH = formatTokens(pos.tokAmt) + ' ' + sym;
          amts.textContent = tokH + ' + ' + pairH + ' | oracle ' + truncAddr(pos.oracleHook);
          var prep = prepareRemoveLiquidity(chainId, pos, acct);
          rm.disabled = false; rm.textContent = 'Remove';
          openTxConfirm({
            chain: chainNameOf(chainId), chainId: chainId, contract: 'Uniswap V4 PositionManager', address: prep.posm,
            'function': 'modifyLiquidities', value: '0',
            calldata: encodeFunctionData({ abi: lpPositionManagerAbi, functionName: 'modifyLiquidities', args: [prep.unlockData, prep.deadline] }),
            position: { actions: 'BURN_POSITION, TAKE_PAIR (0x0311)', tokenId: pos.tokenId.toString(), expectedReturns: tokH + ' + ' + pairH,
              minimumReturns: formatTokens(prep.tokenMin) + ' ' + sym + ' + ' + formatBalance(prep.pairMin, pos.pair.decimals, pos.pair.symbol), recipient: acct },
            args: { unlockData: prep.unlockData, deadline: 'set at signing (~20 min)' },
          }, function (ctx) {
            ctx.confirm.disabled = true; ctx.cancel.disabled = true; ctx.showStatus('Removing liquidity…', 'pending');
            lpSendTx(chainId, { account: acct, address: prep.posm, abi: lpPositionManagerAbi, functionName: 'modifyLiquidities', args: [prep.unlockData, prep.deadline], value: 0n }).then(function (hash) {
              ctx.modal.close();
              var ok = el('div', 'modal-status success'); ok.appendChild(document.createTextNode('Removed | TX: ')); ok.appendChild(renderExplorerTxLink(chainId, hash, truncAddr(hash)));
              row.innerHTML = ''; row.appendChild(ok);
              if (onDone) onDone();
            }).catch(function (e) {
              ctx.confirm.disabled = false; ctx.cancel.disabled = false;
              var msg = errMessage(e, 'Remove failed'); ctx.showStatus(msg.length > 160 ? msg.slice(0, 160) + '…' : msg, 'error');
            });
          }, { title: 'Confirm remove liquidity', confirmText: 'Confirm & remove', closeOnConfirm: false });
        }).catch(function (e) {
          rm.disabled = false; rm.textContent = 'Remove'; rmStatus.className = 'modal-status error'; rmStatus.style.display = '';
          var msg = errMessage(e, 'Could not refresh this position');
          rmStatus.textContent = msg.length > 160 ? msg.slice(0, 160) + '…' : msg;
        });
      });
      row.appendChild(rm);
      list.appendChild(row);
    });
  }).catch(function () { list.innerHTML = ''; var er = el('div', 'modal-status error'); er.textContent = 'Could not load positions.'; list.appendChild(er); });
}

function buildAddLiquidityModal(project) {
  var sym = project.tokenSymbol || 'tokens';
  var wrap = el('div', 'modal-body');
  var lpChains = (project.chains || []).filter(function (c) { return POSITION_MANAGER_BY_CHAIN[c.id] && POOL_MANAGER_BY_CHAIN[c.id]; });
  if (!lpChains.length) {
    var n = el('div', 'modal-status'); n.textContent = 'No Uniswap V4 position manager on this project’s chains.'; wrap.appendChild(n); return wrap;
  }
  // Issuance ceiling = base token per project token at the current issuance weight (the top of the AMM band).
  var weight = project.ruleset ? Number(project.ruleset.weight) : 0;
  var ceiling = weight > 0 ? 1e18 / weight : 0;
  // ethBal holds the PAIR-token balance (native ETH or USDC); pair is the resolved accounting/pair token.
  var state = { chainId: lpChains[0].id, poolP: 0, floor: 0, ceiling: ceiling, revBal: null, ethBal: null, driver: null, pair: null };
  function pairSym() { return state.pair ? state.pair.symbol : 'accounting token'; }
  function pairDec() { return state.pair ? state.pair.decimals : 18; }

  var intro = el('div', 'modal-balance');
  intro.textContent = 'Seed the buyback pool so payers can route through the AMM. Liquidity is added at the current pool price.';
  wrap.appendChild(intro);

  // Your balance per chain, boxed at the top (like the cash out modal). Add-liquidity skips project balances.
  var balTable = el('div', 'cashout-bal-table'); wrap.appendChild(balTable);
  renderBalanceTables(balTable, project, sym, { skipProjectBalances: true });

  var chainRow = el('div', 'ops-chainrow');
  var chainSel = opsChainSelect(project, function (cid) { state.chainId = cid; refreshPair(); }, { chains: lpChains });
  chainRow.appendChild(chainSel);
  wrap.appendChild(chainRow);

  // Slim line for the pair token (ETH/USDC) balance — the table above covers the project token.
  var balLine = el('div', 'modal-balance'); balLine.style.marginTop = '8px'; wrap.appendChild(balLine);
  var priceLine = el('div', 'modal-balance'); wrap.appendChild(priceLine);

  // Number-line of where the selected range sits relative to floor / pool price / issuance ceiling.
  var graphWrap = el('div', 'lp-graph'); wrap.appendChild(graphWrap);
  var graphHolder = el('div', 'lp-graph-holder'); graphWrap.appendChild(graphHolder);
  var graphTip = el('div', 'lp-graph-tip'); graphTip.style.display = 'none'; graphWrap.appendChild(graphTip);
  var graphScale = null;
  // Hover anywhere on the range bar to read the price at that point (mapping cursor x → pair-token value).
  graphWrap.addEventListener('mousemove', function (e) {
    if (!graphScale || !graphScale.maxV) { graphTip.style.display = 'none'; return; }
    var rect = graphHolder.getBoundingClientRect();
    if (rect.width <= 0) return;
    var svgX = (e.clientX - rect.left) / rect.width * graphScale.W;
    var span = graphScale.W - graphScale.padL - graphScale.padR;
    var value = span > 0 ? (svgX - graphScale.padL) / span * graphScale.maxV : 0;
    if (!(value > 0)) { graphTip.style.display = 'none'; return; }
    graphTip.textContent = '≈ ' + formatPrice(value) + ' ' + pairSym() + ' / ' + sym;
    graphTip.style.display = '';
    graphTip.style.left = Math.max(2, Math.min(rect.width - 110, e.clientX - rect.left + 8)) + 'px';
  });
  graphWrap.addEventListener('mouseleave', function () { graphTip.style.display = 'none'; });

  var lblR = el('div', 'modal-label'); lblR.textContent = 'Price range (ETH per ' + sym + ')'; wrap.appendChild(lblR);
  var rnote = el('div', 'modal-balance'); rnote.textContent = 'Defaults span the current cash out floor to the issuance ceiling.'; wrap.appendChild(rnote);
  var rangeRow = el('div', 'ops-rangerow');
  var minField = el('div', 'ops-field ops-field--grow');
  var minInput = el('input', 'ops-amount'); minInput.type = 'number'; minInput.placeholder = 'Min'; minField.appendChild(minInput);
  rangeRow.appendChild(minField);
  var toSpan = el('span', 'ops-between'); toSpan.textContent = 'to'; rangeRow.appendChild(toSpan);
  var maxField = el('div', 'ops-field ops-field--grow');
  var maxInput = el('input', 'ops-amount'); maxInput.type = 'number'; maxInput.placeholder = 'Max'; maxField.appendChild(maxInput);
  rangeRow.appendChild(maxField);
  wrap.appendChild(rangeRow);
  minInput.addEventListener('input', onRangeChange);
  maxInput.addEventListener('input', onRangeChange);

  // Token + ETH amounts — editing one auto-fills the other at the current price within the range.
  // Both sides share one row (two columns).
  var addGrid = el('div', 'lp-add-grid'); wrap.appendChild(addGrid);
  var tokCol = el('div', 'lp-add-col'); addGrid.appendChild(tokCol);
  var tokHead = el('div', 'lp-add-head'); tokCol.appendChild(tokHead);
  var lbl1 = el('div', 'modal-label'); lbl1.textContent = sym + ' to add'; tokHead.appendChild(lbl1);
  var tokMax = el('button', 'lp-max'); tokMax.textContent = 'Max'; tokHead.appendChild(tokMax);
  var tokField = el('div', 'ops-field ops-field--grow');
  var tokAmt = el('input', 'ops-amount'); tokAmt.type = 'number'; tokAmt.placeholder = '0.00'; tokField.appendChild(tokAmt);
  var tu = el('span', 'ops-unit'); tu.textContent = sym; tokField.appendChild(tu); tokCol.appendChild(tokField);

  var ethCol = el('div', 'lp-add-col'); addGrid.appendChild(ethCol);
  var ethHead = el('div', 'lp-add-head'); ethCol.appendChild(ethHead);
  var lbl2 = el('div', 'modal-label'); lbl2.textContent = 'ETH to add'; ethHead.appendChild(lbl2);
  var ethMax = el('button', 'lp-max'); ethMax.textContent = 'Max'; ethHead.appendChild(ethMax);
  var ethField = el('div', 'ops-field ops-field--grow');
  var ethAmt = el('input', 'ops-amount'); ethAmt.type = 'number'; ethAmt.placeholder = '0.00'; ethField.appendChild(ethAmt);
  var eu = el('span', 'ops-unit'); eu.textContent = 'ETH'; ethField.appendChild(eu); ethCol.appendChild(ethField);

  var pairNote = el('div', 'modal-balance'); pairNote.style.marginTop = '6px';
  wrap.appendChild(pairNote);
  var sideNote = el('div', 'modal-balance'); sideNote.style.marginTop = '4px'; sideNote.style.color = '#b8602e'; sideNote.style.display = 'none';
  wrap.appendChild(sideNote);

  // Re-label everything that names the pair token (range unit, second amount, ratio note) once it's known.
  function applyPairLabels() {
    var ps = pairSym();
    lblR.textContent = 'Price range (' + ps + ' per ' + sym + ')';
    lbl2.textContent = ps + ' to add';
    eu.textContent = ps;
    pairNote.textContent = 'Enter either amount; the other is calculated at the pool price. Near Min uses more '
      + sym + '; near Max uses more ' + ps + '.';
  }
  applyPairLabels();

  tokAmt.addEventListener('input', function () { state.driver = 'tok'; autofill(); });
  ethAmt.addEventListener('input', function () { state.driver = 'eth'; autofill(); });
  tokMax.addEventListener('click', function () {
    if (state.revBal == null) { connect(); return; }
    tokAmt.value = formatAmount(state.revBal, 18); state.driver = 'tok'; autofill();
  });
  ethMax.addEventListener('click', function () {
    if (!state.pair) { status.textContent = 'Accounting token is still loading.'; return; }
    if (state.ethBal == null) { connect(); return; }
    // Keep ~0.001 ETH for gas only when the pair IS native ETH; an ERC-20 pair (USDC) can go to the brim.
    var buf = state.pair.isNative ? 1000000000000000n : 0n;
    var v = state.ethBal > buf ? state.ethBal - buf : 0n;
    ethAmt.value = formatAmount(v, pairDec()); state.driver = 'eth'; autofill();
  });

  var status = el('div', 'modal-status'); wrap.appendChild(status);
  var foot = el('div', 'modal-foot');
  var btn = document.createElement('button'); btn.className = 'modal-submit'; btn.textContent = 'Add liquidity';
  foot.appendChild(btn); wrap.appendChild(foot);

  function currentRange() {
    var pa = parseFloat(minInput.value), pb = parseFloat(maxInput.value);
    return { pa: pa > 0 ? pa : 0, pb: pb > 0 ? pb : 0 };
  }
  function drawGraph() {
    var r = currentRange();
    var g = renderLpRangeSvg(state.floor, state.ceiling, state.poolP, r.pa, r.pb);
    graphHolder.innerHTML = g.html;
    graphScale = g.maxV ? g : null;
  }
  // Which token(s) the position actually needs at the current price + range. At/above the range top the position is
  // single-sided in the PAIR (USDC/ETH); at/below the bottom it's single-sided in the project token; strictly inside,
  // both. Order-independent: lpCounterpart returns 0/null on these same boundaries regardless of pool token ordering.
  function activeSides(r) {
    var p = state.poolP;
    if (!(p > 0) || !(r.pa > 0) || !(r.pb > r.pa)) return { tok: true, eth: true };
    if (p >= r.pb) return { tok: false, eth: true };   // all pair — the project token isn't part of the position here
    if (p <= r.pa) return { tok: true, eth: false };   // all project token — the pair isn't part of the position here
    return { tok: true, eth: true };
  }
  // Enable only the side(s) the position needs; disable + zero the other so typing there can't clear the active side.
  function applySides() {
    var s = activeSides(currentRange());
    tokAmt.disabled = !s.tok; ethAmt.disabled = !s.eth;
    tokCol.style.opacity = s.tok ? '' : '0.45'; ethCol.style.opacity = s.eth ? '' : '0.45';
    tokMax.style.visibility = s.tok ? '' : 'hidden'; ethMax.style.visibility = s.eth ? '' : 'hidden';
    if (!s.tok) tokAmt.value = '0';
    if (!s.eth) ethAmt.value = '0';
    if (s.tok && s.eth) { sideNote.style.display = 'none'; sideNote.textContent = ''; }
    else {
      sideNote.style.display = '';
      sideNote.textContent = s.eth
        ? 'At the current price (top of your range) the position is single-sided ' + pairSym() + ' — add ' + pairSym() + ' only. To seed ' + sym + ', the pool price has to be lower within your range (move the price down with a swap, or widen the range).'
        : 'At the current price (bottom of your range) the position is single-sided ' + sym + ' — add ' + sym + ' only. To seed ' + pairSym() + ', the pool price has to be higher within your range.';
    }
  }
  function autofill() {
    var r = currentRange();
    var s = activeSides(r);
    // Single-sided: the inactive side is 0; leave the active side's user-entered amount alone (no counterpart to fill).
    if (!(s.tok && s.eth)) { if (!s.tok) tokAmt.value = '0'; if (!s.eth) ethAmt.value = '0'; return; }
    if (state.driver === 'eth') {
      var eth = parseFloat(ethAmt.value);
      if (!(eth > 0)) { tokAmt.value = ''; return; }
      var tok = lpCounterpart(eth, true, state.poolP, r.pa, r.pb);
      if (tok != null) tokAmt.value = lpTrimNum(tok);
    } else if (state.driver === 'tok') {
      var t = parseFloat(tokAmt.value);
      if (!(t > 0)) { ethAmt.value = ''; return; }
      var e = lpCounterpart(t, false, state.poolP, r.pa, r.pb);
      if (e != null) ethAmt.value = lpTrimNum(e);
    }
  }
  function onRangeChange() { drawGraph(); applySides(); autofill(); }

  // Resolve the pair (accounting) token for the selected chain, then refresh labels, balances, and price.
  var pairSeq = 0;
  var lpBalanceSeq = 0;
  var lpPriceSeq = 0;
  function refreshPair() {
    var cid = state.chainId, seq = ++pairSeq;
    ++lpBalanceSeq; ++lpPriceSeq;
    state.pair = null; state.revBal = null; state.ethBal = null;
    state.poolP = 0; state.floor = 0;
    btn.disabled = true; balLine.textContent = 'Loading the verified accounting token…'; priceLine.textContent = '';
    lpPairFor(project, cid).then(function (p) {
      if (seq !== pairSeq || state.chainId !== cid) return;
      if (!p) throw new Error('Could not resolve the project’s accounting token.');
      state.pair = p; applyPairLabels();
      btn.disabled = true; status.textContent = '';
      refreshBalances(); refreshPrice();
    }).catch(function () {
      if (seq !== pairSeq || state.chainId !== cid) return;
      state.pair = null; btn.disabled = true;
      balLine.textContent = 'Could not verify the project’s accounting token on this chain.';
    });
  }

  function refreshBalances() {
    if (!state.pair) return;
    var cid = state.chainId, pair = state.pair, seq = ++lpBalanceSeq;
    var acct = getAccount && getAccount();
    if (!acct) { balLine.textContent = ''; state.revBal = null; state.ethBal = null; return; }
    balLine.textContent = 'Your ' + pairSym() + ': …';
    var pairTokenAddr = pair.isNative ? NATIVE_TOKEN : pair.addr;
    Promise.all([readUserBalance(project, cid), readWalletTokenBalance(cid, pairTokenAddr, acct)]).then(function (r) {
      if (seq !== lpBalanceSeq || state.chainId !== cid || state.pair !== pair || !getAccount() || getAccount().toLowerCase() !== acct.toLowerCase()) return;
      state.revBal = r[0]; state.ethBal = r[1];
      balLine.textContent = 'Your ' + pair.symbol + ': ' + (r[1] != null ? formatBalance(r[1], pair.decimals, pair.symbol) : '—');
    });
  }

  function refreshPrice() {
    if (!state.pair) return;
    var cid = state.chainId, pair = state.pair, seq = ++lpPriceSeq;
    priceLine.textContent = 'Pool price: …';
    Promise.all([readAmmPrice(project, cid), readCashoutPrice(project, cid)]).then(function (res) {
      if (seq !== lpPriceSeq || state.chainId !== cid || state.pair !== pair) return;
      var amm = res[0], floor = res[1];
      state.poolP = (amm && amm > 0) ? amm : 0;
      state.floor = (floor && floor > 0) ? floor : 0;
      btn.disabled = !amm;
      priceLine.textContent = amm ? ('Pool price: ~' + formatPrice(amm) + ' ' + pair.symbol + ' / ' + sym) : 'Pool not initialized on this chain.';
      var poolP = state.poolP > 0 ? state.poolP : (ceiling > 0 ? ceiling / 10 : 0);
      var defaultRange = lpDefaultRange(poolP, state.floor, ceiling);
      if (defaultRange.min > 0) minInput.value = lpTrimNum(defaultRange.min);
      if (defaultRange.max > 0) maxInput.value = lpTrimNum(defaultRange.max);
      rnote.textContent = defaultRange.economic
        ? 'Defaults span the cash out floor (' + formatPrice(state.floor) + ') to the issuance ceiling.'
        : (state.floor > 0
          ? 'The floor and ceiling do not straddle the pool price. The default range is widened so both tokens can be added.'
          : 'No cash out floor yet. The default range is widened around the pool price so both tokens can be added.');
      onRangeChange();
    }).catch(function () {
      if (seq !== lpPriceSeq || state.chainId !== cid || state.pair !== pair) return;
      state.poolP = 0; state.floor = 0; btn.disabled = true;
      priceLine.textContent = 'Could not verify the current pool price.';
    });
  }

  refreshPair();

  btn.addEventListener('click', function () {
    if (!(getAccount && getAccount())) { connect(); return; }
    if (!state.pair) { status.className = 'modal-status error'; status.textContent = 'Could not verify the project’s accounting token.'; return; }
    var cid = state.chainId;
    var inputSnapshot = [minInput.value, maxInput.value, tokAmt.value, ethAmt.value].join('|');
    var pairAmount, tokenAmount;
    try { pairAmount = ethAmt.value ? parseAmount(ethAmt.value, pairDec()) : 0n; } catch (_) { status.className = 'modal-status error'; status.textContent = 'Invalid ' + pairSym() + ' amount'; return; }
    try { tokenAmount = tokAmt.value ? parseAmount(tokAmt.value, 18) : 0n; } catch (_) { status.className = 'modal-status error'; status.textContent = 'Invalid ' + sym + ' amount'; return; }
    if (pairAmount <= 0n && tokenAmount <= 0n) { status.className = 'modal-status error'; status.textContent = 'Enter an amount'; return; }
    if (state.revBal == null || state.ethBal == null) { status.className = 'modal-status error'; status.textContent = 'Wallet balances are still loading or could not be verified.'; return; }
    if (tokenAmount > state.revBal) { status.className = 'modal-status error'; status.textContent = sym + ' amount exceeds your balance.'; return; }
    if (pairAmount > state.ethBal) { status.className = 'modal-status error'; status.textContent = pairSym() + ' amount exceeds your balance.'; return; }
    var r = currentRange();
    if (!(r.pa > 0) || !(r.pb > r.pa)) { status.className = 'modal-status error'; status.textContent = 'Set a valid price range'; return; }
    btn.disabled = true;
    status.className = 'modal-status'; status.textContent = 'Preparing…';
    var lpOpts = { project: project, chainId: cid, pairAmount: pairAmount, tokenAmount: tokenAmount, pa: r.pa, pb: r.pb };
    prepareAddLiquidity(lpOpts).then(function (prep) {
      if (state.chainId !== cid || inputSnapshot !== [minInput.value, maxInput.value, tokAmt.value, ethAmt.value].join('|')
        || !state.pair || state.pair.addr !== prep.pair.addr || !getAccount() || getAccount().toLowerCase() !== prep.acct.toLowerCase()) throw new Error('Liquidity inputs or the connected account changed while the transaction was being prepared. Review and try again.');
      btn.disabled = false;
      status.textContent = '';
      var chainName = (lpChains.filter(function (c) { return c.id === cid; })[0] || {}).name || ('Chain ' + cid);
      // Show the exact transaction before signing — same confirm modal as the Pay flow.
      openTxConfirm(buildAddLiquidityPayload(cid, chainName, sym, prep), function (ctx) {
        ctx.confirm.disabled = true; ctx.cancel.disabled = true;
        runAddLiquidityTxs(cid, prep, function (m, kind) { ctx.showStatus(m, kind); }).then(function (hash) {
          ctx.modal.close();
          status.className = 'modal-status success';
          status.innerHTML = '';
          status.appendChild(document.createTextNode('Liquidity added | TX: '));
          status.appendChild(renderExplorerTxLink(cid, hash, truncAddr(hash)));
          refreshBalances(); refreshPrice();
        }).catch(function (e) {
          ctx.confirm.disabled = false; ctx.cancel.disabled = false;
          var msg = errMessage(e, 'Add liquidity failed');
          ctx.showStatus(msg.length > 160 ? msg.slice(0, 160) + '…' : msg, 'error');
        });
      }, { title: 'Confirm add liquidity', confirmText: 'Confirm & add liquidity', closeOnConfirm: false });
    }).catch(function (e) {
      btn.disabled = false;
      status.className = 'modal-status error';
      var msg = errMessage(e, 'Could not prepare');
      status.textContent = msg.length > 160 ? msg.slice(0, 160) + '…' : msg;
    });
  });
  return wrap;
}

function opsRow(c, s, b, u, isHead, isTotal, chainId, lp) {
  // `u === undefined` → drop the Max-loan column (custom projects). `lp` (trailing, optional) adds an LP-positions
  // column; existing callers that pass ≤7 args are unaffected. Column count drives the grid class (3 / 4 / 5).
  var cells = [c, s, b];
  if (u !== undefined) cells.push(u);
  if (lp !== undefined) cells.push(lp);
  var colClass = cells.length === 3 ? ' detail-ops-3' : (cells.length === 5 ? ' detail-ops-5' : '');
  var row = el('div', 'detail-ops-row' + colClass + (isHead ? ' detail-ops-head' : '') + (isTotal ? ' detail-ops-total' : ''));
  cells.forEach(function (v, i) {
    var cell = el('span', 'detail-ops-cell');
    if (i === 0 && chainId != null) {
      cell.classList.add('detail-ops-chain');
      cell.appendChild(chainLogo(chainId, c));
      cell.appendChild(document.createTextNode(c));
    } else if (v && v.nodeType === 1) {
      cell.appendChild(v); // pre-built DOM node (e.g. the clickable LP-positions cell)
    } else if (v && typeof v === 'object' && v.lines) {
      // { lines: [...] } — one value per line (per-token balance). A line may be a plain string OR a
      // { main, sub } pair, where `sub` renders as the same muted sub-line the Supply column uses.
      v.lines.forEach(function (ln, li) {
        if (li) cell.appendChild(document.createElement('br'));
        if (ln && typeof ln === 'object') {
          cell.appendChild(document.createTextNode(ln.main));
          if (ln.sub) { var s2 = el('span', 'detail-ops-sub'); s2.textContent = ln.sub; cell.appendChild(s2); }
        } else { cell.appendChild(document.createTextNode(ln)); }
      });
    } else if (v && typeof v === 'object') {
      // { main, sub } — main value with a muted secondary (e.g. a share-of-total percentage).
      cell.appendChild(document.createTextNode(v.main));
      if (v.sub) { var sub = el('span', 'detail-ops-sub'); sub.textContent = v.sub; cell.appendChild(sub); }
    } else {
      cell.textContent = v;
    }
    row.appendChild(cell);
  });
  return row;
}

// A part's share of a total, formatted as a percent with adaptive precision (so tiny chains still read).
function pctOf(part, total) {
  if (part == null || !total || total === 0n) return null;
  var pct = Number(part * 100000000n / total) / 1000000; // percent, 6-dec internal precision
  if (pct === 0) return '0%';
  var dec = pct >= 1 ? 2 : pct >= 0.001 ? 3 : 4;
  return pct.toFixed(dec) + '%';
}

var peerChainAdjustedAccountsAbi = [{
  type: 'function', name: 'peerChainAdjustedAccountsOf', stateMutability: 'view',
  inputs: [{ name: 'projectId', type: 'uint256' }], outputs: [
    { name: 'supply', type: 'uint256' },
    { name: 'contexts', type: 'tuple[]', components: [
      { name: 'token', type: 'bytes32' }, { name: 'decimals', type: 'uint8' },
      { name: 'surplus', type: 'uint128' }, { name: 'balance', type: 'uint128' },
    ] },
  ],
}];

function readGossipAdjustment(chainId, pid, current) {
  var metadata = current && (current[1] || current.metadata);
  var hook = metadata && metadata.dataHook;
  if (!hook || /^0x0+$/.test(hook)) return Promise.resolve({ verified: true, supply: 0n, tokens: [] });
  return clientFor(chainId).readContract({ address: hook, abi: peerChainAdjustedAccountsAbi, functionName: 'peerChainAdjustedAccountsOf', args: [pid] })
    .then(function (result) {
      var contexts = result && (result.contexts || result[1]) || [];
      var tokens = contexts.map(function (ctx) {
        var token = '0x' + String(ctx.token).slice(-40);
        var decimals = Number(ctx.decimals);
        if (!isAddr(token) || !Number.isInteger(decimals) || decimals < 0 || decimals > 36) throw new Error('Invalid adjusted accounting context.');
        return { token: token, balance: toBigInt(ctx.balance), decimals: decimals, symbol: acctTokenSymbol(token, decimals) };
      });
      return { verified: true, supply: toBigInt(result && (result.supply != null ? result.supply : result[0]) || 0), tokens: tokens };
    })
    // The sucker intentionally treats a non-supporting/reverting data hook as no adjustment. A malformed successful
    // return or an RPC failure cannot be distinguished here, so stay conservative instead of claiming exact sync.
    .catch(function () { return { verified: false, supply: 0n, tokens: [] }; });
}

function fetchOps(project) {
  var pid = BigInt(project.id);
  var chains = (project.chains && project.chains.length) ? project.chains : DISCOVER_CHAINS;
  return Promise.all(chains.map(function (chain) {
    var cid = chain.id;
    var terminal = getAddress('JBMultiTerminal', cid);
    return Promise.all([
      read(cid, 'JBDirectory', controllerOfAbi, 'controllerOf', [pid]).catch(function () { return null; }),
      read(cid, 'JBDirectory', terminalsOfAbi, 'terminalsOf', [pid]).then(function (list) { return { verified: true, list: list || [] }; }).catch(function () { return { verified: false, list: [] }; }),
      terminal ? resolveAcctToken(cid, pid).catch(function () { return null; }) : Promise.resolve(null),
    ]).then(function (res) {
      var controller = res[0], surface = res[1], acct = res[2];
      var controllerReads = controller && !/^0x0+$/.test(controller)
        ? Promise.all([
          clientFor(cid).readContract({ address: controller, abi: totalSupplyWithReservedAbi, functionName: 'totalTokenSupplyWithReservedTokensOf', args: [pid] }).catch(function () { return null; }),
          clientFor(cid).readContract({ address: controller, abi: currentRulesetAbi, functionName: 'currentRulesetOf', args: [pid] }).catch(function () { return null; }),
        ])
        : Promise.resolve([null, null]);
      return controllerReads.then(function (controllerResult) {
      var supply = controllerResult[0] != null ? toBigInt(controllerResult[0]) : null;
      var current = controllerResult[1];
      var balP = terminal && acct
        // Actual reclaimable surplus (net of payout limit), not raw balanceOf — overstated the unit value.
        ? read(cid, 'JBTerminalStore', currentSurplusOfAbi, 'currentSurplusOf', [pid, [], [acct.address], BigInt(acct.decimals), borrowCurrencyForAccountContext(acct)]).catch(function () { return null; })
        : Promise.resolve(null);
      // All accounting tokens this chain holds (a project can settle in ETH + USDC).
      var toksP = terminal ? readChainBalances(cid, pid).catch(function () { return { tokens: [], verified: false }; }) : Promise.resolve({ tokens: [], verified: false });
      var adjustmentP = current ? readGossipAdjustment(cid, pid, current) : Promise.resolve({ verified: false, supply: 0n, tokens: [] });
      return Promise.all([balP, toksP, adjustmentP]).then(function (arr) {
        var balance = arr[0], chainBalances = arr[1], adjustment = arr[2];
        var tokens = chainBalances.tokens || [];
        var listed = surface.list || [];
        // The router registry / direct router forward funds and record no balances (their surplus reads are
        // hardwired to 0), so they only add zero-amount duplicate contexts to the sucker's snapshot — having
        // them listed must not block verification, or every router-enabled project reads "Unverified".
        var routerRegistry = routerTerminalFor(cid);
        var directRouter = getAddress('JBRouterTerminal', cid);
        var accounted = listed.filter(function (listedTerminal) {
          return !sameAddr(listedTerminal, routerRegistry) && !sameAddr(listedTerminal, directRouter);
        });
        var standardOnly = !!terminal && accounted.every(function (listedTerminal) { return sameAddr(listedTerminal, terminal); });
        var standardListed = !!terminal && listed.some(function (listedTerminal) { return sameAddr(listedTerminal, terminal); });
        var baseGossipTokens = standardListed ? tokens : [];
        var gossipTokens = baseGossipTokens.concat(adjustment.tokens || []);
        var tokenReadsVerified = baseGossipTokens.every(function (token) { return token.balance != null; });
        var gossipVerified = supply != null && surface.verified && standardOnly
          && (!standardListed || (chainBalances.verified && tokenReadsVerified)) && adjustment.verified;
        var gossipSupply = supply;
        if (gossipSupply != null && adjustment.verified) {
          var maxUint = (1n << 256n) - 1n;
          // SuckerLib drops both parts of a hook adjustment when its supply would overflow the controller supply.
          if (adjustment.supply <= maxUint - gossipSupply) gossipSupply += adjustment.supply;
          else gossipTokens = baseGossipTokens;
        }
        var base = { id: cid, name: chain.name, supply: supply, balance: balance, tokens: tokens, unitValue: null, acct: acct,
          tokensVerified: !!chainBalances.verified && tokenReadsVerified,
          gossipSupply: gossipSupply, gossipTokens: gossipTokens, gossipVerified: gossipVerified };
        // Unit value = reclaim for 1 token at current supply + surplus; only meaningful once there's at
        // least a token of supply. No currency conversion → no price-feed revert.
        if (supply && supply >= ONE_TOKEN && balance != null) {
          return read(cid, 'JBTerminalStore', reclaimableAbi, 'currentReclaimableSurplusOf', [pid, ONE_TOKEN, supply, balance])
            .then(function (uv) { base.unitValue = uv; return base; })
            .catch(function () { return base; });
        }
        return base;
      });
      });
    });
  }));
}

function emptyCard(title, message) {
  var card = el('div', 'detail-card');
  var t = el('div', 'detail-card-title');
  t.textContent = title;
  card.appendChild(t);
  var body = el('div', 'detail-card-body');
  body.textContent = message;
  card.appendChild(body);
  return card;
}

function kvRow(key, value) {
  var row = el('div', 'detail-ruleset-row');
  var k = el('span', 'detail-ruleset-key');
  k.textContent = key;
  row.appendChild(k);
  var v = el('span', 'detail-ruleset-val');
  v.textContent = value;
  row.appendChild(v);
  return row;
}

// A ruleset-detail row whose key is a node (a split recipient) and value is a percentage.
function splitConfigRow(recipientNode, pct) {
  var row = el('div', 'detail-ruleset-row');
  var k = el('span', 'detail-ruleset-key'); k.appendChild(recipientNode); row.appendChild(k);
  var v = el('span', 'detail-ruleset-val'); v.textContent = (Math.round(pct * 100) / 100) + '%'; row.appendChild(v);
  return row;
}
